window.AGENDA = [{"id":"0b83f3a2-35ba-45c7-9442-54556469d958","date":"2026-06-28","dayLabel":"Sunday, June 28, 2026","start":"2026-06-28T14:00:00+00:00","end":"2026-06-28T18:30:00+00:00","s":"1500","e":"1930","name":"EPS Pre-Registration","loc":"Strathblane: Level 0","track":"","type":"Function","details":"Beat the rush by collecting your badge early for EPS.\nPlease note, there are no sessions on this day - only registration will be open."},{"id":"42ed6079-ff3f-4106-9bfd-0431ec3980cc","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T07:00:00+00:00","end":"2026-06-29T08:00:00+00:00","s":"0800","e":"0900","name":"EPS Registration","loc":"Strathblane: Level 0","track":"","type":"Function","details":"All attendees must register and collect their badge before accessing any of the sessions."},{"id":"58ab69af-3c23-41fc-ab56-c125358c05c1","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T08:00:00+00:00","end":"2026-06-29T08:40:00+00:00","s":"0900","e":"0940","name":"EPS 2026 Opening Ceremony","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":"Join us as we welcome in the week and kick off to EPS 2026!\n\nAll attendees are invited to the opening plenary in the Pentland Suite."},{"id":"903b7b0f-b1f1-4045-9452-0aeee0dc38f9","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T08:40:00+00:00","end":"2026-06-29T09:10:00+00:00","s":"0940","e":"1010","name":"Award Talks: I.101  2026 Alfven Prize:  P. Browning - Solar Coronal Physics","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":""},{"id":"42b66f79-2389-43c2-937a-595962c6a75e","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T09:10:00+00:00","end":"2026-06-29T09:50:00+00:00","s":"1010","e":"1050","name":"Award Talks : 1.102  S Jacquemot Early Career Prize: E Grace - Single-shot spatiotemporal plasma density measurements with a chirped probe pulse","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":"High-power (>TW), short-pulse (<ps) laser systems are generating significant interest worldwide due to their numerous applications in science, technology, medicine and industry. Each of these applications relies upon the plasma that is initially produced by the laser's interaction with the target matter. These laser-plasmas range widely in spatial scales from microns to millimeters, and their dynamics can evolve on femtosecond to nanosecond timescales. Due to the sensitivity with which the plasma properties depend on the laser system, and the downstream effects of this initial plasma on the subsequent secondary sources and physics applications, diagnostics that capture a robust picture of their temporal and spatial evolution on a single shot must be developed for and demonstrated on high-power laser systems.\nStudies of high-power-laser plasmas to-date have been limited by either temporal or spatial resolution or rely on scanning a variable, such as time or delay. Such measurements that use multiple laser shots to form a measurement cannot reliably distinguish between changes due to shot-to-shot variations and changes due to the variable being scanned. To address this problem, we present the development and demonstration of a diagnostic for the measurement of the spatial and temporal evolution of plasma density in a single shot [2]. Single-shot Advanced Plasma Probe HolographIc REconstruction (SAPPHIRE) uses a chirped probe pulse, a diffractive optical element, a self-referenced interferometer, and an interference bandpass filter to achieve high-fidelity electron density measurements suitable for underdense plasmas that exhibit cylindrical symmetry. It overcomes limitations in conventional diagnostics, such as reliance on shot-to-shot reproducibility, while capturing plasma dynamics on picosecond timescales with micron-level spatial resolution. The capabilities of SAPPHIRE are demonstrated through measurements of laser-driven plasma channels in gas jets, including the formation and expansion of plasma channels and the propagation of supersonic ionization fronts while revealing shot-to-shot variations in the plasma profiles. Experimental results are validated against theoretical models and scaling laws, underscoring the robustness and accuracy of this technique. By enabling ultrafast, high-resolution plasma diagnostics in a single exposure, SAPPHIRE represents a transformative advancement in plasma measurement technology.\n[1] E Grace et al. Optica 12 1522 (2025).\n\nAuthor\nElizabeth Grace (Lawrence Livermore National Laboratory)\n\nCo-authors\nAndrew Longman (Lawrence Livermore National Laboratory)\nAustin Linder (Lawrence Livermore National Laboratory)\nDanny Attiyah (University of California Irvine)\nDerek Mariscal (Lawrence Livermore National Laboratory)\nEthan Welch (University of Nebraska Lincoln)\nDr Ghassan Zeraouli (Colorado State University)\nJerry Clark\nMatthew Hill (Lawrence Livermore National Laboratory)\nNuno Lemos (LLNL)\nRick Trebino (Georgia Institute of Technology)\nScott Wilks (Lawrence Livermore National Laboratory)\nStephen Maricle (Lawrence Livermore National Laboratory)\nTammy Ma (Lawrence Livermore National Laboratory)"},{"id":"3b5d9655-a9d2-4d6d-9663-be55b4a43adf","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T09:50:00+00:00","end":"2026-06-29T10:20:00+00:00","s":"1050","e":"1120","name":"***Monday: Morning Refreshment Break***","loc":"Cromdale: Level -2","track":"","type":"Function","details":""},{"id":"ed78dd51-b4e9-41a5-846c-63b8ce998425","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T10:20:00+00:00","end":"2026-06-29T10:55:00+00:00","s":"1120","e":"1155","name":"Plenary Talks - 1.103  S Corde - Plasma acceleration, extreme focusing and SFQED using petawatt electron beams","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":"With today’s accelerator and laser facilities, such as the 10 GeV FACET-II facility at SLAC National Accelerator Laboratory or laser-accelerated electron beams at multipetawatt laser facilities, extreme beam physics is emerging as a promising science area where ultrashort and dense electron beams can be used as a source of TV/m fields, enabling high field matter interaction and new applications in photon science and particle acceleration. In this talk I will present an overview of recent experimental progress, prospects and physics opportunities for the FACET-II accelerator facility and the multipetawatt laser facilities APOLLON and ELI-NP. By delivering extreme electron beams with peak current reaching 100 kA, corresponding to petawatt peak power at 10 GeV, these facilities enable a broad science program ranging from high-field plasma-based acceleration, laboratory astrophysics, extreme focusing and attosecond sources, and probing quantum electrodynamics at the scale of the Schwinger critical field in the so-called strong-field quantum electrodynamics (SFQED) regime. I will highlight recent breakthroughs achieved at FACET-II, such as the most precise measurements of quantum radiation reaction to date, the generation of 100-kA class beams by laser-electron beam shaping, the demonstration of a brightness and energy transformer, efficient plasma acceleration with percent-level field uniformity, and extreme beam focusing by leveraging intense coherent transition radiation in beam-multifoil collisions. At laser facilities, I will show that extreme beam focusing is also possible thanks to the high current of the laser-accelerated electron beams, and I will highlight how plasma mirrors can be used to generate self-aligned nonlinear inverse Compton scattering from high-energy electron beams, opening the way to the study of SFQED at fields well above the Schwinger critical field.\n\nAuthor\nSebastien Corde (Ecole Polytechnique, LOA)"},{"id":"71451c2a-7509-453d-9140-a24648a84647","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T10:55:00+00:00","end":"2026-06-29T11:05:00+00:00","s":"1155","e":"1205","name":"Plenary Talks: I.217   A.  Schekochihin - tribute to Prof. N. Loureiro","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":""},{"id":"0399f7e7-1833-4213-a9a3-a1b9b14de2ce","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T11:05:00+00:00","end":"2026-06-29T11:40:00+00:00","s":"1205","e":"1240","name":"Plenary Talks: 1.104  B Qiao - Research progress of laboratory astrophysics based on large laser facilities in China","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":"Large laser facilities now enables human to generate extreme conditions in the laboratory that can mimick astrophysical environments, creating a new research field known as \"laboratory astrophysics.\" This field is a primary goal for major international facilities like NIF, Omega, Vulcan, and LULI. In China, large laser facilities such as Shenguang-II (SG-II), SG-III, and Xingguang-III (XG-III) have seen major capability enhancements, opening new opportunities for groundbreaking laboratory astrophysics research. Recently, a series of great achievements have been made on these facilities for experimental simulations of various key astrophysical problems, including the origin of magnetic fields in plasmas, particle acceleration in turbulent plasmas, turbulent magnetic reconnection, and accretion disk and jet formation dynamics. Results indicate the kinetic Weibel instability as a fundamental mechanism for cosmic magnetic field generation [1], reveal inherent particle acceleration mechanisms in turbulent plasmas and magnetic reconnections [2-4], and identify the critical role of magnetorotational instability in accretion processes [5,6]. This talk will summarize these advancements and future plans for laboratory astrophysics in China. [1] Z.H. Zhao et al., Sci. Adv. (2024); [2] D.W. Yuan et al., Nat. Commun. (2024); [3] Y. L. Ping et al., Nat. Phys. (2023); [4] Z.H. Zhao et al., Astrophys. J. Letts. (2025); [5] Z. Lei et al., Commun. Phys. (2024); [6] L.X. Li et al., submitted (2025).\n\nAuthors\nProf. Bin Qiao (Peking University)\nDr D.W. Yuan (National Astronomical Observatories, CAS)\nProf. G. Zhao (National Astronomical Observatories, CAS)\nProf. J. Zhang (Shanghai Jiao Tong University)\nProf. J.Y. Zhong (Beijing Normal University)\nDr Y.L. Ping (Beijing Normal University)\nProf. Y.T. Li (Institute of Physics, CAS)\nDr Z. Lei (Institute of Applied Physics and Computational Mathematics)\nDr Z.H. Zhao (Peking University)"},{"id":"d2ef0a8d-08bf-40e9-bdfb-75fc6d1cc01a","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T11:40:00+00:00","end":"2026-06-29T12:15:00+00:00","s":"1240","e":"1315","name":"Plenary Talks: I.109  2025 Alfven Prize: M. Koenig - Laser-plasma interactions applied in the domain of laboratory astrophysics, of high-energy density physics, and of inertial confinement fusion","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":""},{"id":"7a329a75-e34c-4b85-92a2-e396560d5244","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T12:15:00+00:00","end":"2026-06-29T13:30:00+00:00","s":"1315","e":"1430","name":"***Monday: Lunch***","loc":"","track":"","type":"Function","details":"Please note lunch is not catered for during the event. \nThere are many options close by; we have included some recommendations here in the app.\nPlease note that it is not permitted to bring food from outside into the EICC."},{"id":"846384d7-62e6-4506-b3a7-55c2cb028016","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T13:30:00+00:00","end":"2026-06-29T14:30:00+00:00","s":"1430","e":"1530","name":"Monday: POSTER SESSION 2 - BPIF | BSAP","loc":"Kilsyth: Level 0","track":"BPIF","type":"Session","details":"BPIF01 Inertial Confinement Fusion\nBPIF02 High Energy Density Plasmas, Warm Dense Matter and Atomic Physics in Plasmas\nBPIF06 other\n_______________________________________________________________\nBSAP04 Fundamental Plasma Physics - Theory"},{"id":"20a17f72-d127-47bb-a70c-09ce929bc532","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T13:30:00+00:00","end":"2026-06-29T14:30:00+00:00","s":"1430","e":"1530","name":"Monday: POSTER SESSION 1 - MCF | LDTP","loc":"Cromdale: Level -2","track":"MCF","type":"Session","details":"MCF02 SOL, Divertor and PWI\nMCF06 Plasma Diagnostics and Data Analysis\nMCF07 Edge and Pedestal Physics\n__________________________________________________________\nLTDP01 LTP Plasmas for Sustainability\nLTDP03 Agricultural and Bio-medical Applications\nLTDP06 Other"},{"id":"b33e6c71-3a9a-43c2-ae9f-8c931e517b32","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T14:30:00+00:00","end":"2026-06-29T15:00:00+00:00","s":"1530","e":"1600","name":"***Monday: Afternoon Refreshment Break***","loc":"Cromdale: Level -2","track":"","type":"Function","details":""},{"id":"16127492-7f2c-4bf3-bdc6-968105108a6f","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T15:00:00+00:00","end":"2026-06-29T15:40:00+00:00","s":"1600","e":"1640","name":"Plenary Talks: 1.106   T. Eich - Review of Power Exhaust Studies in European Tokamaks and Application to SPARC","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":"Understanding and controlling power exhaust is crucial for the success of SPARC and other future tokamaks. This work presents a comprehensive review of power exhaust studies conducted across European tokamaks. The analysis integrates data from both carbon-based and metallic-wall regimes to characterize divertor heat fluxes. We detail the foundational research that established the empirical multi-machine scaling law for the inter-ELM scrape-off layer (SOL) power decay length. This parameter is needed to predict the steady-state heat flux to the divertor, which in turn determines the level of power dissipation needed to protect the divertor targets from excessive damage or erosion.\n\nWe then review the experimental efforts from JET, ASDEX Upgrade, and MAST to characterize transient heat loads caused by Edge Localized Modes (ELMs). A relationship between the ELM energy fluence and the upstream pedestal-top pressure was identified and later validated on several other tokamaks, including COMPASS, allowing for the prediction of transient heat fluxes in next-step devices. Using these scalings, we show that SPARC and ITER will have similar steady-state and ELM-transient heat fluxes.\n\nTo link these exhaust challenges to operational constraints, we have developed the Separatrix Operational Space (SepOS) framework. This framework describes operational domains such as LH transition and density limit in terms of separatrix parameters which are key for power dissipation and detachment access. In addition, it has been shown to correlate with the transition between large “type-I” ELMs and the small-ELM QCE/EDA regime. This allows us to identify conditions where both the steady-state and transient heat fluxes can be tolerated in high-performance regimes on future tokamaks.\n\nHowever, the studies on SepOS do not yet include impurity seeding cases. Furthermore, SOLPS modeling for ITER has shown that the highest achievable separatrix density is limited by the presence of impurities in the divertor region. The application of this methodology to SPARC yields similar results, identifying a corresponding reduction in the available separatrix operational space. Thus, the presentation concludes with both a discussion on these remaining gaps in our understanding, as well as a brief outlook to the boundary digital twin for SPARC, which incorporates the extensive heritage and data from European tokamaks.\n\nAuthor\nThomas Eich (Commonwealth Fusion Systems)\n\nCo-authors\nAlberto Loarte (ITER Organization)\nDr Andreas Redl (Commonwealth Fusion Systems)\nB Lomanowski (Oak Ridge National Laboratory)\nBernhard Sieglin (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nDr Itziar Balboa (UKAEA)\nJeremy Lore (Oak Ridge National Laboratory)\nMichael Faitsch (Max Planck Institute for Plasma Physics)\nProf. Peter Manz (University of Greifswald)\nPhilip Snyder (Commonwealth Fusion Systems)\nRichard A. Pitts (ITER Organisation, France)\nDr Sean Ballinger (Commonwealth Fusion Systems)\nStuart Henderson (UKAEA)\nDr Thomas Body (Commonwealth Fusion Systems)\nDr Thomas Looby (Commonwealth Fusion Systems)"},{"id":"5fa0107d-6926-4172-bd8d-6fd80cce8473","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T15:40:00+00:00","end":"2026-06-29T16:20:00+00:00","s":"1640","e":"1720","name":"Plenary Talks: I.107   T. Wauters - From startup to burn: plasma-wall interaction implications for Q=10 in the full tungsten ITER","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":"The new 2024 ITER baseline introduces a tungsten (W) first wall (FW), requiring renewed assessments of plasma-wall interactions and their impact on achieving the Q=10 performance target. This contribution provides a brief update of the status of ITER, and focusses on assessments of how the new wall material will impact key phases of ITER scenarios, from burn-through in limiter configuration, through diverted L-modes and finally, to the principal objective of burning plasma operation in H-mode. It details the implementation of risk mitigation measures, in particular the boronization system, which is critical for plasma start-up as demonstrated in dedicated experiments performed in WEST and ASDEX Upgrade. This overview also addresses the important issue of fuel retention and recovery strategies.\nThroughout the limiter phase of ITER plasma scenarios, W erosion, core W contamination and edge power flow are coupled in an experimentally confirmed strongly self-regulated system, resulting in high core radiation and advantageously lowering power fluxes to the FW surface, but requiring central electron cyclotron heating (ECH) to prevent uncontrolled W accumulation. For L-mode diverted plasmas, central ECH also enables operation with moderate core radiated fractions from W wall sources, consistent with the range observed in current experiments with W plasma-facing components. For Q ≥ 10 H-mode scenarios, assumed to have no ELMs (either by active control or by access to naturally ELM-free plasmas compatible with Q ≥ 10), the full W pathway from source to core is quantified by combining new wide grid plasma boundary simulations, where wall and divertor loads are set within design specifications, with erosion source modelling to predict the W concentration at the separatrix, coupled to the core through state-of-the-art integrated modelling. This approach improves on the first studies performed for the re-baseline by maintaining consistent W transport assumptions across codes to provide a realistic assessment of the W source and transport. The analysis confirms, with greater confidence in the W source modelling, the key finding of the initial physics studies in support of the re-baseline, that the risk to the 500 MW fusion power target of switching to an all-W ITER is mitigated by the increased ECH power in the re-baseline, although with a reduction of Q for the highest W erosion sources for wall loads reaching their design limits.\n\nAuthors\nTom Wauters (ITER Organization (IO))\nRichard A. Pitts (ITER Organisation, France)\nAlberto Loarte (ITER Organization)\nChristoph Baumann (Forschungszentrum Jülich)\nSebastijan Brezinsek (Forschungszentrum Jülich)\nMaksim Dubrov (ITER Organization)\nFlorian Koechl (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 Saint Paul-lezDurance Cedex, France)\nHenri Kumpulainen (Forschungszentrum Jülich)\nAndrei Pshenov (ITER Organization (IO))"},{"id":"2a01fc17-a2c0-4116-816a-f51b82c08107","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T16:20:00+00:00","end":"2026-06-29T16:50:00+00:00","s":"1720","e":"1750","name":"Plenary Talks: I.108   M. Jakubowski - Key Physics Gaps on the Path from W7-X to a HELIAS Reactor","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":"Advancing a HELIAS-type stellarator toward DEMO requires a systematic reduction of critical physics uncertainties that directly impact reactor performance. This work discusses and prioritizes these uncertainties based on their influence on machine design, the urgency for near-term decisions, and the feasibility of closing knowledge gaps through current experimental access and tool maturity. The analysis focuses on five key areas: core transport, MHD stability, fast-ion confinement, plasma exhaust, and plasma-material interactions.\n\nWhile W7-X has successfully validated neoclassical transport optimization, significant gaps remain. Turbulent transport must be characterized across diverse density-gradient regimes to fully understand configuration-dependent confinement. Furthermore, advanced core turbulence modelling is needed to incorporate electromagnetic effects at high pressure and Alfvénic mode coupling, both of which can significantly alter heat transport. As W7-X is currently a predominantly carbon device, establishing impurity-tolerant operation compatible with a metallic wall remains a critical challenge; multi-species impurity transport must therefore be addressed to ensure core-edge compatibility.\n\nFast-ion confinement at high-β, particularly regarding losses driven by Alfvén eigenmode coupling, represents another critical uncertainty affecting first-wall loading and requires high-fidelity quantitative predictions. Finally, island divertor physics presents several open questions: drift effects on heat and particle transport must be quantified, and the necessity of divertor closure for HELIAS needs validation. Ensuring consistent detachment, assessing helium ash removal against dilution limits, and verifying the robustness of divertor topology under finite-β variations are essential for defining a stable exhaust geometry. Addressing these priorities — specifically by executing integrated scenarios at 5–7 T with coupled core–edge modelling — will establish the physics foundation for next-step stellarator reactors.\n\nAuthor\nMarcin Jakubowski (Max Planck Institute for Plasma Physics)\n\nCo-authors\nDr Alexandr Mischenko (Max Planck Institute for Plasma Physics)\nDr Andreas Dinklage (Max Planck Institute for Plasma Physics)\nArturo Alonso (CIEMAT)\nChristoph Slaby (Max Planck Institute for Plasma Physics)\nDaniel Carralero (CIEMAT)\nDr Dirk Naujoks (Max Planck Institute for Plasma Physics)\nFelix Reimold (Max Planck Institut for Plasma Physics)\nProf. Felix Warmer (Max Planck Institute for Plasma Physics)\nDr Heinrich Laqua (Max Planck Institute for Plasma Physics)\nDr Ivan Calvo (CIEMAT)\nDr Joachim Geiger (Max Planck Institute for Plasma Physics)\nDr Joaquim Loizu (EPFL)\nDr Joris Fellinger (Max Planck Institute for Plasma Physics)\nJose Luis Velasco (CIEMAT)\nDr Jose Manuel Garcia-Regaña (CIEMAT)\nDr Juri Romazanov (Forschungszentrum Jülich)\nDr Ksenia Aleynikova (Max Planck Institute for Plasma Physics)\nNerea Panadero (CIEMAT)\nDr Pavel Aleynikov (Max Planck Institute for Plasma Physics)\nProf. Sebastijan Brezinsek (Forschungszentrum Jülich)\nDr Sergey Bozhenkov (ITER Russia)\nDr Thierry Kremeyer (Max Planck Institute for Plasma Physics)\nDr Valeria Perseo (Max Planck Institute for Plasma Physics)"},{"id":"9744ea34-56e2-4232-8a32-0c6f61d3833b","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T16:50:00+00:00","end":"2026-06-29T17:30:00+00:00","s":"1750","e":"1830","name":"Plenary Talks: I.105   M. Janvier - The Sun and the solar wind: Linkage science with Solar Orbiter","loc":"Pentland Suite: Level +3","track":"PLENARY","type":"Session","details":"The ESA/NASA Solar Orbiter mission started its nominal science phase at the end of 2021, after a little less than two years of cruise phase. By June 2026, 9 remote-sensing observation campaigns will have taken place, with coordination with other international space missions as well as ground-based infrastructures. On top of this, Solar Orbiter regularly monitors the Sun and the heliosphere with its 10 suites of remote-sensing and in situ instruments.\n\nThe mission therefore gives an unprecedented linkage between the activity of the Sun and measurements of dynamic processes happening in the solar wind.\n\nRecent observations reveal that tiny plasma jets in coronal holes, only a few hundred kilometers wide and lasting about a minute, may contribute to both the fast and slow solar wind, suggesting that similar small-scale processes can feed multiple outflow regimes. Coordinated campaigns have also shown that variations in the elemental and charge-state composition of the solar wind correspond to specific source regions on the Sun, from open coronal holes to boundary layers between open and closed magnetic field structures. These regions, shaped by magnetic reconnection, provide escape channels for plasma with distinctive composition “fingerprints” that ultimately can flow into interplanetary space.\n\nOn top of this, the Sun’s atmosphere is highly dynamical: they are the locations of energetic events such as solar flares, which can accelerate particles in the interplanetary medium. These solar energetic particle (SEP) events can have strong enrichments in certain heavy ions, helping connect their source regions via remote composition diagnostics and therefore constrain models of acceleration processes.\n\nThroughout this talk, we will thus see how Solar Orbiter provides an unparalleled opportunity to observe how processes in the solar atmosphere, and in particular its various magnetic regions, shape and modulate events in the heliosphere.\n\nAuthor\nMiho Janvier (European Space Agency)"},{"id":"38d66ebd-1ec9-441c-bf2d-29e6e3a69468","date":"2026-06-29","dayLabel":"Monday, June 29, 2026","start":"2026-06-29T17:30:00+00:00","end":"2026-06-29T20:00:00+00:00","s":"1830","e":"2100","name":"EPS Welcome Reception","loc":"Cromdale: Level -2","track":"","type":"Function","details":"Come and join for a drink, some food and a chance to network as we kick off the week in style."},{"id":"acee574b-a94e-485b-ab17-1f7bc215e107","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T07:00:00+00:00","end":"2026-06-30T08:00:00+00:00","s":"0800","e":"0900","name":"AGENDA KEY INFORMATION: PLEASE READ","loc":"","track":"","type":"Information","details":"Please click on each session to view the session details including the abstract and the authors. \n\nTo add the session to your personal agenda, please click the star. \n\nYou can view your personal agenda by returning to the home screen and clicking the 'My Agenda' icon."},{"id":"ade468f9-322a-4733-8ab7-dc8b9d5fb5d8","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:00:00+00:00","end":"2026-06-30T08:25:00+00:00","s":"0900","e":"0925","name":"I.213 - R. Trines: Laser high-harmonic generation in plasma: the new beat wave","loc":"Fintry: Level +3","track":"BPIF: Laser-plasma radiation sources","type":"Session","details":"In recent years, we have developed a novel framework to describe laser harmonic generation in plasma as an advanced beatwave process [1]. In our framework, all laser pulses are decomposed into modes with pure circular polarisation and “signed” frequencies and wave numbers. Each spectral step in the harmonic generation process can then be described as the beating between two such modes. The resulting harmonic spectrum will then show peaks with regular distribution along a 1-D line or a 2-D grid. We have also developed a novel method to analyse the harmonic radiation that will bring out this regular spectral structure. We apply our framework to the problem of generating harmonics via the interaction of a powerful laser pulse with solid targets with a structured surface and aperture targets with a structured inner edge [1]. We show that regular harmonic spectra are obtained in all cases, and that the spectral peak spacing can be tuned via the structure of the target. We also show how a laser frequency comb can be obtained by first generating a 2-D harmonic spectrum (e.g. frequency and OAM level, or frequency and transverse wave number) and then preferentially selecting a 1-D subset from this spectrum, for which the harmonic peak spacing is wider than in the full 2-D spectrum [2]. The wide range of configurations returning a 2-D harmonic spectrum (laser hitting a complex aperture or a corrugated target, or two laser beams hitting a flat target) guarantees a wide choice of potential frequency combs. Finally, we elucidate the role of symmetries of the original laser-target configuration in predicting the resulting harmonic spectrum [3]. Including these symmetries in our framework allows us to show the connection between our work and well-known mathematical theorems (Noether, Jacobi-Anger) as well as various spectral theorems known from solid-state physics (Laue, Mathieu, Floquet, Bloch).\n\n[1] R. Trines et al., Nature Communications 15, 6878 (2024).\n\n[2] R. Trines et al., arXiv:2410.03599 (2024).\n\n[3] R. Trines et al., arXiv:2507.08635 (2025).\n\nAuthor\nRaoul Trines (STFC Rutherford Appleton Laboratory)\n\nCo-authors\nHolger Schmitz (Central Laser Facility, STFC Rutherford Appleton Laboratory, Didcot, United Kingdom)\nDr Martin King (Department of Physics, SUPA, University of Strathclyde)\nProf. Paul McKenna (Department of Physics, SUPA, University of Strathclyde)\nProf. Robert Bingham (STFC Rutherford Appleton Laboratory)"},{"id":"c65205e8-1992-492b-b3f7-3a01511988d9","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:00:00+00:00","end":"2026-06-30T08:25:00+00:00","s":"0900","e":"0925","name":"I.207 - P. Morrison: On the closure of the BBGKY hierarchy","loc":"Tinto: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (I)","type":"Session","details":"The fundamental closure of the BBGKY hierarchy is based on largeness of the plasma parameter, g, the number of particles in a Debeye sphere. Closure yields the Hamiltonian [1] Vlasov-Maxwell (VM) equations and/or the metriplectic [2] VM equations with the Landau-Lenard-Balescu (LLB) collision operator. Both models are used with arbitrary initial conditions, with the latter model having a formal H-theorem to thermal equilibrium. Here we address two issues: i) Because g depends on a temperature, for any initial condition, what is meant by this approximation? ii) The LLB collision operator derivation uses the Bogoliubov (B) assumption on the decay of correlations. Given that structures can appear in phase space, to what degree is this assumption valid. With regard to issue i) we can consider alternative closure procedures. However, issue ii) is problematic given the lack of rigor and numerical testing, which is prohibitive because of high dimensionality. A 1D electrostatic plasma model that can bring computations within reach has been proposed [3]. This model replaces particles by disks that exhibits 1-D features at short distances, but retains 3-D features at large distances. The dynamics of this model is investigated analytically, implementation for numerical validation of the B assumption is formulated, and recent results described.\n\n[1] J Marsden, et al., Contemp. Math. 28, 115 (1984).\n\n[2] P J Morrison, and M. Updike, Phys. Rev. E 09, 045202 (2024).\n\n[3] F Pegoraro et al., Rev. Mod. Plasma Phys. 8, 36 (2024)\n\nAuthor\nProf. Philip Morrison (The University of Texas at Austin)"},{"id":"099f0bc1-4fc0-4a9d-a682-9ea3a0d4541b","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:00:00+00:00","end":"2026-06-30T08:25:00+00:00","s":"0900","e":"0925","name":"I.227 - D. Dellasega: Understanding the features of high power impulse magnetron sputtering plasma for the synthesis of nanostructured materials","loc":"Moorfoot: Level 0","track":"LTDP: Magnetized Plasmas","type":"Session","details":"High power impulse magnetron sputtering is a new and promising physical vapor deposition technique. In this technique, differently from DC magnetron sputtering, the use of proper voltage pulses, in the microsecond regime, leads to the formation of a plasma population made of sputtered species in addition to the usual Ar ones. The evolution of such plasma plays a pivotal role in determining the features of the growing film. Thanks to the presence of the metal ion population, the deposition of more compact and crystalline films, as well as formation of compounds at low temperature, is possible [1]. If, on one side, this technique is very promising, on the other many parameters determine the generation of a so complex plasma (e.g. pulse features, magnetic field, gas composition, pressure, etc.) and their role need to be understood. To properly investigate this phenomenon, a multi technique approach is presented focused on metallic and nitride nanomaterials for energy applications [2]. The features of the grown films (morphology and crystallinity) are studied using a material science approach, by SEM and XRD, allowing to link materials feature and process parameters. Then plasma is characterized by OES determining the generated ionic species and monitoring the plasma current during the voltage pulse. The composition of such current is modelled by means of an Ionization Region Model [3,4] that allows the prediction of temporal evolution of every single species. Combining the data it’s possible to envisage the evolution of plasma. This, in turn, allows to predict the coating growth conditions depending on the composition of the impinging ion flux.\n\nReference:\n[1] J. T. Gudmundsson, N. Brenning, D. Lundin, et al., J. Vac. Sci. Technol. A, 30, 2012\n[2] L. Bana, et al., Surface and Coatings Technology, 514, 2025, 132544\n[3] J.T. Gudmundsson, et al., Plasma Sources Sci. Technol. 25 (6), 2016, 065004\n[4] M.A. Raadu, et al., Plasma Sources Sci. Technol. 20 (6), 2011, 065007\n\nAuthor\nDavid Dellasega (Politecnico di Milano)\n\nCo-authors\nDr Alessandro Maffini (Politecnico di Milano)\nDr Davide Vavassori (Politecnico di Milano)\nDr Francesco Mirani (Politecnico di Milano)\nProf. Matteo Passoni (Politecnico di Milano)"},{"id":"7aed621d-a13d-4607-acb2-72af4e117bef","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:00:00+00:00","end":"2026-06-30T08:25:00+00:00","s":"0900","e":"0925","name":"I.205 - M. Van Berkel:Systematic multi-machine analysis of the exhaust time-dependent behavior in tokamaks","loc":"Pentland Suite: Level +3","track":"MCF: Div/SOL","type":"Session","details":"This work presents an overview of experimental investigations of the exhaust dynamics in TCV, MAST-U, ASDEX-Upgrade, WEST, DIII-D, and JET. Using various different perturbations such as gas-injection, impurity injection, and power modulations and corresponding responses on various outputs is analyzed. From these experiments, a clear picture arises on properties of the exhaust dynamics across machines. Particularly, we observe that the scrape-off layer equilibrates on fast time-scales and strong similarities across scenarios (H-mode, L-mode), injected species, and injection locations. On the other hand, we see clear differences when analyzing different exhaust properties. This is all summarized in a database that is for the validation of dynamic exhaust models for reactor design. Moreover, some measurements presented have formed the basis for systematic exhaust control on the considered devices.\n\nhttps://iopscience.iop.org/article/10.1088/1741-4326/ae30f1\n\nAuthor\nMatthijs van Berkel (DIFFER)"},{"id":"22c89e0e-f032-4680-8934-937035f76014","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:00:00+00:00","end":"2026-06-30T08:25:00+00:00","s":"0900","e":"0925","name":"I.201 - E. Sánchez González: CIEMAT-QI4X: a reactor-candidate quasi-isodynamic stellarator configuration","loc":"Sidlaw: Level +3","track":"MCF: Stellarators","type":"Session","details":""},{"id":"46e35b50-3f76-4b4b-ba61-1ef6da87c268","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:25:00+00:00","end":"2026-06-30T08:50:00+00:00","s":"0925","e":"0950","name":"I.214 - Liao. G: Ultraintense laser-driven terahertz pulses from plasmas","loc":"Fintry: Level +3","track":"BPIF: Laser-plasma radiation sources","type":"Session","details":"Ultraintense laser-plasma interactions offer a novel approach to generating high-power terahertz (THz) radiation, and have aroused ever-increasing interest. This talk will review the latest progress on the ultraintense laser-driven THz radiation from plasmas. TW-scale THz bursts have been demonstrated experimentally by irradiating a thin foil with a high-intensity femtosecond or picosecond laser pulse. By tuning the laser or target parameters, the THz spectra can be tuned effectively over a wide range of 1~20 THz, and the laser-to-THz energy conversion efficiency can be boosted up to ~1%. Recently, the tens-of-femtoseconds duration and ultrafast recirculation dynamics of fast electrons have been revealed from the THz self-emission, demonstrating a novel in-situ diagnostic of laser plasmas. Such extreme THz pulses enable the previously inaccessible relativistic optics in the THz regime. Recent studies on the THz plasmas, including the strong-field THz ionization of dielectrics, anomalous plasma-induced THz self-focusing, and ionization-induced THz transparency, will also be presented.\n\nAuthor\nGuoqian Liao (Institute of Physics, Chinese Academy of Sciences)"},{"id":"1aab6016-7108-4532-96ef-3ac9d571fdad","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:25:00+00:00","end":"2026-06-30T08:50:00+00:00","s":"0925","e":"0950","name":"I.208 - Y-F Li: Numerical Investigation of Spin-Resolved Dynamics for Polarized Particle Generation in Strong-Field QED","loc":"Tinto: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (I)","type":"Session","details":"Polarized positrons and gamma rays are pivotal for probing fundamental physics, yet their generation has long been constrained by a fundamental trade-off between yield, polarization, and efficiency. Conventional methods suffer from low yields or significant depolarization, while existing laser-driven approaches typically produce only transversely polarized particles.\nThis talk presents a unified theoretical framework for modeling spin and polarization dynamics in strong-field QED interactions [1-3]. Building on this foundation, they propose novel all-optical schemes to generate polarized high-brightness gamma-ray sources [3] and spin-polarized positron beams using ultra-intense lasers [1,5]. They works also reveal new polarization physics arising from QED radiative corrections in laser-electron interactions. They demonstrate a method to generate highly polarized GeV gamma-rays and a compact, single-stage scheme producing longitudinally polarized positrons with high yield and polarization. These advanced beams open the way for laboratory-scale investigations of astrophysical radiation mechanisms—such as gamma-ray bursts and black hole jet emissions—by enabling controlled studies of polarization-dependent, high-energy interactions. This work also establishes a practical route toward compact polarized positron sources for next-generation high-energy physics.\n\n[1] Li et al., Phys. Rev. Lett. 125, 044802 (2022);\n[2] Li et al., Phys. Rev. Lett. 124, 014801 (2020);\n[3] Li et al., Phys. Rev. Lett. 122, 154801 (2019);\n[4] Wu et al., Commun Phys 8, 156 (2025);\n[5] Qin et al., to be submitted (2025).\n\nAuthor\nYan-Fei Li (Xi'an Jiaotong University)"},{"id":"74f31486-12ab-49aa-9b3c-52cb6abbe61d","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:25:00+00:00","end":"2026-06-30T08:50:00+00:00","s":"0925","e":"0950","name":"I.228 - RP. Brinkmann: Field-aligned Clebsch-type flux coordinates for rectangular magnetrons","loc":"Moorfoot: Level 0","track":"LTDP: Magnetized Plasmas","type":"Session","details":"Large-scale rectangular magnetrons are central to industrial high-throughput coating, yet their theoretical description remains challenging due to the complex topology of their non-axisymmetric magnetic fields. We construct field-aligned Clebsch-type flux coordinates for the confinement region above the cathode, starting from a physically admissible vacuum field generated by an optimized ensemble of sub-surface magnetic dipoles. The magnetic flux partitions the domain into core, return region, and halo, bounded by neutral curves that form the geometric backbone of the construction. In contrast to axisymmetric devices with a single apex null and magnetic dome, elongated rectangular configurations may, beyond a critical aspect ratio, undergo a symmetry-breaking bifurcation of the central null and develop additional off-axis null points. Below the corresponding bifurcation height we identify a regular domain in which field lines remain arc-like and connect core and return region. The technically relevant active region is a subset of this domain and comprises those arc-like field lines along which the magnetic field strength exceeds a prescribed threshold. Within the regular domain, a magnetic flux function and a generalized azimuth are constructed that label flux surfaces and individual field lines and reproduce the magnetic field in Clebsch form, while an arc-length coordinate completes the system.\n\nAuthor\nRalf Peter Brinkmann (Ruhr-Universität Bochum)\n\nCo-authors\nDenis Eremin\nDennis Krüger\nJens Kallähn\nKevin Köhn\nLiang Xu\nLukas Vogelhuber\nYulia Sharova"},{"id":"d31f93a8-872e-457e-b050-e992370ee3af","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:25:00+00:00","end":"2026-06-30T08:50:00+00:00","s":"0925","e":"0950","name":"I.206 - F. Reimold: Stellarator island divertor physics in Wendelstein 7-X: Current understanding and remaining challenges towards a reactor exhaust concept","loc":"Pentland Suite: Level +3","track":"MCF: Div/SOL","type":"Session","details":"In recent years, the stellarator concept has attained increasing attention as an alternative path to a fusion reactor. The Wendelstein 7-X (W7-X) experiment has successfully demonstrated power and particle exhaust with the island divertor, achieving high-performance operation and homogeneous detachment. However, the current open divertor geometry suffers from an unfavorable scalings of divertor density and neutral pressure with upstream density, posing challenges for power and particle exhaust towards a reactor. Despite these limitations, W7-X has significant flexibility in operational and magnetic configuration parameters, allowing for a better understanding of the complex 3D geometry and relevant physics, both in full and simplified models. Recent advancements in imaging diagnostics have provided clear signatures of the 3D structure of the island divertor plasma, and emerging reactor-relevant scaling approaches are being developed. Advances in modeling capabilities enable mean-field and turbulence simulations with the drift-reduced Braginskii model, which are paired with W7-X observations to gain insight into island divertor physics. The boundary island geometry is becoming part of magnetic configuration optimization for future reactor designs, and refined insights into geometric island parameters are being developed to tailor properties for new concepts. Initial results suggest promising paths towards reactor-relevant exhaust performance.\n\nAuthors\nAmit Kharwandikar (Max Planck Institut for Plasma Physics)\nAnastasios Tsikouras (Max Planck Institut for Plasma Physics)\nCarsten Killer (Max Planck Institut for Plasma Physics)\nDaniel Matthew Kriete (Auburn University)\nDirk Naujoks (Max Planck Institut for Plasma Physics)\nFelix Reimold (Max Planck Institut for Plasma Physics)\nFrederik Henke (Max Planck Institut for Plasma Physics)\nNassim Maaziz (Max Planck Institut for Plasma Physics)\nSebastian Thiede (Max Planck Institut for Plasma Physics)\nSergei Makarov (Proxima Fusion)\nTobias Tork (Max Planck Institut for Plasma Physics)\nValeria Perseo (Max Planck Institut for Plasma Physics)\nVictoria Haak (Max Planck Institut for Plasma Physics)\nVictoria Winters (University Greifswald)\nW7-X Team (Max Planck Institut for Plasma Physics)\nYu Gao (Max Planck Institut for Plasma Physics)"},{"id":"9a2abb3c-6ffb-4267-b448-b02f23f04974","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:25:00+00:00","end":"2026-06-30T08:50:00+00:00","s":"0925","e":"0950","name":"I.202 - G. Plunk: Optimizing the physics of quasi-isodynamic stellarators","loc":"Sidlaw: Level +3","track":"MCF: Stellarators","type":"Session","details":"The non-axisymmetric toroidal magnetic geometry of a stellarator presents a vast space, in which one can find designs of different shapes and properties, filling a number of different stellarator classes. This talk focuses on the quasi-isodynamic (QI) stellarator, which promises a number of uniquely attractive properties that make it a front-runner for future stellarator power plants. Although the Wendelstein 7-X stellarator, whose design can be thought of as an early precursor of the QI variant, has validated a number of these expectations, it is only over recent years that advances in stellarator optimization have demonstrated that the full potential of QI stellarators could be realized in practice. We will discuss the physics of QI stellarators, and how this understanding is being used to design the next generation of experiments and fusion reactor designs. These designs combine intrinsic stability, excellent confinement of fusion-born alpha particles, and the resilience in shape needed for reliable and predictable operation. Our deepening understanding of the turbulence in QI stellarators has also enabled us to incorporate key physics into the optimization, such as zonal flows, flux compression, and maximum-\n stabilization. Understanding the strong coupling of heat and particle transport channels has lead to designs with a tendency to draw fuel inward, with strong consequences for performance and economics of future devices.\n\nAuthors\nDr Alan Goodman (Max Planck Institute for Plasma Physics)\nCraig D. Beidler\nGabriel Plunk (Max Planck Institute for Plasma Physics)\nHakan Smith (Max Planck Institute for Plasma Physics)\nKsenia Aleynikova (Max Planck Institute for Plasma Physics)\nDr Michael Drevlak (Max Planck Institute for Plasma Physics)\nP. Helander\nMr Paul Costello\nDr Pavlos Xanthopoulos (Max Planck Institute for Plasma Physics)\nMr Sven Stroteich"},{"id":"587d29cb-aec6-4384-9248-b2e9b9e86fba","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:50:00+00:00","end":"2026-06-30T09:15:00+00:00","s":"0950","e":"1015","name":"I.515 - M. Mirzaie: Strong-Field QED Studies with multi PW lasers","loc":"Fintry: Level +3","track":"BPIF: Laser-plasma radiation sources","type":"Session","details":"State-of-the-art high-power laser systems are now enabling the exploration of quantum electrodynamics (QED) in the nonperturbative, strong-field regime, where electromagnetic fields approach or surpass the so-called critical “Schwinger” limit of QED [1]. In this extreme regime, phenomena such as nonlinear Breit-Wheeler pair production, vacuum birefringence, and quantum radiation reaction effects are predicted to emerge — effects that remain experimentally unobserved under controlled laboratory conditions. Achieving the required field strengths demands laser intensities around 2.3×10²⁹ W/cm², which greatly exceed the current maximum of 10²³ W/cm² [2]. A promising approach to access this regime involves nonlinear Compton scattering between ultra-relativistic electron beams and ultra-intense laser pulses, offering a practical platform to investigate strong-field QED effects. Resent advances in laser-plasma accelerator technology, particularly laser wakefield acceleration (LWFA) [3], has opened new possibilities for all-optical investigation of strong-field QED, now actively pursued by several research groups worldwide. In our previous study, we experimentally investigated nonlinear Compton scattering in intense laser fields, where a multi-GeV electron simultaneously interacts with hundreds of laser photons. Using LWFA, we generated an ultra-relativistic electron beam and collided it with a high-intensity laser pulse, reaching the quantum nonlinearity parameter corresponding to about half of Schwinger field strength. This interaction produced GeV-scale gamma rays via multiphoton Compton scattering, extending well beyond the linear Compton limit and marking the onset of the strongly nonlinear regime [4].\nHere, we present our latest experimental results demonstrating interactions at effective field intensity exceeding the Schwinger limit. We utilized CoReLS 1 PW beamline for scattering laser, increasing its ɑ0 by a factor of four, and collided with 2.2 GeV LWFA-driven electron using another multi PW beamline. The resulting post-collision electron spectra show signatures consistent with radiation reaction effects, calculated using experimental parameters.\nThis work was supported by the Institute for Basic Science grant (IBS-R038-D1).\nReferences\n[1] A. Di Piazza, et al. \"Extremely high-intensity laser interactions with fundamental quantum systems.\" Rev. Mod. Phys. 84, 1177-1228 (2012).\n[2] Yoon, Jin Woo, et al. \"Realization of laser intensity over 1023 W/cm2.\" Optica 8.5, 630-635 (2021).\n[3] M. Mirzaie et al. \"Demonstration of self-truncated ionization injection for GeV electron beams.\" Sci. Rep. 5, 14659 (2015).\n[4] M. Mirzaie et al. \"All-optical nonlinear Compton scattering performed with a multi-petawatt laser.\" Nat. Photon. 18, 1212-1217 (2024).\n\nAuthor\nDr Mohammad Mirzaie (Center for Relativistic Laser Science (CoReLS), IBS Korea)\n\nCo-authors\nDr Calin Ioan Hojbota (Center for Relativistic Laser Science (CoReLS), IBS Korea)\nDr Do Yeon Kim (Center for Relativistic Laser Science (CoReLS), IBS Korea)\nProf. Marija Vranic (GoLP/Instituto Superior Tecnico Unversidade de Lisboa, Lisbon, Portugal)\nMr Oscar Amaro (GoLP/Instituto Superior Tecnico Unversidade de Lisboa, Lisbon, Portugal)\nDr Chul Min Kim (Advanced Photonics Research Institute, GIST, Gwangju, Korea)\nDr Joohwan Kim (Center for Relativistic Laser Science (CoReLS), IBS Korea)\nDr Ki Hong Bae (Advanced Photonics Research Institute, GIST, Gwangju, Korea)\nDr Jae Hee Sung (Advanced Photonics Research Institute, GIST, Gwangju, Korea)\nDr Hyung Taek Kim (Advanced Photonics Research Institute, GIST, Gwangju, Korea)\nProf. Kyung Taec Kim (Dept. of Physics and Photon Science, GIST, Gwangju, Korea)\nProf. Chang Hee Nam (Dept. of Physics and Photon Science, GIST, Gwangju, Korea)"},{"id":"6b066a22-9c16-474d-8969-d6c0c1ec9e27","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:50:00+00:00","end":"2026-06-30T09:15:00+00:00","s":"0950","e":"1015","name":"I.209 - P. Bilbao (PhD prize): Kinetic Instabilities in Extreme Plasma Physics: Laboratory and Astrophysical Dynamics","loc":"Tinto: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (I)","type":"Session","details":"Extreme plasma physics concerns regimes in which strong electromagnetic fields, intense radiation, and matter–antimatter pair production fundamentally alter kinetic plasma behaviour. Such conditions arise in pulsar and black-hole magnetospheres, relativistic shocks, and are increasingly accessible in laboratory experiments. This thesis addresses two central components of this field: radiative plasma kinetics and electron–positron pair-plasma dynamics.\nA kinetic model for radiatively dominated plasmas is developed using analytical theory and large-scale particle-in-cell simulations. Synchrotron cooling in strongly magnetized collisionless plasmas is shown to drive phase-space bunching, generically producing anisotropic ring-shaped momentum distributions with population inversion, i.e., ∂ f /∂ p⊥ > 0. These non-equilibrium states are unstable to the electron cyclotron maser instability (ECMI). Radiation reaction sustains the phase-space bunching, maintaining coherent emission beyond classical saturation. An analogous radiation-reaction–driven mechanism also arises in plasma wakefield accelerators, where betatron cooling induces amplitude bunching and ring-like phase-space structures in relativistic beams, enabling coherent emission via the ion-channel laser instability.\nThe thesis further investigates the collective behaviour of relativistic electron–positron plasmas, with contributions to the first laboratory generation of high-density, quasi-neutral pair beams at CERN’s SPS and led three-dimensional kinetic simulations demonstrating that realistic energy spread and angular divergence suppress current-filamentation growth. Additional non-ideal effects, including charge imbalance and multi-species components, were also analysed. This improved understanding of pair-beam instabilities establishes experimental constraints relevant to γ-ray–induced pair cascades and limits on the intergalactic magnetic field.\nTogether, these studies advance a unified kinetic description of extreme plasmas encompassing both radiative effects and pair-plasma dynamics.\n\nAuthor\nDr Pablo Bilbao (GoLP/Instituto de Plasmas e Fusão Nuclear, Instituto Superior Técnico, Universidade de Lisboa, 1049-001 Lisbon, Portugal)"},{"id":"2766dbe7-8144-49a7-a653-7b3e35e86626","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:50:00+00:00","end":"2026-06-30T09:15:00+00:00","s":"0950","e":"1015","name":"I.229 - R. Karimov: Impact of resonant second-harmonic generation on helicon-wave damping","loc":"Moorfoot: Level 0","track":"LTDP: Magnetized Plasmas","type":"Session","details":"Helicon discharges are widely used to produce high density, low temperature, moderate magnetic field plasmas and are central in a broad range of applications, such as plasma-material interaction studies, electric propulsion, fundamental plasma physics investigations, auxiliary heating in tokamaks, and wake-field particle acceleration. In such plasmas, helicon wave damping is commonly assumed to be dominated by collisional dissipation.\n\nIn this work, we combine a normal-mode analysis with spatially resolved magnetic field measurements using a movable B-dot probe to investigate helicon wave damping over a broad parameter space. While collisional models accurately describe most operating regimes, we identify a specific parameter window in which the damping of the fundamental helicon mode is reduced by approximately a factor of two relative to collisional predictions. In this regime, a coherent magnetic-field component at the second harmonic frequency 2ω becomes clearly detectable, contributing up to ~10% of the total magnetic signal.\n\nUsing a weakly nonlinear perturbative framework, we show that this second-harmonic component arises from a resonant wave–wave interaction of the form ω + ω → 2ω. Importantly, the analysis reveals a nonlinear back-coupling from the second harmonic to the fundamental mode, which quantitatively accounts for the observed reduction in damping. Although second-harmonic helicon waves have been reported previously, their role has not been identified as a resonant nonlinear mechanism with a measurable impact on helicon wave dissipation.\n\nBased on this analysis, we derive a simple predictive criterion that identifies the parameter range in which this nonlinear interaction is important. Preliminary measurements from the CERN AWAKE Helicon Plasma Source exhibit similar harmonic signatures, suggesting that this mechanism may be robust across different helicon devices.\n\nAuthor\nRenat Karimov (Ecole Polytechnique Fédérale de Lausanne (EPFL))\n\nCo-authors\nDr Christine Stollberg (Ecole Polytechnique Fédérale de Lausanne (EPFL))\nProf. Ivo Furno (Ecole Polytechnique Fédérale de Lausanne (EPFL))\nDr Philippe Guittienne (Ecole Polytechnique Fédérale de Lausanne (EPFL))\nMr Rémy Jacquier (Ecole Polytechnique Fédérale de Lausanne (EPFL))\nDr Simon Vincent (Ecole Polytechnique Fédérale de Lausanne (EPFL))\nProf. Stephan Brunner (Ecole Polytechnique Fédérale de Lausanne (EPFL))"},{"id":"237ec24a-4a7a-408d-a298-5e4b99122ee1","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:50:00+00:00","end":"2026-06-30T09:05:00+00:00","s":"0950","e":"1005","name":"O.205 - V. Rohde: Boronisation at AUG: Investigations in view of the ITER operation","loc":"Pentland Suite: Level +3","track":"MCF: Div/SOL","type":"Session","details":"With the recent ITER rebaseline decision introducing a full-tungsten first wall configuration, the efficacy of wall conditioning via boronisation has become a high priority issue in the ITER operational planning. ASDEX Upgrade (AUG), equipped with tungsten (W) plasma facing components and using deuterated diborane, has the unique capability to investigate the main issues arising for ITER: These include the influence of boronisation on plasma start up, homogeneity of the boron coating, lifetime of boronisation and tritium inventory in the boron hydride layers.\nThe ITER plasma start-up scenario was adapted to AUG, matching all relevant plasma parameters. First experiments without boronisation did not lead to stable plasma conditions. Applying even a partial boronisation by intentionally using only two of the installed four glow anodes immediately allowed reliable plasma start-ups and stable discharges.\nQuartz microbalance sensors installed at seven different locations and a manipulator system to expose witness samples offer investigations of layers produced by the coating. The layer thickness at different locations varies only by a factor of three. Switching off one anode reduces the nearby deposition by only about 60 % as opposed to a factor ~100 reduction predicted by initial simulations carried out by ITER. The discrepancy is attributed to the sticking of borane radicals, which was measured to be ~30% while the simulations assumed 100% sticking. The in-situ measurements were complemented by 54 long term samples exposed during the entire campaign. For typical plasma edge temperatures at AUG, W is sputtered mainly by light residual impurity species. These are reduced by boronisation and by this also the W source. The deposited layers on the long-term samples were analysed by ion beam techniques to get information on the elementary composition. A typical D/B ratio of 0.3 is found. This yields a T inventory of less than 2 gr T per boronisation in ITER.\n\nAuthors\nMr Andreas Redl (Max Planck Institute for Plasma Physics)\nMrs Hannah Lindl (Max Planck Institute for Plasma Physics)\nMr Karl Krieger (Max Planck Institute for Plasma Physics)\nMr Ralph Dux (Max Planck Institute for Plasma Physics)\nMrs Sangeetha Sasidharan (Max Planck Institute for Plasma Physics)\nMr Sebastian Hoermann (Max Planck Institute for Plasma Physics)\nMr Tim Hohmann (Max Planck Institute for Plasma Physics)\nVolker Rohde (Max Planck Institut for Plasmaphysics)\n\nCo-authors\nMr Joerg Hobirk (Max Planck Institute for Plasma Physics)\nMr Martin Balden (Max Planck Institute for Plasma Physics)\nMr Seehon An (Max Planck Institute for Plasma Physics)"},{"id":"1927ead5-8695-4032-805a-60fcd913fe1f","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T08:50:00+00:00","end":"2026-06-30T09:15:00+00:00","s":"0950","e":"1015","name":"I.203 - T. Estrada: High performance plasmas of the TJ-II stellarator: Experiments and validation of first-principles models","loc":"Sidlaw: Level +3","track":"MCF: Stellarators","type":"Session","details":"In stellarators and tokamaks, transport of energy and particles in the plasma core critically determines device performance. Therefore, it is essential to identify advanced operational regimes that yield high-performance conditions and understand the mechanisms governing such regimes. In the TJ-II stellarator several routes to improved confinement have been identified, including L–H transitions driven by turbulence suppression via sheared flows and more recently, enhanced confinement induced by pellet injection, resembling pellet-fueled high-performance plasmas in W7-X. A better confinement is achieved already after the injection of a single pellet as well as after multiple pellets. In order to understand the mechanisms behind this confinement improvement a series of gyrokinetic simulations (using stella and EUTERPE) complemented by neoclassical simulations (using SFINCS) have been carried out and compared with power balance analysis estimates and source modeling using HPI2 and ASCOT. The results show that in TJ-II the physical mechanisms behind the improved confinement do not seem to be so tightly linked to a reduction in turbulent transport due to an increase in the density gradient as demonstrated in W7-X. This work contributes to the interpretation and validation of TJ-II high-performance scenarios in the broader context of stellarator research.\n\nAuthor\nTeresa Estrada (CIEMAT)\n\nCo-authors\nDr Alvaro Cappa (CIEMAT)\nDr Arturo Alonso (CIEMAT)\nDr Daniel Carralero (CIEMAT)\nDr Edilberto Sánchez (CIEMAT)\nDr Isalbel García-Cortés (CIEMAT)\nDr Jose Luis Velasco (CIEMAT)\nDr Jose Manuel García-Regaña (CIEMAT)\nDr Kieran McCarthy (CIEMAT)\nDr Nerea Panadero (CIEMAT)"},{"id":"822d2985-eed7-42b8-88fa-b059bae8e161","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:05:00+00:00","end":"2026-06-30T09:20:00+00:00","s":"1005","e":"1020","name":"O.206 - S. Silburn: Buffering and Burn Through of Transients in the MAST-U Super-X Divertor","loc":"Pentland Suite: Level +3","track":"MCF: Div/SOL","type":"Session","details":"The MAST Upgrade super-X divertor [1,2] creates ideal conditions for detachment with a long connection length and high neutral pressure in the divertor region. While results have shown the super-X strongly mitigates heat flux during steady state plasma conditions, the survivability of the divertor during transient events is a key requirement for future plasma devices[3]. Although large transients such as ELMs are not expected to be tolerable in future devices, certain types of transients, such as H-L back transition, are unavoidable and the ability to tolerate slightly larger transients may open up useful operational regimes.\n\nThe impact of transients in the Super-X configuration has been investigated on MAST-U using advanced diagnostics, focused experiments and improved modelling. An Ultra Fast Divertor Spectroscopy providing fast Fulcher measurements of the detachment front position has offered new insight into what is occurring during transients. This has been combined with fast Infra-Red camera data, divertor Thomson scattering at the target and camera imaging. Dedicated experiments have been performed on both ELMs and Sawteeth transients, scanning neutral deuterium gas pressure, performing nitrogen seeding in the Super-X chamber and using X-point Target Configuration to mitigate the heat flux, as well as dedicated comparisons with conventional divertor configurations.\n\nThe experimental results have quantified the dependence of the buffering on transient energy and neutral deuterium gas pressure. An approximately linear increase in peak power flux is observed with transient energy, or reducing neutral gas pressure, up to a certain point where it enters a second regime with larger increase in target heat flux. It may be that the second regime is where the neutral inventory has been depleted and after which point additional energy causes proportionately greater increase in heat flux. Comparing Super-X with the conventional divertor has shown reduced heat flux in line with the improved geometry of the Super-X divertor. Very strong mitigation of transients with Nitrogen gas have also been demonstrated albeit with some impact on core performance, offering a promising path forward using impurities to mitigate transients. The heat flux from transients greatly increase Te and ne in the divertor. These increases have been captured in Thomson scattering data and are compared with modelling in the ReMKiT1D framework[4]. This modelling has shown that recycling plays a key role in understanding the transient heat flux.\n\nThis work has been carried out within the framework of the EUROfusion Consortium, funded by the European Union via the Euratom Research and Training Programme (Grant Agreement No. 101052200—EUROfusion). It has also been supported by the EPSRC Energy Programme (grant number EP/W006839/1).\n\nReferences\n[1] Leonard, A. W, Plasma Phys. Control. Fusion 60 (2018) 044001\n[2] J. Harrison et al., “Overview of the mast upgrade super-x divertor”, Nuclear Materials and Energy 12, 1072–1076 (2017).\n[3] G. Federici et al., “Plasma-material interactions in current tokamaks and their implications for next step fusion reactors”, Nuclear Fusion 41, 1967–2137 (2001)\n[4] S. Mijin et al, “ReMKiT1d: a framework for building reactive multi-fluid models of the tokamak scrape-off layer with coupled electron kinetics in 1d”, Computer Physics Communications 300, 109195 (2024).\n\nAuthors\nDr David Moulton (UKAEA)\nMr Jack Flanagan (University of Liverpool)\nDr Peter Ryan (UKAEA)\nRory Scannell (UKAEA)\nDr Scott Silburn (UKAEA)\nSid Leigh (UK Atomic Energy Authority)"},{"id":"15f4e18a-7f0e-4664-b2c8-c5b8f2aee258","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:15:00+00:00","end":"2026-06-30T09:30:00+00:00","s":"1015","e":"1030","name":"O.212 - JA. Perez Hernandez: Proton acceleration efficiency via ultra-short PW-class lasers","loc":"Fintry: Level +3","track":"BPIF: Laser-plasma radiation sources","type":"Session","details":"Proton beams generated via Target Normal Sheath Acceleration1,2 (TNSA) using the VEGA PW-class laser at CLPU were studied by covering pulse durations from 30–500 fs at fixed laser energies, spanning intensities from 2 × 1018 to 2 × 1020 W/cm2. This provided a unique, consistent dataset from a single campaign. Results show cut-off proton energies distribution versus pulse duration exhibit a maximum that scales with laser energy, occurring at intensities within 1 × 1019 and 2 × 1019 W/cm2, thus revealing a saturation mechanism in proton acceleration which differ with several published scaling from picosecond-driven experiments. Data analysis, supported by theoretical models and simulations, indicates this behaviour is linked to VEGA high contrast driving ultrashort scale-length plasma expansion. Consequently, pulse duration strongly impacts efficiency, decreasing sharply for shorter pulses. Updated electrostatic model, Bayesian analysis rand numerical simulations reproduce the trend, yielding a new scaling law that identifies optimal pulse duration for given laser energies. These results3 enable improved optimization of proton beams from ultrashort femtosecond high-power lasers, with potential applications in compact ion and neutron sources, inertial confinement fusion, radioisotope production and medical physics.\n\n[1] M. Passoni and M. Lontano, Physical Review Letters 101(11), 115001 (2010).\n[2] S.C. Wilks et al., Physics of Plasmas 8, 542–549 (2001)\n[3] Jose. A. Pérez-Hernández et al., Proton acceleration efficiency via ultra-short PW-class lasers, under review.\n\nList item\n\nAuthor\nJose Antonio Perez Hernandez et al. (Center for Pulsed Lasers (CLPU))"},{"id":"ad58dc0c-1f73-4a60-bf11-e0b9528882b5","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:15:00+00:00","end":"2026-06-30T09:30:00+00:00","s":"1015","e":"1030","name":"O.208 - T. Sano: Efficient gamma-ray generation via relativistic two-wave resonance driven by ultra-intense lasers","loc":"Tinto: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (I)","type":"Session","details":"We investigate an efficient mechanism for gamma-ray generation based on relativistic two-wave resonance driven by ultra-intense\ncounter-propagating laser pulses in a strongly magnetized plasma. In the\npresence of a sufficiently strong external magnetic field, electrons can\nsimultaneously resonate with both laser fields, enabling sustained and\ncoherent energy transfer from the electromagnetic waves to relativistic\nparticles. This dual-resonance configuration leads to rapid electron\nenergization and enhanced high-frequency radiation.\n\nUsing a combination of analytical modeling and particle-in-cell\nsimulations that incorporate radiation reaction effects, we identify the\nparameter regime in which relativistic two-wave resonance is established\nand maintained. When the resonance condition is satisfied, electron\ntrajectories become strongly phase-correlated with the laser fields and\nexhibit pronounced transverse oscillations. These dynamics significantly\nenhance synchrotron emission, resulting in efficient gamma-ray\nproduction. The energy conversion occurs on timescales comparable to the\nlaser period, demonstrating a rapid channel for transferring laser\nenergy into high-energy photons.\n\nOur simulations show that a substantial fraction of the incident laser\nenergy can be converted into gamma-ray radiation under optimized\nconditions. The resulting photon spectra depend sensitively on key\nplasma and laser parameters, including plasma density, magnetic field\nstrength, and laser intensity, indicating that the emission\ncharacteristics can be tuned in a controllable manner.\n\nThe mechanism explored here is closely related to resonant wave–particle\ninteractions in extreme astrophysical environments, where relativistic\nparticles interact with intense electromagnetic and Alfvénic\nfluctuations. Relativistic two-wave resonance thus provides a\nlaboratory-accessible analogue of these high-energy processes.\n\nThese results establish relativistic two-wave resonance as a robust and\ncontrollable pathway for laser-driven gamma-ray generation, bridging\nlaboratory high-energy-density plasma physics and astrophysical\ngamma-ray emission mechanisms, and opening new prospects for compact, high-brilliance gamma-ray sources.\n\nAuthor\nTakayoshi Sano (Institute of Laser Engineering, The University of Osaka,)"},{"id":"7a9a9cdf-2faa-4f21-a700-429fe39c8b6c","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:15:00+00:00","end":"2026-06-30T09:30:00+00:00","s":"1015","e":"1030","name":"O.224 - V. Desages: High density helicon mode triggered by current injection","loc":"Moorfoot: Level 0","track":"LTDP: Magnetized Plasmas","type":"Session","details":"Radio-frequency helicon sources usually display three modes of operation: a capacitive mode at low radio-frequency power Pᵣf, an inductive mode at intermediate power and a wave-sustained (W) mode, above a critical power Pᶜ. The W-mode is reached when the plasma density allows solutions for the dispersion relation of the natural helicon/Trivelpiece Gould (W) modes, which depend on the antenna design and the plasma cavity geometry. A large plasma density jump is observed at the transition to the W mode. A strong hysteresis is usually observed, and high-density natural W-modes are observed in the ramp-down, when Pᵣf is further decreased.\n\nWe demonstrate here a strategy to trigger W-modes well below the natural critical power Pc, when a small electron current is transiently injected on-axis. When current injection is stopped, the radio-frequency source maintained at Pᵣf < Pᶜ sustains the high-density natural W-modes observed during the ramp-down. A thorough experimental characterization of spatially-resolved plasma density and wave magnetic fields structure is detailed for a half-helical antenna in a 1m long, 20cm\n in diameter plasma vessel, operating in the range of 0.1 Pa and with a static magnetic field of a few hundreds of Gauss. We stress here that a few tens of Watts of DC current injection allows to trigger a W-mode at Pᵣf = 500 W (i.e. 0.5 Pᶜ).\n\nThe underlying mechanism lies in the modification of the density profile, which is more centrally peaked in the presence of current injection, and modifies the wave coupling. This mechanism has been validated using the HELIC code, which solves Maxwell's equations with boundary conditions for a given plasma density profile and antenna design. The computation of the absorbed power using experimentally informed plasma density profiles demonstrates that high density W-modes are triggered at lower Pᵣf\n in the presence of peaked profiles. In this simplified model, the predicted steady-state working points reproduce the experimental features. When injection is stopped, the high density in the cavity allows the sub-critical natural modes to be maintained. These results potentially open new avenues for the development of efficient helicon sources at low radio-frequency power.\n\nAuthor\nVassili Desages (Univ Lyon, ENS de Lyon, CNRS, Laboratoire de Physique, F-69342 Lyon, France)\n\nCo-authors\nMr Nicolas Plihon (Univ Lyon, ENS de Lyon, CNRS, Laboratoire de Physique, F-69342 Lyon, France)\nMr Francis Pagaud (Univ Lyon, ENS de Lyon, CNRS, Laboratoire de Physique, F-69342 Lyon, France)\nMr Vincent Dolique (Univ Lyon, ENS de Lyon, CNRS, Laboratoire de Physique, F-69342 Lyon, France)"},{"id":"f146db1f-9e92-4811-984a-fa1633cb9a9c","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:15:00+00:00","end":"2026-06-30T09:30:00+00:00","s":"1015","e":"1030","name":"O.201  - A.  Dinklage: Sustaining long-pulse, high-performance plasmas in the optimized stellarator W7-X by repetitive pellet injection","loc":"Sidlaw: Level +3","track":"MCF: Stellarators","type":"Session","details":"We report on the development of discharge scenarios that enable long-term stabilization (t>TL/R) of equilibrated high-performance plasmas in the optimized stellarator W7-X. The scenarios exploit repetitive pellet injection combined with second-harmonic O-mode heating, which together may raise the ion temperature beyond the ion-temperature clamping limit (>1.5 keV) and sustain a quasi-stationary operational cycle at high density and plasma energy up to the available heating duration.\n\nSurprisingly, these plasmas exhibit indications of central fueling and the plasma ions appear to contribute to the thermalisation of the injected pellet material. Targeted impurity seeding mitigates heat loads on critical components without impurity accumulation thereby enabling longer pulses. As a consequence of pellet injection, the plasma parameters oscillate within a limited range. In particular, under constant and optimized pellet fueling and plasma heating, good confinement is achieved over several dozen pellet cycles. This PULSE (Pellet-Utilized Long-Pulse Steady-State Enabled) regime proves robust: if irregularities in pellet size temporarily reduce plasma performance, recovery to high performance is observed once the nominal fueling rate is restored.\n\nIn initial experiments, central ion temperatures exceeding 2 keV and central densities above \n were obtained at the maximum of the pellet-induced cycles. During these phases, central beta values of up to 4 % were achieved, together with confinement consistent with the ISS04 scaling (\n). The improved confinement appears to be related to a local reduction of transport that remains stabilized over a pellet cycle in the PULSE regime. For the first time, dimensionless parameters of reactor relevance have been achieved in stellarator plasmas sustained for up to 43 s.\n\nAuthor\nAndreas Dinklage\n\nCo-authors\nAdrian v. Stechow\nBirger Buttenschön\nDaihong Zhang\nDorothea Gradic\nEdelgardo Villalobos Granados\nGolo Fuchert\nHenning Thomsen\nHjördis Bouvain\nJakob Brunner\nJonas Zimmermann\nJürgen Baldzuhn\nKen Hammond\nLarry Baylor\nMiklos Veczei\nNerea Panadero\nNiklas Polei\nNovimir Pablant\nStepan Sereda\nThe W7-X Team\nThomas Wegner\nTorsten Stange\nYu Gao"},{"id":"81cc4efb-0bf5-41cb-8813-1c16bda8165a","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:20:00+00:00","end":"2026-06-30T09:50:00+00:00","s":"1020","e":"1050","name":"O.207 - J. Lovell: Study of the X divertor on MAST Upgrade: development, control and impact on power exhaust","loc":"Pentland Suite: Level +3","track":"MCF: Div/SOL","type":"Session","details":"Plasma scenarios with an X divertor configuration [1] developed on MAST Upgrade exhibit a reduction in heat and particle fluxes at the divertor targets compared with conventional divertor configurations. We use the Toksys [2] and TED [3] frameworks to modify a conventional divertor magnetic equilibrium to increase poloidal flux expansion at the target and apply feed-forward changes to poloidal field coil currents to realise these configurations in Ohmic and beam-heated L-mode and H-mode plasmas.\n\nThe highest target poloidal flux expansion is achieved by zeroing the radial and vertical magnetic field components just below the strike point; this strategy is however very sensitive to plasma evolution and cannot be sustained by feed forward control. Moving the field null further from the target reduces the peak flux expansion but gives a more robust scenario. Designing solely for target flux expansion instead of imposing a field null constraint also achieves a robust scenario at the cost of with lower peak flux expansion. Adding strike point position feedback control after forming the X divertor maintains acceptable flux expansion for longer durations, but only for lower poloidal flux expansion scenarios.\n\nIn Ohmic and NBI-heated L mode plasmas using the field-null strategy, we achieved high peak flux expansion only in the far SOL, with modest flux expansion at the strike point. Increased interaction of the SOL with the divertor entrance and a corresponding increase in upstream neutral influx and radiated power precluded isolating the impact of the divertor geometry from the impact of the increased wall interaction at the divertor entrance. Moving the location of the peak flux expansion closer to the strike point and sacrificing peak flux expansion avoided excessive wall interaction. This scenario achieved a 10%-30% reduction in peak parallel heat flux and earlier detachment onset in N2-seeded H mode plasmas compared with the conventional divertor.\n\n[1] M. Kotschenreuther et al Phys. Plasmas 20, 102507 (2013)\n[2] H. Anand et al 2024 Nucl. Fusion 64 086051\n[3] O P Bardsley et al 2024 Plasma Phys. Control. Fusion 66 055006\n\nWork supported by EPSRC EP/W006839/1 and US-DOE DE-AC05-00OR22725.\n\nAuthor\nJack Lovell (Oak Ridge National Laboratory)\n\nCo-authors\nStuart Henderson (UKAEA)\nFabio Federici (Oak Ridge National Laboratory)\nPeter Ryan (UKAEA)\nScott Silburn (UKAEA)\nNicola Lonigro (United Kingdom Atomic Energy Authority)\nHimank Anand (General Atomics)\nOliver Bardsley (UK Atomic Energy Authority)\nJeremy Lore (Oak Ridge National Laboratory)"},{"id":"32bbba57-c4af-4cea-bac1-7b212f28bade","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:30:00+00:00","end":"2026-06-30T09:50:00+00:00","s":"1030","e":"1050","name":"O.213 - L. Ribotte: Ultra-intense neutron source production using laser-driven photonuclear reactions on the LMJ-PETAL facility","loc":"Fintry: Level +3","track":"BPIF: Laser-plasma radiation sources","type":"Session","details":"This work tackles the production and experimental characterization of a broad-range ultra-intense neutron source on the LMJ-PETAL facility. Using the PETAL laser (700 J, 500 fs) as a driver of laser-plasma accelerated electron beams, bremsstrahlung gamma-rays were radiated by the relativistic electrons in a 5cm-thick lead (Pb) converter in a pitcher-catcher configuration. The high-energy photons were then able to induce the emission of photoneutrons through (γ,xn) photonuclear reactions with Pb. The primary electrons were accelerated in the self-modulated laser-wakefield acceleration (SM-LWFA) regime within a supersonic helium gaz jet. This acceleration mechanism is known to generate high electron charges approaching the microCoulomb (μC), hence its potential for secondary source generation. Using time-of-flight neutron (nToF) scintillator detectors, nuclear activation diagnostics and Geant4 simulations, the setup is shown to have produced up to 2 × 10¹⁰ fast neutrons per shot with energies reaching about 20 MeV. Such high-flux sources could find application in nuclear physics and astrophysics, as well as in material science.\nMoreover, traces of high-energy gamma-induced nuclear fragmentation were recorded on our nuclear activation diagnostic, demonstrating the potential of this scheme to produce radioisotopes akin to conventional spallation facilities but with a more compact setup and a lower overall production cost.\n\nAuthor\nMr Lucas Ribotte (CEA-DAM)\n\nCo-authors\nDr Benjamin Vauzour (CEA-DAM, DIF)\nDr Benoît Mahieu (CEA-DAM, DIF)\nProf. Emmanuel d'Humières (CELIA)\nDr Félicie Albert (LLNL)\nDr Guillaume Boutoux (CEA-DAM, DIF)\nDr Julien Fuchs (LULI)\nProf. Laurent Gremillet (CEA-DAM, DIF)\nDr Nathalie Blanchot (CEA-DAM, CESTA)\nDr Witold Cayzac (CEA-DAM, DIF)\nDr Xavier Davoine (CEA-DAM, DIF)"},{"id":"780e26ba-6018-4525-971d-9d3e94938b6f","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:30:00+00:00","end":"2026-06-30T09:50:00+00:00","s":"1030","e":"1050","name":"O.209 - S. Zenitani: Hyper Boris integrators for kinetic plasma simulations","loc":"Tinto: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (I)","type":"Session","details":"Particle-in-cell (PIC) simulations are important research tools in theoretical plasma physics. Inside the PIC code, the particle integrator is extensively used to solve the Newton-Lorentz equation to advance charged particles. The Boris method (Boris 1970; also known as the Buneman-Boris method) has been the de facto standard particle integrator for more than a half century. It has second-order accuracy in time --- the numerical error is proportional to the square of the timestep, ~ (dt)^2.\nIn this presentation, we propose three extensions to the nonrelativistic Boris solver. First, we introduce n-times subcycling: we repeat the numerical procedure n-times, with an n-times smaller timestep of dt/n. This allows us to solve the equation with better second-order accuracy, ~ (dt/n)^2. Second, we extend the second-order Boris method to higher order. In addition to the well-known \"gyrophase correction\" to the magnetic field, we use an anisotropic correction to the electric field, to achieve fully higher-order accuracy, ~ (dt)^N [N = 2, 4, 6...]. Third, we combine these two methods to amplify their benefits. We call the hybrid method the hyper Boris solvers, because it has two hyperparameters of the subcycling number n and the order of accuracy, N. The accuracy of the n-cycle Nth-order solver is remarkably high, ~ (dt/n)^N, even though its computational cost is affordable.\n\nFor further details, see S. Zenitani & T. N. Kato, Comput. Phys. Commun. 2025, doi:10.1016/j.cpc.2025.109695.\n\nAuthor\nDr Seiji Zenitani (Austrian Academy of Sciences)\n\nCo-author\nProf. Tsunehiko Kato (Rikkyo University)"},{"id":"91c02542-fd5f-450f-9b66-d913661d830c","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:30:00+00:00","end":"2026-06-30T09:50:00+00:00","s":"1030","e":"1050","name":"I.204 - A. Goodman (PhD prize): Quasi-Isodynamic Stellarator Optimisation","loc":"Sidlaw: Level +3","track":"MCF: Stellarators","type":"Session","details":"Quasi-isodynamic (QI) magnetic fields are a uniquely attractive feature for stellarator power plants due to their low neoclassical transport and small toroidal currents [1], the latter offering robust plasma stability. It is for this reason that several stellarator companies, including Type One Energy [2] and Proxima Fusion [3], have based their power plant designs around QI magnetic fields. Like most properties in stellarators, one must use numerical optimisation techniques to find plasma equilibria that are QI. In this work, we begin by presenting the first method ever developed that is able to find stellarator equilibria with sufficient QI quality for a fusion power plant [4]. Any stellarator reactor must be resilient to magnetohydrodynamic (MHD) and turbulent instabilities, the latter of which limits the performance of Wendelstein 7-X [5], itself a roughly QI stellarator. As such, we next merged our QI optimisation methodology with other novel methods to find a new class of stellarators, “SQuIDs” (Stable Quasi-Isodynamic Designs) [6], which satisfy these conditions alongside excellent QI quality. Findings from Kappel et al. [7] can be included in SQuID designs, yielding configurations that are compatible with relatively simple electromagnetic coils. The final publication in this work therefore presents coil-compatible SQuIDs [8], which additionally feature an island divertor concept, along with other new and interesting physics properties such as an electron root — a region of outward pointing radial electric field — which may result a transport barrier akin to an H-mode placed the plasma radius of the designer’s choosing [9]. Future work on SQuIDs includes introducing an inward particle pinch [10], resulting in further improved fusion power output and plasma confinement.\nReferences\n[1] P. Helander and J. N¨uhrenberg. Bootstrap current and neoclassical transport in quasiisodynamic stellarators. Plasma Physics and Controlled Fusion, 51(5):055004, feb 2009.\n[2] CC Hegna, DT Anderson, EC Andrew, A Ayilaran, A Bader, TD Bohm, K Camacho Mata, JM Canik, L Carbajal, A Cerfon, et al. The infinity two fusion pilot plant baseline plasma physics design. Journal of Plasma Physics, 91(3):E76, 2025.\n[3] J Lion, J-C Angl`es, L Bonauer, A Ba˜n´on Navarro, SA Cadena Ceron, R Davies, M Drevlak, N Foppiani, J Geiger, A Goodman, et al. Stellaris: A high-field quasi-isodynamic stellarator for a prototypical fusion power plant. Fusion Engineering and Design, 214:114868, 2025.\n[4] Alan Goodman, Katia Camacho Mata, Sophia A Henneberg, Rogerio Jorge, Matt Landreman, Gabriel Plunk, Hakan Smith, Ralf Mackenbach, and Per Helander. Constructing precisely quasi-isodynamic magnetic fields, 2022.\n[5] M. N. A. Beurskens and et al. Ion temperature clamping in Wendelstein 7-X electron cyclotron heated plasmas. Nuclear Fusion, 61(11):116072, oct 2021.\n[6] Alan G. Goodman, Pavlos Xanthopoulos, Gabriel G. Plunk, H˚akan Smith, Carolin N¨uhrenberg, Craig D. Beidler, Sophia A. Henneberg, Gareth Roberg-Clark, Michael Drevlak, and Per Helander. Quasi-isodynamic stellarators with low turbulence as fusion reactor candidates. PRX Energy, 3:023010, Jun 2024.\n[7] J. Kappel, M. Landreman, and D. Malholtra. The magnetic gradient scale length explains why certain plasmas require close external magnetic coils. Plasma Physics and Controlled Fusion, 66, 01 2024.\n[8] Alan G Goodman, Gabriel G Plunk, Pavlos Xanthopoulos, Michael Drevlak, Joachim Geiger, Robert Davies, H˚akan M Smith, Carolin N¨uhrenberg, Craig D Beidler, Sophia A Henneberg, et al. A quasi-isodynamic stellarator configuration towards a fusion power plant. Submitted Journal Plasma Physics, 2025.\n[9] C. D. Beidler, M. Drevlak, J. Geiger, P. Helander, H. M. Smith, and Y. Turkin. Reduction of neoclassical bulk-ion transport to avoid helium ash retention in stellarator reactor. Submitted to Nuclear Fusion, Jan 2024.\n[10] G. G. Plunk, A. G. Goodman, P. Xanthopoulos, P. Costello, H. M. Smith, K. Aleynikova, C. D. Beidler, M. Drevlak, and P. Helander. Enhanced performance in quasi-isodynamic max-j stellarators with a turbulent particle pinch, 2025.\n\nAuthor\nDr Alan Goodman (Max-Planck-Institut f¨ur Plasmaphysik, D-17491 Greifswald, Germany)"},{"id":"e99ee505-1327-47aa-a9cd-58eb54b03523","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T09:50:00+00:00","end":"2026-06-30T10:20:00+00:00","s":"1050","e":"1120","name":"***Tuesday: Morning Refreshment Break***","loc":"Cromdale: Level -2","track":"","type":"Function","details":""},{"id":"ad7d86ae-bd59-4f5f-84e4-c3e299f6d901","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T10:20:00+00:00","end":"2026-06-30T10:55:00+00:00","s":"1120","e":"1155","name":"Plenary Talks: I.215   M.  Bonitz - Quantum effects in dense plasmas and how to simulate them","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"The year 2025 had been designated by UNESCO as the International Year of\nQuantum Science and Technology. By now, quantum mechanics is the theoretical foundation of most fields of physics. Plasma physics, on the other hand, got away with classical physics methods for a long time. This has changed radically with the growing importance of dense plasmas, both in astrophysics and in the laboratory. The most important current application is inertial confinement fusion that is seeing a dramatic surge of activity in the U.S. and in Europe and where progress crucially depends on reliably taking into account quantum effects.\n\nStarting with a brief historical overview the talk will discuss the broad parameter range that is characteristic for plasmas and where quantum effects are relevant. It will discuss the quantum methods that are available and which of them are of relevance for plasma physics, finishing with an outlook on future developments.\n\nReferences\n\nM. Bonitz et al., Towards first principles-based simulations of dense hydrogen, Phys. Plasmas 31, 110501 (2024).\nM. Bonitz et al., Ab initio simulation of warm dense matter, Phys. Plasmas 27, 042710 (2020).\nM. Bonitz, “Quantum Kinetic Theory” 2nd. ed. Springer 2016.\nJ. Vorberger et al., Roadmap for warm dense matter physics, Plasma Phys. Control. Fusion (2026), arXiv: 2505.02494\n\nAuthor\nMichael Bonitz\n\nCo-authors\nMr Christopher Makait\nDr Daniels Krimans\nDr Hanno Kählert (Kiel University)"},{"id":"21bc7634-1a15-4b3a-82a3-c8ef45749126","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T10:55:00+00:00","end":"2026-06-30T11:30:00+00:00","s":"1155","e":"1230","name":"Plenary Talks: I.216  T.  Nagayama - Laboratory benchmark experiments for stellar opacities","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"Opacity quantifies the absorption of photons in matter and is essential for understanding energy transport through radiation in high-energy-density (HED) plasmas, such as those found in stars and inertial confinement fusion. While opacity models provide local thermodynamic equilibrium (LTE) opacities for all elements based on temperature and density, they depend on multidisciplinary physics and include untested approximations. Calculating opacities under HED conditions is challenging due to density effects and the overwhelming number of excited states involved. This raises questions about the accuracy of calculated opacities, especially when discrepancies arise between simulations and observations. For instance, solar models have shown inconsistencies with helioseismic observations, raising concerns about the opacities being used. Experimental validation of HED opacity is difficult due to the need for a bright backlight to overcome self-emission from hot, dense plasmas. In 2015, we utilized the Z-machine at Sandia National Laboratories, which is the most energetic X-ray source on Earth, to test iron opacity at solar interior temperatures for the first time. The measurements revealed significant discrepancies between calculated and measured iron opacities, raising significant concerns within the HED and astrophysics communities. We will summarize experimental and theoretical challenges associated with HED opacity, as well as our recent progress in our time-resolved measurements and first oxygen opacity measurements. Systematic experimental investigations into opacity issues will help resolve the solar problem and reduce uncertainty in radiation-hydrodynamic simulations.\n\nSNL is managed and operated by NTESS under DOE NNSA contract DE-NA0003525.\n\nAuthor\n aisuke Nagayama\n\nCo-authors\nDaniel Mayes (University of Texas, Austin)\nGregory Rochau (Sandia National Laboratories,)\nGuillaume Loisel (sandia national laboratories)\nJames Bailey (sandia national laboratories)\nStephanie Hanse (Sandia National Laboratories,"},{"id":"59049ba2-f746-4485-95ad-17e352965c5e","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T12:00:00+00:00","end":"2026-06-30T13:30:00+00:00","s":"1300","e":"1430","name":"***PRE-REGISTERED ONLY LUNCH: Women in Plasma***","loc":"Moorfoot: Level 0","track":"","type":"Function","details":"This lunch is only available to those attendees who have registered in advance.\n\nIt is at capacity so no onsite registrations for this lunch can be accepted.\n\nIf you have registered already in advance it should show in your 'My Agenda' icon on the app home screen."},{"id":"064114a8-8ca5-4d0c-9794-b547171e7fc0","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T12:00:00+00:00","end":"2026-06-30T13:30:00+00:00","s":"1300","e":"1430","name":"***Tuesday: Lunch***","loc":"","track":"","type":"Function","details":"Please note lunch is not catered for during the event. \nThere are many options close by; we have included some recommendations here in the app.\nIt is not permitted to bring food from outside into the EICC."},{"id":"f345bbc0-14b9-48db-97f9-e5d64a7d44d5","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T13:00:00+00:00","end":"2026-06-30T15:00:00+00:00","s":"1400","e":"1600","name":"Tuesday: POSTER SESSION 3 - BPIF","loc":"Strathblane: Level 0","track":"BPIF: Laser-plasma radiation sources","type":"Session","details":"BPIF04 Laser-plasma Acceleration of Particles and Plasma-based Radiation Sources (BPIF)"},{"id":"3122d438-0693-4c3c-a0ac-b4efced21eae","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T13:00:00+00:00","end":"2026-06-30T15:00:00+00:00","s":"1400","e":"1600","name":"Tuesday: POSTER SESSION 1 - MCF | LTDP | BSAP","loc":"Cromdale: Level -2","track":"MCF: Div/SOL","type":"Session","details":"MCF01 Plasma Turbulence and Transport\n_____________________________________________________\nLTDP04 Dusty and Strongly Coupled Plasmas\n_____________________________________________________\nBSAP01 Solar and Space Plasmas\nBSAP05 Fundamental Plasma Physics - Laboratory \nBSAP06 Other"},{"id":"da569966-4ccc-493c-b40e-182f471a0733","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T13:00:00+00:00","end":"2026-06-30T15:00:00+00:00","s":"1400","e":"1600","name":"Tuesday: POSTER SESSION 2 - MCF","loc":"Kilsyth: Level 0","track":"MCF: Div/SOL","type":"Session","details":"MCF05 Scenario Development, H&CD"},{"id":"d964385b-a3a7-4dac-a374-ff59a3a79bce","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:00:00+00:00","end":"2026-06-30T15:30:00+00:00","s":"1600","e":"1630","name":"***Tuesday: Afternoon Refreshment Break***","loc":"Cromdale: Level -2","track":"","type":"Function","details":""},{"id":"a2fcc4c9-15e4-4e0e-9e9e-d325025c0d6d","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:30:00+00:00","end":"2026-06-30T15:55:00+00:00","s":"1630","e":"1655","name":"I.210  M. Tatarakis: The HiPER+ Initiative: Advancing Direct-Drive Inertial Confinement Fusion: Past, Present, and Future”","loc":"Fintry: Level +3","track":"BPIF : Direct Drive","type":"Session","details":""},{"id":"74ef1274-8d00-4f5a-83d1-1015d1c70ae9","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:30:00+00:00","end":"2026-06-30T15:55:00+00:00","s":"1630","e":"1655","name":"I.224   K. Ida: New Frontier in Aurora Optical Observation by Hyperspectral Camera for Aurora Imaging (HySCAI)","loc":"Tinto: Level 0","track":"BSAP : Solar and Space Plasmas","type":"Session","details":"The hyperspectral camera for auroral imaging (HySCAI), which can provide a two-dimensional (2D) aurora image with full-spectrum coverage, was developed to explore a new frontier in auroral optical observation. HySCAI consists of an all-sky lens, a monitor camera, a galvanometer scanner that scans a slit image of the spectrograph onto the all-sky image plane, a grating spectrograph, and an electron-multiplying charge-coupled device (EM-CCD). HySCAI has two gratings: one with 500 grooves/mm for a wide spectral coverage of 400–800 nm and a spectral resolution (FWHM) of 2.1 nm, and the other with 1500 grooves/mm for a higher spectral resolution of 0.73 nm and a narrower spectral coverage of 123 nm. This system was installed at the KEOPS (Kiruna Esrange Optical Platform Site) of the SSC (Swedish Space Corporation) in Kiruna, Sweden, in 2023 [1]. Unlike conventional filter-based cameras, HySCAI captures more than 25 monochromatic images simultaneously, enabling quantitative auroral measurements even under twilight conditions by accounting for background emission. It also provides the spectral shapes of molecular bands. Three key results have been obtained: 1) The two-dimensional distribution of precipitating electron energy, derived from intensity ratios I(427.8nm)/I(630.0nm) and I(557.7nm)/I(630.0nm), shows a sudden increase to 1–2 keV during auroral breakup [2]. 2) The altitude profile of N₂⁺ density, determined from the 427.8 nm resonance scattering emission, peaks at 200 km [3], significantly higher than the 130 km predicted by the GLOW model. 3) The rotational temperature of nitrogen, obtained from N₂ 1PG and Meinel band spectra, is higher on the north (polar) side and increases with time during red auroral expansion. Data and related resources are available at the Data Repository Aurora Imaging Spectroscopy (DRAIS) in the National Institute for Fusion Science (NIFS) [4]. A second system, HySCAI-2, is under development for installation at Showa Station, Antarctica. It will offer higher spectral resolution for proton aurora velocity measurements and polarization-resolved measurements to investigate electron anisotropy.\n\n[1] Aurora Observation Project https://projects.nifs.ac.jp/aurora/en/\n[2] M.Yoshinuma, K.Ida, Y.Ebihara, Earth, Planets and Space 76 (2024) 96.\n[3] K.Ida, Y.Ebihara, M.Yoshinuma, K.Shiokawa, Geophys. Res. Lett. 52 (2025) e2025GL118375.\n[4] Data Repository Aurora Imaging Spectroscopy (DRAIS) https://doi.org/10.57451/nifs.aurora‐project\n\nAuthors\nKatsumi Ida (National Institute for Fusion Science)\nDr Mikirou Yoshinuma (National Institute for Fusion Science)\nProf. Yusuke Ebihara (Research Institute for Sustainable Humanosphere, Kyoto University"},{"id":"00d7dc4a-4321-4139-886a-e033b095b4fe","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:30:00+00:00","end":"2026-06-30T15:55:00+00:00","s":"1630","e":"1655","name":"I.222   J. Huang: Physics Understanding and Solutions to Key Issues of Long Pulse High Performance Operation on EAST","loc":"Sidlaw: Level +3","track":"MCF : Long pulse and Future Devices","type":"Session","details":"EAST has achieved a pivotal breakthrough by sustaining a steady-state high-confinement plasma for 1066 seconds with an injected energy of 3.05 GJ, setting a world record for both pulse duration and cumulative energy input. This major achievement integrates high-confinement performance with low momentum input, efficient heating and current drive, water-cooled tungsten divertors, active control of heat fluxes, precise recycling and particle balance regulation, magnetic configuration and equilibrium for long-duration operations. With this result, EAST has become the first tokamak that can operate with a pulse length in thousand-second scale, with plasma temperatures in the tens of million degrees Celsius and self-driven current.\n\nKey technical solutions were developed to overcome the challenges of long-pulse H-mode plasma operation over 1066 seconds, which was achieved in a lower single-null configuration with \n and \n, driven by \n and \n. A no/small ELM regime was realized by positioning the outer strike point on the horizontal target, which not only facilitates efficient radio frequency (RF) power coupling but also mitigates tungsten (W) sputtering and erosion. Fully non-inductive current drive was achieved at an electron density equivalent to 63\\% of the Greenwald density, with a confinement enhancement factor \n enabled by an electron temperature internal transport barrier (e-ITB). The synergistic effects between on-axis ECRH and LHCD are critical for maintaining high-confinement plasmas.\n\nThe e-ITB H-mode discharge exhibits nonlinear self-organization characteristics, emerging near the magnetic axis without external momentum injection. This long-term operational stability provides a unique opportunity to investigate the anomalous energy fluxes driven by plasma turbulence. Active control of a high-field side flux loop maintained zero loop voltage for non-inductive operation. Low-Z material wall coating and real-time powder injection techniques were implemented to enhance particle control capability. The evolution of wall materials was systematically studied through plasma-wall integrated modeling, while core-edge integration in high-performance steady-state operation scenarios compatible with metallic walls was experimentally explored.\n\nThis paper also presents the detailed physical mechanisms and technological advancements associated with the upgrade of EAST’s operational capabilities, which are tailored to the development of future fusion reactors such as ITER-relevant configurations.\n\nAuthor\nJuan Huang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\n\nCo-authors\nProf. X.Z Gong (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. B Zhang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. M.H Li (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nW.B Liu (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nL.Q Xu (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nDr C.Y Pan (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. S.X Wang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. H.M Zhang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. Y.W Yu (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. G.L Xu (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. Q Zang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. J.P Qian (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. Y.T SONG (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)"},{"id":"f4ac697f-452a-47e4-9ab7-48b112c010bd","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:30:00+00:00","end":"2026-06-30T15:55:00+00:00","s":"1630","e":"1655","name":"I.218   B. Vanovac: ELM suppression and confinement properties in negative triangularity plasmas in ASDEX Upgrade","loc":"Pentland Suite: Level +3","track":"MCF : NT and ELM-free","type":"Session","details":"Recent studies during the 2025 experimental campaign in ASDEX Upgrade (AUG) have achieved negative triangularity (NT) shaping beyond previous limits. This new set of experiments, guided by the ideal-MHD stability calculations using the BALOO code and supported by predictive results from TCV, have demonstrated a transition to an edge more stable against\npeeling ballooning modes, leading to ELM-free plasmas. In some of the AUG cases, a dithery behavior is observed similar to the limit cycle oscillations observed in DIII-D during shaping ramps. In this work we provide the details on the operational boundaries for the NT regime\nat various heating mixes and density values. AUG profiles and confinement are compared to a DIII-D discharge similar in shaping and key parameters, although the two machines operate at different values of edge safety factor and have different wall materials. This AUG/DIII-D similarity experiment serves as a basis for comparison of confinement quality and the underlying turbulence regimes using linear and nonlinear gyrokinetic simulations. Achieved ELM avoidance on AUG confirms the universality of the ballooning limited pedestals, previously addressed\non TCV and DIII-D in strongly shaped NT plasmas. Overall, these findings support the feasibility of ELM-free operation in future metal-wall tokamaks using negative-triangularity shaping, offering a viable path forward for high-performance, steady-state fusion scenarios.\n\nAuthor\nBranka Vanovac (Plasma Science and Fusion Center, Massachusetts Institute of Technology, Cambridge, MA 02139, USA)\n\nCo-authors\nAnne White (Plasma Science and Fusion Center, MIT, Cambridge, MA 02139, USA)\nAthina Kappatou (Max-Planck-Institut f¨ur Plasmaphysik, 85748 Garching, Germany)\nDirk Joachim Stieglitz (Max Planck Institute for Plasma Physics)\nGabriele Merlo (Max-Planck-Institut f¨ur Plasmaphysik, 85748 Garching, Germany)\nGiovanni Tardini (Max-Planck-Institut f¨ur Plasmaphysik, 85748 Garching, Germany)\nJoerg Hobirk (Max-Planck-Institut für Plasmaphysik, 85748 Garching, Germany)\nMichael Dunne (Max Planck Institute for Plasma Physics, Garching)\nMichael Faitsch\nOak Nelson (Columbia University, New York, New York 10027, USA)\nOlivier Sauter (EPFL-SPC, CH-1015 Lausanne, Switzerland)\nPaola Mantica (Institute of Plasma Science and Technology, CNR, Milano, Italy)\nRainer Fischer\nThomas Pütterich (Max-Planck-Institut f¨ur Plasmaphysik, 85748 Garching, Germany)\nXianyi Liu (Max-Planck-Institut f¨ur Plasmaphysik, 85748 Garching, Germany)"},{"id":"855187d8-631e-484c-8165-ec94e8ec1ab1","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:55:00+00:00","end":"2026-06-30T16:20:00+00:00","s":"1655","e":"1720","name":"I.211   W. Theobald: On the Way to a Self-Consistent Target Design for Laser Direct Drive Inertial Fusion Energy","loc":"Fintry: Level +3","track":"BPIF : Direct Drive","type":"Session","details":"Inertial Fusion, proved by the NIF's milestone achievement of ignition and gain of ~4, is a scientifically mature concept for Inertial Fusion Energy (IFE). However, the NIF's indirect-drive method faces challenges in scaling to a commercially required gain of ~100. Laser-Direct Drive (LDD) is a compelling alternative, offering high efficiency gain by coupling ~5× more laser energy directly to the target. This path needs solutions for mitigating Laser-Plasma (LPI) and hydrodynamic instabilities and will need to implement design constraints from target manufacturability and target survival during the injection process. This talk details Focused Energy's program to develop a self-consistent LDD implosion target for an IFE Pilot Plant. Such a target needs to satisfy critical constraints across implosion physics, target fabrication, laser and reactor design. Achieving high confidence in ignition and high gain relies on developing a target manufacturing method that ensures high quality and scales to mass production and additionally on optimizing the laser system for high wall-plug efficiency and robust LPI/hydrodynamic mitigation. Key laser requirements are the implementation of broad spectral bandwidth and temporal beam smoothing. Paired with careful target design choices, these laser system improvements promise to suppress LPI and laser imprint. We will show the concept for our multi-color broadband laser and its implementation within our coming experimental laser facility, designed for LPI and hydrodynamic mitigation studies. Besides, we will present results from LPI experiments using spectrally broadband lasers at PHELIX and FLUX, which are vital to demonstrate the technological feasibility of this LDD mitigation strategy.\n\nAuthor\nDr Wolfgang Theobald (Focused Energy and Department of Mechanical Engineering, University of Rochester, Rochester, NY, 14627, USA)\n\nCo-authors\nMr Alfonso Mateo (Focused Energy and ETSI Aeronáutica y del Espacio, Universidad Politécnica de Madrid, Madrid, Spain)\nDr Arnaud Debayle (Focused Energy)\nDr Debbie Callahan (Focused Energy)\nProf. Florian Wasser (Focused Energy)\nDr Gabriel Schaumann (Focused Energy and Technische Universität Darmstadt, Department of Physics, Darmstadt, Germany)\nProf. Javier Honrubia (Focused Energy and ETSI Aeronáutica y del Espacio, Universidad Politécnica de Madrid, Madrid, Spain)\nMr Javier Monteliu (Focused Energy)\nDr K. Linh Nguyen\nProf. Manolo Perlado (Focused Energy)\nProf. Markus Roth (Focused Energy and Technische Universität Darmstadt, Department of Physics, Darmstadt, Germany)\nMr Matthias Brönner (Focused Energy and Technische Universität Darmstadt, Department of Physics, Darmstadt, Germany)\nProf. Stefano Atzeni (Focused Energy)\nDr Valeria Ospina-Bohórquez (Focused Energy)\nDr Xavier Vaisseau (Focused Energy)"},{"id":"6b435433-bfcc-4697-87fc-b5d66d874e69","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:55:00+00:00","end":"2026-06-30T16:20:00+00:00","s":"1655","e":"1720","name":"I.509   S. Cerri: Kinetic plasma turbulence: recent insights on sub-ion-scale cascades, magnetic reconnection, and ion heating from numerical simulations","loc":"Tinto: Level 0","track":"BSAP : Solar and Space Plasmas","type":"Session","details":"Understanding the properties of turbulent fluctuations and the mechanisms underlying their transfer through scales and dissipation is crucial to understand how turbulence feeds back on the macro-scale evolution and energetics of a wide range of space and astrophysical plasmas. In this context, the solar wind and the near-Earth environment are probably the best laboratory for the study of plasma turbulence. Over the past decades, in-situ measurements from space missions have indeed uncovered a complex scenario whereby several collisionless plasma processes may be simultaneously at play within the turbulent cascade (e.g., from magnetic reconnection to wave-particle interaction and cascades in velocity space). Alongside observations, direct numerical simulations have always played a key role in providing a test ground for the existing theories and models of plasma turbulence and turbulent heating.\nIn this talk, I will discuss recent advances in our understanding of sub-ion-range turbulence, turbulent heating and the role of magnetic reconnection that have been achieved via hybrid-kinetic and gyro-fluid simulations.\n\nAuthor\nSilvio Sergio Cerri (Observatoire de la Côte d'Azur, CNRS Laboratoire Lagrange)"},{"id":"a9b724a4-7025-4b8e-83e1-d31980f8cf7c","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:55:00+00:00","end":"2026-06-30T16:20:00+00:00","s":"1655","e":"1720","name":"I.223   F. Auriemma: Time dependent advanced scenario modelling on present and future fusion devices","loc":"Sidlaw: Level +3","track":"MCF : Long pulse and Future Devices","type":"Session","details":"The high poloidal beta (βp) scenario [Ding_Nature2024] is one of reactor-relevant advanced tokamak regimes, combining high confinement (H98y2 > 1.5) with operation at Greenwald fraction ≥ 1. The most specific feature of this scenario is the formation of an internal transport barrier (ITB) at large radius (≥ 0.5), enabled by an optimized current ramp-up phase and current profile shaping that establish favorable magnetic shear conditions to suppress core turbulence.\nFirst demonstrated in JT-60U [Takenaga_NF2005] and subsequently developed in DIII-D, the high βp scenario has been reproduced in several devices as EAST, ASDEX-U, JET and, more recently, also explored in MAST-U, establishing a solid experimental and physics basis. In this invited talk, we focus on how integrated modelling can be used to study the performance and robustness of this scenario, with particular emphasis on access conditions, density evolution toward the Greenwald limit, and the sustainment of the ITB condition during the flat-top phase.\nUsing an ASTRA–TGLF integrated modelling framework [Bonanomi_NF2025], we study the time-dependent evolution of high βp plasmas in DIII-D, from current ramp-up through flat-top. The analysis highlights the key role of the turbulence stabilization in the formation and sustainment of the ITB, a feature consistently captured by both gyrokinetic studies and the quasi-linear TGLF model. Particular attention is paid to magnetic shear and pressure gradient, and their dominant impact on transport, as well as the effect of the toroidal velocity and its minor role in the formation and sustainment of the ITB.\nThe validated DIII-D analysis opens the possibility to extend such approach to MAST-U cases to provide insights on the influence of low aspect ratio on current diffusion, turbulence stabilization, and ITB physics.\nFinally, the physics understanding gained from present devices is applied to the design of a high βp scenario for the DTT tokamak, currently under construction in Italy. The results illustrate how integrated modelling can guide the development of high-performance, reactor-relevant scenarios in next-step, high-field superconducting machines.\n\nAuthor\nFulvio Auriemma (Consorzio RFX (CNR, ENEA, INFN, University of Padova, Acciaierie Venete), Padova, Italy; Institute of Plasma Science and Technology, CNR, Padova, Italy)\n\nCo-authors\nDr Andrea Garofalo (General Atomics, San Diego, CA, United States)\nDr Chiara Piron (enea c.r. frascati, frascati, italy)\nDr Christopher Ham (UKAEA, Culham Campus Abingdon, United Kingdom;)\nDr Giulio Rubino (Institute of Plasma Science and Technology, CNR, Bari, Italy)\nDr Hyun-Tae Kim (UKAEA, Culham Campus Abingdon, United Kingdom;)\nDr Jacopo Lombardo (Consorzio RFX (CNR, ENEA, INFN, University of Padova, Acciaierie Venete), Padova, Italy)\nDr Paola Mantica (Institute of Plasma Science and Technology, CNR, Milano, Italy)\nMr Qingyun Hu (Department of Physics ‘G. Occhialini’, University of Milano-Bicocca, Milano, Italy;)\nDr Sam Blackmore (UKAEA, Culham Campus Abingdon, United Kingdom;)\nDr Shengyu Shi (General Atomics, San Diego, CA, United States)\nDr Siye Ding (General Atomics, San Diego, CA, United States)\nDr Valentin Igochine (Max-Planck-Institut fur Plasmaphysik, Garching, Munchen, Germany)\nDr Vito Konrad Zotta (Dipartimento di Ingegneria Elettrica ed Energetica, Sapienza Università di Roma, via Eudossiana 18, 00184, Roma, Ital)"},{"id":"b73c9358-c5bf-44da-affc-691e76d7a9bd","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T15:55:00+00:00","end":"2026-06-30T16:20:00+00:00","s":"1655","e":"1720","name":"I.219   L. Radovanovic: Pedestal dynamics at the shape driven transition to QCE: a multi-scale analysis","loc":"Pentland Suite: Level +3","track":"MCF : NT and ELM-free","type":"Session","details":"Experiments on ASDEX Upgrade investigate how plasma shaping and the poloidal beta (βpol) affect pedestal behaviour in H-mode plasmas. The focus is placed on the transition from type-I ELMy H-mode to the quasi-continuous exhaust (QCE) regime, which is accessed experimentally by increasing plasma shaping while keeping βpol approximately constant. The dataset spans a wide range of shaping parameters and covers the full transition between these confinement regimes, providing a controlled framework to isolate the role of geometry in pedestal formation and stability.\nA versatile combination of experimental diagnostics and numerical tools is employed to analyse this dataset. High-resolution profile measurements are used to reconstruct kinetic pedestal profiles, which are then assessed using a comprehensive modelling approach. This includes local and global MHD stability analysis, transport simulations, and gyrokinetic calculations addressing both ion- and electron-scale turbulence. The joint application of these complementary methods allows stability limits, transport channels, and profile evolution to be examined, offering a detailed view of pedestal dynamics across the ELMy–QCE transition.\nThe analysis demonstrates that pedestal formation is not governed by a single dominant mechanism, but rather by the interplay of multiple instabilities and stabilising effects acting across different radial regions of the pedestal. The interplay between local magnetic shear is found to strongly stabilise kinetic ballooning modes (KBMs), which play a central role in regulating both the density gradient and turbulent ion heat transport. Increased shaping facilitates access to the second stability regime, allowing larger pressure gradients while simultaneously shifting the most unstable region radially.\nThe behaviour of KBMs at the pedestal foot emerges as a key element in setting the boundary conditions for accessing and sustaining the QCE regime. Complementary MHD and gyrokineticanalysis, further elucidates the role of shaping in modifying magnetic shear and stability boundaries.\nTaken together, these results provide a detailed, multi-scale view of pedestal structure and establish a foundation for understanding the transition from ELMy H-mode to QCE. The presented analysis is used as the groundwork for the development of a predictive pedestal model for QCE-relevant regimes, with direct relevance for future devices and reactor-oriented operation.\n\nAuthor\nLidija Radovanovic (Institute of Applied Physics, TU Wien, Vienna, Austria)\nCo-authors\nClemente Angioni (Max-Planck-Institut fuer Plasmaphysik, 85478 Garching bei Muenchen, Germany)\nEUROfusion Tokamak Exploitation Team (See the author list of E. Joffrin et al., Nucl. Fusion 64, 112019, 2024)\nElisabeth Wolfrum (Max Planck Institute for Plasma Physics, Garching)\nFacundo Sheffield (Max Planck Institute for Plasma Physics, Boltzmannstraße 2, 85748 Garching, Germany)\nFriedrich Aumayr (1 Institute of Applied Physics, TU Wien, Fusion@ÖAW, Wiedner Hauptstr. 8-10, 1040 Vienna Austria)\nMichael Dunne (Max Planck Institute for Plasma Physics, Garching)\nTobias Görler (Max Planck Institute for Plasma Physics, Garching)\nThe ASDEX Upgrade Team (see author list of H. Zohm et al 2024 Nucl. Fusion 64 112001)"},{"id":"b2587994-1506-47b9-bfe5-6ae4b71f865a","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:00:00+00:00","end":"2026-06-30T16:25:00+00:00","s":"1700","e":"1725","name":"I.230   K. Batani: Laser driven radioisotope production for medical applications","loc":"Moorfoot: Level 0","track":"BPIF :  Applications of laser-plasma radiation sources","type":"Session","details":"Laser generated sources of TNSA protons and alpha particles (produced by proton boron fusion reactions) can be used for the production of radioisotopes of medical interest. The present work discusses the results from experiments performed using the PW-class, short duration and high repetition laser VEGA-III at CLPU, Spain. In the experiment, we used the pitcher-catcher scheme, using thin Al foils to produce accelerated protons, which were directed on various targets including boron catchers (BN, BNH6) to produce alpha particles through proton boron fusion reactions. We used a High Purity Germanium (HPGe) detector to trace gamma ray emission lines from the activated catcher showing emission lines from 7Be, 11C, and 18F, measuring their lifetime and estimating their activity [1, 2]. We also used high density calcium\nsilicate (Ca2SiO4) catchers to produce scandium radioisotopes either by the interaction with alpha-particles produced by proton-boron fusion or directly by the accelerated proton beam. The results indicate the presence of the scandium radioisotopes: 43Sc, 44Sc, and 48Sc. We are reporting on two experiments. The first one demonstrated possibility of radioisotope production [1, 2], the second one put light on developments, which might allow developing laser-driven sources of radioisotopes for medical applications.\nReferences\n[1] M. R. D. Rodrigues, A. Bonasera, M. Scisciò, et al., Radioisotopes production using lasers: from basic science to applications, Matter Radiat. Extremes 9, 037203 (2024)\n[2] K. L. Batani, M.R.D. Rodrigues, A. Bonasera, et al., Generation of radioisotopes for medical applications using high-repetition, high-intensity laser, HPLSE 13, e11 (2025)\nACKNOWLEDGEMENT\nThis work has been carried out within the framework of the COST Action CA21128-PROBONO “PROton BOron Nuclear fusion: from energy production to medical applications”, supported by COST (European Cooperation in Science and Technology - www.cost.eu).\n\nAuthor\nKatarzyna Batani (Institute of Plasma Physics and Laser Microfusion, Warsaw, Poland)"},{"id":"6f105d67-de08-4c7b-9f04-ae0acb42211b","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:20:00+00:00","end":"2026-06-30T16:45:00+00:00","s":"1720","e":"1745","name":"I.517  H. Fetsch: Fusion reactivity enhanced by turbulence","loc":"Fintry: Level +3","track":"BPIF : Direct Drive","type":"Session","details":"Turbulence increases the reactivity of fusion plasma, allowing ignition at lower temperature. This “shear flow reactivity enhancement” [1] occurs because in plasmas, as opposed to other fluids, particles’ collisional mean free paths increase rapidly with their velocity. In sheared flows, and in solenoidal turbulent flows [2], energetic particles can travel long distances and pass between regions with large differences in flow, ending up at higher velocities relative to the local fluid. Such a velocity boost greatly increases the number of tail particles available to participate in energy-sensitive processes, such as fusion reactions. Furthermore, because the mean free paths of thermal ions and tail ions are widely separated, the effect can appear even in highly collisional plasmas; in fact, because thermal ions determine viscosity, their short mean free paths help to support strong flow gradients.\n\nA central paradigm in inertial confinement fusion (ICF) – that imploding kinetic energy should thermalize to maximize fusion reactivity – must therefore be revised. In some cases, driving micron-scale turbulence inside ICF hot spots allows ignition at lower energy density [3]. Colder fuel improves the confinement of alpha particles, allowing for a smaller hot spot and offering particularly large energy savings in fast-ignition and shock-ignition configurations [1]. The shear flow reactivity enhancement effect raises the prospect of a new scheme for ICF in which targets are seeded with perturbations to generate turbulence on optimal scales during compression, reducing thermal losses and potentially enabling higher gain. Beyond the implications for high-yield experiments, consequences of the effect with broader scientific relevance will be discussed, including modifications to yield ratios and fusion-product spectra (affecting, for example, diagnostics based on these quantities).\n\n[1] Fetsch, H. & Fisch, N. J. Enhancement to Fusion Reactivity in Sheared Flows. Phys. Rev. Lett. 135, 155101 (2025).\n[2] Fetsch, H. & Fisch, N. J. Analytical models for the enhancement of fusion reactivity by turbulence. Phys. Plasmas 32, 112703 (2025).\n[3] Fetsch, H. & Fisch, N. J. An ignition criterion for inertial fusion boosted by microturbulence. Phys. Plasmas 33, 020703 (2026).\n\nThis work was supported by the NNSA SSAP under DOE Cooperative Agreement DE-NA0004148 and by the NSF under Grant PHY-2308829.\n\nAuthor\nHenry Fetsch (Princeton University)\n\nCo-author\nDr Nathaniel Fisch (Princeton University)"},{"id":"9bf7c585-e410-46f8-a117-128f5be2dadd","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:20:00+00:00","end":"2026-06-30T16:45:00+00:00","s":"1720","e":"1745","name":"I.226   M. Marcucci: Unveiling plasma energization and energy transport in the Magnetospheric System through multi-scale observations: the ESA M7 Plasma Observatory mission candidate","loc":"Tinto: Level 0","track":"BSAP : Solar and Space Plasmas","type":"Session","details":"The comprehension of particle energization and energy transport is a grand challenge of plasma physics that has implications on research fields that span from space weather to the understanding of the farthest astrophysical plasmas. The Earth’s Magnetospheric System, where strong energization and energy transport occurs, is the best natural laboratory to study these processes through in situ measurements. Theory, numerical simulations and previous multi-point observations from missions such as ESA/Cluster, NASA/MMS and THEMIS evidenced that cross-scale coupling has a fundamental role in plasma energization and energy transport. Therefore, simultaneous in situ measurements at both large, fluid and small, kinetic scales are required. Such measurements are currently not available. Here we present the Plasma Observatory (PO) multi-scale mission tailored to study plasma energization and energy transport in the Earth’s Magnetospheric System through simultaneous measurements at both fluid and ion scales. PO baseline mission employs seven identical smallsat Sister Space Craft (SSC) in two nested tetrahedral formation in an HEO 7.2x17 RE orbit, enabling observations in all the key regions of the Magnetospheric System including the foreshock, the bow shock, the magnetosheath, the magnetopause, the transition region and the magnetotail current sheet. The nominal mission duration is 3.5 years with 3 Nominal Science Phases during which the scale of the inner/outer tetrahedra are increased in three steps: 30-60/150-300 km, 100-200/500-1000 km, and 3500-6500 km, covering all typical ion and fluid scales of interest in the magnetospheric key regions. The SSC payload provides a complete characterization of electromagnetic fields and particles simultaneously at multiple locations with measurements tailored to ion and fluid scales. PO is the next logical step after Cluster and MMS and will allow us to resolve for the first time scale coupling in the Earth’s Magnetospheric System, leading to transformative advances in the field of space plasma physics. Plasma Observatory is one of the three ESA M7 candidates, which have been selected in November 2023 for a competitive Phase A with a mission selection planned in June 2026 and launch in 2037.\n\nAuthors\nMaria Federica Marcucci (INAF-IAPS)\nPlasma Observatory Team"},{"id":"18431471-f5e1-4352-9b47-3d60b8f85b4b","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:20:00+00:00","end":"2026-06-30T16:35:00+00:00","s":"1720","e":"1735","name":"O.217   X.  Litaudon: DIII-D–WEST Hybrid Scenario Similarity Experiments for Long-Pulse Operation","loc":"Sidlaw: Level +3","track":"MCF : Long pulse and Future Devices","type":"Session","details":"For the first time, identity and similarity experiments between DIII-D and WEST were performed in the ITER \"hybrid-like\" regime during dedicated campaigns on the two facilities in 2025. These experiments exploit the complementary capabilities of the two facilities and aim to illuminate the path toward combined high fusion performance with high-normalised pressure N (DIII-D) and long-pulse scenarios (WEST) in a tungsten environment.\nThe matched parameters include elongation, positive triangularity, ion ∇B drift direction toward X-point, safety factor profile, and core dimensionless physics quantities such as normalized pressure, normalized gyroradius, electron collisionality, and the ion to electron temperature ratio, Ti/Te. Core transport physics is explored across different aspect ratios (R/a) (3 at DIII-D and 5 on WEST). DIII-D accessed high- regimes (strong electromagnetic effects) under low injected torque (~0 ± 0.5 N·m) using high heating power, while scanning heating mix (ion vs electron), , Ti/Te, core radiation via controlled tungsten injection using the Laser Blow-Off system. WEST extended operation toward long duration pulses using its actively cooled tungsten divertor. Boron impurity injection was scanned on WEST to control edge conditions and core performance.\nIt is found that core confinement improves—manifested in higher electron temperature, total energy content, neutron rate, and ion temperature — under conditions of low separatrix density, consistent with previous observations. The ratio of the thermal energy confinement time (τE) to the volume-averaged electron–ion collisional heat exchange time (τe-i) emerges as a key parameter for enhancing ion heating and potentially facilitating H-mode access in electron-heated regimes. Conditions for both H-mode access and ion heating in electron-dominated regimes on WEST and DIII-D are compared (role of aspect ratio, ion heating versus electron heating). An outlook is also provided on extending the campaign by matching aspect ratio, increasing the ECRH power level, or replicating the dimensionless studies in negative-triangularity configurations with similar L-mode edges.\nThe first-of-a-kind coordinated DIII-D and WEST experiments provide a unique multi-machine dataset to validate predictive models and support extrapolation toward ITER and future fusion power plants, leveraging the complementary strengths of the two facilities.\n\nAuthor\n Xavier LITAUDON (CEA)"},{"id":"ca9e7289-bf49-4842-973d-58c656b1e9aa","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:20:00+00:00","end":"2026-06-30T16:45:00+00:00","s":"1720","e":"1745","name":"I.220   D. Ryan: First observation of RMP ELM suppression in a Spherical Tokamak","loc":"Pentland Suite: Level +3","track":"MCF : NT and ELM-free","type":"Session","details":"Edge Localised Modes (ELMs) - a periodic MHD instability ubiquitous in H-mode tokamak plasmas - are projected to degrade the plasma facing components of reactor scale devices, and so pose a threat to the viability of tokamak based commercial fusion power[2]. By applying Resonant Magnetic Perturbations (RMPs) ELMs can be mitigated, in which the ELM frequency is increased and energy content decreased, or suppressed, in which the ELMs vanish entirely and the peaked heat loads of ELMs are replaced by continuous transport[3]. ELM suppression has been demonstrated on many conventional aspect ratio tokamaks, but full suppression was not achieved in any spherical tokamak despite concerted efforts[4], posing a challenge in extrapolating suppression access from current tokamaks to the power plant scale. This work reports the first instances of RMP induced ELM suppression observed on a spherical tokamak – MAST Upgrade – and its interpretation supported by linear MHD modelling of the plasma response to the applied field using the MARS-F code. The application of a dominantly n=3 RMP caused a global deceleration of the toroidal rotation, density pump out and the disappearance of ELM activity, in a stationary ELM suppressed regime maintained for over 300ms. The core electron temperature was unaffected, and plasma pressure stabilised at βN~2.0. While the ne and Te pedestal heights were reduced, H mode was maintained. The evolutions of these and further experiments to explore this regime, and modelling results, will be reported.\n[1] J R Harrison et al, 2019, Nuclear Fusion, 59, 112011\n[2] A Loarte et al, 2003, Plasma Physics and Controlled Fusion, 45, 1549–1569\n[3] T E Evans et al, 2004, Physical Review Letters, 92, 235003\n[4] A Kirk et al, 2013, Plasma Physics and Controlled Fusion, 55, 124003\n\nAuthor\nDavid Ryan (UKAEA)\n\nCo-authors\nDr Andrew Kirk (UKAEA)\nDr Eli Viezzer (University of Seville, Spain)\nDr Lidia Piron (University of Padova, Italy)\nDr Stefano Munaretto (Princeton Plasma Physics Laboratory, USA)\nDr Tomas Markovic (Institute of Plasma Physics CAS)\nProf. Wolfgang Suttrop (Max Planck Institute for Plasma Physics)"},{"id":"dfdfd568-4e69-4441-8d42-f00972c70f4b","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:25:00+00:00","end":"2026-06-30T16:50:00+00:00","s":"1725","e":"1750","name":"I.231  M. Salvadori: Towards on-demand production of 18F radiopharmaceuticals via high-rep rate laser-driven accelerator and microfluidic systems","loc":"Moorfoot: Level 0","track":"BPIF :  Applications of laser-plasma radiation sources","type":"Session","details":"Advances in laser technology have made it possible to deliver energies of the order of a joule in tens of femtoseconds at relatively high repetition rates (e.g., 100 Hz). When focused onto a thin solid target, such lasers can generate multi-MeV proton beams with fluxes exceeding 10¹⁰ particles per shot. These sources are promising for producing the ¹⁸F radioisotope via the ¹⁸O(p,n)¹⁸F nuclear reaction. This development could significantly benefit the wider adoption of Positron Emission Tomography, which relies on the availability of short-lived positron-emitting radiopharmaceuticals. At present, these compounds are mainly produced at selected cyclotron facilities and then transported to hospitals, limiting the geographical availability of PET and making economically viable only the production in large batches. We investigate, through Monte Carlo simulations, the feasibility of employing laser-driven proton sources combined with microfluidic systems for on-demand production of ¹⁸F radiopharmaceuticals. The simulations were benchmarked against results obtained in a dedicated experiment carried out at low repetition rate. Proton beams obtained through TNSA were directed onto a [¹⁸O]H₂O sample contained within a custom PDMS microfluidic target chip intended for direct integration with the radiochemical apparatus used in radiopharmaceutical synthesis. During the experiment, a peak activity of ∼5 Bq was measured, while tens of MBq are expected for HRR operation and adopting an optimized irradiation scheme aimed at maximizing the proton flux reaching the enriched water sample.\n\nAuthor\nMartina Salvadori (CNR-INO, ILIL)"},{"id":"02557e90-53ac-4434-ae41-8f1f4954c11b","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:35:00+00:00","end":"2026-06-30T16:50:00+00:00","s":"1735","e":"1750","name":"O.218   H. Meyer: An Updated Plasma Scenario for the Spherical Tokamak for Energy Production","loc":"Sidlaw: Level +3","track":"MCF : Long pulse and Future Devices","type":"Session","details":"The UK’s Spherical Tokamak for Energy Production (STEP) programme, aiming to provide a prototype fusion power plant (SPP) based on the spherical tokamak concept targeting 2040 [1], has now moved from the conceptional to preliminary design phase. Key objectives of the SPP, which will drive the creation of a UK fusion economy, are to deliver net electric power \n and demonstrate tritium self-sufficiency. Choosing a fully non-inductive flat top operating point without inboard breeding drives the design to low aspect ratio A~1.8, high elongation κ~3 and high normalised plasma pressure \n [2] as fusion power scales like \n at high bootstrap current fraction \n. The high \n reduces the demand on the auxiliary microwave based heating and current drive system on STEP. In addition to the usual electromagnetic electron cyclotron wave current drive (ECCD), the use of electrostatic electron Bernstein waves current drive (EBCD) in combination is considered[3]. EBCD provides a 3 times higher normalised current drive efficiency than ECCD and opens opportunities to potentially access scenarios at commercial power plant relevant fusion gain of \n. The ECCD scenario operates at Q~11. Since publishing the original design base (SPP-1) (\n , \n , \n , \n in 2025) [1], to reduce the risk the centre column, the design has moved to a larger baseline (SPP-2) with \n , \n but with the same fusion power range and aspect ratio, leading to a similar \n. Plasma solutions for the larger design have proven to be more challenging in some areas, while making it easier to find an exhaust solution. To handle the heat load in the divertor at this high fusion power a core radiation fraction \n is adopted. Recent efforts to explore solutions with lower recirculating power have led to plasma flat-top operating points at lower \n and lower fusion power \n that open attractive opportunities for the plasma and the machine design, whilst still meeting the objectives. The physics basis for STEP has grown considerably, reducing uncertainties in plasma core performance, divertor performance, control and operations without type-I ELMs. The onset of high core transport fluxes in high β regimes with low torque input due to the dominant hybrid kinetic ballooning mode (hKBM) turbulence is now understood. The competition between the Reynolds and Maxwell stresses with respect to zonal flow generation leading to these high fluxes is governed by a a threshold \n (\n: magnetic shear, \n: E×B flow shear). This has been used to optimise the flat-top solution in SPP-2. Although, most of the scenario exploration is done with using JETTO or RAPTOR with \n feedback used to achieve the required \n , codes like an ST optimised version of TGLF or a newly developed quasilinear model for hKBM transport provide flux driven predictive capabilities. Machine learning has been used to provide surrogates for faster scenario evaluation. An optimised divertor design has been developed to provide good detachment access and efficient He exhaust at the same time. The first coupled core edge simulations are being used to understand the impact of He and Ar on the scenario performance. A novel scheme for vertical control in double null has been developed and tested on TCV. A runaway electron (RE) beam mitigation coil (REMC) has been incorporated into the design to provide a feasible solution to dissipate the RE current in combination with shattered pellet injection. This reduces a key risk to the STEP plasma scenario by deconfining >75% of the REs in less than 0.1 ms . A manageable R&D programme to develop key diagnostic systems for STEP is being established. This paper will give an overview of the most important aspects in which risk and uncertainty in of the STEP plasma scenario has been reduced. Considerable progress has been made in STEP scenario modelling capability but still many challenges remain. The burning plasma solution is driving physics development at the forefront of fusion research.\nThis work has been funded by STEP, a major technology and infrastructure programme led by UK Industrial Fusion Solutions Ltd (UKIFS), which aims to deliver the UK’s prototype fusion powerplant and a path to the commercial viability of fusion. To obtain further information on the data and models underlying this paper please contact PublicationsManager@ukaea.uk.\n[1] C. Waldon et al., Phil. Trans. R. Soc. A 382, 20230414 (2024).\n[2] H. Meyer et al., Phil. Trans. R. Soc. A 382, 20230406 (2024).\n[3] S. Freethy et al., Nuclear Fusion 64, 126035 (2024).\n\nAuthor\nHendrik Meyer (UK Industrial Fusion Solutions Ltd.)"},{"id":"aa974538-78b4-4a79-af9d-a63621789482","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:45:00+00:00","end":"2026-06-30T17:00:00+00:00","s":"1745","e":"1800","name":"O.210  JJ. Santos: Innovative Ignition Concepts in Laser-Driven Inertial Fusion: Toward High-Gain Regimes","loc":"Fintry: Level +3","track":"BPIF : Direct Drive","type":"Session","details":"nertial Fusion Energy (IFE) is increasingly regarded as a credible long-term option for large-scale, carbon-free power production. The recent demonstration of ignition with net target gain at the National Ignition Facility (NIF) marks a decisive scientific milestone for laser-driven inertial confinement fusion (ICF). Since 2022, repeated ignition shots have been achieved, with fusion gains increasing from ~1.5 [1] to above ~4 by 2025. These results validate decades of theoretical and experimental efforts devoted to implosion symmetry control, instability mitigation, and ignition physics.\nYet single-shot ignition at gain of a few is not equivalent to a viable energy pathway. An economically relevant fusion system delivering >750 MW of electricity would ultimately require repetition rates of the order of 10 Hz and target gains exceeding 100. Although advances in laser efficiency, target production and injection, and reactor technologies are indispensable, the achievable fusion gain remains fundamentally conditioned by the underlying ignition physics. In this respect, the central question is not merely how to scale present approaches, but whether alternative ignition regimes offer intrinsically more favorable gain margins and robustness.\nThis talk will therefore focus on a comparative assessment of advanced ignition concepts aimed at substantially increasing target gain beyond conventional central hot-spot ignition. Concepts proposed over the past three decades – including shock [2] and shock-augmented ignition [3], electron- [4] and proton-driven fast ignition [5], and magnetized inertial confinement fusion [6] – will be evaluated in terms of physical robustness, scalability toward high gain (>100), sensitivity to asymmetries and instabilities, and compatibility with existing or emerging large-scale laser infrastructures.\nDrawing on 25 years of research and teaching experience and a synthesis of key reference works, I will propose an independent perspective on the most promising physics-driven strategies for substantially increasing fusion gain within the current international academic and emerging semi-industrial ecosystem. Particular emphasis will be placed on identifying the critical physical bottlenecks that may ultimately determine which approaches can realistically mature in the coming decades.\nReferences\n[1] H. Abu-Shawareb et al., Phys. Rev. Lett. 132, 065102 (2024).\n[2] R. Betti et al., Phys. Rev. Lett. 98, 155001 (2007).\n[3] R.H.H. Scott et al., Phys. Rev. Lett. 129, 195001 (2022).\n[4] M. Tabak et al., Phys. Plasmas 1 (5), 1626 (1994).\n[5] M. Roth et al., Phys. Rev. Lett. 86, 3, 436-439 (2001).\n[6] L. J. Perkins et al., Phys. Plasmas 24, 062708 (2017).\n\nAuthor\nJoão Jorge Santos (CELIA, Université de Bordeaux, CNRS, CEA, UMR 5107, 33405 Talence, France)"},{"id":"0ca70129-21a3-475a-a2a1-14f43e1718bc","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:45:00+00:00","end":"2026-06-30T17:00:00+00:00","s":"1745","e":"1800","name":"O.220  J. Stawarz: Turbulence-Driven Magnetic Reconnection: From Cluster and Magnetospheric Multiscale to Plasma Observatory","loc":"Tinto: Level 0","track":"BSAP : Solar and Space Plasmas","type":"Session","details":"Both magnetic reconnection and turbulence are fundemental plasma phenomena active across laboratory, space, and astrophysical plasmas. Magnetic reconnection events initiated within the tangled magnetic fields produced in turbulent plasmas have long been thought to play an important role in turbulent dynamics. These events have traditionally been challenging to examine from either a numerical or experimental perspective due to their small-scale nature and the complex magnetic topologies involved. However, multi-spacecraft measurements from the natural plasma environments in near-Earth space have provided a step-change in understanding this complex phenomenon. Since the days of ESA's Cluster mission, evidence has been found for turbulence-driven magnetic reconnection embedded within the turbulent fluctuations of Earth's magnetosheath, making it an ideal location for studying the physics and importance of turbulence-driven magnetic reconnection. In this presentation, we will highlight the observational insights into turbulence-driven reconnection that have been enabled by the systematic identification and analysis of reconnection events in Earth's magnetosheath by missions such as NASA's Magnetospheric Multiscale (MMS) and ESA’s Cluster missions – including the importance of so-called electron-only reconnection and estimates that suggest magnetic reconnection can account for a significant fraction of the energy dissipated in turbulent plasmas. Using kinetic simulations of turbulence reminiscent of the plasmas found in Earth’s magnetosheath, we will further demonstrate and evaluate how multi-scale measurements from a mission such as ESA’s proposed seven-spacecraft Plasma Observatory mission will enable key observational constraints characterizing the 3D structure and distribution of turbulence-driven magnetic reconnection events that will usher in a new era of advancements on the subject.\n\nAuthor\nJulia Stawarz (Northumbria University)\n\nCo-authors\nDr Luca Franci (Northumbria University)\nPaulina Quijia Pilapana (Northumbria University)\nJeffersson Andres Agudelo Rueda (Northumbria university)\nDr Prayash Pyakurel (University of California Berkeley)\nProf. Michael Shay (University of Delaware)\nDr Tai Phan (University of California Berkeley)\nDr Naoki Bessho (NASA Goddard Spaceflight Center)\nDr Imogen Gingell (University of Southhampton)"},{"id":"e546bac5-4b82-4512-b1cc-f572c7c1c96d","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:45:00+00:00","end":"2026-06-30T17:00:00+00:00","s":"1745","e":"1800","name":"O.214   S. Rienäcker: Link between edge radial electric field and confinement improvement in negative triangularity plasmas in TCV","loc":"Pentland Suite: Level +3","track":"MCF : NT and ELM-free","type":"Session","details":"Negative triangularity (NT) has emerged as a promising alternative to the conventional positive triangularity (PT) shape of tokamak plasmas. Owing to the suppression of large ELMs, combined with outstanding L-mode confinement, NT appears as a suitable candidate for core-edge integration [1,2]. While the fundamental reason for the NT L-mode performance improvement over PT remains unclear, experiments emphasize the role of the NT edge region [3,4]. This contribution investigates the edge radial electric field (Er) and its shear as possibly relevant distinguishing features between the NT and PT edge. The study is based on recent experiments on the TCV tokamak that, for the first time, compare the edge Er profile in matched NT/PT discharges [5]. Measurements using a Doppler backscattering diagnostic [6] reveal an Er well that is deeper in NT than in PT, along with improved L-mode confinement. The stronger edge Er × B shear in NT is observed systematically under Ohmic, NBI, or ECRH heating. It coincides—at equal heating power—with higher edge density and temperature. Notably, a deeper Er well is still observed in NT, even when the auxiliary power in PT is adjusted to match the edge density and temperature profiles of NT. Implications of this decoupling of Er from kinetic profile differences are dicussed. Overall, the results are compatible with edge Er × B shear stabilization as a possible cause for the beneficial L-mode confinement properties of the NT edge. Turbulent transport modelling based on the presented data is underway to elucidate the origin of the differing Er behavior between NT and PT.\n\n[1] K. E. Thome et al. Plasma Physics and Controlled Fus. 2024\n[2] O Février et al. Submitted to Nuclear Fusion 2026\n[3] A. Balestri et al. Plasma Physics and Controlled Fus. 2024\n[4] A. O. Nelson et al. Plasma Physics and Controlled Fus. 2024\n[5] S. Rienäcker et al. Nuclear Fusion 2026\n[6] S. Rienäcker et al. Plasma Physics and Controlled Fus. 2025\n\nAuthor\nSascha Rienäcker (Laboratoire de Physique des Plasmas (LPP), CNRS)\n\nCo-authors\nBaptiste Frei (Max Planck Institute for Plasma Physics)\nBenjamin Vincent (EPFL-SPC)\nBenoît Labit (Ecole Polytechnique Fédérale de Lausanne (EPFL) - SPC)\nCyrille Honoré (Laboratoire de Physique des Plasmas (LPP), CNRS)\nMrs Laure Vermare (Laboratoire de Physique des Plasmas (LPP), CNRS)\nOleg Krutkin (EPFL-SPC)\nPascale Hennequin (Laboratoire de Physique des Plasmas (LPP), CNRS)\nStefano Coda (EPFL-SPC, Lausanne, Switzerland)"},{"id":"01433bf9-8ef5-407e-8ab3-a5b7b35e408c","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:50:00+00:00","end":"2026-06-30T17:05:00+00:00","s":"1750","e":"1805","name":"O.225  F. Mirani: Experimental Application of Laser–Plasma Radiation Sources to Cultural Heritage Studies at ELI Beamlines","loc":"Moorfoot: Level 0","track":"BPIF :  Applications of laser-plasma radiation sources","type":"Session","details":"Laser-plasma particle acceleration based on solid targets [1] is promising for many applications, from nuclear medicine to materials characterization. Laser-plasma sources can generate different radiations (e.g., ions and photons), allow for energy tuning, and can operate within potentially compact setups. Control over the laser (e.g., intensity) and target parameters (e.g., thickness) enables one to tune the maximum energy of accelerated ions. Therefore, laser-plasma sources represent promising alternatives to conventional accelerators which, although based on mature technologies, remain limited in terms of flexibility and compactness.\nParticle Induced X-Ray Emission (PIXE) and X-Ray Fluorescence Spectroscopy (XRF) are complementary materials characterization techniques used in several fields including artworks analysis [3]. They rely on the irradiation of samples with protons and photons to induce characteristic X-ray emission. PIXE and XRF could benefit from the use of laser-plasma sources [4]. Indeed, the energies of the laser-driven protons and photons are suitable for the characterization of cultural heritage materials.\nHere, we present artworks characterization with laser-plasma sources via laser-driven PIXE and XRF. We performed a campaign at the ELIMAIA beamline [5] (ELI Beamlines) driven by the HAPLS laser. Using a proof-of-principle setup [2], laser-driven protons and photons were transported in air to irradiate certified materials, medieval bronzes, and Iron Age ceramics. We measured the characteristic X-rays emitted by the sample, and the spectra were analysed with a numerical tool that integrates the theoretical description of PIXE in the PyMCA code [6] for XRF analysis. In this way, it is possible to determine the elements present in the samples and their concentrations. This study lays the foundation for the development of laser-plasma accelerators tailored to the characterization of cultural heritage materials, suggesting that this suorces could achieve results comparable to conventional accelerators while maintaining their inherent versatility.\n\n[1] A. Macchi et al., Rev. Mod. Phys (2013) 85-2\n[2] F. Mirani, et al., Phys. Rev. Appl 24.1 (2025):014017\n[3] L. Sottili, et al. Appl. Sci 12.13 (2022):6585\n[4] F. Mirani et al., Sci. Adv (2021) 7-3\n[5] D. Margarone, et al. Quantum Beam Sci 2.2 (2018):8\n[6] V. A. Solé, et al. Spectrochim. Acta B 62.1 (2007):63-68.\n\nAuthor\nFrancesco Mirani (Politecnico di Milano, Dipartimento di Energia)\n\nCo-authors\nAlessandro Maffini (Politecnico di Milano)\nProf. Andrea Pola (Politecnico di Milano)\nDr Claudia Conti (National Research Council, Institute of Heritage Science)\nDaniele Margarone (The Extreme Light Infrastructure ERIC - ELI Beamlines Facility)\nDr Dario Rastelli (Raylab s.r.l.)\nDavid Dellasega (Politecnico di Milano)\nDr Davide Mazzucconi (Politecnico di Milano)\nDr Francesco Gatti (European XFEL)\nFrancesco Schillaci (The Extreme Light Infrastructure ERIC - ELI Beamlines Facility)\nMr Kevin Ambrogioni (Politecnico di Milano)\nLorenzo Giuffrida (The Extreme Light Infrastructure ERIC - ELI Beamlines Facility)\nMatteo Passoni (Politecnico di Milano)\nProf. Valeria Russo (Politecnico di Milano)\nDr Vasiliki Kantarelou (The Extreme Light Infrastructure ERIC, ELI Beamlines Facility)"},{"id":"2dd3acff-14e0-4e76-994d-35085a85e02c","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T16:50:00+00:00","end":"2026-06-30T17:15:00+00:00","s":"1750","e":"1815","name":"O.219    M Siccinio: Physics basis of a Volumetric Neutron Source (VNS) for component testing and qualification","loc":"Sidlaw: Level +3","track":"MCF : Long pulse and Future Devices","type":"Session","details":"A study is being carried out within EUROfusion to address the feasibility of a Volumetric Neutron Source (VNS). VNS is a medium-size tokamak (R = 2.67 m, B0 = 5.6 T, A = 4.25, Ip = 2.54 MA) operating D-T plasmas, able to achieve a significant neutron wall load (approximately 0.5 MW/m2) on long pulses, to be built and operated in parallel to ITER. Purpose is to test and qualify in-vessel components, in particular the breeding blanket and the divertor, under large neutron irradiation, fluence and heat flux in a reactor-relevant environment. VNS is based on beam-target fusion reactions, which enable a significant fusion power despite the reduced device size. Neutral Beams are employed both to generate the beam-target reactions (as in JET D-T fusion energy record [Maslov, NF 2023, PPCF2026 submitted]), and to drive the plasma current to sustain the requested long pulses. Additional EC power is installed to keep the electron temperature high (a fundamental aspect in beam-target driven devices), and for control reasons. This work illustrates the design-driving criteria according to which the current VNS design point has been identified. A series of scans performed with the plasma simulator METIS [Artaud, NF 2018] coupled with the code MADE [Giannini, FED 2023] for preliminary magnets sizing is also presented. The results highlight the impact of relevant machine parameters on the VNS performance.\n\nIn addition, this work reviews the VNS plasma scenario, with focus on its critical features. This is currently being investigated with codes of different level of fidelity, both looking at some particular aspect in isolation, but also with integrated modelling – e.g. for tungsten accumulation. Further analyses deal with MHD stability (with particular attention on the interplay with energetic particles), power exhaust, fast particles confinement (both beams and alpha's) and beam deposition, as well as magnetic equilibrium and control. In the near future, a study of the dynamic phases and of the machine controllability in a broad sense via Pulse Design tools (e.g. Fenix [David, OPS 2025]) is planned, following what has recently been carried out for EU-DEMO [Di Grazia, FED 2025].\n\nAuthor\nMattia Siccinio (Max-Planck-Institut für Plasmaphysik)\n\nCo-authors\nAndrea Quartararo (EUROfusion Consortium)\nChristian Bachmann (EUROfusion Consortium)\nClarisse Bourdelle (CEA Cadarache)\nElisabetta Bray (Politecnico di Torino)\nFrancesco Maviglia (EUROfusion Consortium)\nLorenzo Giannini (EUROfusion Consortium)\nPasquale Zumbolo (EUROfusion Consortium)\nPhilipp Lauber (Max-Planck-Institut für Plasmaphysik)\nSven Wiesen (DIFFER)"},{"id":"d0996081-3b3d-49e8-8164-fd7bc1c28ce8","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T17:00:00+00:00","end":"2026-06-30T17:15:00+00:00","s":"1800","e":"1815","name":"O.211  R  Gonzalez-Arrabal: Plasma facing material in inertial confinement fusion reactors operated in the direct drive dry wall approach","loc":"Fintry: Level +3","track":"BPIF : Direct Drive","type":"Session","details":"Nuclear fusion is a promising option for future large-scale energy supply. There are two main approaches to fusion energy: magnetic confinement fusion (MCF) and inertial confinement fusion (ICF). In 2022 ICF achieved, by the first time, ignition with gain at the National Ignition Facility (NIF). Since then, several campaigns carried out in it have replicated this milestone, achieving successive increases in gain in each of them. These breakthroughs have motivated a notable increase in public and private funding for the development of projects aimed at the conceptualization of commercial power plants.\n\nDespite the achievements, there are still several challenges that need to be addressed prior to up-scaling to a commercial facility. One of them is the development of plasma facing materials (PFMs) able to withstand the combined effects of large thermal loads and radiation environments taking place in these reactors.\n\nIn this contribution, we will show the different radiation environments that PFMs have to withstand in ICF reactors operated in the direct drive dry wall approach [1]. We briefly introduce the limitations of coarse-grained W acting as PFM [2]. Finally, based on a combination of experimental and multiscale computer simulation data, we will discuss the capabilities and limitations of alternative W-based materials to act as PFM: nanostructured W, with a large density of grain boundaries [3–7], and W nanocolumns, with a large surface area [8].\n\n[1] J. Alvarez et al., Potential common radiation problems for components and diagnostics in future magnetic and inertial confinement fusion devices, Fusion Engineering and Design 86 (2011) 1762–1765. https://doi.org/10.1016/j.fusengdes.2011.01.080.\n[2] R. Gonzalez-Arrabal et al., Limitations for tungsten as plasma facing material in the diverse scenarios of the European inertial confinement fusion facility HiPER: Current status and new approaches, Matter and Radiation at Extremes 5 (2020) 055201. https://doi.org/10.1063/5.0010954.\n[3] M. Panizo-Laiz et al., Experimental and computational studies of the influence of grain boundaries and temperature on the radiation-induced damage and hydrogen behavior in tungsten, Nucl. Fusion 59 (2019) 086055. https://doi.org/10.1088/1741-4326/ab26e9.\n[4] G. Valles et al., Influence of grain boundaries on the radiation-induced defects and hydrogen in nanostructured and coarse-grained tungsten, Acta Materialia 122 (2017) 277–286. https://doi.org/10.1016/j.actamat.2016.10.007.\n[5] P. Díaz-Rodríguez et al., Direct observation of hydrogen permeation through grain boundaries in tungsten, Emergent Mater. 5 (2022) 1075–1087. https://doi.org/10.1007/s42247-021-00344-w.\n[6] D. Fernández-Pello et al., Coexistence of a self-interstitial atom with light impurities in a tungsten grain boundary, Journal of Nuclear Materials 560 (2022) 153481. https://doi.org/10.1016/j.jnucmat.2021.153481.\n[7] J. Suárez-Recio et al., Early stages of self-healing at tungsten grain boundaries from ab initio machine learning simulations, Commun Mater 6 (2025) 1–14. https://doi.org/10.1038/s43246-025-00945-6.\n[8] R. Gonzalez-Arrabal et al., Sputtering fabrication of isolated W nanocolumns: A possible alternative as plasma facing material for nuclear fusion reactors, Nuclear Materials and Energy 40 (2024) 101704. https://doi.org/10.1016/j.nme.2024.101704.\n\nAuthor\nRaqel Gonzalez-Arrabal (Instituto de Fusión Nuclear “Guillermo-Velarde” and Departamento de Ingeniería Energética, ETSI de Industriales, Universidad Politécnica de Madrid, Madrid, Spain)\n\nCo-authors\nC. Ruestes (1Instituto de Fusión Nuclear “Guillermo-Velarde” and Departamento de Ingeniería Energética, ETSI de Industriales, Universidad Politécnica de Madrid, Madrid, Spain 2Departamento de Física, Universidad de Oviedo, Oviedo, Spain)\nJ. Suarez-Recio (1Instituto de Fusión Nuclear “Guillermo-Velarde” and Departamento de Ingeniería Energética, ETSI de Industriales, Universidad Politécnica de Madrid, Madrid, Spain 2Departamento de Física, Universidad de Oviedo, Oviedo, Spain)\nJ.M. Perlado (1Instituto de Fusión Nuclear “Guillermo-Velarde” and Departamento de Ingeniería Energética, ETSI de Industriales, Universidad Politécnica de Madrid, Madrid, Spain, 3 Focused Energy GmbH,Im Tiefen See, Darmstadt, Germany)\nM.A. Cerdeira (Departamento de Física, Universidad de Oviedo, Oviedo, Spain)\nR. Iglesias (Departamento de Física, Universidad de Oviedo, Oviedo, Spain)"},{"id":"197569f1-6d74-41b6-bc8d-bede2d07a52e","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T17:00:00+00:00","end":"2026-06-30T17:15:00+00:00","s":"1800","e":"1815","name":"O.221  I  Svenningsson: Electron heat flux and whistler instability in the Earth’s magnetosheath","loc":"Tinto: Level 0","track":"BSAP : Solar and Space Plasmas","type":"Session","details":"In collisionless plasma, several processes contribute to plasma heating and energy dissipation. One such example is wave-particle interactions between electromagnetic whistler waves and electrons. In the solar wind, the whistler-heat flux instability is known to regulate the electron heat flux by pitch-angle scattering of strahl electrons. Similar instabilities are believed to operate in various astrophysical plasma, but most such systems can only be studied remotely and through simulations. The Earth’s magnetosheath downstream of the bow shock is accessible to high-quality in situ spacecraft measurements, allowing the measurement of heat flux and detailed studies of wave-particle interactions. The heat flux properties and evolution across the magnetosheath have not yet been explored.\n\nWe present Magnetospheric Multiscale (MMS) observations from 18 hours of high-resolution burst-mode measurements. We quantify the electron heat flux in the magnetosheath and examine the role of whistler instabilities in regulating it. Our results show that the heat flux follows the magnetosheath magnetic field as it drapes around the magnetosphere. We find that the heat flux is constrained by whistler instability thresholds and is aligned with the propagation of low-frequency whistler waves. We also present a case study investigating direct evidence for the whistler-heat flux instability in the magnetosheath.\n\nAuthor\nDr Ida Svenningsson (Chalmers University of Technology)\n\nCo-authors\nDr Alexandros Chasapis (Laboratory for Atmospheric and Space Physics, University of Colorado, Boulder, USA)\nDr Emiliya Yordanova (Swedish Institute of Space Physics)\nDr Giulia Cozzani (Laboratoire de Physique et Chimie de l'Environnement et de l'Espace (LPC2E), Orléans, France)\nProf. Mats André (Swedish Institute of Space Physics)\nMax Larsson (Chalmers University of Technology)\nProf. Steven J. Schwartz (Imperial College London, London)\nProf. Yuri V. Khotyaintsev (Swedish Institute of Space Physic"},{"id":"078ad2a9-a0a3-4016-ab02-cf4df3fdf83b","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T17:00:00+00:00","end":"2026-06-30T17:15:00+00:00","s":"1800","e":"1815","name":"I.221   S. Coda (PPCF paper prize): TBC","loc":"Pentland Suite: Level +3","track":"MCF : NT and ELM-free","type":"Session","details":""},{"id":"f946edfb-9010-44fe-9ba3-2c4d76100442","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T17:05:00+00:00","end":"2026-06-30T17:30:00+00:00","s":"1805","e":"1830","name":"O.226  F  Kohlmeier: Full reconstruction of the energy partitioning in 2-μm-wavelength-laser-driven plasma sources of extreme ultraviolet light","loc":"Moorfoot: Level 0","track":"BPIF :  Applications of laser-plasma radiation sources","type":"Session","details":"State-of-the-art nanolithography uses extreme ultraviolet (EUV) radiation at 13.5 nm emitted from tin laser-produced plasma (LPP), driven by a 10.6 µm-wavelength CO2-gas laser, to create the smallest features on semiconductor devices. Advances in solid-state laser technologies have led to the alternative concept of a 2 µm-wavelength-driven LPP as a promising candidate for a more efficient and more powerful EUV source. At this drive laser wavelength a high conversion efficiency of laser energy into EUV radiation of 4% has been demonstrated [Appl. Phys. Lett. 123, 234101 (2023)], but a full picture of the plasma has not been shown to date.\nIn this study we characterize the partitioning of all emissions of a 2 µm laser driven plasma to have a full picture of the energy sinks. We use our custom-built high energy 2 μm laser system, developed at ARCNL, to heat a tin sheet into an EUV emitting plasma. Plasma emissions are measured by an extensive diagnostic suite: In-band EUV light (13.5nm±1%) is measured, correcting for the emission anisotropy, by a set of EUV photodiodes. The EUV emission is combined with the emission spectrum measured in 5-260nm in order to reconstruct the full radiative emission. Ion emissions are measured with a set of retarding field analyzers, reconstructing the charge-state-resolved ion kinetic energy spectrum. Together with laser reflection and kinetics of the remaining neutral tin this accounts for the energy sinks in the plasma.\nWe can for the first time reconstruct 100% of the incoming laser energy. With ~70%, most of the energy goes into photons, the largest part of which is emitted in the 5-80 nm wavelength range. Plasma ions contribute ~30% of the energy, and, contrary to available theory and numerical simulations, we find that this fraction decreases as a function of the laser intensity. This is a key insight in finding pathways to optimize plasma for industrial application. Our results offer insight into the energy partitioning of EUV-emitting plasmas for research and industrial nanolithography alike, and provide a benchmark for plasma light source development.\n\nAuthor\nFelix Kohlmeier (ARCNL)\n\nCo-authors\nBas Slotema (ARCNL)\nDr Dion Engels (ARCNL)\nProf. John Sheil (ARCNL)\nProf. Oscar Versolato (ARCNL)\nProf. Ronnie Hoekstra (University of Groningen)\nProf. Wim Ubachs (ARCNL)\nDr Yahia Mostafa (ARCNL)"},{"id":"5209ee90-fef4-495a-8e65-596817151a22","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T17:15:00+00:00","end":"2026-06-30T17:30:00+00:00","s":"1815","e":"1830","name":"O.222  G  Zank: Turbulence and its Potential Impact on Solar Chromospheric and Coronal Heating","loc":"Tinto: Level 0","track":"BSAP : Solar and Space Plasmas","type":"Session","details":"Low-frequency turbulence in the solar chromosphere remains poorly understood. Here we address 1) the sources of low-frequency turbulence that potentially contribute to the heating of the chromosphere, and 2) how turbulence is transported and dissipated throughout the chromosphere, including into the lower corona. We use particle-in-cell simulations to investigate imbalanced and balanced mixed polarity magnetic fields that correspond to emergent magnetic carpet field in coronal hole or quiet Sun regions. In both cases, the initial mixed polarity magnetic field transitions rapidly to a highly turbulent state dominated by advected small-scale nonlinear structures, where the initial current sheet breaks up into multiple magnetic flux ropes of different scales that interact and merge, continuously producing secondary flux ropes or magnetic islands. For imbalanced mixed polarity magnetic field, the simulations show that low-frequency turbulence is anisotropic both spectrally and in variance, dominated by quasi-2D nonlinear structures, with a minority slab turbulence population. By contrast, reconnection-driven turbulence in the quiet Sun (balanced turbulence) is dominated by isotropically distributed advected structures. In both cases, the emergent mixed polarity magnetic field is almost completely annihilated to be replaced by predominantly advected nonlinear small-scale structures or flux ropes and minority slab turbulence. We present a model for the predominantly advected turbulence that describes its transport and dissipation throughout the chromosphere by a field of randomly distributed flows described by log-normal statistics. We compute the expectations of the evolution of the total energy per unit volume, the Elsasser specific energy (i.e., the energy per unit mass), the heating rate, and the correlation length as functions of chromospheric height up to the lower corona. The injection of turbulent energy into the low corona is via a distributed random “patchwork” of injection sites across the surface of the transition region. We find that for either magnetic carpet-generated turbulence only or magnetic carpet-generated plus entrained photospheric turbulence, the expected energy injection rates for the chromosphere and at the base of the corona exceed the estimated energy requirements needed [Withbroe & Noyes, 1977, Anderson & Athay, 1989] to heat both the chromosphere and corona.\n\nAuthor\nProf. Gary Zank (The University of Alabama in Huntsville)\n\nCo-authors\nDr Xiaocan Li (3Los Alamos National Laboratory)\nDr Krishna Khanal (The University of Alabama in Huntsville)\nDr Alphonse Sterling (4NASA/Marshal Space Flight Center)\nDr Masaru Nakanotani1 (The University of Alabama in Huntsville)\nProf. Lingling Zhao (The University of Alabama in Huntsville)\nProf. Laxman Adhikari (The University of Alabama in Huntsville)\nDr Mehemt Yalim (The University of Alabama in Huntsville)\nProf. P.S. Athiray (The University of Alabama in Huntsville)\nDr Ronald Moore (The University of Alabama in Huntsville)"},{"id":"a3e3a077-0538-459f-a2f5-5f1aa7a1b99a","date":"2026-06-30","dayLabel":"Tuesday, June 30, 2026","start":"2026-06-30T17:15:00+00:00","end":"2026-06-30T17:30:00+00:00","s":"1815","e":"1830","name":"O.216   F Rath: Gyrokinetic investigation of microturbulence in the edge of ELM suppressed H-modes in ASDEX Upgrade","loc":"Pentland Suite: Level +3","track":"MCF : NT and ELM-free","type":"Session","details":"High confinement mode (H-mode) access in tokamaks is based on the formation of a radially narrow steep gradient region in the plasma edge and a concomitant radial electric field (Er​).\nThere is growing evidence that the profiles of temperature and density in the H-mode edge are partly determined by turbulent transport connected with microinstabilities driven by the steep gradients and its interplay with the E×B shear flow related to the Er-well.\nThrough a gyrokinetic investigation with the code GKW it is shown that the slab branch of the ion temperature gradient (ITG) driven instability is dominantly unstable under edge conditions of edge localized mode (ELM) suppressed H-modes in ASDEX Upgrade (AUG).\nThis work explicitly takes into account the gyroaverage in the background E×B shear flow model.\nIt is shown that this has significant impact on linear stability and turbulent transport:\nThe slab ITG is then hardly stabilized and turbulent transport is not reduced when a gyroaveraged E×B shear flow is added.\nThis lack of stabilization renders the slab ITG a strong candidate for setting the ion temperature profile in the steep gradient edge region.\nFurthermore, a sign sensitive E×B shear flow induced radial symmetry breaking of slab ITG Eigenmodes is discussed.\nIn the inhomogeneous Er-well this symmetry breaking mechanism determines the most unstable Eigenmode and renders linear stability and turbulent transport highly sensitive to the sign of the E×B shear flow.\nHence, it is not only the magnitude of the E×B shear rate, but also its sign which determines microturbulence in the steep gradient edge region.\nFinally, three-dimensional (3d) magnetic perturbations (MPs), applied in the considered AUG scenario to suppress ELMs, are shown to impact slab ITG turbulence:\nSingle helicity 3d MPs with high mode number parallel to the ambient magnetic field destabilize the slab ITG and thereby augment turbulent transport.\nThe 3d MP aided increase of slab ITG turbulence and connected particle transport might relate to the density pump-out responsible for ELM suppression.\n\nAuthor\nFlorian Rath (Universität Bayreuth)\n\nCo-authors\nASDEX Upgrade team (Max-Planck-Institut für Plasmaphysik)\nProf. Arthur Peeters (Universität Bayreuth)\nBojana Stefanoska (Max Planck Institute for Plasma Physics)\nMatthias Willensdorfer (Max Planck Institute for Plasma Physics, Garching)\nWolfgang Suttrop (Max Planck Institute for Plasma Physics)"},{"id":"6e907c33-a8e0-4df7-86ac-6451b2f0d520","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T07:00:00+00:00","end":"2026-07-01T08:00:00+00:00","s":"0800","e":"0900","name":"AGENDA KEY INFORMATION - PLEASE READ","loc":"","track":"","type":"Information","details":"Please click on each session to view the session details including the abstract and the authors. \n\nTo add the session to your personal agenda, please click the star. \n\nYou can view your personal agenda by returning to the home screen and clicking the 'My Agenda' icon."},{"id":"2e4521d7-a0d6-48b4-94a3-8e076bc35012","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T08:00:00+00:00","end":"2026-07-01T08:35:00+00:00","s":"0900","e":"0935","name":"Plenary Talks: I.301  2026 Innovation prize: C. Laux - nanosecond pulsed discharges and demonstrating their practical use for sustainable energy solutions including plasma-assisted combustion and methane plasmalysis","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":""},{"id":"185715da-7da3-4372-bd68-2f7116027a69","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T08:35:00+00:00","end":"2026-07-01T09:10:00+00:00","s":"0935","e":"1010","name":"Plenary Talks: I.302   A. Borrás - Plasma-enabled nanoarchitectures: from synthesis to devices","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"Plasma and vacuum deposition technologies are transforming the possibilities in nanoengineering, particularly for porous thin films and low-dimensional materials, while also emphasizing sustainability and energy efficiency. In this presentation, we will share our latest advances in applying these techniques to design complex, supported nanoarchitectures with control over composition, morphology, and functionality. A key component of our strategy is the integration of the one reactor concept for vacuum and plasma assisted deposition methods with a soft template approach.[1,2] This technique involves growing single crystal small molecule nanowires under mild conditions compatible with the substrate. These crystalline templates facilitate the fabrication of nanowires and nanotubes with precisely tailored core@multishell configurations, where each shell introduces novel physical responses or synergistic multifunctionality. We will discuss how plasma assisted and vacuum based methods allow for the integration of these nanoarchitectures as supported platforms and device ready architectures while preserving structural integrity and enabling scalable processing. The versatility of these techniques enables the deposition of a remarkable range of materials, including organic molecules, polymer layers, hybrid perovskites, metals, and metal oxides, which can function as conductors, semiconductors, dielectrics, photoabsorbers, piezoelectrics, triboelectric components, or plasmonic elements. The presentation will focus on two application domains where these nanoengineered systems have recently achieved breakthrough results. First, we will demonstrate how these nanoarchitectures facilitate multisource energy harvesting, combining piezoelectric, solar, pyroelectric, and triboelectric mechanisms within a unified platform.[3–5] Our latest achievements involve solar and indoor light photovoltaic cells,[6–8] pyroelectric,[9] piezoelectric and triboelectric nanogenerators,[3–5] and hybrid devices[10] that leverage the complementary nature of these transduction pathways. Second, we will present innovative concepts for smart surfaces, including semi transparent nanoelectrodes,[1] tunable wetting layers,[11] and advanced de icing/anti icing coatings activated by acoustic waves.[12] This emerging area showcases where plasma engineered materials offer unique advantages in terms of robustness, transparency, and energy efficiency.\nReferences\n[1] J. Castillo-Seoane, J. Gil-Rostra, V. López-Flores, G. Lozano, F. Javier Ferrer, J. P. Espinós, K. (Ken) Ostrikov, F. Yubero, A. R. González-Elipe, Á. Barranco, J. R. Sánchez-Valencia, A. Borrás, Nanoscale 2021, 13, 13882.\n[2] M. Macias-Montero, A. N. Filippin, Z. Saghi, F. J. Aparicio, A. Barranco, J. P. Espinos, F. Frutos, A. R. Gonzalez-Elipe, A. Borras, Advanced Functional Materials 2013, 23, 5981.\n[3] A. N. Filippin, J. R. Sanchez-Valencia, X. Garcia-Casas, V. Lopez-Flores, M. Macias-Montero, F. Frutos, A. Barranco, A. Borras, Nano Energy 2019, 58, 476.\n[4] X. García-Casas, F. J. Aparicio, J. Budagosky, A. Ghaffarinejad, N. Orozco-Corrales, K. (Ken) Ostrikov, J. R. Sánchez-Valencia, Á. Barranco, A. Borrás, Nano Energy 2023, 114, 108686.\n[5] X. García-Casas, A. Ghaffarinejad, F. J. Aparicio, J. Castillo-Seoane, C. López-Santos, J. P. Espinós, J. Cotrino, J. R. Sánchez-Valencia, Á. Barranco, A. Borrás, Nano Energy 2022, 91, 106673.\n[6] J. Castillo-Seoane, L. Contreras-Bernal, A. J. Riquelme, S. Fauvel, Y. Kervella, J. Gil-Rostra, G. Lozano, A. Barranco, R. Demadrille, J. R. Sánchez-Valencia, A. Borrás, Materials Today Energy 2025, 49, 101851.\n[7] J. Castillo-Seoane, L. Contreras-Bernal, J. M. Obrero-Perez, X. García-Casas, F. Lorenzo-Lázaro, F. J. Aparicio, C. Lopez-Santos, T. C. Rojas, J. A. Anta, A. Borrás, Á. Barranco, J. R. Sanchez-Valencia, Advanced Materials 2022, 34, 2107739.\n[8] M. Nabil, L. Contreras-Bernal, G. P. Moreno-Martinez, J. Obrero-Perez, J. Castillo-Seoane, J. A. Anta, G. Oskam, P. Pistor, A. Borrás, J. R. Sanchez-Valencia, A. Barranco, Materials Today Energy 2025, 54, 102117.\n[9] “Unlocking the hybrid piezo and pyroelectric nanogenerators performance by SiO2 nanowires confinement in poly(vinylidene fluoride), APL Electronic Devices, 2025, 3361768\n[10] F. Núñez-Gálvez, X. García-Casas, L. Contreras-Bernal, A. Descalzo, J. M. Obrero-Pérez, J. Castillo-Seoane, A. Ginés, G. Leger, J. C. Sánchez-Lopez, J. P. Espinós, Á. Barranco, A. Borrás, J. R. Sánchez-Valencia, C. López-Santos, Nano Energy 2026, 148, 111678.\n[11] L. Montes, J. M. Román, X. García-Casas, J. Castillo-Seoane, J. R. Sánchez-Valencia, Á. Barranco, C. López-Santos, A. Borrás, Advanced Materials Interfaces 2021, 8, 2170122.\n[12] J. del Moral, L. Montes, V. J. Rico-Gavira, C. López-Santos, S. Jacob, M. Oliva-Ramirez, J. Gil-Rostra, A. Fakhfouri, S. Pandey, M. Gonzalez del Val, J. Mora, P. García-Gallego, P. F. Ibáñez-Ibáñez, M. A. Rodríguez-Valverde, A. Winkler, A. Borrás, A. R. González-Elipe, Advanced Functional Materials 2023, 33, 2209421.\n\nAuthor\nAna Borrás (Spanish Research Council (CSIC), Materials Science Institute of Seville)"},{"id":"c6bb4c8f-3538-409c-a680-a9e9873cf696","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T09:10:00+00:00","end":"2026-07-01T09:50:00+00:00","s":"1010","e":"1050","name":"Plenary Talks: I.303   D. Sun - Functional Nanocomposites Synthesized through Atmospheric Pressure Plasma Induced Liquid Chemistry","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"The development of functional bionanocomposites has gained significant attention due to their potential in sustainable materials, biomedical applications, and advanced functional coatings [1-4]. Non-thermal Atmospheric Pressure Plasma Induced Liquid Chemistry (PiLC) is an emerging green synthesis route that enables the fabrication of nanocomposites with tailored functionalities, eliminating the need for hazardous chemicals or extreme processing conditions.\n\nThis talk summarizes the work carried out at Queen’s University Belfast on the synthesis and functionalization of various bio-based nanocomposites using PiLC, leveraging natural polymers such as nanocellulose and chitosan in combination with inorganic nanofillers like gold and silver nanoparticles. The plasma-liquid interaction plays a crucial role in generating reactive species, leading to nanocomposite with desirable structure and properties. Key physicochemical properties of the resulting nanocomposites such as microstructure, surface chemistry, thermal property and mechanical integrity have been investigated thoroughly. Preliminary results demonstrate the resulting materials have tunable functional properties, making these nanocomposites highly promising for applications in such as biosensing, photothermal conversion and anti-microbial coatings. The study further highlights the potential of PiLC in engineering next-generation bionanocomposites with controlled morphology and superior functionality.\n\n[1] D. Sun, et al., Composites Science and Technology, (2020) 186, 107911.\n[2] D. Sun, et al., Journal of Physics D-Applied Physics, (2020) 53, 42, 425207.\n[3] D. Sun, et al., Langmuir, (2019) 35, 13, 4577.\n[4] H Nolan, et al., Plasma Processes and Polymers, (2018) 15, 11, e1800112.\n\nAuthor\nDan Sun (Queen's University Belfast)"},{"id":"0f9929d9-8418-46eb-9f1f-78a84cc7f667","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T09:50:00+00:00","end":"2026-07-01T10:20:00+00:00","s":"1050","e":"1120","name":"***Wednesday: Morning Refreshment Break***","loc":"Cromdale: Level -2","track":"","type":"Function","details":""},{"id":"b18cefe4-d91f-4f40-aa24-619203f06091","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:20:00+00:00","end":"2026-07-01T10:45:00+00:00","s":"1120","e":"1145","name":"I.315   D.  Singh: Holographic gaseous lenses for high-power lasers","loc":"Tinto: Level 0","track":"BPIF: High power laser-plasma interaction","type":"Session","details":"Constructing next-generation lasers with energies exceeding several megajoules, or peak powers\ngreater than ten petawatts, will require optical elements that tolerate significantly higher intensities than\nsolid-state media. For use in practical inertial confinement fusion energy plants or miniaturized particle\naccelerators, these optics must also withstand harsh environments with intense backscattered light and\nenergetic particles. Structured gases, rather than solids, can meet these stringent requirements [1,2]. We\npresent the first experimental demonstration of a diffractive gas lens for steering and focusing high-energy\nnanosecond to high-power femtosecond beams [3]. These lenses were constructed holographically via the\ninterference of two ultraviolet “write” beams (6 mJ, 5 ns, 266 nm) in an ozone-doped gas mixture. The\nwrite beams drove a structured density profile via spatially-varied heat deposition through ultravioletinduced photodissociation of ozone [4]. The resulting lenses manipulated the focus of a third “read” beam\nthat was substantially more energetic (220 mJ, 5 ns, 532 nm) at an incident fluence of 35 J/cm2 with greater\nthan 50% efficiency. These lenses also exhibited sufficient spectral bandwidth to diffract ultrashort 35-fs\n800-nm pulses. As holograms, we tuned these lenses to focus, collimate, and defocus the read beam. The\noptic showed stable beam pointing and diffraction efficiency without degradation during 10 Hz operation\nover sustained periods of time. These results suggest that gaseous optics may enable arbitrary, damageresistant manipulation of intense light.\nThis work was partially supported by NNSA Grant DE-NA0004130, NSF Grant PHY-2308641, and\nthe Lawrence Livermore National Laboratory LDRD program (24-ERD-001). Work performed under the\nauspices of the U.S. Department of Energy by Lawrence Livermore National Laboratory under Contract\nDE-AC52-07NA27344. This work was supported by the U.S. Department of Energy, Advanced Research\nProjects Agency-Energy (ARPA-E), under Award Number DE-AR0002056.\n\nAuthor\nDevdigvijay Sing"},{"id":"9ad5739f-9847-4553-a574-08e31d8736ad","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:20:00+00:00","end":"2026-07-01T10:45:00+00:00","s":"1120","e":"1145","name":"I.309   H.  Miura: Hall MHD turbulence: implications for intermittency and multiscaling in space plasma physics","loc":"Moorfoot: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (II)","type":"Session","details":"Space- and solar-plasma physics continue to pose major challenges for the characterization of　turbulence in these systems. Satellite observations of solar-wind-plasma turbulence have shown a fluid energy spectrum with an inertial range with a -5/3 exponent. However, the magnetic-energy spectrum displays MHD- and sub-ion-scale power-law ranges, the former consistent with the -5/3 power, but the latter characterized by an exponent that is approximately -2.8. These observations have examined (a) the multiscaling of velocity- and magnetic-field structure functions and (b) the alignment of velocity- and magnetic-field fluctuations. One study has found simple scaling of magnetic structure–functions in the sub-ion range, but multiscaling in the MHD range. By carrying out simulations of three-dimensional (3D) Hall magnetohydrodynamics (HMHD) turbulence, we show that it provides a natural framework for understanding solar-wind turbulence, and its dependence on non-dimensional parameters in the sub-ion scale. We present several statistical properties of 3D HMHD turbulence and compare them with their counterparts in solar-wind turbulence. We compute (a) the wave-number dependence of spectra and the scale-dependent Alfven ratio on ion-cyclotron and whistler waves and (b) different measures of the intermittency and multiscaling. The power-laws in the energy spectra are under influences of the Alfven ratio, magnetic Prandtl number, and others. We present relationships between the power-laws and these parameters. Intermittency and multiscaling natures are typically characterized by probability distribution functions and structure functions of magnetic field and current density field. We present the intermittency and multiscaling natures not only by the analysis of magnetic and current density fields, but also by relating these quantities to ion-cyclotron modes and whistler modes.\nOur analysis can be related to space- and solar-plasma observations, some of which report relevant multi-fractal, multiscaling nature of turbulence. A comparison of such observatory reports with our simulation results with various settings highlights essences of multiscaling nature of turbulence.\n\nAuthor\nHideaki Miura (National Institute for Fusion Science)"},{"id":"5b3dcb83-b597-4c02-9b28-fd86d8dde7a5","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:20:00+00:00","end":"2026-07-01T10:45:00+00:00","s":"1120","e":"1145","name":"I.312 D. Kontziampasis: Engineering Surfaces for Sustainability and Health with Low Temperature Plasmas","loc":"Fintry: Level +3","track":"LTDP: Plasma processing and applications I","type":"Session","details":"Nature’s ingenuity is epitomised by nanometre‐scale architectures, as for example the lotus leaf’s self‐cleaning surface and the moth eye’s anti-reflective design. Following nature’s example, surfaces of materials can be manipulated and modified with plasmas to alter properties such as colour, wettability, reactivity, or to influence the interface and the interactions of surfaces with proteins, cells, bacteria, and viruses. My key area of interest is plasma bionanotechnology, where I aspire to control the behaviour of cellular and protein systems at their interfaces with plasma modified material surfaces. My work aims to influence the growth and development of living tissues and organs, contributing to advancements in areas such as artificial organ development, and regenerative medicine. In parallel, I am committed to driving sustainability in the broader context of materials science and engineering. This involves investigating and simplifying the mechanisms needed to facilitate the sustainable transition of manufacturing processes, laboratory practices, and advanced material preparation and characterisation methods. By addressing both the biological and engineering aspects of materials science, my work provides innovative solutions to global challenges, such as improving healthcare outcomes and reducing the environmental impact of industrial and scientific processes, necessary not only for future technological developments, but also the survival of our species.\n\nAuthor\nDr Dimitrios Kontziampasis (University of Leeds)"},{"id":"a822e04d-3d72-4343-8318-598332d223d5","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:20:00+00:00","end":"2026-07-01T10:45:00+00:00","s":"1120","e":"1145","name":"I.307 P. Cano-Megias: Investigation of multi-ion heat transport using new edge main ion measurements at the ASDEX Upgrade tokamak","loc":"Sidlaw: Level +3","track":"MCF/LTDP: Diagnostics","type":"Session","details":"A high-resolution main ion charge exchange recombination spectroscopy system has been used to characterize the deuterium temperature at the edge of H-mode plasmas in the ASDEX Upgrade tokamak, enabling new advances in edge physics and heat transport studies [1]. Both main ion (TD) and impurity (Tz) temperatures have been measured, revealing temperature differences up to 80 eV, with TD>TZ. These findings, identified at the pedestal top in cases with higher ECRH power, challenge the conventional assumption of TD=TZ due to strong ion collisional coupling [2].\nTo interpret these observations, the flexibility of the ASTRA code [3] has been exploited, as it allows for independent implementation of the main ion and impurity heat transport equations. Power balance analysis has been carried out to characterize the experimental deuterium and impurity heat conductivities, revealing a significantly higher χz/χD ratio when TD>TZ.\nThe properties of χz/χD have been explored using gyrofluid (TGLF) [4] and gyrokinetic (GKW) models [5], showing that χz/χD depends on the ion to the electron heat flux (Qi/Qe), in agreement with analytical theory [6]. The compatibility of the theoretical results with the experimental observations have been tested via predictive modeling with ASTRA. The predictive simulations successfully reproduce a temperature difference of 60 eV, consistent with experimental results, providing first-of-a-kind validation of multi-ion heat transport physics at the plasma edge [2].\n\n[1] P. Cano-Megias et al 2019 J. Instrum. 14 C10040\n[2] P. Cano-Megias et al 2025 Nucl. Fusion 65 096027\n[3] G.V. Pereverzev and P.N. Yushmanov 2002. Automated system for transport analysis. Technical Report (Max-Planck-Institut für Plasmaphysik)\n[4] G. Staebler et al 2024 Nucl. Fusion 64 103001\n[5] A.G. Peeters et al 2009 Comput. Phys. Commun. 180 2650–72\n[6] C. Angioni, 2015 Phys. Plasmas 22, 102501\n\nAuthor\nPilar Cano Megias (Universidad de Sevilla)\n\nCo-authors\nASDEX Upgrade Team\nAnton Jansen van Vuuren\nBenedikt Zimmermann\nClemente Angioni\nDiego José Cruz-Zabala\nEUROfusion WPTE Team\nProf. Eleonora Viezzer\nEmiliano Fable\nJulia Perez-Gonzalez\nMarco Cavedon (Department of Physics ‘G. Occhialini’, University of Milano-Bicocca, Milan, Italy)\nPierre Manas\nDr Rachael McDermott (Max Planck Institute for Plasma Physics)\nRalph Dux\nRoxana Takacs (Max Planck Institute for Plasma Physics)"},{"id":"2ce06eba-10eb-4c39-949a-1d984aa3d6ea","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:20:00+00:00","end":"2026-07-01T10:45:00+00:00","s":"1120","e":"1145","name":"I.304 M. Becoulet: Global gyro-kinetic Ion Temperature Gradient and Trapped Electron Mode turbulence modelling in X-point geometry in negative and positive triangularity","loc":"","track":"MCF: Gyrokinetic and pedestal","type":"Session","details":"Tokamak plasmas with sufficiently strong negative triangularity (NT), in contrast to the conventional positive triangularity (PT) shaping, have been shown to suppress the transition to H-mode while still achieving high confinement regimes comparable to H-mode plasmas, but without harmful for plasma facing components (PFC) Edge Localized Modes (ELMs). Comparative modelling of Ion Temperature Gradient and Trapped Electron Modes (ITG/TEM) turbulence in NT and PT plasma shapes was performed using the nonlinear global gyrokinetic electrostatic particle code JOREK-GK in realistic X-point tokamak geometry including the Scrape Off Layer (SOL) for TCV, DIII-D and WEST tokamaks parameters. The numerical scans of upper (up and lower (low) triangularities at the same plasma profiles demonstrated the existence of the averaged negative triangularity threshold 0.5(uplow) < avth , showcasing the beneficial stabilizing effect of NT compared to PT on ITG/TEM turbulence. For the WEST parameters tested here the threshold was about avth < -0.25. Existence of longer correlation length of density fluctuations in PT compared to NT was demonstrated similar to experimental measurements on DIII-D. Stronger and more sheared zonal flows are generated in NT compared to PT. These factors are stabilizing for TEM/ITG turbulence and lead to smaller heat fluxes and heat conductivities in NT compared to PT plasmas. Bohm-like confinement scaling with normalized ion gyro-radius * was obtained both in NT and PT, however with better confinement for NT compared to PT which could be a favorable factor for future reactor size machines operation in negative triangularity without triggering ELMs.\n\nAuthor\nMarina Becoulet (CEA/IRFM)\n\nCo-authors\nDr Alessandro Balistri (7EPFL-SPC, CH-1015 Lausanne, Switzerland)\nDr Alessandro Marinoni (Jacobs School of Engineering, University of California San Diego, USA)\nDr Colin Chrystal (General Atomics, San Diego, USA)\nDr Guido Huijsmans (CEA/IRFM)\nDr Guilhem Dif-Pradalier (CEA/IRFM)\nLothar Schmitz (3University of California-Los Angeles)\nDr M J Pueschel (Eindhoven University of Technology, 5600 MB Eindhoven, Netherlands)\nDr Olivier Sauter (EPFL-SPC, CH-1015 Lausanne, Switzerland)\nDr Patrick Maget (CEA/IRFM)\nDr Peter Donnel (CEA/IRFM)\nDr Philipp Ulbl (Max Planck Institute for Plasma Physics, Germany)\nDr Stefano Coda (EPFL-SPC, Lausanne, Switzerland)\nDr Xavier Garbet (CEA/IRFM)\nDr Yanick Sarazin"},{"id":"fe4b5e0d-36a9-4075-9d7d-38ca1faf74cd","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:45:00+00:00","end":"2026-07-01T11:10:00+00:00","s":"1145","e":"1210","name":"I.316   M.  Cipriani: High-power laser interaction with micro-structured materials: experiments and simulations","loc":"Tinto: Level 0","track":"BPIF: High power laser-plasma interaction","type":"Session","details":"In the context of Inertial Confinement Fusion (ICF), micro-structured low-density materials, or foams, have been shown to be able to reduce the effects of hydrodynamic instabilities, while increasing the laser absorption efficiency and enhancing the pressure at the shock front. 3D-printing represents the new manufacturing method for controlling the morphology, gradients in density and pore size, and sample shapes, opening the way to realizing wetted foams.\nIn this work, the results of experiments in which different kinds of micro-structured materials have been irradiated at the ENEA-ABC laser facility at high intensity of 10\n W/cm\n will be discussed. The irradiated samples included chemical, 3D-printed and innovative micro-structured materials. The results of 3D simulations for 3D-printed foams obtained with the FLASH code will be discussed.\n\nReferences\nM. Cipriani, et al., PoP, 25(9), 092704 (2018)\nM. Cipriani, et al., HPLSE, 9, e40 (2021).\nM. Cipriani et al., MRE, 11, 027401 (2026).\n\nAuthor\nMattia Cipriani (ENEA - Research Center Frascati)"},{"id":"cc7212af-3b97-42ce-b1af-29a5225100b1","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:45:00+00:00","end":"2026-07-01T11:10:00+00:00","s":"1145","e":"1210","name":"I.310   M.  Linkmann: The physics of the energy cascade in magnetohydrodynamic turbulence","loc":"Moorfoot: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (II)","type":"Session","details":"In turbulent plasma flows, magnetic field and flow fluctuations interact, resulting in complex multi-scale energy transfer and conversion processes. Here, I discuss an analytical method to decompose the energy flux across scales in magnetohydrodynamic (MHD) turbulence into terms that are physically interpretable and measurable from numerical and observational data. Applying this method to data from three-dimensional direct numerical simulations, we identify the physical MHD processes that drive the energy cascade, akin to vortex stretching and strain amplification in hydrodynamic turbulence. Independent of the level of anisotropy, magnetic energy is transferred from large to small scales mainly by current-sheet thinning, a process where current sheets are stretched by large-scale straining motion into regions of magnetic shear at smaller scales – a process with a natural relation to magnetic reconnection. Contributions from current-filament stretching – the analogue to vortex stretching – is negligible. The small-scale magnetic shear generated by current-sheet thinning in turn drives extensional flows at smaller scales, while hydrodynamic processes such as vortex stretching and strain self-amplification are strongly depleted. Hence, magnetic and kinetic energy are transferred from large to small scales almost exclusively by magnetic effects, connected with the generation of regions of small-scale intense strain induced by the Lorentz force. These results become exact in the limit of very strong background magnetic fields. In consequence, we show that all relevant physics driving the energy cascade are present in reduced MHD, as processes that enter at higher order are negligible, irrespective of the plasma beta. I discuss applications of the method to helicity fluxes and Hall physics and present an exact mathematical analogy between the Hall flux and the kinetic helicity flux, and show in the strong-field limit that magnetic energy transfer due to Hall physics is given by current-sheet thinning, now due shear currents, again a process with a natural relation to magnetic reconnection. Implications of these results for subgrid-scale modelling of magnetohydrodynamic turbulence are discussed.\n\nAuthor\nDr Moritz Linkmann (School of Mathematics, University of Edinburgh)"},{"id":"1626245b-705d-491e-b1e4-7e7b39e42a0b","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:45:00+00:00","end":"2026-07-01T11:10:00+00:00","s":"1145","e":"1210","name":"I.313 J. Trieschmann: From data-integrated physical simulation to machine learning analysis of plasma processing of resistive switching devices","loc":"","track":"LTDP: Plasma processing and applications I","type":"Session","details":"The field of machine learning (ML) in plasma science has experienced an immense development in the past decade [1], advancing low-temperature plasma modeling and simulation, as well as experiments and diagnostics [2,3]. Part of this development relates to plasma processing, enabling fine control over tailored material properties at the nanoscale. In this study, plasma processing of SiO\n/Cu resistive switching devices [4] is investigated for reactive radio-frequency magnetron sputter deposition with Ar/O\n through ML surrogate modeling, data-integrated physical simulations, and a data-driven classification of corresponding wafer-level measurements. Initially, Tridyn simulations [5] of the reactive plasma-surface interaction (PSI) during Ar and O\n ion impingement on SiO\n are conducted to establish an extensive data set. This is leveraged to devise a ML PSI surrogate model. The latter is subsequently utilized in an axially symmetric 2D particle-in-cell/Monte Carlo collision simulation with dynamical chemical surface coverage for the comprehensive prediction of discharge and surface conditions during reactive sputter deposition. Insights from this simulation study are correlated with a data-driven classification of measured electrical device characteristics. Specifically, a statistical analysis at the wafer-level is applied to over 50,000 devices to identify how processing conditions relate to device characteristics. The analysis reveals distinct device types attributed to the local process conditions during deposition, highlighting the importance of plasma process control in determining functional outcomes in nanoscale electronic devices.\n\n[1] R. Anirudh et al., 2022 Review of Data-Driven Plasma Science, IEEE Transactions on Plasma Science 51, 1750 (2023)\n[2] J. Trieschmann et al., Review: Machine learning for advancing low-temperature plasma modeling and simulation, Journal of Micro/Nanopatterning, Materials, and Metrology 22, 041504 (2023)\n[3] M. He et al., Data-driven plasma science: A new perspective on modeling, diagnostics, and applications through machine learning, Plasma Processes and Polymers 21, 2400020 (2024)\n[4] R. Lamprecht et al., Thickness-Related Analog Switching in SiO/Cu/SiO Memristive Devices for Neuromorphic Applications, Advanced Engineering Materials 27, 2401824 (2025)\n[5] W. Möller and W. Eckstein, Tridyn - A TRIM simulation code including dynamic composition changes, Nuclear Instruments and Methods in Physics Research Section B: Beam Interactions with Materials and Atoms 2, 814 (1984)\n\nAuthor\nJan Trieschmann (Kiel University)\n\nCo-authors\nRouven Lamprecht (Kiel University)\nTobias Gergs (Kiel University)\nSahitya Yarragolla (Kiel University)\nOle Gronenberg (Kiel University)\nLorenz Kienle (Kiel University)\nHermann Kohlstedt (Kiel University)"},{"id":"b8456fdd-7a79-4f06-9464-0cee051e4b90","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:45:00+00:00","end":"2026-07-01T11:00:00+00:00","s":"1145","e":"1200","name":"O.304 R. Florido: Spectroscopic characterization of hydrogen pellet ablation clouds at LHD: analysis of Balmer emission including opacity effects","loc":"Sidlaw: Level +3","track":"MCF/LTDP: Diagnostics","type":"Session","details":"The use of solid hydrogen pellets in magnetically confined fusion plasmas has been proposed both as a promising fueling technique and as a tool to investigate the effect of impurities on plasma dynamics. Pellets are typically injected at high speed, depositing fuel in the denser inner plasma regions, where the evaporation rate is higher. In this work, we present a spectroscopic model for the characterization of the resulting ablation cloud by analyzing the Balmer emission in the 300–700 nm wavelength range. Atomic level populations were calculated assuming local thermodynamic equilibrium. An extensive dataset of line shapes for transitions up to n = 9 → 2 was computed using state-of-the-art Stark-broadening simulations. The spectral intensity was obtained by solving the radiation transport equation for a spherical plasma source under uniform conditions. Instrumental broadening was accounted for by convolving the synthetic spectra with a Gaussian function of appropriate width. The model successfully reproduces measured pellet ablation cloud spectra at the Large Helical Device across the entire Balmer region, including both the optically thick Balmer α line and the emission beyond the ionization limit. The inclusion of opacity effects enables an independent estimate of the pellet core radius during the vaporization process. Additionally, it is shown that the use of the Inglis–Teller approach, together with detailed Stark-broadened line profiles, successfully describes line merging and continuum lowering phenomena, whereas other models, such as the widely used Stewart–Pyatt formulation, fail to reproduce the experimental observations.\n\nAuthors\nMr Aridai Bordón (Universidad de Las Palmas de Gran Canaria)\nMotoshi Goto (National Institute for Fusion Science, National Institutes of Natural Science, Toki, Japan. The Graduate University of Advanced Studies, SOKENDAI, Toki, Japan)\nDr Gabriel Pérez-Callejo (Universidad de Valladolid)\nDr Marco Antonio Gigosos (Universidad de Valladolid)\nRicardo Florido (Universidad de Las Palmas de Gran Canaria)"},{"id":"ac454acb-00c1-4ef3-b225-838c3fc4e7cb","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T10:45:00+00:00","end":"2026-07-01T11:10:00+00:00","s":"1145","e":"1210","name":"I.305 B. Frei: Unravelling the nature of H-mode access at ASDEX Upgrade using gyrokinetic simulations","loc":"Pentland Suite: Level +3","track":"MCF: Gyrokinetic and pedestal","type":"Session","details":"The physical mechanism behind the difference in the H-mode power threshold between favourable and unfavourable drift configurations is still not fully understood and remains an active field of research in view of ITER operation. Experimental evidence indicates that the radial electric field (Er) shear facilitates H-mode access in the favourable configuration, while it is weaker in the unfavourable case [1]. However, the role of turbulence in the self-consistent interplay between transport, equilibrium profiles, and Er has not yet been clarified.\nHere, we leverage the recent computational boost in the full-f gyrokinetic code GENE-X [2–4] to perform first-of-their-kind edge and scrape-off layer (SOL) turbulence simulations with X-points of a matched pair of L-mode ASDEX Upgrade discharges in favourable and unfavourable drift configurations [1]. The simulations are validated against experimental measurements and show excellent agreement. In particular, the experimental Er profiles are reproduced, and the simulations demonstrate that poloidal flows provide the dominant contribution to the radial force balance. Most importantly, while these simulated flows remain close to the neoclassical level in the unfavourable configuration, they significantly exceed neoclassical predictions in the favourable case, producing the experimentally observed stronger Er shear. We identify turbulence-driven poloidal flows [5], arising from enhanced nonlinear turbulence–mean-flow energy transfer driven by the radial gradient of the total velocity stress (a full-f generalization of the Reynolds stress [6]), as the key mechanism underlying the observed difference in Er between favourable and unfavourable configurations. This nonlinear energy transfer is much weaker in the unfavourable configuration, yielding a shallower Er well. Edge turbulence and geodesic acoustic mode activity are also found to be weaker in the favourable configuration. The universality of these findings is demonstrated by extending the present analysis to the TCV tokamak. Within the turbulence–flow shear suppression paradigm, the deeper Er well and reduced turbulence intensity in the favourable configuration may underlie the observed configuration dependence of the H-mode power threshold. Extensions toward H-mode are presented by attempting a sudden increase in the input power [7].\nReferences\n\n[1] U. Plank et al., Phys. Plasmas 30, 042513 (2023)\n[2] D. Michels et al., Comput. Phys. Comm. 264, 107986 (2021)\n[3] B. J. Frei et al., Comput. Phys. Comm. 316, 109817 (2025)\n[4] B. J. Frei et al., Nucl. Fusion 65, 116026 (2025)\n[5] B. J. Frei et al., Submitted to Phys. Rev. Lett. (2026)\n[6] O. Grover et al., Nucl. Fusion 64, 056020 (2024)\n[7] W. Zholobenko et al., Phys. Rev. Lett. (2026)\n\n*Correspondence email: baptiste.frei@ipp.mpg.de\n\nAuthor\nBaptiste Frei (Max Planck Institute for Plasma Physics)\n\nCo-authors\nBenoît Labit (Ecole Polytechnique Fédérale de Lausanne (EPFL) - SPC)\nFrank Jenko (Max Planck Institute for Plasma Physics, Garching)\nLaure Vermare (Laboratoire de Physique des Plasmas (LPP), CNRS)\nDr Ondrej Grover (Max Planck Institute for Plasma Physics, Germany)\nPascale Hennequin (Laboratoire de Physique des Plasmas (LPP), CNRS)\nPhilipp Ulbl (Max Planck Institute for Plasma Physics, Germany)\nDr Roberto Bilato (Max Planck Institute for Plasma Physics, Germany)\nMr Sascha Rienaecker (Laboratoire de Physique des Plasmas (LPP), CNRS)\nDr Wladimir Zholobenko (Max Planck Institute for Plasma Physics)"},{"id":"ddd089fd-ac24-45a3-8f39-c01f107bfc41","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:00:00+00:00","end":"2026-07-01T11:15:00+00:00","s":"1200","e":"1215","name":"O.305 M. Carrard: First demonstration of X-mode reflectometry as a sensor for density and plasma position control on the WEST tokamak","loc":"Sidlaw: Level +3","track":"MCF/LTDP: Diagnostics","type":"Session","details":"This work presents the first use of real-time (RT) sensors provided by the eXtraordinary mode (X-mode) reflectometry for density and plasma position control. Density control using Ordinary (O-mode) reflectometry as a sensor was demonstrated in Asdex-Upgrade in 2010 [1], but requires an assumption on the density profile position. On the contrary, the X-mode reflectometry enables to detect the plasma edge radial position, which is used to start the density profile reconstruction and was planned on ITER [2].\n\nA new acquisition system and a new algorithm dedicated to RT measurements were implemented on the WEST X-mode edge reflectometer. The world first electron density profiles were reconstructed in real-time during 2024, providing profiles every few ms [3].\n\nReal-time density profiles can provide several sensors for plasma control. The first sensor is the local density at a fixed radial position. The second sensor is the edge plasma position deduced from the major radius of a fixed density. Thirdly, the plasma position knowledge allows to compute the density at given distance to the plasma edge, roughly the density at a fixed flux surface.\n\nThe first control experiments using X-mode reflectometry sensors have been performed on WEST in 2025. Density control is usually achieved using the interferometry line integrated density (every ms), the actuator is the gas injection. First, we replaced the line integrated sensor with the density at a fixed radial position, to perform control of the local edge density. Secondly, we replaced the density sensor by the density at a given relative position, allowing to control the local edge density during a plasma radial translation. These two control experiments were successful, without any specific issue. Lastly, we replaced the magnetic sensor used to control the plasma position by the radial position obtained from RT reflectometry. The actuators are the PF coils. The first experiments showed radial position oscillations due to a latency of about 30 𝑚𝑠 on the measurements, specific to reflectometry plasma position control. We improved all the RT data processing to shorten this latency to a few milliseconds, and the new plasma position control experiments were performed successfully without any radial oscillations.\n\nAuthors\nMr Christian Jammes (CEA)\nMr Christophe Bouchand (CEA)\nMr Frédéric Clairet (CEA)\nMaylis Carrard (CEA)\nMr Rémy Nouailletas (CEA)\nMr Roland Sabot (CEA)\nMr Yassir Moudden (CEA)\nMrs Christine Bottereau (CEA)"},{"id":"c07f6d88-f0e5-4d1d-a06f-7f0b7ce9d0d2","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:10:00+00:00","end":"2026-07-01T11:35:00+00:00","s":"1210","e":"1235","name":"I.317   E.  Oliva Gonzalo: 3D multiscale modelling of the interaction of structured light with inhomogeneous plasmas: applications to plasma diagnosis","loc":"Tinto: Level 0","track":"BPIF: High power laser-plasma interaction","type":"Session","details":"The use of structured light is opening exciting paths in several fields, taking advantage of the different geometrical and topological structures of these beams. This work presents recent results on the interaction of structured IR, UV, and XUV beams with plasmas. Experimental and modelling results unveil its potential applications in plasma diagnosis, in the fields of Inertial Confinement Fusion (ICF), plasma-based lasers and Laboratory Astrophysics. Using our multiscale, multiphysics computational framework [1] it is possible to model the full process undergone by the system: plasma creation and hydrodynamic expansion; collisional and radiative processes; and the propagation and interaction of UV/XUV beams.\n\nThe presentation will focus in recent modelling and experimental results on the interaction of structured light with plasmas: the use of spatio-temporal couplings to create a flying focus and improve the amplification of High Order Harmonics (HOH) in dense plasmas [2] and boost the UV emission of nitrogen filaments; the emission and amplification of structured UV light by cavity-free nitrogen plasmas, with applications in atmospheric air lasing; and the application of HOH beams carrying OAM towards diagnosing hot, dense plasmas [3,4,5], by measuring the perturbation of the wavefront after propagation through the plasma and relating this perturbation to the electron density and its gradient.\n\n[1] E. Oliva, et al, The European Physical Journal D, 75, 11 (2021)\n[2] A. Kabacinski, et al, Nat. Phot. 17, 345-359 (2023)\n[3] F. Tuitje, et al, Light: Sci Appl, 9, 1 (2020)\n[4] S. López, et al, Opt. Exp., 31, 5, 8465-8478 (2023)\n[5] S. López, et al, Opt. Exp., 33, 22, 46285-46303 (2025)\n\nAuthors\nEduardo Oliva Gonzalo (Universidad Politécnica de Madrid)\nMr Ismael Torres (Universidad Politécnica de Madrid)\nMr Marcos García Barriopedro (Universidad Politécnica de Madrid)\nMr Santiago López (Universidad Politécnica de Madrid)"},{"id":"c0012bd4-a846-4435-809f-db494a93aa80","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:10:00+00:00","end":"2026-07-01T11:35:00+00:00","s":"1210","e":"1235","name":"I.311   L.  Franci: Modelling the particle dynamics in turbulent plasmas using the innovative multi-scale Box-In-Box (BIB) approach","loc":"Moorfoot: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (II)","type":"Session","details":"The particle dynamics in plasmas has a highly multi-scale nature in terms of spatial scales, temporal scales, and energy range. In the solar wind, it spans about eight orders of magnitude in length (from fractions of the electron gyroradius to the Sun-Earth distance) and about five in energy. These ranges are way more extreme in astrophysical systems. Tackling the particle dynamics is thus a very challenging task, especially when the background plasma is highly turbulent.\n\nWe have developed an innovative approach, the multi-scale Box-in-Box (BIB), to model particle energisation in turbulent plasmas over a massive range of scales. First, we model the turbulent energy cascade from very large to very small scales coupling different models (MHD, hybrid, and fully kinetic), using a portion of a large simulation as initial condition for one with higher resolution multiple times in sequence. Then, we advance the trajectories of hundreds of millions of test particles on the evolving turbulent background from small to large scales while their gyroradius (and energy) increases. Our BIB approach allows for modelling the large-scale propagation of energetic particles in turbulent plasmas while retaining a realistic and self-consistent description of the microphysics responsible for particle energization. BIB simulations are key tools for developing new visualisation and analysis techniques for future multi-scale space missions such as NASA HelioSwarm and ESA Plasma Observatory.\n\nAuthor\nDr Luca Franci (Northumbria University)\n\nCo-author\nDr Emanuele Papini (National Institute for Astrophysics INAF,Institute for Space Astrophysics and Planetology IAPS, Northumbria University)"},{"id":"6f7d3874-4e72-4217-9a72-8ad666273515","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:10:00+00:00","end":"2026-07-01T11:35:00+00:00","s":"1210","e":"1235","name":"I.314 J. Muñoz Espadero: From fundamental plasma characterization to technological optimization: Maximizing graphene production in a microwave plasma torch","loc":"Fintry: Level +3","track":"LTDP: Plasma processing and applications I","type":"Session","details":"The global demand for high-quality graphene continues to drive the search for sustainable, scalable, and cost-effective synthesis methods. Among the most promising emerging technologies, microwave-induced plasmas generated by the TIAGO torch (Torche à Injection Axiale sur Guide d’Ondes) offer a streamlined, catalyst-free, and environmentally friendly approach to producing few-layered graphene nanosheets through ethanol decomposition at atmospheric pressure. While this technology represents a significant leap forward in green nanomaterial manufacturing, unlocking its full industrial potential requires a deeper understanding of the fundamental physics governing its energy transport mechanisms.\n\nUsing optical emission spectroscopy techniques, the fundamental characteristics of the TIAGO torch have been investigated, revealing that it behaves as a surface wave discharge (SWD), where electromagnetic wave sustaining it propagates along the plasma-dielectric (air) interface. More importantly, a distinct \"radiation zone\" located near the nozzle exit has been identified for the first time at atmospheric pressure, highlighting a critical inefficiency: nearly 43% of the input microwave energy can be dissipated as non-guided radiation. This fundamental insight serves as the cornerstone for technological optimization of graphene synthesis.\n\nBy implementing a custom-designed metallic electromagnetic shielding around the reaction chamber it is possible to suppress these radiation losses. This strategic modification results in a significant volumetric expansion of the plasma and a more efficient decomposition of carbon precursors. Quantitative analysis demonstrates a remarkable 22.8% increase in graphene production alongside a 21% improvement in overall energy yield.\n\nCritically, this boost in productivity does not come at the expense of material integrity. Extensive multi-technique characterization, including Raman spectroscopy, X-ray photoelectron spectroscopy (XPS), and High-Resolution Transmission Electron Microscopy (HRTEM), confirms that the synthesized powder maintains its high-quality, few-layered structure with low defect density and high sp2 hybridization. Ultimately, the bridge between fundamental plasma diagnostics and industrial optimization proves that understanding basic energy loss mechanisms is the key to achieving the energy efficiency and scalability required for the next generation of sustainable nanostructure manufacturing.\n\nAcknowledgements: This work was supported by project PID2023-147436OA-I00 funded by MICIU/AEI /10.13039/501100011033 and by FEDER, UE. The predoctoral contract of F.J. Morales-Calero was granted by MOD-2.2 from Plan Propio de la Universidad de Córdoba (2020).\n\nAuthors\nProf. José Muñoz Espadero (Laboratory of Innovation in Plasmas (LIPs), Universidad de Córdoba (Spain))\nProf. Francisco Javier Morales Calero (Laboratory of Innovation in Plasmas (LIPs), Universidad de Córdoba (Spain))\nMr Antonio Cobos Luque (Laboratory of Innovation in Plasmas (LIPs), Universidad de Córdoba (Spain))\nProf. Andrés María Raya Bejarano (Laboratory of Innovation in Plasmas (LIPs), Universidad de Córdoba (Spain))\nProf. Norma Yadira Mendoza González (Laboratory of Innovation in Plasmas (LIPs), Universidad de Córdoba (Spain))\nProf. Jorge Alberto Alcusón Belloso (Laboratory of Innovation in Plasmas (LIPs), Universidad de Córdoba (Spain))\nProf. María Dolores Calzada Canalejo (Laboratory of Innovation in Plasmas (LIPs), Universidad de Córdoba (Spain))\nProf. Rocío Rincón Liévana (Laboratory of Innovation in Plasmas (LIPs), Universidad de Córdoba (Spain))"},{"id":"59a2c367-92ca-4fbf-b56c-00536bbf65c6","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:10:00+00:00","end":"2026-07-01T11:35:00+00:00","s":"1210","e":"1235","name":"I.306 C. Silva: Spatio-temporal evolution of the edge flows and turbulence across the L-H transition on JET","loc":"Pentland Suite: Level +3","track":"MCF: Gyrokinetic and pedestal","type":"Session","details":"A validated, physics-based model of the L–H transition threshold is essential for estimating heating requirements in future burning-plasma experiments. However, no consensus has yet been reached on the mechanisms that trigger the transition, particularly regarding the generation of the initial flow shear believed to be required for turbulence suppression.\nThe aim of this work is to improve understanding of turbulence reduction at the L–H transition. The JET correlation reflectometer allows determination of the perpendicular velocity, \n, and density fluctuation level, \n, slightly above the outer midplane, from the SOL to inside the pedestal top. L–H transitions were induced at JET using NBI or ICRH in plasmas with different main ion masses and divertor configurations. Earlier studies found no universal edge flow shear across the JET dataset, suggesting that H-mode access is not solely set by the \n profile [C. Silva NF 2021]. No significant variation in \n was detected during the heating ramp, though fast dynamics (<10 ms) near the transition were not explored at that time.\nNew high-temporal-resolution results, obtained in both single-step and long-dithering L–H transitions, indicate that \n and \n are strongly intermittent, yet show no clear trend in the milliseconds preceding the transition. A robust feature of the L–H transition is the sharp reduction of turbulence on a timescale shorter than 50 μs, localized from the separatrix to the pedestal top. Simultaneously, the density profile steepens, though in a narrower radial region. No clear changes in the edge flow shear are observed before the L–H transition, nor immediately afterward, when turbulence suppression begins. These results highlight current limitations while also defining a path forward, namely the need to characterize turbulence in order to enable validation of physics-based models of the L–H transition.\n\nAuthor\nCarlos Silva (IST/IPFN)\n\nCo-authors\nDr Carine Giroud (UKAEA)\nE Delabie\nDr Emilia R. Solano (Laboratorio Nacional de Fusión, CIEMAT, Spain)\nLuís Gil\nMr Mário Vaz (IST/IPFN)\nDr Nicola Vianello\nDr Rennan Morales (UKAEA)"},{"id":"3e4e20e4-57b0-4957-9cd2-b0568a53c773","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:15:00+00:00","end":"2026-07-01T11:30:00+00:00","s":"1215","e":"1230","name":"O.306 M. Schroeder: Characterization of a high-repetition-rate laser filament-induced plasma in air using optical emission spectroscopy","loc":"Sidlaw: Level +3","track":"MCF/LTDP: Diagnostics","type":"Session","details":"When ultrafast laser pulses with sufficient peak power propagate through transparent media, laser filamentation arises from the dynamic interplay between self-focusing and photoionization-induced plasma defocusing. The plasma can be described as an initial primary photoionization-driven plasma and a secondary plasma, governed solely by plasma kinetics. As modern laser systems reach higher repetition rates, interpulse times approach plasma-kinetic timescales, and accumulation effects may arise [1]. As such, simulation and characterization of plasma-chemical kinetics in laser-induced filamentation are becoming increasingly important to account for the plasma’s molecular composition and its influence on optical properties.\nIn this work, we investigate how accumulation effects at elevated repetition rates affect photochemical reactions and alter the molecular composition of filament-induced plasmas. We measure the time-dependent plasma dynamics and key parameters—including gas temperature, electron temperature, electron density, and species-specific decay times—for filaments generated at a repetition rate of 10 kHz.\nThe experimental setup employs a Yb-based thin-disk regenerative amplifier (DIRA 500-10, TRUMPF Scientific Lasers) delivering sub-picosecond pulses at a central wavelength of 1030 nm and pulse energies of 2.5 mJ, 5 mJ, and 10 mJ. The pulses are tightly focused to promote filamentation and plasma ignition. Plasma characterization is performed using optical emission spectroscopy with an echelle spectrometer coupled to an intensified charge-coupled device (ICCD) camera, providing a resolution of 500 ps.\nAnalysis of the vibrational distributions and temporal evolution of molecular nitrogen emission bands enables identification of the excitation mechanisms responsible for nitrogen photoemission [2]. Electron density, electron temperature, and gas temperature are quantitatively determined from emission spectra and optical filament images within a collisional-radiative modeling framework, which was adapted from the diagnosis of electrically driven plasmas [2].\nThis diagnostic approach complements conventional optical probing techniques commonly used in filamentation studies [3], offering a comprehensive characterization of the plasma wake from a single measurement. It provides insight into changes in optical properties caused by the formation and extinction of molecular species. To our knowledge, this represents the first study of laser-filament-driven plasma at a 10 kHz repetition rate, where plasma wake characterization becomes particularly important due to reduced interpulse times and potential accumulation effects.\nReferences\n[1] T.-J. Wang, M. H. Ebrahim, I. Afxenti, D. Adamou, A. C. Dada, R. Li, Y. Leng, J.-C. Diels, D. Faccio, A. Couairon, C. Milián, and M. Clerici, \"Cumulative Effects in 100 kHz Repetition‐Rate Laser‐Induced Plasma Filaments in Air,\" Adv. Photonics Res. 4, 2200338 (2023).\n[2] S. Gröger, M. Fiebrandt, M. Hamme, N. Bibinov, and P. Awakowicz, \"Characterization of a transient spark micro-discharge in nitrogen using simultaneous two-wavelength diagnostics,\" Meas. Sci. Technol. 31, 075501 (2020).\n[3] Y.-H. Chen, S. Varma, T. M. Antonsen, and H. M. Milchberg, \"Direct Measurement of the Electron Density of Extended Femtosecond Laser Pulse-Induced Filaments,\" Phys. Rev. Lett. 105, 215005 (2010).\n\nAuthor\nDr Malte Schroeder (Photonics and Ultrafast Laser Science)\n\nCo-authors\nMr Robin Löscher (Photonics and Ultrafast Laser Science)\nDr Nikita Bibinov (Applied Electrodynamics and Plasma Technology)\nDr Ihor Korolov (Applied Electrodynamics and Plasma Technology)\nProf. Peter Awakowicz (Applied Electrodynamics and Plasma Technology)\nProf. Thomas Mussenbrock (Applied Electrodynamics and Plasma Technology)\nProf. Clara Saraceno (Photonics and Ultrafast Laser Science)"},{"id":"261c70b5-901d-440d-9d77-385e040b05c1","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:30:00+00:00","end":"2026-07-01T11:45:00+00:00","s":"1230","e":"1245","name":"O.307 T. Donders: Microwave Cavity Resonance Spectroscopy as a diagnostic technique for plasmas and electron beams","loc":"Sidlaw: Level +3","track":"MCF/LTDP: Diagnostics","type":"Session","details":"One of the main defining characteristics of a plasma is the electron density. Conventional electron density diagnostic techniques, such as Langmuir probes or Thomson scattering are generally relatively invasive. As an alternative, Microwave Cavity Resonance Spectroscopy (MCRS) can be used as a minimally invasive diagnostic technique for the electron density. MCRS relies on measuring the eigenfrequency of a cylindrical cavity using microwaves. As the permittivity of the medium inside the cavity changes, the eigenfrequency of the cavity shifts.\n\nThis work will give an overview of the working principles of MCRS, and highlights three of its key capabilities across various applications. First, its high temporal resolution is demonstrated through measurements on pulsed plasmas. Second, a method for obtaining qualitative spatial information is shown using nanodusty plasma experiments and FEM simulations. Finally, the high sensitivity of MCRS is illustrated through the characterization of an electron beam.\n\nAuthor\nTim Donders (Eindhoven University of Technology)\n\nCo-authors\nJob Beckers (Eindhoven University of Technology)\nMr Rick Budé (Eindhoven University of Technology)\nRik Peelen (Eindhoven University of Technology)"},{"id":"5aaff618-d401-409b-bc0f-a65d9cef2daf","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:35:00+00:00","end":"2026-07-01T11:50:00+00:00","s":"1235","e":"1250","name":"O.313   Xu. Z: Propagation-based X-ray phase contrast imaging of laser-driven shocks in planar targets at the GSI PHELIX laser facility","loc":"Tinto: Level 0","track":"BPIF: High power laser-plasma interaction","type":"Session","details":"X-ray phase contrast imaging (XPCI) is a cutting-edge diagnostic technique based on the phase shift of x-ray photons induced by a density gradient. By enhancing contrast through refraction and diffraction at material interfaces and density gradients, XPCI is particularly well-suited for imaging laser-driven shock propagation inside targets. In this work, we advanced the platform originally developed by L. Antonelli et al [EPL 125, 35002 (2019)] at the GSI PHELIX laser facility. We have compared different X-ray sources and geometries to optimize the backlighter performance. Results demonstrate high-quality imaging of shock waves propagating through planar plastic and foam targets. We will also discuss the next step of extending this platform toward direct imaging of early-time, laser-imprinted perturbations.\n\nAuthor\nXu Zhao (University of York)\n\nCo-authors\nYuyao Wang (University Of York)\nBen Fisher (The university of York)\nEmma Hume (University of York)\nDalir Kosimov (The University of York)\nRyan Carlo Saputil (York Plasma Institute, University of York, Heslington, York YO10 5DQ, United Kingdom)\nMr Bruce Dias\nMr Jay Shadbolt\nDr Paul Neumayer\nDr Bernhard Zielbauer\nLuca Antonelli\nNigel Woolsey (University of York"},{"id":"c287617a-f913-4776-9689-12cadf3eff50","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:35:00+00:00","end":"2026-07-01T11:50:00+00:00","s":"1235","e":"1250","name":"O. 309   T.  Fredon: Hamiltonian simulation of spectrally truncated ideal fluids on quantum computers","loc":"Moorfoot: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (II)","type":"Session","details":"The ongoing development of quantum computers may pave the way for\nimprovements in the state of the art of fluid and plasma simulations. While the Hamiltonian nature of quantum mechanics makes quantum computers natural tools for simulating Hamiltonian dynamics, we propose an approach to fluid dynamics that explicitly exploits the underlying Hamiltonian structure of ideal fluids.\nMore precisely, we consider the simulation of spectrally truncated fluid equations, such as the inviscid Burgers’ equation and the multidimensional Euler equations. We embed the nonlinear fluid dynamics into a Liouville equation defined in a configuration space, describing the linear evolution of the probability density. This linear evolution can be efficiently implemented on a digital quantum computer, as it is both linear and unitary.\nThe proposed quantum algorithm relies on three main steps: (i) efficient and physically motivated state preparation, (ii) Hamiltonian-based time evolution, and (iii) recovery of the original fluid variables through measurement of the averaged position of the probability density.\nThese results open new perspectives for encoding and simulating fluid dynamics on quantum computers, and pave the way toward the quantum simulation of ideal magnetohydrodynamics.\n\nAuthor\nMr Thibault Fredon (Plasma Science and Fusion Center, MIT)\n\nCo-authors\nMr Martin Pujol (CERFACS)\nJulien Zylberman (CERFACS)\nMr Fabrice Debbasch (Sorbonne Université, LUX)"},{"id":"8107bee1-ce97-42f8-86d7-558c0de62a7d","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:35:00+00:00","end":"2026-07-01T11:50:00+00:00","s":"1235","e":"1250","name":"O.311 F. Greiner: Influence of a soft plasma wall on the millimeter sized low pressure argon plasmas","loc":"Fintry: Level +3","track":"LTDP: Plasma processing and applications I","type":"Session","details":"Electrodes and other solid boundaries are invariably separated from a plasma by a non-neutral transition region known as the plasma sheath. Depending on the discharge pressure and plasma parameters, the sheath has a minimum thickness on the order of the electron Debye length.The intrinsic properties of the wall material, including its electrical conductivity, surface roughness, and chemical composition, may affect the plasma facing the wall. Macroscopic gaps, pores, or cavities in the surface are effectively filled with plasma only if their characteristic size is comparable to or larger than the sheath thickness; otherwise, the sheath may span across these features, preventing l plasma infusion.\nTo investigate how aeroglass [1] affects low-pressure (10 - 1000 Pa) argon plasmas, we generated a plasma inside a central millimeter-wide hole in an aeroglass cylinder. The cylinder had a height of 8 mm and a diameter of 8 mm. As the bore radius decreases, the ratio of the interface area to the plasma volume increases, thereby enhancing the relative influence of surface-related processes. Under such conditions, any material-specific effects of the aeroglass on plasma density, electron temperature, or discharge stability should become more pronounced and experimentally accessible.\nPlasma diagnostic was performed using electrostatic double probes, enabling local measurements of plasma parameters without the need for an external reference electrode. At discharge pressures of < 700 Pa, we observed the emergence of a high-density plasma mode that was not present when conventional wall materials were used under otherwise identical conditions. This finding suggests that the aeroglass walls play an active role in the modification of the plasma wall interaction.\n\n[1] Lena M. Saure et al., ACS-Nano 2023, 17, 22, 22444*22455, DOI: 10.1021/acsnano.3c05329\n\nAuthor\nFranko Greiner (Kiel Unversity)\n\nCo-authors\nKarin Hansen (Institute of Experimental and Applied Physics, Kiel University, Germany)\nKerstin Sgonina (Institute of Experimental and Applied Physics, Kiel University, Germany)\nJulian Held (Plasma & Materials Processing Eindhoven University of Technology)\nJonas Lumma (Department of Materials Science, Kiel University, Germany)\nRainer Adelung (Department of Materials Science, Kiel University, Germany)"},{"id":"4f977df5-ffab-496e-b6e6-d71c89167ab5","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:35:00+00:00","end":"2026-07-01T11:50:00+00:00","s":"1235","e":"1250","name":"O.301 K. Zhang: Turbulence simulations of the Quasi-Continuous Exhaust regime","loc":"Pentland Suite: Level +3","track":"MCF: Gyrokinetic and pedestal","type":"Session","details":"The H-mode in tokamaks brings fusion performance within reach but faces two major challenges: damaging ELMs and excessive divertor heat loads. Recent results across tokamak experiments identified an ELM-free H-mode—the quasi-continuous exhaust (QCE) regime—combining high pedestal pressure, reactor-relevant separatrix density, and a broadened the scrape-off layer (SOL) heat width, making it promising for a fusion reactor [1]. A first-principles understanding of the turbulence dynamics in QCE plasmas has been elusive, given the complexities of nonlinear, separatrix-spanning electromagnetic modes and their interactions with large-amplitude, intermittent filaments in the SOL.\n\nWe address the challenge using two-fluid turbulence code GRILLIX [2,3]. We conduct global simulations of the QCE regime across the pedestal and SOL in realistic ASDEX Upgrade geometry. The results reveal a quasi-coherent mode (QCM) [4] spanning the separatrix and launching ballistic, filamentary blobs into the SOL, reproducing not only mean profiles but also fluctuation spectra and mode structure seen in experiments.\nWe identify QCM as a kinetic ballooning mode (KBM) with a long radial correlation length, which yields transport levels exceeding those of a KBM-unstable ELMy pedestal foot. The transport by QCM in the pedestal foot is regulated by two key ingredients: the self-consistent formation of a broad Er well, and the finite Larmor radius physics. The resistivity remains prominent near the X-point and triggers a secondary resistive X-point mode (RXM) [5]. The emergence of RXM strengthens interchange dynamics at the outermost extent of the QCM, thereby launching blobs into the SOL. The blob-dominated SOL temperature fall-off is then well decoupled from the pedestal-foot gradient set by the QCM. Together, these dynamics outline a pathway to self-sustained H-mode confinement with manageable heat exhaust.\n\n[1] M. Faitsch et al., Nucl. Fusion 63, 076013 (2023).\n[2] K. Zhang et al., Nucl. Fusion 64, 036016 (2024).\n[3] K. Zhang et al., Computer Physics Communications 314, 109670 (2025).\n[4] J. Kalis et al., Nucl. Fusion 64, 016038 (2024).\n[5] J. R. Myra et al., Phys. Plasmas 7, 4622 (2000).\n\nAuthors\nKaiyu Zhang (Max Planck Institute for Plasma Physics)\nDr Wladimir Zholobenko (Max Planck Institute for Plasma Physics)\nDr Andreas Stegmeir (Max Planck Institute for Plasma Physics)\nDr Michael Faitsch (Max Planck Institute for Plasma Physics)\nFrank Jenko (Max Planck Institute for Plasma Physics, Garching)"},{"id":"157525b2-8811-4594-bcb4-c9dd7e07abb1","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:45:00+00:00","end":"2026-07-01T12:00:00+00:00","s":"1245","e":"1300","name":"O.308 R. Barni: Surface Dielectric Barrier Discharge characterization based on mass spectrometry diagnostic techniques","loc":"Sidlaw: Level +3","track":"MCF/LTDP: Diagnostics","type":"Session","details":"Surface Dielectric Barrier Discharge characterization\nbased on mass spectrometry diagnostic techniques\nR. Barni, D. Pal, C. Riccardi\nDipartimento di Fisica G. Occhialini, Università degli Studi di Milano-Bicocca,\nPiazza della Scienza 3, I-20126 Milano, Italy\nNon-thermal plasmas in atmospheric air have been proposed as a tool aimed to various applications, including air purification, food packaging, textile finishing and new materials development, owing to its capacity to generate highly reactive species under ambient conditions. Surface Dielectric Barrier Discharges (SDBD) are particularly promising because the plasma state is almost two-dimensional and confined to region facing the dielectric surface, with only indirect interactions with the surrounding gas-phase or with the to be exposed surfaces aimed for functionalization. One key aspect is the generation of reactive oxygen and nitrogen species (RONS), which play a fundamental role in oxidative processes. The relative concentrations of these species determine the overall oxidative potential of the plasma and its effectiveness in biological and chemical applications. Therefore, the accurate identification and quantification of these species are essential for any optimization strategy to enhance the efficiency of the plasma. Mass spectroscopy could be used to gain insight into such gas-phase composition. Our mass-spectrometer (HPR60 by Hiden) in particular, with its ability to change the electron energy in an extended range (namely 4-150 eV), their intensity (about four decades between 0.2 to 2000 uA) and the electrical optics (so that it is able to collect native positive and negative ions from the discharge region), could aim to a a comprehensive characterization of plasma gas-phase. Here we presents the results of an experimental campaign aimed to this.\n[1] “Mass spectroscopy of oxygen plasmas with energetic ions”, R. Barni, M. Daghetta, C. Piferi, C. Riccardi, AIP Advances 13, 065207.1-5 (2023).\n\nAuthor\nRuggero Barni (Università degli Studi di Milano-Bicocca)\n\nCo-authors\nProf. Claudia riccardi (Università degli Studi di Milano-Bicocca)\nDr Dipak Pal (Università degli Studi di Milano-Bicocca"},{"id":"3a8081df-b8c2-4faa-b5f4-43bd5561e037","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:50:00+00:00","end":"2026-07-01T12:05:00+00:00","s":"1250","e":"1305","name":"O.314   J.  La Porte: On the conservation of orbital angular momentum in laser-plasma interactions","loc":"Tinto: Level 0","track":"BPIF: High power laser-plasma interaction","type":"Session","details":"On the conservation of orbital angular momentum in laser-plasma interactions\n Not scheduled\n 20m\n EICC, Edinburgh\nOral Presentation Laser and Particle Beam Interaction with Plasmas, Hydrodynamics and Instabilities (BPIF)\nThe contributions of this event have not been published yet. You can only access this page because you are an event manager.\nDescription\nOrbital angular momentum (OAM) transfer in laser-plasma interactions is a fundamental process far less understood than energy or linear momentum transfer. However, it has important direct applications, such as the production of strong magnetic fields.\n\nPrevious studies of angular momentum transfer in laser–plasma interactions have investigated both dissipative processes, as well as single electron motion in laser fields carrying OAM.\n\nIn this work, we present a novel ray-based approach of laser OAM transfer to plasmas. In this framework, refraction in plasmas with azimuthal density gradients enables non-dissipative transfer of OAM between the laser and plasma. These gradients can be pre-existing in the plasma, or self-generated by a spatiotemporally shaped laser pulse. This process is analogous to the mechanism behind orbital AM transfer in spiral phase plates. Our model provides a simple unified interpretation of OAM transfer in many laser-plasma interactions and can be used to explain previous results.\n\nUtilizing recent breakthroughs in spatio-temporal shaping of high power laser systems, we show that light springs - lasers carrying multiple OAM modes in multiple frequency bands, can indeed drive plasma waves with helical density gradients, and self couple into the plasma driving strong axial magnetic fields. Using SMILEI particle-in-cell simulations, we validate this model and show that light springs are efficient at transferring the AM to electrons, leading to the generation of strong longitudinal magnetic fields (a few 100s of Tesla) at moderate laser power (a few 100s of GW to a few TW).\n\nAuthors\nAndrew Longman (Lawrence Livermore National Laboratory)\nJeremy La Porte (Laboratoire pour l'utilisation des lasers intenses (LULI))\nCo-authors\nAnna Grassi (Laboratoire pour l’Utilisation des Lasers Intenses)\nCaterina Riconda (Laboratoire pour l’Utilisation des Lasers Intenses)\nEugene Kur (Lawrence Livermore National Laborator)"},{"id":"ebc76fe6-f4e3-4d39-b433-dbf4b2def0cb","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:50:00+00:00","end":"2026-07-01T12:15:00+00:00","s":"1250","e":"1315","name":"O.310   L. Horan: Reconstructing plasma density structure from shadowgraphic images of a pulsed-power-driven reconnection layer","loc":"Moorfoot: Level 0","track":"BSAP: Fundamental Plasma Physics Theory (II)","type":"Session","details":"We present updated results from magnetic reconnection experiments with both strong radiative cooling and the plasmoid instability [1,2]. These two plasma processes are intertwined with reconnection events across a wide range of astrophysical environments, including the interstellar medium, the solar chromosphere, and black hole accretion disks. The MARZ (Magnetic Reconnection on Z) experiments at Sandia National Laboratories investigate these key physics of astrophysically-relevant reconnection in the laboratory. The MARZ pulsed-power platform consists of two exploding aluminum wire arrays, through which a large current (20 MA, 300 ns rise time) is driven by the Z Machine, to generate a reconnection layer. In three separate MARZ experiments, the spacing between the two arrays was shifted; in changing the inflow parameters (velocity, density, field), we vary the reconnection layer formation and evolution. Using a laser imaging diagnostic, we take time-resolved measurements of the density structures in and near the layer. We gain a qualitative understanding of the features in these experimental images by comparison to synthetic shadowgrams produced from 3-D MHD simulations. These features include: a dense layer with temporally-increasing density gradients due to radiative collapse; standing MHD shocks outside the layer; and apparent nonuniformities along the axial direction consistent with instabilities. Quantitative measurements of these time-evolving density structures is challenging; our experimental shadowgraphic data exhibits large intensity variations, caustics, and noise. As-such, we have adopted a forward model approach: we fit our experimental intensity profiles to model profiles, which are quickly computed from a simple parameterized model of the layer structure. Fitting techniques, such as differential evolution and nonlinear least-squares, survey the multidimensional parameter space to find the best-estimates of the layer density jump, width, and length.\n\nReferences:\n[1] Datta, Rishabh et al. PRL 2024\n[2] Datta, Rishabh et al. PoP 2024\n\nFunding Acknowledgements:\nThis work is supported by the Department of Energy’s NNSA Stewardship Science Graduate Fellowship (SSGF) program under Cooperative Agreement DE-NA0003960. We also acknowledge funding through NSF EAGER PHY2213898. SNL is managed and operated by NTESS under DOE NNSA contract DE-NA0003525.\n\nAuthors\nMr Lansing Horan (Massachusetts Institute of Technology (MIT) Plasma Science and Fusion Center (PSFC))\nDr Katherine Chandler (Sandia National Laboratories)\nDr David Yager-Elorriaga (Sandia National Laboratories)\nJack Hare (Cornell University)"},{"id":"560b4e57-7717-44df-9a84-de7bcaff87b1","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:50:00+00:00","end":"2026-07-01T12:15:00+00:00","s":"1250","e":"1315","name":"O.312 A. Diallo: Laser-produced tin plasmas for EUV lithography: Experiment and modeling","loc":"Fintry: Level +3","track":"LTDP: Plasma processing and applications I","type":"Session","details":"Extreme ultraviolet (EUV) lithography at 13.5 nm, driven by laser-produced tin (Sn) plasmas, has become the foundational technology in semiconductor manufacturing. A primary challenge is the control of plasma parameters: electron density, electron temperature, and ion charge state distribution, which define the spectral purity and conversion efficiency of the EUV source. Here, we present our experimental and modeling efforts on comprehensively characterizing laser-produced tin plasmas and the resulting EUV emission.\n\nOn the experimental side, we introduce ''SparkLight\", a new platform for generating and characterizing laser-produced plasmas. Tin plasmas are generated by irradiating a continuously moving tin-coated wire with a 1064 nm Nd:YAG laser. The facility integrates three complementary diagnostics: EUV emission spectroscopy, laser interferometry, and coherent Thomson scattering.\n\nWe devote particular attention to Thomson scattering, which allows for space- and time-resolved characterization of laser-produced plasmas. To reject stray light and isolate Thomson signal from the plasma self-emission, we utilize a compact and cost-effective design based on a Wollaston prism, volume Bragg grating notch filters, and a single-grating spectrometer.\n\nOn the modeling side, we use the radiation hydrodynamics code FLASH to study how laser pulse shaping can be optimized to improve EUV source performance. We also develop the collisional Particle-in-Cell code PSC to simulate fast ion debris acceleration in current EUV sources and in future, shorter wavelength sources.\n\nThis work demonstrates an integrated and practical approach for experimental and modeling characterization of plasmas in EUV source development.\n\nAuthor\nAhmed Diallo (Princeton Plasma Physics Laboratroy)\n\nCo-authors\nDr Alec Griffith (Hexium)\nDr Anatoli Morozov (Princeton University)\nKirill Lezhnin (Princeton Plasma Physics Laboratroy)\nShurik Yatom (Princeton Plasma Physics Laboratroy)\nDr Stanislav Musikhin (Princeton Plasma Physics Laboratroy)"},{"id":"4e9828ba-9685-4b21-8a0a-b7deef4dded4","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T11:50:00+00:00","end":"2026-07-01T12:05:00+00:00","s":"1250","e":"1305","name":"O.303 R. Takacs: Understanding the impact of the divertor configuration on the L-H transition in the ASDEX Upgrade tokamak","loc":"Pentland Suite: Level +3","track":"MCF: Gyrokinetic and pedestal","type":"Session","details":"Future tokamak devices, will operate in high-confinement mode (H-mode) in order to achieve the plasma confinement required for sustained net energy production. A key parameter describing H-mode is the power threshold for the L-H transition (\n), which has been shown to depend on various parameters, such as the plasma density, main isotope and plasma shaping. Experiments on different tokamaks, including JET [E. Delabie, 2014], DIII-D [P. Gohil, 2011] and MAST [H. Meyer, 2011] showed that \n can vary by up to a factor of two depending on the divertor configuration, indicating the importance of the edge and divertor conditions in the L–H transition. Despite this sensitivity, the widely used \n scaling law [Y.R. Martin, 2008] does not include the divertor configuration as a parameter, which leads to a significant uncertainty in the predictions. In the ASDEX Upgrade tokamak, during the 2024 campaign, dedicated upper single null (USN) discharges with different divertor configurations were performed at low and high densities. Together with a set of lower single null (LSN) plasmas from a previous campaign, these discharges provide a dataset with similar operational parameters (plasma current, magnetic field and heating scheme) to study the divertor configuration dependence of \n in ASDEX Upgrade. Significant variations in \n were observed between the different divertor configurations in both the LSN and USN discharges and in both density branches. The analysis focuses on the divertor conditions and the evolution of the midplane kinetic profiles prior to the L–H transition. This study can help us to understand the underlying physics of the L-H transition, to clarify the role of the divertor configuration on the \n and to improve our ability to optimize H-mode access in future fusion reactors.\n\nAuthor\nMs Roxana Takacs (Max Planck Institute for Plasma Physics, Garching)\n\nCo-authors\nDr Gregor Birkenmeier (Max Planck Institute for Plasma Physics, Garching)\nDr Matthias Willensdorfer (Max Planck Institute for Plasma Physics, Garching)\nDr Michael Dunne (Max Planck Institute for Plasma Physics, Garching)"},{"id":"99c4ac0e-9dff-4dd6-920c-b3a904d87fb5","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T12:00:00+00:00","end":"2026-07-01T12:15:00+00:00","s":"1300","e":"1315","name":"I. 308 J. Schleitzer (PhD prize): Probing Ion Drag and Electric Field Forces in 2f CCPs using Optically Trapped Microparticles","loc":"Sidlaw: Level +3","track":"MCF/LTDP: Diagnostics","type":"Session","details":"Boundary regions of low-pressure capacitively coupled plasmas (CCPs) – the presheath and sheath – govern ion acceleration, momentum transfer, and plasma–surface interactions, yet remain challenging to probe experimentally. In dual-frequency (2f) CCPs, the Electrical Asymmetry Effect (EAE) allows global tuning of plasma parameters via the relative phase between driving frequencies, but its local impact on boundary-layer forces has remained largely unexplored.\nIn this work, optically trapped microparticles are employed as spatially\nresolved, minimally invasive force probes to investigate boundary-layer dynamics in dual-frequency CCPs. A single SiO2 microparticle (7 μm diameter) is confined in a three-dimensional optical tweezer and scanned vertically through the discharge. By tuning the trap stiffness, strong electrostatic forces in the sheath and weaker ion drag forces in the presheath are selectively resolved (Fig. 1).\nThe measured force profiles reveal a clear spatial separation of dominant forces: ion drag emerges in the presheath, reaches a maximum near the sheath edge, and is overtaken by the rapidly increasing electric field force inside the sheath. Under dual-frequency excitation, both force magnitude and spatial distribution exhibit pronounced asymmetry with respect to the RF phase, reflecting phase-dependent modifications of\nelectron heating and plasma density.\nParticle charges derived from the sheath force profiles are consistent with orbital-motion-limited theory and literature estimates.\nThis approach establishes optically trapped microparticles as highly sensitive, force-resolved probes of boundary-layer physics, directly linking bulk plasma behavior with sheath dynamics.\nIt provides quantitative insight into local force balances, ion acceleration, and momentum transfer in phase-controlled 2f CCPs, and opens new experimental pathways toward force-resolved studies of plasma–surface interaction in technologically relevant RF discharges.\n\nAuthors\nH. Kersten (Institute of Experimental and Applied Physics, Christian-Albrechts-University Kiel, Germany)\nDr Jessica Schleitzer (1 Institute of Experimental and Applied Physics, Christian-Albrechts-University Kiel, Germany)\n\nCo-author\nV. Schneider (Institute of Experimental and Applied Physics, Christian-Albrechts-University Kiel, Germany)"},{"id":"e7ea5fe1-41be-4d85-a127-1cd2a6d77add","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T12:05:00+00:00","end":"2026-07-01T12:20:00+00:00","s":"1305","e":"1320","name":"O.601   H. Maguire: Experimental evidence of in vitro sparing effects for single-pulse, picosecond radiation from a laser-plasma accelerator","loc":"Tinto: Level 0","track":"BPIF: High power laser-plasma interaction","type":"Session","details":"Laser-driven plasma accelerators generate ultra-short (picosecond-femtosecond) and extremely high dose-rate (10\n -10\n Gy/s) radiation sources that can induce unique cellular responses. These beams deliver multi-Gy doses on timescales overlapping with the earliest physico-chemical stages of radiation interaction. We present the in vitro cell response of biological samples to single-pulse, multi-Gy electron radiation, delivered over picosecond timescales.\n\nSingle-pulse doses of up to 8 Gy (dose-rates of (10\n -10\n Gy/s), were delivered to two healthy and two cancer human cell lines. Dosimetric characterisation from radiochromic film and Monte Carlo simulations confirmed high beam uniformity across samples, with transverse and longitudinal dose variations of 3 Gy, a consistent departure was observed, with reduced radiosensitivity indicative of a FLASH-like sparing effect. This was reflected in decreased RBE10 values (RBE\n ~ 0.84 for all cell lines).\n\nThese results establish the potential of laser-driven plasma sources for investigating radiation responses at previously inaccessible timescales, providing a pathway to mechanistic insight into the earliest radiochemical processes involved in high dose-rate radiobiology.\n\nAuthor\n Ms Hannah Maguire (School of Mathematics and Physics, Queen's University Belfast)\nCo-authors\n Dr Conor McAnespie (School of Mathematics and Physics, Queen's University Belfast)\n Dr Pankaj Chaudhary (Radiotherapy and Dosimetry Group, National Physical Laboratory)\n Ms Lucia Corrigan (School of Mathematics and Physics, Queen’s University Belfast)\n Mr Temour Foster (School of Mathematics and Physics, Queen’s University Belfast)\n Prof. Stephen McMahon (Johnston Cancer Research Centre, Queen’s University Belfast)\n Dr Daniel Molloy (School of Mathematics and Physics, Queen’s University Belfast)\n Dr Gagik Nersisyan (School of Mathematics and Physics, Queen’s University Belfast)\n Ms Niamh O'Connor (School of Mathematics and Physics, Queen’s University Belfast)\n Prof. Kevin Prise (Johnston Cancer Research Centre, Queen’s University Belfast)\n Prof. Giuseppe Schettino (Radiotherapy and Dosimetry Group, National Physical Laboratory)\n Prof. Gianluca Sarri (School of Mathematics and Physics, Queen’s University Belfast)"},{"id":"ad2fc2d0-aa3e-4828-a556-13aee1f65a3d","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T12:05:00+00:00","end":"2026-07-01T12:30:00+00:00","s":"1305","e":"1330","name":"O.302 ER. Solano: Plasma shape effects on L-H power threshold and H-mode in JET-ILW","loc":"Pentland Suite: Level +3","track":"MCF: Gyrokinetic and pedestal","type":"Session","details":"Early studies in JET-C already indicated that the power threshold for the L-H transition (PLH) depends on plasma magnetic configuration [1]: PLH is lower in plasmas with strike points on horizontal targets (HT) when compared with vertical target (VT) plasmas. Initial studies in the JET-ILW have shown that even small changes in outer strike location can affect both PLH, and the density at which PLH is minimum (ne,min) [2,3].\nFurther detailed studies have confirmed these trends, expanding the shapes being studied and pointing out differences in transition dynamics [4]. Configurations with both inner and outer strikes on Vertical tiles (VT, vertical target) and with strikes on the corners of the divertor (CC, corner-corner) both have higher PLH and lower ne,min than those with the outer strike on the tilted central divertor tile (HT, horizontal target). The perpendicular rotation of the turbulence before the L-H transition differs significantly amongst configurations [5]. For any configuration, lower plasma current reduces ne,min, which in general is related to fGW,min= ne,min/nGW [6]. Additionally, it has been shown that for given configuration fGW,min depends on plasma content, being lowest for Tritium, followed by Deuterium, D+T, Hydrogen [6,7].\nThe configuration effect on PLH and ne,min introduces factor of 2 uncertainties on the prediction of PLH in future devices [7]. No explanation is available yet.\nInterestingly, once in the ELMy H-mode regime, the configurations with higher PLH exhibit considerably better confinement and lower type I ELM frequency, the latter being affected even by small strike sweeps. Therefore, the ratio of input power over PLH is not a good indicator of the power required to obtain good H-mode confinement, indicating that the mechanisms responsible for triggering the formation of an edge transport barrier don’t determine its evolution in a well-established H-mode.\n[1] Y Andrew et al PPCF 50 124053 (2008) [2] E. Delabie et al 25th IAEA Fusion Energy Conf., Saint-Peterburg, Russia, 2014, poster EX/5–24 [3] C. F. Maggi et al NF 54 023007 (2014)\n[4] E. Delabie et al Proc. 42nd EPS Conf. on Plasma Physics, Lisbon, Portugal, 2015, Oral O3.113\n[5] C. Silva, et al, NF 62 126057 (2022) [6] E. R. Solano et al 2021 NF 61 124001 (2021)\n[7] E. R. Solano et al NF 63 112011 (2023) [8] E. Delabie et al NF 66 036016 (2026)\n\nAuthors\nDr Emilia R. Solano (Laboratorio Nacional de Fusión, CIEMAT, Spain)\nDr E Delabie (Oak Ridge National Laboratory)\nDr C Silva (Instituto de Plasmas e Fusão Nuclear)\nDr C Maggi (UKAEA)\nDr P Vincenzi (Consorzio RFX)\nDr L Frassinetti (Fusion Plasma Physics, EECS, KTH)\nR.B. Morales (UKAEA)\nZ. Huang (UKAEA)\n Dr S Saarelma (UKAEA,)\n Dr Elena de la Luna (Laboratorio Nacional de Fusión, CIEMAT)\n Dr B Lomanowski (Oak Ridge National Laboratory)\n Dr Y Andrew (Blackett Laboratory, Imperial College London)\n JET Collaborators"},{"id":"9f2afe70-bfcd-478b-ab54-7e99784e157e","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T12:20:00+00:00","end":"2026-07-01T12:45:00+00:00","s":"1320","e":"1345","name":"O.606   S. Glenzer: Shock propagation in cryogenic deuterium-wetted foams","loc":"Tinto: Level 0","track":"BPIF: High power laser-plasma interaction","type":"Session","details":"Low-density polymer foams wicked with cryogenic liquid hydrogen are prime candidates to deliver nuclear fuel in inertial fusion power plants. These targets allow fast filling and uniform distribution of the fuel on the inside of a spherical capsule that is required for high-convergence implosions using laser-driven shock waves driven by ablation pressure. Their design requires high-precision equation of state data and understanding of instability hydrodynamics.\nIn April 2026, we completed the first cryogenic wetted foam experiment that visualizes shock wave propagation through foams that have been wicked with liquid deuterium at 25K. We utilized high-resolution X-ray imaging measurements at the Titan laser facility at Lawrence Livermore National Laboratory that delivered a 150-J, 600 fs short-pulse laser beam to drive a Cu K-alpha X-ray backlighter source at 8 keV. This setup provides X-ray phase-contrast images with 100 picosecond temporal resolution and 20-micron spatial resolution of the shock-compressed plasma driven by a second long-pulse laser beam at 450 J energies and smoothed with a 600-micron continuous phase plate. Our measurements provide new results on the shock speed and the shock uniformity for various types of foam structures revealing a path towards approaching the uniformity achieved in a pure deuterium liquid. The data further visualize the mixing of foam material with the liquid behind the shock, providing important benchmark data for hydrodynamic simulations of laser-driven fusion targets for inertial fusion energy.\nThese experiments provide the first measurements of the equation of state of wetted foams and comparisons with liquid deuterium. The results are of critically importance to design inertial fusion targets for public and private fusion efforts.\n\nThis work was funded by the DOE Office of Science, Fusion Energy Science under FWP100182. We acknowledge support from Department of Energy (DOE), Office of Science, Fusion Energy Sciences, under Award No. DE-SC 0024882: IFE-STAR was issued as SLAC FWP 101126. The work of XX, JV., SM, and RC was performed under the auspices of the U.S. Department of Energy by Lawrence Livermore National Laboratory under Contract No. DE-AC52-07NA27344.\n\nAuthor\nProf. Siegfried Glenzer (SLAC National Accelerator Laboratory)"},{"id":"2a901bfe-1569-4798-9b91-4439a6eaa243","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T12:30:00+00:00","end":"2026-07-01T13:30:00+00:00","s":"1330","e":"1430","name":"***Wednesday Lunch***","loc":"","track":"","type":"Break Activity","details":"Please note lunch is not catered for during the event. \nThere are many options close by; we have included some recommendations here in the app."},{"id":"b54cbc01-4416-4dfc-b276-7d69936267f6","date":"2026-07-01","dayLabel":"Wednesday, July 1, 2026","start":"2026-07-01T14:00:00+00:00","end":"2026-07-01T17:00:00+00:00","s":"1500","e":"1800","name":"Optional Tours","loc":"","track":"","type":"Break Activity","details":"These have been pre-booked and already paid for.\n\nIf you have pre-booked a tour it will show in your personal agenda."},{"id":"b2d510be-f7d9-4627-86c7-c96c5252f4e7","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T07:00:00+00:00","end":"2026-07-02T08:00:00+00:00","s":"0800","e":"0900","name":"AGENDA KEY INFORMATION | PLEASE READ","loc":"","track":"","type":"Information","details":"Please click on each session to view the session details including the abstract and the authors. \n\nTo add the session to your personal agenda, please click the star. \n\nYou can view your personal agenda by returning to the home screen and clicking the 'My Agenda' icon."},{"id":"e032bdf3-0155-41fe-9644-98460ae50bc3","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:00:00+00:00","end":"2026-07-02T08:25:00+00:00","s":"0900","e":"0925","name":"I.405 A. Milder: Novel measurements of plasma conditions with a high bandwidth ultraviolet laser using cross-beam energy transfer","loc":"Fintry: Level +3","track":"BPIF: Coronal plasma and laser-plasma instabilities","type":"Session","details":"The Fourth-generation Laser for Ultrabroadband eXperiments (FLUX) was recently activated at the Laboratory for Laser Energetics to study the effects of laser bandwidth on laser-plasma instabilities. FLUX delivers a spectrally incoherent beam with 5 nm of bandwidth centered around 351 nm to the target chamber of the Omega Laser Facility. FLUX was initially used was used to demonstrate a novel plasma diagnostic that can measure spatially localized plasma conditions. By crossing the FLUX beam with a narrow 351-nm beam in a nitrogen/hydrogen plasma, a broadband electromagnetic beat wave excited ion-acoustic waves in a ~0.004 mm^3 volume was created. The response of the ion-acoustic waves to this beat wave was imprinted on the spectrum of the transmitted FLUX beam. The ion-acoustic resonances transfer energy between the FLUX beam and the narrow band beam (i.e., cross-beam energy transfer (CBET) moves energy between the two beams). The locations and width of the resonant peaks in the output spectrum provide a measure of the electron and ion temperature, respectively, and the magnitude of transfer was used to determine the plasma density. This technique provides an alternative to Thomson scattering and can have powerful advantages in many situations. It also greatly accelerates our ability to validate CBET models, because the entire CBET gain curve is now captured in a single shot. FLUX is poised to deliver data on laser-plasma instability suppression paving the way for next generation ICF designs. This work is supported by the Department of Energy under contract numbers: DE-NA-0004144 and DE-SC0024863.\n\nAuthors\nAvi Milder (Laboratory for Laser Energetics)\nChristophe Dorrer (Laboratory for Laser Energetics)\nDr David Turnbull (Laboratory for Laser Energetics)\nDr Dustin Froula (Laboratory for Laser Energetics)\nElizabeth Hill\nJoe Katz (Laboratory for Laser Energetics)\nDr Nathaniel Shaffer (Laboratory for Laser Energetics)\nDr Rahul Shah (Laboratory for Laser Energetics)\nRichard Dean (Laboratory for Laser Energetics)\nProf. Wojciech Rozmus (University of Alberta)"},{"id":"fbbc5744-cdf3-41a0-8111-579d491a5e8f","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:00:00+00:00","end":"2026-07-02T08:25:00+00:00","s":"0900","e":"0925","name":"I.403   J. Halliday: A Laboratory Analogue of Cosmic Ray Interactions in Magnetised Plasma","loc":"Moorfoot: Level 0","track":"BSAP : Astrophysical plasmas & Laboratory Astrophysics","type":"Session","details":"Understanding how cosmic rays gain energy and scatter in astrophysical environments remains one of the central open questions in plasma astrophysics. We report on an experiment at the GSI Helmholtz Centre for Heavy Ion Research, in which a monoenergetic 450 MeV chromium ion beam was propagated through a magnetized plasma formed by the collision of two counter-propagating, laser-ablated flows. The plasma, diagnosed using interferometry and ion deflectometry, showed an interaction region largely free from fluid-scale turbulence, consistent with magnetohydrodynamic simulations performed with FLASH [Moczulski et al., Phys. Plasmas 31, 122105 (2024)]. Despite this, time-of-flight diagnostics revealed both velocity-space diffusion and bulk acceleration of the ion beam.\n\nThe absence of strong, fluid-scale turbulence rules out Fermi acceleration as the cause of the observed scattering and energization. An analytical treatment, constrained by experimental observations, suggests wave–particle scattering by short-wavelength electrostatic kinetic turbulence as an alternative explanation. A forthcoming beamtime campaign at GSI will directly probe these electrostatic fluctuations using collective optical Thomson scattering, providing a quantitative test of the proposed mechanism. These experiments establish a new laboratory platform for studying cosmic-ray-like transport and pre-acceleration in magnetized plasmas. See [arXiv:2509.07880] for initial results.\n\nAuthor\nJack Halliday (STFC Rutherford Appleton Laboratory)\n\nCo-authors\nJ. Y. T. Chu (University of Oxford)\nR. Bingham (STFC Rutherford Appleton Laboratory)\nGianluca Gregori (University of Oxford)"},{"id":"b33e6c67-e837-453d-b923-a667cff79e19","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:00:00+00:00","end":"2026-07-02T08:25:00+00:00","s":"0900","e":"0925","name":"I.408 K. Sgonina: Multiscaled Aeromaterial Reactor for Plasma Catalysis","loc":"Tinto: Level 0","track":"LTDP: Plasma processing and applications II","type":"Session","details":"The intermittency of renewable energy sources such as wind and solar often results in electricity generation when demand is low, leading to curtailment and energy losses. Converting this surplus power into chemical energy carriers, such as ammonia, offers a viable storage route. Conventional ammonia synthesis via the Haber-Bosch process is efficient but inflexible and centralized. Non-thermal plasma catalysis provides a promising alternative, enabling ammonia production under mild conditions and direct coupling to intermittent renewable electricity.\n\nAmong reactor concepts, packed-bed designs offer high catalytic surface area but suffer from plasma penetration limits, pressure drops, and heat management challenges. Honeycomb reactors, while exhibiting low pressure drop and uniform gas flow, struggle to sustain stable discharges in narrow channels. Here, we present a novel reactor concept based on multiscaled aeromaterials that merges the advantages of both configurations. The open, hierarchical architecture promotes uniform plasma generation and enhanced plasma-surface coupling. When combined with advanced catalytic materials, these reactors could provide a versatile platform for studying discharge dynamics, plasma-surface interactions, and catalytic enhancement mechanisms. This approach represents a step toward efficient, renewable-energy-driven plasma catalysis and decentralized ammonia synthesis.\n\nRecent results utilizing the novel reactor with optical access to study the fundamental plasma penetration through aeromaterials will be presented. For the proof-of-concept non-catalytic aeroglass (SiO\n) was used to confirm the plasma penetration in this material.\n\nAuthor\nDr Kerstin Sgonina (Institute of Experimental and Applied Physics, Kiel University, Germany)\n\nCo-authors\nDr Franko Greiner (Institute of Experimental and Applied Physics, Kiel University, Germany)\nJonas Lumma (Department of Materials Science, Kiel University, Germany)\nProf. Rainer Adelung (Department of Materials Science, Kiel University, Germany)\nProf. Jan Benedikt (Institute of Experimental and Applied Physics, Kiel University, Germany)"},{"id":"f798436c-a250-46de-a9b0-c7b6bb80e3af","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:00:00+00:00","end":"2026-07-02T08:25:00+00:00","s":"0900","e":"0925","name":"I.401   D. Kennedy: The transport challenge for fusion power plants at high βₚ","loc":"Pentland Suite: Level +3","track":"MCF: High beta / beta-pol","type":"Session","details":"Electromagnetic microinstabilities are expected to dominate core transport in the high-\n conditions targeted by next-generation fusion pilot plants (FPPs) such as STEP [1], where \n denotes the ratio of electron thermal pressure to magnetic pressure. In the absence of strong sheared flow, nonlinear local gyrokinetic simulations indicate that unstable electromagnetic modes can drive heat fluxes exceeding the available heating power. Predicting transport in this regime is challenging, as such simulations often fail to attain a robust steady state. Instead, as \n increases, the turbulence becomes more electromagnetic and undergoes a transition from a low-transport state dominated by strong zonal flows to a high-transport state in which zonal-flow regulation is weakened and transport rises sharply.\n\nThis work addresses these challenges in the context of STEP. Using the stress-balance framework of Zhang et al. [2] and Kennedy et al. [3], we provide a predictive description of this transition in terms of the zonal-flow torque balance. We confirm that the onset of extreme transport correlates with a critical value of \n (equivalently a limit in \n), where \n is the safety factor, which can lie well below any relevant linear stability boundary in \n space. Extensive nonlinear simulations show that the transition is governed by a competition between electrostatic and magnetic-flutter zonal torques: below threshold, the net torque reinforces zonal flows and supports saturation, whereas above threshold electromagnetic torques counteract the electrostatic drive, suppress zonal-flow regulation, and enable electromagnetic runaway. We further show that access to a second-stable regime at sufficiently high \n permits re-saturation at larger \n, with the ideal ballooning mode threshold providing a useful proxy for delineating this region, with direct implications for flux-driven simulations.\n\nThis talk will review these results with a primary focus on their implications for next-generation FPPs. We discuss how the predicted transport regimes constrain viable high-\n operating scenarios and examine multiple high-performance MAST-U discharges to assess how close present-day experiments approach the predicted \n threshold. Implications for scenario design, including tailoring the \n-profile, achieving sufficient heating power, or exploiting profile control to avoid the transition, are discussed.\n\nAuthor\nDaniel Kennedy (UK Atomic Energy Authority)\n\nCo-authors\nArka Bokshi\nBhavin Patel\nColin Roach\nFrancis Casson\nHarry Dudding\nHoward Wilson\nMantas Abazorius\nPlamen Ivanov\nSam Blackmore\nToby Adkins\nYujia Zhang"},{"id":"cb6c9460-72cf-4e6a-a82b-e0aeef9c3ae2","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:00:00+00:00","end":"2026-07-02T08:25:00+00:00","s":"0900","e":"0925","name":"I.402 R. López-Cansino: Effect of internal magnetic islands on confinement and transport in Wendelstein 7-X plasmas","loc":"Sidlaw: Level +3","track":"MCF: Transport & high confinement regimes","type":"Session","details":"A quantitative understanding of the impact of magnetic islands (MIs) on transport and their possible role in enhanced confinement is important for the design and optimization of future stellarator devices. The Wendelstein 7-X stellarator allows for magnetic configurations where static 5/5 MIs form near the separatrix inside the confined region. These configurations have been found to provide improved confinement compared to equivalent configurations where MIs are placed in the scrape-off layer. Confinement transitions associated with MI growth beyond a critical width, \n with \n the MI width, can be triggered in turbulence-dominated scenarios by scanning \n with external control coils. In turbulence-suppressed regimes, where ITG turbulence is suppressed with density gradients, these transitions are observed spontaneously. Upon these transitions, the plasma diamagnetic energy decreases by ~30-40 %, associated with a flattening of both ion (\n) and electron (\n) temperature profiles. The Coherence Imaging Charge Exchange Recombination Spectroscopy (CICERS) diagnostic is employed to characterize the impact of these transitions within one MI on \n, carbon impurity density (\n) and flow velocity (\n), delivering poloidally resolved 2D images of such parameters. While turbulence-dominated regimes show only minor changes in \n and \n, associated with the flattening of the profiles, the turbulence-suppressed scenarios display a strong \n accumulation centered around the O-point of the MI, with \n increasing up to a factor of 4. Additionally, an island inboard-outboard flow asymmetry is observed, potentially linked to the development of \n flows inside the MI. Maintaining \n below \n via strong coil-driven island reduction prevents the spontaneous temperature flattening and associated confinement degradation observed in these configurations in high-performance turbulence-suppressed operation; under these conditions, the current record of Stellarator triple product is obtained.\n\nAuthor\nRamón López Cansino (University of Sevilla)\n\nCo-authors\nDr Eleonora Viezzer (University of Seville, Spain)\nDr Valeria Perseo (Max Planck Institute for Plasma Physics)\nDr Oliver P. Ford (Max Planck Institute for Plasma Physics)\nDr D. Matthew Kriete (Auburn University)\nFelix Reimold (Max Planck Institute for Plasma Physics)\nThilo Romba (Max Planck Institute for Plasma Physics, Greifswald, Germany)\nDr Peter Poloskei (Max Planck Institute for Plasma Physics)\nDr Sebastian Bannmann (Max Planck Institute for Plasma Physics)\nDr Carsten Killer (Max Planck Institute for Plasma Physics)\nDr Jan-Peter Bähner (Max Planck Institute for Plasma Physics, Greifswald, Germany)\nDr Jason Smoniewski (MIT Plasma Science and Fusion Center)\nDr Adrian von Stechow (Max Planck Institute for Plasma Physics)\nDr Golo Fuchert (Max Planck Institute for Plasma Physics)\nDr Tamara Andreeva (Max Planck Institute for Plasma Physics)\nDr Christian Brandt (Max Planck Institute for Plasma Physics)"},{"id":"9a6b8430-6113-4ed9-9462-b4b1fc9b5538","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:25:00+00:00","end":"2026-07-02T08:50:00+00:00","s":"0925","e":"0950","name":"I.406 N. Lemos: Quantifying inner beam Cross Beam Energy Transfer in a Hohlraum like platform at the National Ignition Facility","loc":"Fintry: Level +3","track":"BPIF: Coronal plasma and laser-plasma instabilities","type":"Session","details":"Cross beam energy transfer (CBET) is central to controlling implosion symmetry in all ignition designs at the National Ignition Facility (NIF), and can possibly be even more critical as laser driver energies increase from the current multi megajoule regime toward next generation facilities operating at approximately 10 MJ. In indirect drive inertial confinement fusion (ICF) experiments at NIF, CBET redistributes laser power among the 192 beams via ion wave mediated coupling in the hohlraum plasma, strongly influencing the spatial and temporal drive symmetry on the fusion capsule. While CBET has been essential to achieving ignition, its quantitative behavior remains poorly constrained; current radiation hydrodynamics simulations cannot reliably predict low mode shape and symmetry, and an empirical plasma wave amplitude limiter is routinely applied to CBET models. This limiter must be retuned for each design, laser pulse, and wavelength detuning configuration, creating ambiguity as to whether it compensates deficiencies in the CBET physics or other inaccuracies in hohlraum and capsule modeling. These uncertainties increase the number of required tuning shots and limit confidence in extrapolations to higher energy facilities.\nWe report on a new suite of NIF experiments, conducted in 2025 and 2026, designed to directly measure CBET in a hohlraum-like environment. A novel experimental platform has been developed that, for the first time, quantifies the time resolved transfer of power from outer to inner beam cones, as a function of wavelength detuning Δλ and hohlraum gas fill density. High fidelity time gated x-ray images of the inner cone footprint provide unprecedented maps of post CBET beam powers and intensities over an entire NIF hemisphere.\nThis work was performed under the auspices of U.S. DOE by Lawrence Livermore National Laboratory (LLNL) under Contract DE-AC52-07NA27344\n\nAuthors\nH Meyer (LLNL)\nM Rosen (LLNL)\nM Schneider (LLNL)\nNuno Lemos (LLNL)\nP Michel (LLNL)\nS Ross (LLNL)\nT Chapman (LLNL)\nW Farmer (LLNL)\nW Riedel (LLNL)"},{"id":"2f55e992-d51c-4d4c-aed2-5076fd41d808","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:25:00+00:00","end":"2026-07-02T08:50:00+00:00","s":"0925","e":"0950","name":"I.404  M. Zhou: Genesis, amplification, and decay of cosmic magnetic fields","loc":"Moorfoot: Level 0","track":"BSAP : Astrophysical plasmas & Laboratory Astrophysics","type":"Session","details":"Astronomical observations suggest pervasive, dynamically important magnetic fields in our\nGalaxy and the intracluster medium, yet their origin remains a long-standing question in\nastrophysics and cosmology. It is widely believed that such fields first arose as weak “seeds”\ngenerated by cosmic batteries and were subsequently amplified by turbulent plasma flows to\ncurrent levels via the dynamo process; however, a complete understanding of these processes\nin weakly collisional plasmas, as well as the sustenance of magnetic fields once turbulent\nstretching subsides, is still lacking. This work presents a unified paradigm for the origin and\nevolution of cosmic magnetism by incorporating the effects of nonequilibrium microphysics of\ncollisionless plasmas into macroscopic astrophysical processes. Using analytical theory and\nfirst-principles numerical simulations, it is demonstrated that seed magnetic fields can\nspontaneously emerge under generic turbulent motions through kinetic plasma instabilities,\nimplying that cosmic plasmas are ubiquitously magnetized. The cross-scale, nonlinear coupling\nbetween microscopic magnetic fields and macroscopic flows enhances turbulence and\naccelerates the plasma dynamo, rapidly amplifying the field to energy equipartition with the\nturbulent flow. The subsequent relaxation of these fields after turbulent stretching subsides is\nregulated by pressure-anisotropy-driven instabilities. The ab initio production of equipartitionstrength fields from an initially unmagnetized plasma, together with their relaxation, provides a\npredictive explanation for the prevalence of cosmic magnetism, a key target of upcoming\nobservations such as those by the Square Kilometer Array.\n\nAuthor\nMuni Zhou (Dartmouth College, Department of Physics and Astronomy, Hanover, USA,)\n\nCo-authors\nDawei Dai (Dartmouth College, Department of Physics and Astronomy, Hanover, USA)\nDmitri Uzdensky (Oxford University, Department of Physics, Oxford, UK,)\nMatthew Kunz (Princeton University, Department of Astrophysical Science, Princeton, USA,)\nNuno Loureiro (MIT, Plasma Science and Fusion Center, Cambridge, USA)\nVladimir Zhdankin (University of Wisconsin-Madison, Department of Physics, Madison, USA,)"},{"id":"f085ff0b-0d52-48bf-8636-f4506aec459e","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:25:00+00:00","end":"2026-07-02T08:50:00+00:00","s":"0925","e":"0950","name":"I.409 L. Scarlett: Comprehensive data set of cross sections for molecular hydrogen and its application in fusion and low temperature plasmas","loc":"Tinto: Level 0","track":"LTDP: Plasma processing and applications II","type":"Session","details":"The development of the molecular convergent close-coupling (MCCC) method has enabled large-scale convergence studies to be performed for molecular targets for the first time. Over the last decade we have been applying this technology to the electron-H\n scattering system, with the long-term goal of producing a complete collision data set for application in collisional-radiative models. Previously, the majority of available data were either from small close-coupling calculations valid only at low energies, or semi-classical calculations valid only at high energies. There was also little vibrationally- and rotationally-resolved data available.\n\nMotivated by fusion and astrophysical applications, we have produced cross sections numbering in the hundreds of thousands for electrons scattering on H\n and its five isotopologues, considering vibrational levels in the first 20 electronic states, and rovibrational levels in the first 10. These data have allowed detailed collisional-radiative models for low-temperature hydrogen plasmas to be constructed for the first time. This talk will provide an update on the MCCC project and its applications, including new results for proton collisions with H\n.\n\nAuthor\nLiam Scarlett (Curtin University)\n\nCo-authors\nDr Corey Plowman (Curtin University)\nDr Daniele Galli (INAF–Osservatorio Astrofisico di Arcetri)\nDr Dirk Wünderlich (Max Planck Institute for Plasma Physics)\nProf. Dmitry Fursa (Curtin University)\nProf. Igor Bray (Curtin University)\nDr Marco Padovani (INAF–Osservatorio Astrofisico di Arcetri)\nDr Mark Zammit (Los Alamos National Laboratory)\nDr Richard Bergmayr (Max Planck Institute for Plasma Physics)\nProf. Ursel Fantz (Max Planck Institute for Plasma Physics)"},{"id":"8adad444-5c96-4a8c-bc2c-b68de33ec689","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:25:00+00:00","end":"2026-07-02T08:40:00+00:00","s":"0925","e":"0940","name":"O.401   FP. Orsitto: Overview of High beta experiments on JET in preparation of JT60SA","loc":"Pentland Suite: Level +3","track":"MCF: High beta / beta-pol","type":"Session","details":"High beta discharges with normalized Larmor radius (ρ*), and normalized beta (βN) relatively close to JT-60SA scenarios hybrid and advanced were realized in a new series of experiments on JET-ILW[1]. The strategy of these experiments was to explore high normalized beta (βN) values, MHD effects at different BT ( Toroidal Magnetic field on axis) and find discharges with mild MHD. JET/JT-60SA ‘similarity experiments‘ can be done with plasma parameters on JT-60SA, at BT/Ip=1.45T/1.4MA and heating power less than 10MW. Deuterium plasmas were realized in hybrid scenario at BT = 1.7, 2, 2.4 T, Ip = 1.4 MA, elongation k = 1.7, triangularity δ ≈ 0.4, q95=4-6, and central safety factor q0>1 at NBI ( Neutral Beam Injection) start, with NBI power PNBI = 16-25 MW. The preliminary results of the JET high beta experiments were presented in [1]. Here an overview is presented on the following topics : i) confinement properties of high beta discharges versus input power and scaling of confinement improvement with beta; ii) dynamics of formation of the Internal Transport Barriers(ITB) while approaching high beta; iii) pedestal structure and its evolution at high beta ; iv) current profile evolution. It is found that the maximum normalized beta ( βN) obtainable, increases with input power and depends ( decreases with ) on the magnetic field . These effects are compatible with a small dependence of the confinement time on the input power. Looking into the electron kinetic spatial profiles , the progress toward the high beta is characterized by the formation of an ITB. The confinement dynamics can be related to the critical gradient scale length of the ITG turbulence, which is depending on the ratio Ti/Te and magnetic shear. The confinement properties of these discharges indicate that the H98Y ( the improvement confinement factor with respect to the ITER confinement scaling ) has a linear dependence on the βN, changing with the magnetic field. TRANSP analysis done for the pulse 103116 (B=2.4T) shows that the spatial profile of the diamagnetic current increases from negative values toward zero while βN increases toward the maximum.\n\nF P Orsitto et al , High beta experiments on JET in preparation of JT-60SA , Proc. 50th EPS Conf on Plasma Physics , 8-12 july 2024, Salamanca , Spain , paper P1-151\n\nAuthor\nFrancesco Paolo Orsitto (ENEA)\n\nCo-authors\nMr Fulvio Auriemma (CNR Italy)\nMr Gianluca Pucella (ENEA)\nMr Luca Garzotti (UKEAA)\nMr Stefano Gabriellini (UKAEA)\nMr Matteo Baruzzo (ENEA)"},{"id":"9a22ac7e-e6b8-45e2-ba1c-d1b9b45966c5","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:25:00+00:00","end":"2026-07-02T08:50:00+00:00","s":"0925","e":"0950","name":"I.511 M. Nishiura: Bifurcated states of particle transport driven by regulatory energetic ions in LHD plasmas","loc":"Sidlaw: Level +3","track":"MCF: Transport & high confinement regimes","type":"Session","details":"Control of particle transport is a prerequisite for sustaining burning plasmas, necessitating a precise balance between fuel confinement and helium ash removal. This study investigates the transport bifurcation phenomena in the Large Helical Device (LHD), demonstrating that the velocity-space anisotropy of energetic ions serves as a deterministic control knob to regulate the directionality of radial particle transport.\nInitially, bifurcation of electron density profiles into peaked or flattened steady states was observed following carbon pellet injection. Gyrokinetic analysis suggests that Ion Temperature Gradient (ITG) turbulence remains active in these states, implying a complex interaction between turbulence and transport fluxes. To isolate the regulatory role of energetic ions from pellet fueling effects, systematic experiments were conducted by varying the heating power ratio of energetic neutral beams (\n) from 0 (tangential) to \n (perpendicular) without pellet injection.\nA clear transition in the transport regime was observed: electron density profiles became hollow in tangential-dominant regimes (\n) and shifted to strongly peaked profiles in perpendicular-dominant regimes (\n). Carbon impurity profiles exhibited a synchronized response. Crucially, this bifurcation is interpreted as a transition in the radial electric field structure. The velocity-space anisotropy modifies the non-ambipolar flux of energetic ions, which reconfigures the ambipolar condition and overrides the intrinsic neoclassical transport governed by bulk temperatures. These findings establish that energetic-ion phase-space physics can decouple particle transport from bulk thermal regimes, offering a novel and robust methodology for optimizing confinement and impurity control in future fusion reactors.\n\nAuthor\nMasaki Nishiura (National Institute for Fusion Science)\nCo-authors\nDr Shinsuke Satake (National Institute for Fusion Science)\nProf. Masanori Nunami (National Institute for Fusion Science)\nDr Akirhiro Shimizu (National Institute for Fusion Science)\nProf. Takeshi Ido (Kyushu University)\nMikirou Yoshinuma (National Institute for Fusion Science)\nDr Hiroyuki Yamaguchi (National Institute for Fusion Science)\nDr Hideo Nuga (National Institute for Fusion Science)\nDr Ryohma Yanai (National Institute for Fusion Science)\nDr Keiji Fujita (National Institute for Fusion Science)\nProf. Mirko Salewski (Technical University of Denmark)"},{"id":"d0198b36-863e-43f0-8be6-816b03e67c4a","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:40:00+00:00","end":"2026-07-02T08:55:00+00:00","s":"0940","e":"0955","name":"O.402  XZ. Gong: Development of High-βₚ Scenarios towards High-Q on EAST in Support of ITER Steady-state Operation","loc":"Pentland Suite: Level +3","track":"MCF: High beta / beta-pol","type":"Session","details":"To advance the steady-state operation of ITER and achieve high fusion gain (high-\n) in tokamak devices, experimental research on high poloidal beta (\n) plasma scenarios was conducted on EAST, focusing on ITER-relevant compatibility, fully non-inductive operation, and tungsten (W) divertor adaptation. High-performance high-\n plasma was successfully demonstrated via radio frequency only heating (ECRH, LHCD, ICRF), with key parameters including excellent confinement \n, bootstrap current fraction \n, Greenwald fraction \n, and \n / \n maintained for 100 seconds at \n and \n.\n\nFor steady-state operation of W-divertors towards high-\n, fully non-inductive high-\n plasmas with a boron-coated wall were developed at \n, \n, \n. Driven by dominant electron heating, this plasma achieved \n and \n / \n, and exhibited a series of superior physical characteristics: an internal transport barrier (ITB) that effectively suppresses plasma turbulence, small edge-localized modes (ELMs) with a frequency \n, effective control of tungsten impurity accumulation, a flat core current density profile with \n, and suppression of \n tearing modes via ICRF heating. Transport simulation results showed that \n-stabilization induced by Shafranov shift is the dominant factor governing turbulent transport. The electron thermal ITB is mainly controlled by trapped electron mode (TEM) turbulence, and zonal flow shearing in the ITB region exerts a regulatory effect on TEM-induced energy transport. Notably, increased plasma density and \n were found to elevate the bootstrap current fraction \n, broaden the current density profile, and further improve plasma energy confinement.\n\nSubsequent experiments were performed with ITER-like heating and ITER-shaped (LSN) combinations (ECRH, ICRH, NBI), alongside plasma current scanning in the range \n–\n. The results indicated that increased plasma current caused \n to decrease from 1.35 to 1.1 and reduced the SOL density. Additionally, edge plasma parameters were found to exert a significant influence on the coupling and absorption efficiency of RF heating.\n\nFor further optimization of ITER-configuration plasma scenarios with enhanced capability on EAST, future research will focus on adopting a moderate safety factor \n to extend fusion performance, employing ITER-like heating configurations, adjusting the ion-to-electron temperature ratio \n via ion heating, and broadening the current density profile \n to form a full-channel ITB with \n, which can effectively prevent the onset of low-order tearing modes.\n\nThe experimental results obtained on EAST provide important technical support for ITER’s new research plan, including the material switch of the first wall to tungsten. Furthermore, these findings offer critical physical insights for the development of high-performance plasma scenarios in future fusion power plants.\n\nAuthor\nXianZu Gong (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei, China)\n\nCo-authors\nJuan Huang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nB Zhang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. X. J Zhang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei, China)\nMiaohui Li (Institute of Plasma Physics, Chinese Academy of Sciences)\nW.B Liu (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nChenyu Pan (Institute of Plasma Physics, Chinese Academy of Science)\nDr Y.C Hu (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nY.W Yu (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nS.X Wang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nQ Zang (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nProf. R Ding (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)\nJP Qian\nY.T SONG (Institute of Plasma Physics, Hefei Institutes of Physical Science Chinese Academy of Sciences, Hefei 230031, China)"},{"id":"a9a8274b-1bd4-4deb-8df9-1bdb52066f4d","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:50:00+00:00","end":"2026-07-02T09:05:00+00:00","s":"0950","e":"1005","name":"O.412 E. Hume: Measurements of LPI growth in smoothed and unsmoothed beam interactions of relevance to direct drive ICF","loc":"Fintry: Level +3","track":"BPIF: Coronal plasma and laser-plasma instabilities","type":"Session","details":"The focus of the inertial confinement fusion (ICF) community post-ignition is shifting towards practical schemes for inertial fusion energy production (IFE). Direct drive, where the intense lasers irradiate the fuel pellet exterior directly, and related variants such as shock ignition [1] and fast ignition is a primary candidate for IFE. A critical limitation facing direct drive is the excitation of laser-plasma instabilities (LPI) which act to couple laser waves into scattered light and hot electrons, reducing the efficiency of implosions. The growth of LPI is non-linear with laser intensity, making it a particular issue for shock ignition. Additionally LPI growth is highly dependent on the plasma parameters and kinetic effects, making predictive modelling challenging. Experiments at high power laser facilities with planar targets therefore offer a valuable tool for understanding the fundamental growth of these instabilities.\n\nIn this paper we present results from an experimental study performed at ELI-Beamlines measuring the Stimulated Raman Scattering (SRS) and Stimulated Brillouin Scattering (SBS) instabilities. A full-aperture backscatter (FABS) diagnostic station [2] was used to measure LPI driven under irradiation of thick and thin “exploding foil” targets by the L4n laser in 2⍵ (λ = 526.5 nm) up to intensities ~3 x 1015 W/cm2. In addition, a Distributed Phase Plate (DPP) was used to spatially smooth the focal spot in conditions more relevant to ICF. Filamentation and self-focusing are found to play a significant role in driving LPI considering the larger f-number (f/10.8) of the laser focusing optic. Our measurements highlight the critical role of focal spot statistics and self-focusing in governing LPI growth and demonstrate the utility of exploding foils for expanding the parameter space accessible at high-power laser facilities [3].\n\n[1] R. Betti et al., Phys. Rev. Lett. 98, 155001 (2007)\n[2] F. Wasser et al., Rev. Sci. Instrum. 94, 093503 (2023)\n[3] E. Hume et al., HPLSE (submitted)\n\nAuthor\nEmma Hume (University of York)\n\nCo-authors\nBen Fisher (The university of York)\nDiluka Singappuli (CELIA – Centre Lasers Intenses et Applications, Universit´e de Bordeaux, Talence, France)\nDimitri Batani (University of Bordeaux)\nFlorian Condamine (GenF)\nFlorian Wasser (Focused Energy)\nDr Gabriele Cristoforetti (ILIL, INO-CNR)\nGaëtan Fauvel (CELIA)\nDr Leonida Gizzi (ILIL, INO-CNR)\nDr Martin Sokol (Focused Energy)\nProf. Nigel Woolsey (University of York)\nP.E. Masson-Laborde (CEA , DAM, CEA-DIF, F-91297 Arpajon (France))\nDr Petra Koester (ILIL, INO-CNR)\nDr Raj Singh (Extreme Light Infrastructure ERIC, ELI-Beamlines Facility)\nStefano Atzeni (Focused Energy)\nDr Tomáš Laštovička (Extreme Light Infrastructure ERIC, ELI-Beamlines Facility)\nWolfgang Theobald (Focused Energy GmbH)\nDr Şêro Zähter (Focused Energy)"},{"id":"3e53ee69-d107-4654-8237-c8747ea0cd31","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:50:00+00:00","end":"2026-07-02T09:05:00+00:00","s":"0950","e":"1005","name":"O.409  M. Tabary: The Interplay Between the Bell and Firehose Instabilities","loc":"Moorfoot: Level 0","track":"BSAP : Astrophysical plasmas & Laboratory Astrophysics","type":"Session","details":"In astrophysical shocks, instabilities driven by the streaming of energetic particles into the upstream medium amplify magnetic fields and generate turbulence, enabling efficient cosmic-ray (CR) acceleration (Malkov et al., 2010). However, a complete and self-consistent picture of CR acceleration, spanning the initial generation of magnetic fields through their subsequent amplification and the resulting particle acceleration, remains incomplete. These magnetic fields are expected to arise from the interplay, competition, and nonlinear evolution of several instabilities, notably the Bell (Bell, 2004) and firehose instabilities. These interactions happen across a wide range of scales, making both analytical and numerical investigations challenging. Our work aims at providing a tentative picture of such interplay through a simplified analytical and numerical framework, offering insight into mechanisms responsible for large-scale magnetic-field amplification.\nWe present kinetic simulations performed with the SMILEI particle-in-cell (PIC) code (Derouillat et al., 2018) to study the nonlinear evolution of the Bell and firehose instabilities in counter-streaming monoenergetic proton beams, used here as a minimal model for cosmic-ray–driven turbulence. By varying the beam density ratio, we probe regimes where either the Bell or the firehose instability dominates.\nOur results constitute, to our knowledge, the first observation in fully kinetic PIC simulations of nonlinear self-coupling of the dominant linear mode, leading to growth of large-scale magnetic fields at twice the linear growth rate, in agreement with earlier magnetohydrodynamic simulations (Bykov et al., 2013). We develop an analytical interpretation of this behavior based on the growth of density perturbations, which drive nonlinear electrostatic modes that subsequently feed back into electromagnetic modes. This mechanism provides a potential pathway for the generation of large-scale magnetic fluctuations required to approach Bohm diffusion regimes for CRs, and thus for efficient particle acceleration in astrophysical shocks.\n\nAuthor\nMaxence Tabary (Sorbonne University)\n\nCo-authors\nProf. Andrea Ciardi (Sorbonne University)\nDr Anna Grassi (Sorbonne University)\nDr Arno Vanthieghem (CNRS)"},{"id":"de4bc863-640a-44df-968b-c21021c9b546","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:50:00+00:00","end":"2026-07-02T09:05:00+00:00","s":"0950","e":"1005","name":"O.417 F.J. Morales Calero: Single-step scalable synthesis of high-quality graphene powder by plasma technology: from carbon-based precursors decomposition to high-impact applications","loc":"Tinto: Level 0","track":"LTDP: Plasma processing and applications II","type":"Session","details":"None of the traditional methods for graphene synthesis offers a single-step, low-cost approach. However, plasma technology represents a significant advance in this field. Microwave plasma torches (i.e. TIAGO torch) exhibit high reactivity, being capable of inducing precursors decomposition reactions with high efficiency (~100%), surpassing traditional chemical processes.\n\nSince it is deeply engaging to optimize this technique, a process refinement has been conducted based on two key parameters: the amount of ethanol considered [1] and the applied power [2]. It was discovered that microwave power is the optimal parameter for upscaling the process, without compromising material properties and quality.\n\nRecently, plasma-synthesized graphene has been successfully used in different high-impact applications. It has been demonstrated that the porosity properties of this graphene [3] can fight the shuttle effect, a phenomenon taking place in Li-S batteries resulting in a loss of battery capacity and faster degradation of performance over time. The integration of graphene in sulfur-graphene composite cathode has been proven to be a suitable strategy for the design of Li-S batteries with ultralong cycle life [4].\n\nIn addition, looking for imparting anti-corrosion properties, two plasma-assisted methodologies for applying graphene covertures to metallic surfaces have been developed. Surfaces characterization reveals high surface coverage and superhydrophobic behavior, a relevant milestone since water is a well-known corrosion inducing agent. Despite low adhesion to surfaces, some residual hydrophobic effects persisted post-graphene removal, evidencing a remaining surface modification. These results position microwave plasmas as an industrially viable technology for the development of new applications.\n\n[1] A. Casanova et al, Fuel Processing Technology, 212 (2021) 106630.\n[2] J. Toman et al, Fuel Processing Technology, 239 (2023) 107534.\n[3] F. J. Morales-Calero et al, Chemical Engineering Journal., 498 (2024) 155088.\n[4] J.M. Blázquez-Moreno et al, Journal of Power Sources, 630 (2025) 236173.\n\nAcknowledgements: This work was supported by projects PID2023-147436OA-I00 and PID2023-147080OB-I00 funded by MICIU/AEI /10.13039/501100011033 and by FEDER, UE. The predoctoral contract of F.J. Morales-Calero was granted by MOD-2.2 from Plan Propio de la Universidad de Córdoba (2020). A. Benítez acknowledges financial support from the Ramón y Cajal Programme (RYC2024-050480-I).\n\nAuthors\nDr Almudena Benítez (Instituto Químico para la Energía y el Medioambiente (IQUEMA), Departamento de Química Inorgánica e Ingeniería Química, Universidad de Córdoba (Spain).)\nDr Andrés María Raya (Laboratorio de Innovación en Plasmas (LIPs), Departamento de Física, Universidad de Córdoba (Spain).)\nMr Antonio Cobos-Luque (Laboratorio de Innovación en Plasmas (LIPs), Departamento de Física, Universidad de Córdoba (Spain))\nDr Dalibor Všianský (Department of Geological Sciences, Faculty of Science, Masaryk University, Brno (Czech Republic).)\nDr Francisco Javier Morales-Calero (Laboratorio de Innovación en Plasmas (LIPs), Departamento de Física, Universidad de Córdoba (Spain))\nDr Jesús Manuel Blázquez-Moreno (Instituto Químico para la Energía y el Medioambiente (IQUEMA), Departamento de Química Inorgánica e Ingeniería Química, Universidad de Córdoba (Spain).)\nDr Jorge Alberto Alcusón (Laboratorio de Innovación en Plasmas (LIPs), Departamento de Física, Universidad de Córdoba (Spain))\nDr José Muñoz (Laboratorio de Innovación en Plasmas (LIPs), Departamento de Física, Universidad de Córdoba (Spain).)\nDr María Dolores Calzada (Laboratorio de Innovación en Plasmas (LIPs), Departamento de Física, Universidad de Córdoba (Spain))\nDr Norma Yadira Mendoza-González (Laboratorio de Innovación en Plasmas (LIPs), Departamento de Física, Universidad de Córdoba (Spain))\nDr Ondrej Jašek (Department of Plasma Physics and Technology, Faculty of Science, Masaryk University, Brno (Czech Republic).)\nDr Rocío Rincón (Laboratorio de Innovación en Plasmas (LIPs), Departamento de Física, Universidad de Córdoba (Spain))\nDr Álvaro Caballero (Instituto Químico para la Energía y el Medioambiente (IQUEMA), Departamento de Química Inorgánica e Ingeniería Química,"},{"id":"b96a74b1-24ef-4b2a-bcd0-5b8a9201b8c4","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:50:00+00:00","end":"2026-07-02T09:05:00+00:00","s":"0950","e":"1005","name":"O.404 L. Édes: Impact of edge cooling on current profile evolution and resistive wall tearing stability in JET","loc":"Sidlaw: Level +3","track":"MCF: Transport & high confinement regimes","type":"Session","details":"Edge cooling is frequently observed in tokamak plasmas prior to disruptions and can lead to significant changes in the current density profile, potentially destabilizing magnetohydrodynamic (MHD) activity [1]. Understanding whether such cooling can drive the plasma toward instability, and whether/how the presence of a resistive wall affects this process, is essential for interpreting pre-disruption dynamics and improving disruption prediction.\nIn this work, we first investigate linear MHD stability in the presence of a resistive wall using a newly developed linear solver [2], with particular emphasis on resistive wall tearing modes (RWTMs). These modes correspond to tearing instabilities that would be stable in the presence of an ideal wall but become unstable in the no-wall limit [3]. The results from this fast solver are benchmarked against extended MHD simulations using JOREK–STARWALL and CASTOR3D, providing cross-code validation and establishing confidence in the modeling of RWTMs. This framework enables a systematic study of the effect of current density profile and resistive wall on MHD stability.\nBuilding on this, we further investigate a realistic JET plasma in which edge cooling was experimentally observed prior to a disruption [4] via simulations with the JOREK-STRAWALL code. The simulations are initialized by modeling the edge cooling via impurity radiation and subsequently track the evolution of the current density profile and the onset of MHD activity. Experimental measurements indicate the presence of unusual and intermittent MHD signatures prior to the disruption, motivating a detailed numerical investigation of the underlying dynamics. In this work, we aim to assess whether edge cooling can modify the current profile sufficiently to move the plasma into an unstable regime and to identify the role of the resistive wall in the resulting MHD activity. In particular, by comparing simulated behavior with experimental observations, this work seeks to clarify whether RWTMs provide a consistent interpretation of the observed pre-disruption dynamics in the JET discharge.\nReferences\n[1] G. Pucella et al., Nuclear Fusion 61 (2021): 046020\n[2] L. Édes et al., EFTC 2025\n[3] H. Strauss et al., PPCF 65 (2023): 084002\n[4] H. Strauss et al., PoP 28 (2021): 032501\n\nAuthor\nLili Édes (EPFL SPC)\n\nCo-authors\nDr Jonas Punchmayr (IPP Garching)\nDr Jonathan Graves (EPFL SPC)\nMengdi Kong (Swiss Plasma Center, EPFL)"},{"id":"8b01cc7b-7331-4e15-9a60-300a034c7f76","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T08:55:00+00:00","end":"2026-07-02T09:10:00+00:00","s":"0955","e":"1010","name":"O.403   F. Eriksson: Integrated core-SOL simulations of H-mode access in ITER SRO scenarios","loc":"Pentland Suite: Level +3","track":"MCF: High beta / beta-pol","type":"Session","details":"The start of research operation (SRO) in ITER will explore H-mode operation as well as commission control and protection systems including ELM mitigation systems [1]. For successful commissioning of the ELM mitigation systems, operation in stable ELMy H-mode is required. To inform the development of the plasma control system, fully integrated core, edge, scrape-off layer (SOL), divertor simulations are performed with the JINTRAC suite of codes analysing the access to ELMy H-mode across SRO scenarios. The scenarios studied are 5MA/2.65T and 7.5MA/2.65T deuterium plasma including the L-mode, L-H transition and H-mode ELMy phases. A range of densities are analysed, and deuterium gas puff is used to fuel the plasma to the specified Greenwald density fraction with the potential of adding pellets where gas fuelling is insufficient to provide the required density [2].\nSimulations performed so far show that even for the lower current scenario of 5MA a 60% Greenwald density fraction plasma is marginal for pedestal development using 30MW EC assuming that the ITPA 2008 scaling law holds. Heating schemes available during SRO operation consists of 40MW of ECRH and 10 MW ICRH [1]. At the same current a high-density plasma of 80% Greenwald density fraction needs 40MW EC together with additional IC to access a good quality H-mode.\n\nAuthor\nFrida Eriksson\n\nCo-authors\nAlberto Loarte\nAlexei Polevoi\nElina Militello Asp\nDr Emmi Tholerus\nDr Florian Koechl\nGuillermo Suarez Lopez\nDr James Simpson\nDr Luca Garzotti\nDr Peter De Vries\nDr Romain Futtersack\nDr Simon Pinches\nSun Hee Kim\nTimo Ravensbergen\nVassili Parail\nDr Xavier Bonnin"},{"id":"57904a23-3aba-4793-be20-12b85bf51566","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:05:00+00:00","end":"2026-07-02T09:20:00+00:00","s":"1005","e":"1020","name":"O.413 V. Tikhonchuk: Stimulated scattering of a spectrally broadened laser beam in inhomogeneous plasma","loc":"Fintry: Level +3","track":"BPIF: Coronal plasma and laser-plasma instabilities","type":"Session","details":"Spectral smoothing of laser pulses is considered a promising approach for controlling parametric instabilities and improving laser plasma coupling in inertial fusion research. A limited number of experiments with broadband lasers and contradicting theoretical results motivate a more general assessment of the pump bandwidth on the excitation of parametric instabilities in a spatially inhomogeneous plasma. Here, we report on the studies of the forward and backward scattering in inhomogeneous plasma by comparing a monochromatic pump, a phase-modulated pump, and a pump with random phase modulations. In the time domain, phase-modulated and random pumps produce a qualitatively similar effect, reducing the temporal growth rate approximately inversely proportional to the bandwidth, in agreement with theoretical predictions following from the random phase approximation. Significant differences are observed, however, in the case of convective amplification in a spatially limited pump and in an inhomogeneous plasma. The level of saturation of the scattered light is enhanced and is associated with large temporal and statistical fluctuations if the pump correlation time is larger or comparable to the instability growth time. These fluctuations are associated with high-intensity spikes or groups of spikes in the pump field. The one-dimensional analysis of parametric instabilities is extended to speckled laser beams, assuming that each speckle generates scattered light independently. The laser bandwidth can suppress scattering from low-intensity speckles, but the high-intensity speckles may still dominate the response. A criterion for the bandwidth suppression of stimulated scattering in a speckled beam is proposed.\nReferences:\nV. Tikhonchuk, D. Blackman, P. Loiseau, and C. Ruyer, Effect of spectral bandwidth on the stimulated scattering of laser beams in plasma, Phys. Plasmas 33, 012107 (2026)\n\nAuthor\nProf. Vladimir TIKHONCHUK (UNIVERSITY OF BORDEAUX)\n\nCo-authors\nDr Charles Ruyer (CEA, DAM, DIF)\nDr David Blackman (Extreme Light Infrastructure ERIC)\nDr Pascal Loiseau (CEA, DAM, DIF)"},{"id":"e16f9b6f-1be1-4aec-9460-d8e64364e50e","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:05:00+00:00","end":"2026-07-02T09:20:00+00:00","s":"1005","e":"1020","name":"O.410  T. Seebaruth: Experimental Investigation and Numerical Multi-scale Modelling of Weakly Collisional Shocks","loc":"Moorfoot: Level 0","track":"BSAP : Astrophysical plasmas & Laboratory Astrophysics","type":"Session","details":"Shocks are fundamental drivers of energy dissipation in both astrophysical and laboratory plasmas. A quantitative understanding of how shock dynamics evolve as particle collisions become infrequent, transitioning from collisional to collisionless regimes, remains a frontier problem. Even in the collisional regime, the thermal precursor acts as a critical region where non-thermal effects may emerge [1, 2]. Non-thermal ions can counter-stream against the bulk flow, modifying the shock structure and potentially driving kinetic instabilities.\nWe present high-resolution, time-resolved measurements of shock profiles with Mach numbers ranging from 3 to 5, obtained from experiments at the LULI2000 and GEKKO XII facilities. Using collective optical Thomson scattering, we have mapped the evolution of electron and ion temperatures and densities to resolve both the forward and a reverse shock with unprecedented detail. To analyze these data, we developed a Bayesian analysis framework that self-consistently accounts for multiple ion species, resolving their individual temperatures and relative fractions.\nTo interpret the experimental results, we employ a dual-modeling approach: extended-MHD[3] simulations to capture large-scale plasma dynamics and fully kinetic particle-in-cell simulations[4] to isolate the underlying microphysics. Our results reveal a broad forward shock transition and significant interpenetration between the piston and the background plasma in the downstream region. Furthermore, we observe strong heating of the carbon population immediately ahead of the forward shock, suggesting a significant modification of the energy partition across the shock front driven by kinetic ion behavior.\nReferences:\n[1] Vidal, F. et al. Phys. Fluids B (1993).\n[2] Rinderknecht, H. G. et al. Phys. Rev. Lett. 120 (2018).\n[3] Fryxell, B. et al. Astrophys. J. Suppl. Ser. 131 (2000).\n[4] Derouillat, J. et al. Comput. Phys. Commun. 222, 351–373 (2018).\n\nAuthors\nAndrea Ciardi (Sorbonne University)\nDr Angelos Triantafyllidis ((Laboratoire pour l’Utilisation des Lasers Intenses)\nAnna Grassi (Sorbonne University)\nDr Bruno Albertazzi ((Laboratoire pour l’Utilisation des Lasers Intenses))\nMr Diego Oportus ((Laboratoire pour l’Utilisation des Lasers Intenses))\nDr Jean-Raphaël Marquès ((Laboratoire pour l’Utilisation des Lasers Intenses)\nProf. Roch Smets (Sorbonne University)\nProf. Takayoshi Sano (Institute of Laser Engineering, Osaka)\nThershi Seebaruth (Sorbonne University)\nYouichi Sakawa (Institute of Laser Engineering, Osaka University, Osaka, Japan)"},{"id":"ff884ecb-4bd8-4ce8-be84-336a2780e9e4","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:05:00+00:00","end":"2026-07-02T09:20:00+00:00","s":"1005","e":"1020","name":"O.418 R. Dange: Bridging plasma microphysics to macroscopic ammonia synthesis with machine learning","loc":"Tinto: Level 0","track":"LTDP: Plasma processing and applications II","type":"Session","details":"Low-temperature plasmas enable electron-driven plasma NH3 synthesis, yet a quantitative understanding of microphysical characteristics relative to reactor-scale performance remains elusive. Building on a systematic experimental N₂–H₂ dataset spanning varied reactor configurations and operating conditions, we developed a machine-learning-based framework that links plasma microphysics to macroscopic ammonia synthesis, using electrical diagnostics (Lissajous analysis, micro-discharge statistics), optical emission spectroscopy, and colorimetric NH3 quantification. These charge and excitation descriptors, along with varied operational conditions, were used to train a Random Forest model. The model reveals that total charge per pulse and median micro-discharge energy are the most informative descriptors of the plasma characteristics, which are governed by barrier thickness, gap geometry, voltage, and plasma on time, altering the reactor capacitance and electric field. Further, it is observed that when the discharge gap is fixed, increasing barrier thickness reduces the total micro discharge charge but increases the median energy. On the contrary, fixing the electrode gap and increasing the barrier thickness decreases both total charge and median energy, producing fewer, less energetic filaments. Further, the model showed that the resulting total charge per pulse is the dominant predictor of NH(A–X) and H Balmer intensities intern related to ammonia synthesis. Thus, these insights translate into mechanistic design rules: reducing the discharge gap or increasing barrier thickness increases reactor capacitance and micro discharge energy, which boosts NH(A–X)/H emission and NH₃ concentration but at the expense of energy efficiency, whereas higher total flow may produce less power-dense micro discharges, improving energy efficiency. Overall, this data-driven framework shows how machine learning can deconvolute complex multidimensional plasma behaviour into physically interpretable guidelines for optimising non-thermal plasma reactors for sustainable, decentralised ammonia synthesis.\nThis work builds on Ref. [1].\n\nReference:\n1. Dange, R., Sinausia, D., Bekkerman, A., Leybo, D. & Vogt, C. Systematic evaluation of plasma and reactor parameters in non-thermal dielectric barrier discharge plasma ammonia synthesis. Green Chem. 28, 1234–1256 (2026).\n\nAuthor\nRutvija Dange\n\nCo-authors\nDaniel Sinausia\nAnatoly Bekkerman\nDenis Leybo\nCharlotte Vogt"},{"id":"0760b48e-7106-4b91-8711-3c3132c0e1c0","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:05:00+00:00","end":"2026-07-02T09:20:00+00:00","s":"1005","e":"1020","name":"O.405 G. Huijsmans: Gyrokinetic electrostatic ITG-TEM simulation of H-mode plasmas in COMPASS-like geometry","loc":"Sidlaw: Level +3","track":"MCF: Transport & high confinement regimes","type":"Session","details":"Considerable progress has been made in modelling edge turbulence and the L-H transition using fluid and kinetic approaches. However, the gyrokinetic simulation of a complete transition from steady-state\nL-mode turbulence to a quasi-stationary H-mode remains a challenge. To simulate the transport properties of the H-mode pedestal, an alternative approach, avoiding the L-H transition is to start the simulation with profiles (density, temperature, current density) approximating the expected H-mode profiles. This approach has, for example, been successfully applied in [1] using the GRILLIX drift-fluid code. In this paper, we apply the gyro-kinetic model from the JOREK code (named JOREK-GK) to obtain quasi steady-state H-mode solutions.\nThe JOREK-GK code builds on the C1 finite element discretisation and the discrete particle module to implement the well-established electro-static gyrokinetic model including ions and electrons. The conservative collision model from [2] is included, together with a small-angle scattering model for the e-i collisions. In this paper, only ion-ion and small angle electron-ion collisions are retained. A simple model for the divertor sheath is also used. This implementation allows global, full-f, gradient driven, electrostatic simulations in x-point geometry.\nSimulations are initialised with H-mode density and pressure profiles in COMPASS-like geometry, as in [3], followed by an axisymmetric phase with collisions, i.e. without turbulence, to establish the neoclassical flows. Adding the toroidal harmonics allows to obtain a quasi-steady H-mode solution including ITG-TEM turbulence, and the stabilisation in the pedestal. The pedestal width is ~1.5cm, in reasonable agreement with experimental observations [3]. The resulting radial electric field is ~36 kV/m. The reduced turbulent transport inside the pedestal is associated with both a decrease in fluctuation amplitudes by a factor of 2–3 and a comparable modification of the cross-phase between pressure and electrostatic potential fluctuations, leading to a local reduction of turbulent transport by about an order of magnitude. In absence of MHD and kinetic ballooning (KBM) modes in the electrostatic model, the pedestal height grows well above the experimental value. A medium-n discrete mode, localised within the pedestal and initially at low amplitude, is found to grow and eventually trigger a rapid collapse of the pedestal radial electric field.\n\n[1] W. Zholobenko et al., Nucl. Fusion 64 (2024) 106066\n[2] P Donnel et al., Plasma Phys. Control. Fusion 63 025006 (2021)\n[3] R Pánek et al 2016 Plasma Phys. Control. Fusion 58 014015\n\nAuthors\nDr Guido Huijsmans (IRFM/CEA)\nJOREK Team\nPeter Donnel (CEA/IRFM)"},{"id":"ea4ab98c-d46b-4ce9-bee8-29902e29590c","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:10:00+00:00","end":"2026-07-02T09:25:00+00:00","s":"1010","e":"1025","name":"O.408   T. Wilks: Record H-mode pedestal pressure in high triangularity, high elongation discharges leveraging the new “Shape and Volume Rise” divertor on DIII-D","loc":"Pentland Suite: Level +3","track":"MCF: High beta / beta-pol","type":"Session","details":"A new divertor geometry enabling high shaping on DIII-D has been leveraged to achieve the highest pressure pedestals observed to date on the device. Peeling-ballooning model calculations suggested increased plasma triangularity and volume would allow the pedestal stability boundary to develop a broad channel of operation at high density and pressure simultaneously, leading to a state of a low collisionality pedestal top at high density. This state is rarely achieved in present devices and represents a path for significant gains in future devices, highlighting it as a key challenge for core-edge integration physics.\n\nELMy H-mode, QH-mode, and RMP ELM suppressed regimes were developed to access high pedestal pressure through the Super H-mode channel, with each scenario exploration leading to novel pedestal physics insights. ELMy H-modes and co-Ip QH-modes resulted in the highest pedestal pressure and core performance observed to date in DIII-D, yielding Pped of 37-40kPa, roughly 2-4 times typical ELMy H-mode values, and Ptau/IaB of 11-14, about twice typical values.\n\nCounter-Ip QH-mode discharges reached record QH densities of ~1.4x1020m-3. QH-mode persisted as the density was raised, shifting from the peeling to ballooning stability boundary. This phenomenon is likely due to significantly decoupling of low-n peeling and intermediate/high-n ballooning instabilities as a result of the strong shaping.\n\nRMP experiments established full ELM suppression in the SVR configuration at moderate plasma current (1.2–1.6 MA) with odd-parity n=3 fields. These discharges sustained high performance (βN up to 2.8, H98 up to 2, and E up to 0.4 s) with total pedestal pressures up to 26 kPa and extended suppression windows (q95 ≈ 4.2–5.3). Optimization of dRsep and coil configuration enabled stationary ELM-free operation close to double-null shapes, highly relevant for future pilot plant designs.\n\nThe pedestal width in these experiments for all three regimes did not conform to the EPED1 width scaling typical of H-modes in DIII-D and other devices and instead were found to be consistent with n=60 ballooning mode critical gradient as a proxy for the KBM.\n\nThis work was supported in part by the US Department of Energy under DE-FC02-04ER54698, DE-SC0014264, DE-AC02-09CH11466, DE-AC05-00OR22725, DE-SC0019302, DE-AC52-07NA27344, DE-SC0022270, and DE-FG02-04ER54761.\n\nAuthors\nDr Amanda Hubbard (MIT PSFC)\nDr Andreas Holm (LLNL)\nDr Andrew Oak Nelson (CU)\nDr Chris Holcomb (LLNL)\nDr Daisuke Shiraki (ORNL)\nDr Darin Ernst (MIT PSFC)\nDr David Eldon (General Atomics)\nDr Francesca Turco (CU)\nDr Huiqian Wang (General Atomics)\nMr Jeremy Fleishhacker (MIT PSFC)\nDr Jerry Hughes (MIT PSFC)\nDr Julio Balbin-Arias\nDr Kyungjin Kim (ORNL)\nDr Matthias Knolker (General Atomics)\nDr Morgan Shafer (ORNL)\nDr Philip Snyder (Commonwealth Fusion Systems)\nDr Qiming Hu (PPPL)\nDr Raul Gerru (MIT PSFC)\nDr Robert Wilcox (ORNL)\nDr Sophie Gorno (ORNL)\nTheresa Wilks (MIT PSFC)\nTom Osborne (General Atomics)"},{"id":"0edd97b0-189f-4a02-aa22-00af397f559d","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:20:00+00:00","end":"2026-07-02T09:35:00+00:00","s":"1020","e":"1035","name":"O.414 G. Bouchard: Mitigation of Stimulated Raman Scattering and Stimulated Brillouin Scattering in kinetic regime using Smoothed Broadband Laser","loc":"Fintry: Level +3","track":"BPIF: Coronal plasma and laser-plasma instabilities","type":"Session","details":"High-energy laser beams used in inertial confinement fusion (ICF) experiments are subject to phase aberrations as they propagate through numerous optical elements. These aberrations induce large non-uniformities at the focal spot and significant shot-to-shot variations, which can compromise implosion symmetry. While Random Phase Plates (RPP) are routinely employed to improve beam stability, this spatial smoothing technique inherently creates small-scale hot spots known as speckles. These speckles strongly affect laser-plasma interaction by seeding deleterious instabilities, specifically Stimulated Brillouin Scattering (SBS) and Backward Stimulated Raman Scattering (SRS). These processes lead to potential optics damage, target pre-heating via supra-thermal electrons, and a reduction in the energy effectively delivered to the capsule. To mitigate these effects, the speckle coherence time, tc​, must be shorter than the growth rate of the instabilities. Currently, standard Smoothing by Spectral Dispersion (SSD) appears insufficient to reach this regime. Using 2D and 3D Particle-In-Cell (PIC) simulations optimized for CPU and GPU architectures, we investigate several schemes to break spatial and temporal coherence in the kinetic regime. We focus on Broadband Laser configurations and the Induced Spatial Incoherence (ISI) method. Our results demonstrate that while reducing SBS is achievable, certain configurations can dramatically increase SRS, highlighting limitations of using \"moderate bandwidth\" approaches.\n\nAuthors\nGuillaume BOUCHARD (CEA/DAM/DIF)\nP.E. Masson-Laborde (CEA , DAM, CEA-DIF, F-91297 Arpajon (France))"},{"id":"f6d2eb75-8e96-415a-958a-ea9445ea2a94","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:20:00+00:00","end":"2026-07-02T09:35:00+00:00","s":"1020","e":"1035","name":"O.411  T  Vincent: Experimental characterisation of suppressed thermal conduction in weakly collisional, magnetised plasma","loc":"Moorfoot: Level 0","track":"BSAP : Astrophysical plasmas & Laboratory Astrophysics","type":"Session","details":"Classical transport theory predicts that, in a magnetised, collisional plasma, the heat flux parallel to magnetic field lines is given by Spitzer’s theory of heat conduction for unmagnetised plasmas. Numerous recent theoretical and computational studies have called this prediction into question for weakly collisional magnetised plasmas in which thermal pressure dominates magnetic pressure (so-called high-β plasmas). Such plasmas, notable examples of which include the intra-cluster medium of galaxy clusters and inertial-confinement-fusion deuterium-tritium hotspots, are thought to be susceptible to a host of anisotropy-driven microinstabilities that can suppress parallel heat conduction. Various attempts have been made to construct revised theories of heat conduction in such plasmas, relying on kinetic simulations, but there is a lack of experimental data to benchmark them. In this talk, we report a new experiment at the Orion Laser Facility in which the temporal evolution of the temperature in a high-β, weakly collisional plasma is primarily dependent on the magnitude of the thermal conductivity along its laminar magnetic field. This temperature evolution, along with the plasma’s density and magnetic field, is characterised with a suite of plasma diagnostics: x-ray spectroscopy and imaging, and proton radiography. Our data indicate significant suppression of thermal conduction compared to predictions from Spitzer once stochastic magnetic fluctuations develop. These results have important implications for transport modelling in both astrophysical and laser plasma physics.\n\nAuthor\nThomas Vincent (University of Oxford)\n\nCo-authors\nDr Archie Bott (University of Oxford)\nHeatCondMagPlasma collaboration\nProf. Petros Tzeferacos (University of Rochester)\nDr Tom Hodge (AWE)"},{"id":"dfb6db5b-f2f7-4a1e-aa43-6b2365a5a9f3","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:20:00+00:00","end":"2026-07-02T09:35:00+00:00","s":"1020","e":"1035","name":"O.419 R. Fiorotto: Control the intensity of the induced flow in a liquid by a dual-frequency APPJs","loc":"Tinto: Level 0","track":"LTDP: Plasma processing and applications II","type":"Session","details":"Dual-frequency atmospheric pressure plasma jets (APPJs) represent a promising method to manipulate the ion transportation and the plasma propagation on a surface [1]. Despite the potential shown by these unique devices, the fundamental mechanisms through which such systems interact with a liquid substrate and govern the induced liquid flow have not been investigated yet. In this work, we implemented a coaxial dual-frequency configuration employing an upstream high-frequency electrode (HF) at 17kHz and a downstream radio-frequency (RF) electrode at 27.12 MHz [1].\nWithin this configuration, the plasma discharge is mainly sustained by the RF Ω-mode ionisation regime at twice the RF oscillation frequency (54 MHz). Concomitantly, the HF high-voltage electrode modulates the thickness of the sheath at the liquid interface, triggering the RF γ-regime through secondary electron emission. Time-resolved measurements of the electrode voltage, surface charge on the substrate and optical emission above the liquid substrate demonstrated the transition between the two RF ionisation modes.\nTo quantify the electrohydrodynamic forces (EHD) within the liquid phase, Particle image velocimetry (PIV) was performed using graphene oxide (GO) as tracers in solutions of varying conductivity.\nA significant finding in our work has been revealed by comparing different operational modes. Pulsed HF signal combined with continuous RF excitation led to a discharge with electrical features dominated by the HF component, while the upward induced flow observed is consistently similar to the RF-only operation. These flows remain lower compared to the non-pulsed dual-frequency condition. Moreover, evaporation rate measurements exhibit a strong correlation with the applied RF power, opening possibilities for a precise flow control by reducing the applied RF power combined with micro- or nanosecond pulse generation techniques.\n\n[1] Patelli A, Scaltriti S G, Popoli A, Martines E and Cristofolini A 2025 Plasma-substrate interaction in a dual frequency APPJ Plasma Sources Sci. Technol. 34 025010\n\nAuthor\nMr Riccardo Fiorotto (Department of Physics and Astronomy, University of Padova, Via Marzolo 8, 35131, Italy)\n\nCo-authors\nDr Ehsan Shakerinsab (Department of Physics and Astronomy, University of Padova, Via Marzolo 8, 35131, Italy)\nMr Alessandro Andreetto (Department of Physics and Astronomy, University of Padova, Via Marzolo 8, 35131, Italy)\nProf. Alessandro Patelli (Department of Physics and Astronomy, University of Padova, Via Marzolo 8, 35131, Italy)"},{"id":"e6487ee0-8456-4a7a-8b2b-9094abd75969","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:20:00+00:00","end":"2026-07-02T09:35:00+00:00","s":"1020","e":"1035","name":"O.406 V.K. Zotta: Core-edge-SOL modelling of density and fuel mix control in JET high current and high-performance baseline plasmas in D, T and D-T","loc":"Sidlaw: Level +3","track":"MCF: Transport & high confinement regimes","type":"Session","details":"The experiments performed at the Joint European Torus (JET) in the final years of operation give the unique opportunity to investigate future reactor relevant issues. In preparation to the second deuterium–tritium campaign (DTE2) JET team developed a high-current baseline scenario capable of sustaining high performance for 5 s. The scenario was developed in D plasmas through a stepwise increase in plasma current (2.5-4.0 MA), optimised for high performance and repeatability, while minimising particle throughput. However, when reproduced in T and D-T mixtures, with Ip=3.5 MA and BT=3.3 T, the discharge duration was limited to 2–3 s due to weakened ELM activity.\nThe modelling presented starts from predictive core simulations of these D, T and D-T pulses, performed with JINTRAC equipped with the reduced first-principle based transport model QuaLiKiz. Plasma kinetic profiles, core performance as well as the isotope mixture are well reproduced with a realistic impurity mixture of beryllium, nickel and tungsten. Using COCONUT we extend the simulation domain from core-pedestal to the Scrape-off layer imposing the nominal gas puffing throughput to investigate the role of fuelling in achieving a 50-50 D-T mixture via T gas, D pellets, and neutral beam injection. We are presenting a novel framework of validation with the state-of-the-art models that are being used in ITER re-baselining with D-T isotope segregation and impurities (including W). COCONUT modelling results across isotope mixtures reveal a reduction of core ionisation sources in T and D-T (particularly at low particle throughput) consistent with the experimentally observed weakened ELM activity. Moreover, experiments performed during DTE3 confirmed within the same plasma scenario the possibility of sustaining the pulse in D-T with higher gas puff nominal throughput. Despite the critical importance of density and fuel mix control for future devices, these aspects remain only sporadically explored due to large uncertainties in edge particle sources. The JET baseline scenario offers a unique opportunity to address these ITER relevant conditions (e.g. small compound ELMs, competition between pellet and gas puffing), as it employs multiple fuelling channels with different isotopes, enabling the measured isotope ratio to serve as a constraint for the analysis.\n\nAuthor\nVito Konrad Zotta (Sapienza University of Rome)\n\nCo-authors\nDr Stefano Gabriellini (UK Atomic Energy Authority)\nLuca Garzotti (UKAEA)\nCristiano Leoni (Sapienza University of Rome, Rome, Italy)\nRenato Gatto (Università La Sapienza, Roma, Italy)\nFulvio Auriemma (Consorzio RFX (CNR, ENEA, INFN, University of Padova, Acciaierie Venete), Padova, Italy; Institute of Plasma Science and Technology, CNR, Padova, Italy)\nL Frassinetti (Fusion Plasma Physics, EECS, KTH)\nEmmanuele Peluso (Università degli Studi di Roma Tor Vergata, Italy)\nGianluca Pucella (ENEA)\nFernanda Rimini (UKAEA)\nDavide Silvagni (IPP Garching)\nDirk Van Eester (Laboratory for Plasma Physics LPP-ERM/KMS, Brussels, Belgium)\nNatalia Wendler (Institute of Plasma Physics and Laser Microfusion, Hery 23, 01-497 Warsaw, Poland)\nJET Contributors (See the author list of C.F. Maggi et al., Nucl. Fusion 64, 112012, 2024)\nEUROfusion Tokamak Exploitation Team (See the author list of E. Joffrin et al., Nucl. Fusion 64, 112019, 2024)"},{"id":"95fb002e-604f-4ba2-a9ac-8908e421ce1d","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:35:00+00:00","end":"2026-07-02T09:50:00+00:00","s":"1035","e":"1050","name":"O.415 L. Gremillet: A unified description of spatiotemporal ultrarelativistic beam-plasma instabilities under the quasistatic approximation","loc":"Fintry: Level +3","track":"BPIF: Coronal plasma and laser-plasma instabilities","type":"Session","details":"Plasma streaming instabilities driven by ultrarelativistic charged particle beams in dense ambient plasmas play a central role in astrophysical and laboratory settings [1]. However, their numerical modeling is hampered by the large disparity in dynamical scales between the beam and plasma particles.\n\nHere, we leverage the quasistatic approximation (QSA)–widely used in the context of plasma accelerators [2]–to develop a unified model of unstable modes in the realistic case where the beam continuously encounters fresh plasma at its leading edge. Unlike previous works [3,4], we do not adopt the slowly varying envelope approximation (SVEA). This allows us to capture the unstable modes developing throughout the beam region, and thus to clarify the interplay of the current filamentation (CFI) and oblique-two-stream (OTSI) instabilities, under conditions where standard theory predicts dominance of the OTSI [1]. By contrast, we find that spatiotemporal CFI modes prevail near the front–precisely where the SVEA breaks down–and are superseded by the spatiotemporal OTSI further away.\n\nWe benchmark our theory against high-resolution particle-in-cell (PIC) simulations and QSA-based PIC (QS-PIC) simulations performed using our newly developed QuaSSis code [5]. We demonstrate that the dramatic computational speedup offered by the QS-PIC method makes it possible to probe extreme beam-plasma interactions, such as those expected in the context of blazar jets.\n\nFinally, we extend our theory to collisional systems. We show analytically that the collisionality of the background plasma entails a more complex instability dynamics, involving a succession of spatiotemporal and temporal variants of the CFI and OTSI, which is well reproduced by low-noise collisional QS-PIC simulations.\n\nReferences\n[1] A. Bret et al., Phys. Plasmas 17, 120501 (2010).\n[2] P. Sprangle et al., Phys. Rev. A 41, 4463 (1990).\n[3] V. B. Pathak et al., New J. Phys. 17, 043049 (2015).\n[4] P. San Miguel Claveria et al., Phys. Rev. Res. 4, 023085 (2022).\n[5] Q. Labro et al., arXiv:2506.18567v1 (2025).\n\nAuthor\nLaurent Gremillet (CEA, DAM, DIF, F-91297 Arpajon, France)\n\nCo-authors\nFrederico Fiuza (GoLP/Instituto de Plasmas e Fusão Nuclear, Instituto Superior Técnico, Lisboa, Portugal)\n Luc Bergé (CELIA, Université de Bordeaux, CNRS, UMR 5107, 33405 Talence, France)\nMatteo Tamburini (Max-Planck-Institut für Kernphysik, Saupfercheckweg 1, D-69117 Heidelberg, Germany)\nPablo San Miguel Claveria (GoLP/Instituto de Plasmas e Fusão Nuclear, Instituto Superior Técnico, Lisboa, Portugal)\nQuentin Labro (CEA, DAM, DIF, F-91297 Arpajon, France)\nSébastien Corde (LOA, ENSTA Paris, CNRS, École Polytechnique, Institut Polytechnique de Paris, 91762 Palaiseau, France)\nXavier Davoine (CEA, DAM, DIF, F-91297 Arpajon, France)"},{"id":"3f31b3d4-40ae-42f7-89ac-ff66e4cbad8f","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:35:00+00:00","end":"2026-07-02T09:50:00+00:00","s":"1035","e":"1050","name":"O.407 K. Kirov: Particle transport modelling for D/T ratio control experiments in JET","loc":"Sidlaw: Level +3","track":"MCF: Transport & high confinement regimes","type":"Session","details":"This study presents particle transport modelling results for D/T ratio control experiments conducted during the JET DTE3 campaign [1]. Interpretative TRANSP and predictive JETTO simulations were performed to analyse the evolution of the D/T mixture [2] in these experiments [3]. Using simplified Bohm–gyroBohm-based transport models, the simulations successfully reproduced electron density, steady-state D/T ratio, and neutron rate evolution. However, during the transient phases the predicted D/T ratio responded to control requests faster than observed experimentally. Additional scenarios, including cases which could not be realised experimentally where gas injection and pellet sources were swapped, were also investigated, and the corresponding simulation results are discussed.\nThe findings in this study demonstrate that simple models and assumptions regarding D and T transport and sources can be successfully adopted to predictively model the behaviour of Real Time (RT) controllers for D/T ratio. Detailed modelling of the SOL and core across all channels is not required for such tasks. It has been demonstrated that a simplified approach can be effective, using (i) measured Te, Ti, (ii) not modelling the SOL physics, and (iii) adopting simplifying particle transport assumptions. This conclusion is crucial for developing numerical tools to test future controllers.\nIn general, the proposed approach for developing and testing real-time D/T controllers should be directly applicable to future conventional tokamaks, such as ITER, SPARC, and DEMO, where simplified assumptions about energy and particle transport are valid. For devices where the transport models require validation — such as STEP — applicability largely depends on the extent to which transport can be reasonably simplified. Regarding source terms, the proposed model appears broadly applicable. The simulations presented here indicate that particle sources from pellet injection and NBI can be reliably captured by the models employed in this work. However, for gas injection sources, the simplified treatment used in this study code may not be adequate for devices or scenarios characterized by significantly different SOL physics.\n[1] C. Maggi et al 2024 Nucl. Fusion 64 112012\n[2] K. K. Kirov et al 2025 Nucl. Fusion 65 (2025) 106016\n[3] M. Lennholm et al 2025 PRX Energy 4 023007\n\nAuthor\nKrassimir Kirov\n\nCo-authors\nM. Lennholm (UK Atomic Energy Authority)\nLidia Piron (University of Padova, Italy)\nD. Valcarcel (UK Atomic Energy Authority)\nMatteo Baruzzo (ENEA)\nMatthijs van Berkel (DIFFER)\nT. Bosman (DIFFER)\nL. Ceelen (DIFFER)\nPeter Fox (UKAEA)\nLuca Garzotti (UKEAA)\nB. Kool (DIFFER)\nJ. Mitchell (UK Atomic Energy Authority)\nH. Sun (UK Atomic Energy Authority)\nJET contributors\nEUROfusion Tokamak Exploitation Team"},{"id":"0c3911fa-ec81-4358-9aad-f5a0b0fe8e34","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T09:50:00+00:00","end":"2026-07-02T10:20:00+00:00","s":"1050","e":"1120","name":"***Thursday: Morning Refreshment Break***","loc":"Cromdale: Level -2","track":"","type":"Function","details":""},{"id":"c43ed1fc-b6b7-44bf-a1fb-474892248077","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T10:20:00+00:00","end":"2026-07-02T10:55:00+00:00","s":"1120","e":"1155","name":"Plenary Talks: I.410   J. Palastro - Laser-plasma interactions driven by flying-focus pulses","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"The flying focus refers to a family of techniques for creating laser pulses with dynamic focal points. The peak intensity of a flying-focus pulse can move independently of the group velocity—along, against, or transverse to the propagation direction—while maintaining a near-invariant profile over distances far exceeding a Rayleigh range. These features enable and enhance laser-plasma applications that benefit from a tunable velocity or an extended interaction length. This talk will summarize the concepts underlying flying-focus pulses, the conventional and plasma optics-based configurations used for their formation, and recent theoretical and experimental advances in their application to laser–plasma interactions. Applications to be discussed include laser wakefield acceleration, nonlinear Thomson scattering, free-electron lasing, direct laser acceleration, THz generation, and tests of vacuum polarization and radiation reaction.\n\nThis material is based upon work supported by the Department of Energy [National Nuclear Security Administration] under Award Number DE-NA0004144, the Office of Science under Award Numbers DE-SC0021057 and DE-SC0025497/SUB0000841, and the Air Force Office of Scientific Research under award number FA9550-24-1-0160.\n\nAuthor\nJohn Palastro (Laboratory for Laser Energetics)"},{"id":"31742ee7-ef02-46d6-a38b-37076669c279","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T10:55:00+00:00","end":"2026-07-02T11:30:00+00:00","s":"1155","e":"1230","name":"Plenary Talks: I.411   G. Zheng - Ultrarelativistic radiative spin-polarized plasmas","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"Ultrarelativistic radiative plasmas represent an extreme state of matter in which radiation reaction and high-energy gamma-ray emission play a central role. When an ultrarelativistic electron emits a gamma-ray photon, radiative spin-flip processes can induce electron spin polarization, implying that such plasmas may become intrinsically spin polarized. This introduces spin polarization as a new carrier of physical information beyond conventional charge and energy diagnostics. In this talk, we focus on the correlation between transient plasma dynamics and the associated spin-polarization signatures. By exploiting spin-polarization signals, we identify several nontrivial plasma phenomena, including asymmetric magnetic structures in laser-driven plasma channels [1], nonlinear filament dynamics driven by Weibel-like instabilities [2], the electron slingshot acceleration mechanism in relativistic collisionless shocks [3], and the emergence of spiral attractors in plasma phase space during magnetic reconnection [4].\n\n[1] Z. Gong, K. Hatsagortsyan, C. Keitel, PRL 127, 165002 (2021)\n[2] Z. Gong, K. Hatsagortsyan, C. Keitel, PRL 130, 015101 (2023)\n[3] Z. Gong, X. Shen, K. Hatsagortsyan, C. Keitel, PRL 131, 225101 (2023)\n[4] Z. Gong, K. Hatsagortsyan, C. Keitel, PRL 135, 045101 (2025)\n\nAuthor\nZheng Gong (Institute of Theoretical Physics, Chinese Academy of Sciences)"},{"id":"0d5d83af-cc82-4b28-909d-cda86b62decd","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T11:30:00+00:00","end":"2026-07-02T12:10:00+00:00","s":"1230","e":"1310","name":"Plenary Talks: I.412   T. Kluge - Seeing the Invisible: A decade of small angle x-ray scattering diagnostics at XFELs for high-intensity-laser plasmas","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"Understanding how matter behaves under extreme conditions is a central challenge in plasma physics, with implications ranging from laboratory astrophysics to fusion energy research. Over the past decade, small-angle X-ray scattering (SAXS) at X-ray free-electron lasers (XFELs) has emerged as a powerful diagnostic for studying laser-driven plasmas. Extreme states of matter are created when intense laser pulses rapidly heat and compress solid materials into dense, transient plasma conditions. Unlike traditional diagnostics, SAXS provides direct access to nanometer-scale density structures and their ultrafast evolution, enabling us to observe processes that previously could only be inferred indirectly from simulations.\n\nEarly experiments demonstrated that coherent X-ray scattering could reveal microscopic filamentary structures, return-current dynamics, and shock formation inside optically opaque targets. These observations have significantly advanced our understanding of energy transport in dense plasmas, especially the propagation and stability of energetic electron beams. Such processes are central to the fast ignition approach to inertial fusion, where efficient coupling of laser energy into the fuel depends critically on controlling electron transport and instability growth. SAXS measurements provide unique insight into the underlying density modulations and collective plasma behaviour that influence beam guiding, energy deposition, and compression symmetry.\n\nAt large-scale facilities such as European XFEL and LCLS, the success of SAXS has helped to develop integrated experimental platforms combining scattering, imaging, spectroscopy, and synchronized high-power laser drivers. These multi-modal environments enable simultaneous observation of structural evolution and plasma dynamics across multiple scales, strengthening the link between theory, simulation, and experiment.\n\nThis plenary talk will present a ten-year perspective on SAXS as a plasma diagnostic, highlighting key discoveries, methodological advances, and interdisciplinary connections with photon science and condensed matter physics. The presentation will place these developments within the broader context of fusion research, illustrating how scattering-based diagnostics are contributing to the understanding of fast ignition physics and outlining future opportunities enabled by next-generation high-repetition-rate XFEL facilities.\n\nAuthor\nThomas Kluge (Helmholtz-Zentrum Dresden-Rossendorf)\n\nCo-authors\nThomas E. Cowan (Helmholtz-Zentrum Dresden - Rossendorf)\nDr Alejandro Laso Garcia (Helmholtz-Zentrum Dresden-Rossendorf)\nProf. Christian Gutt (Universität Siegen)\nSiegfried Glenzer (SLAC National Accelerator Laboratory)\nJosefine Metzkes-Ng (Helmholtz-Zentrum Dresden - Rossendorf)\nDr Masato Ota\nDr Motoaki Nakatsutsumi (European XFEL)\nDr Lisa Randolph (Universität Siegen)\nUlrich Schramm (Helmholtz-Zentrum Dresden - Rossendorf)\nHans-Peter Schlenvoigt (Helmholtz-Zentrum Dresden - Rossendorf)\nDr Michal Smid (Helmholtz-Zentrum Dresden-Rossendorf)\nProf. Toma Toncian (Helmholtz-Zentrum Dresden-Rossendorf)"},{"id":"d43a4c87-2d18-4bcd-ad31-bc2d4c98d2cc","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T12:10:00+00:00","end":"2026-07-02T13:40:00+00:00","s":"1310","e":"1440","name":"***PRE-REGISTERED ONLY LUNCH: Vision for Fusion: Inertial Fusion Energy - Future Prospects***","loc":"Moorfoot: Level 0","track":"","type":"Function","details":"This lunch is only available to those attendees who have registered in advance.\n\nIt is at capacity so no onsite registrations for this lunch can be accepted.\n\nIf you have registered already in advance it should show in your 'My Agenda' icon on the app home screen."},{"id":"c0c926af-eae9-473f-85c7-45b0a2481c9e","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T12:10:00+00:00","end":"2026-07-02T13:40:00+00:00","s":"1310","e":"1440","name":"***Thursday: Lunch***","loc":"","track":"","type":"Function","details":"Please note lunch is not catered for during the event. \nThere are many options close by; we have included some recommendations here in the app.\nIt is not permitted to bring food from outside into the EICC."},{"id":"b4e155b1-a3c4-4ec5-acae-6cdd116bc846","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T13:40:00+00:00","end":"2026-07-02T14:30:00+00:00","s":"1440","e":"1530","name":"Thursday: POSTER SESSION 2 - BPIF | BSAP | | LTDP","loc":"Kilsyth: Level 0","track":"BPIF: Coronal plasma and laser-plasma instabilities","type":"Session","details":"BPIF03 Laser and Particle Beam Interaction with Plasmas, Hydrodynamics and Instabilities\n_________________________________________________________________\nBSAP02 Astrophysical Plasmas\nBSAP03 Laboratory Astrophysics\n__________________________________________________________________\nLTDP05 Plasma Processing and Applications"},{"id":"10b4f034-bfaf-4035-979b-ee6da0323c25","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T13:40:00+00:00","end":"2026-07-02T14:30:00+00:00","s":"1440","e":"1530","name":"Thursday: POSTER SESSION 1 - MCF | BPIF","loc":"Cromdale: Level -2","track":"MCF: High beta / beta-pol","type":"Session","details":"BPIF05 Ultra-high Intensity Laser-matter Interaction and High Field Physics\n_________________________________________________________________\nMCF03 Energetic Particles and MHD\nMCF04 Plasma Control\nMCF08 Sellarator Physics and Optimization\nMCF09 Disruptions and Runaway Electrons\nMCF10 Power Plant Design\nMCF 11 Other"},{"id":"a08c7a83-d8c1-495d-8334-5cde9845f533","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T14:30:00+00:00","end":"2026-07-02T15:00:00+00:00","s":"1530","e":"1600","name":"***Thursday: Afternoon Refreshment Break***","loc":"Cromdale: Level -2","track":"","type":"Function","details":""},{"id":"d78f4be1-5053-493b-8231-b66b2efcd2c2","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T15:30:00+00:00","end":"2026-07-02T16:05:00+00:00","s":"1630","e":"1705","name":"Plenary Talks: I.413   C.  Angioni - Tungsten in tokamaks, how one of the elements producing largest radiation losses can be compatible with a nuclear fusion plasma","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"Tungsten is becoming the leading solution as first wall material of magnetic confinement fusion reactors, as confirmed by the recent decision of ITER to also adopt tungsten in the main chamber.\nTungsten is the metal with the highest melting point and combines low erosion rates with low fuel retention. However, tungsten is also one of the elements which leads to the highest radiation losses in a wide range of fusion relevant temperatures. In this plenary talk, progress in experiments, theory and predictive modelling dedicated to tungsten transport in tokamak plasmas is retraced, highlighting the main milestones.\nThese in particular include: the development of appropriate strategies to reduce tungsten erosion and limit the tungsten concentration in the plasma; the positive role of central wave heating to prevent central accumulation, through modifications of the tungsten transport and of the main plasma profiles; the complicated impact of plasma rotation on collisional transport, which is understood to be particularly unfavorable in usual plasma conditions in present tokamaks. All transport mechanisms, collisional, turbulent and MHD-driven, are involved and can compete. The understanding of these processes has helped to identify effective actuators to mitigate the risk of excessive core radiation and to increase the predictive capability for present and future tokamaks. Some aspects are still challenging the scientific community, particularly to predict turbulent transport at the plasma edge.\nThese achievements have progressively allowed the integration of tungsten in tokamak operation, overcoming the challenges provided by the need to successfully combine competing requirements of the plasma edge, where tungsten originates, and the plasma core, where strong accumulation can occur. A successful core-edge coupling is essential for the high plasma performance required in a fusion reactor, but which tungsten makes more difficult to achieve. However, strategies to limit tungsten erosion and edge plasma contamination practically coincide with those which are in any case imposed by the heat exhaust and a long lifetime of the plasma-facing components.\nExperimental and theoretical research have advanced together, converging on deeper physics knowledge, controlled plasma operation and more reliable reactor predictions, enabling more future tokamak projects to confidently choose tungsten as plasma-facing material.\n\nAuthors\nClemente Angioni (Max-Planck-Institut fuer Plasmaphysik, 85478 Garching bei Muenchen, Germany)\nthe ASDEX Upgrade Team (see author list of H. Zohm et al 2024 Nucl. Fusion 64 112001)\nJET contributors (see author list of C. Maggi et al 2024 Nucl. Fusion 64 112012)\nthe EUROfusion Tokamak Exploitation Team (see author list of E. Joffrin et al 2024 Nucl. Fusion 64 112019)"},{"id":"972db95c-9e08-44c7-8813-c2bba2c8e4c5","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T16:05:00+00:00","end":"2026-07-02T16:15:00+00:00","s":"1705","e":"1715","name":"PLenary Talks: I.414   Tribute to Prof F  Romanelli","loc":"","track":"Plenary","type":"Session","details":""},{"id":"c1300263-0b81-4dd3-977e-8a796136ca45","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T16:15:00+00:00","end":"2026-07-02T16:25:00+00:00","s":"1715","e":"1725","name":"PLenary Talks: I.416   Tribute to Prof B Taylor FRS","loc":"","track":"Plenary","type":"Session","details":""},{"id":"822db148-4249-4250-9b12-1d4cd77f229d","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T16:30:00+00:00","end":"2026-07-02T17:00:00+00:00","s":"1730","e":"1800","name":"PLenary Talks: I.415   O. Sauter - Negative triangularity plasma shapes: how bad ideal MHD properties can lead to excellent perspectives for a fusion power plant","loc":"","track":"Plenary","type":"Session","details":"This contribution will first review the history of tokamak plasma physics research related to\nnegative triangularity (NT), starting by explaining why it was disregarded early on, based on\nideal MHD considerations [1]. Nevertheless, leveraging on the pioneering work on TCV, NT\nstudies have been extended to larger tokamaks among which DIII-D, AUG and even JET on its\nlast day of plasma operation, and significant progress was made. For the three main pillars\nconsidered to design a reactor (plasma confinement, heat exhaust and integrated design), no\nshowstopper is identified so far. While the baseline scenario for ITER and next step devices\nrelies on the H-mode confinement regime, and its harmful edge localized modes, the promise\nof NT is that plasma confinement is as good as H-mode PT (positive triangularity) but in Lmode\n[see papers in 2 and refs therein]. This benefit alleviates the problem of ELM suppression\nbut also the request to ensure a certain level of power crossing the separatrix to maintain the Hmode.\nThe H-mode avoidance for NT shapes is explained by a closed path to the second stability\nregion for ballooning modes, hence the benefit of “bad” ideal stability, and allows robust\npredictions. The example of JET experiments will be used to illustrate these aspects. Another\nbreakthrough is that operation at much larger densities than the “density limit” in tokamaks has\nbeen demonstrated in DIII-D. Here also, theoretical advancements are supporting the\nexperimental findings. Prospects for an optimized DEMO-NT will be explained.\n[1] A. Marinoni, S. Coda and O. Sauter, Reviews of Modern Plasma Physics 5 (2021) 6\n[2] S. Coda, T. Happel, M. Kikuchi, C. Paz-Soldan, Special Issue on Advances in the Physics Basis of Negative Triangularity Tokamaks, https://iopscience.iop.org/collections/ppcf-231109-\n412\na B.P. Duval et al 2024 Nucl. Fusion 64 112023\nb K E Thome et al 2024 Plasma Phys. Control. Fusion 66 105018\nc H. Zohm et al 2024 Nucl. Fusion 64 112001\nd C.F. Maggi et al 2024 Nucl. Fusion 64 112012\ne E. Joffrin et al 2024 Nucl. Fusion 64 112019\n\nAuthor\nOlivier Sauter (SPC-EPFL)\n\nCo-authors\nthe TCV team\nthe negD-DIII-D Team\nthe ASDEX Upgrade Team\nthe JET Contributors\nthe EUROfusion Tokamak Exploitation Team"},{"id":"52485364-9ac2-456f-98ea-d52593d73e88","date":"2026-07-02","dayLabel":"Thursday, July 2, 2026","start":"2026-07-02T18:00:00+00:00","end":"2026-07-02T22:00:00+00:00","s":"1900","e":"2300","name":"EPS 2026 Gala Dinner","loc":"National Museum Scotland","track":"","type":"Function","details":"Pre-booked tickets only - this is a paid extra and not included in your registration fee. You must already have pre-booked to attend.\n\nIf you have booked onto this, it will show in your 'My Agenda' tile on your app home screen.\n\n19:00 Drinks Reception\n20:00 Dinner \n23:00 Evening Close"},{"id":"e77c80d6-77e2-4fa7-942b-cae02c4ee50d","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T07:00:00+00:00","end":"2026-07-03T08:00:00+00:00","s":"0800","e":"0900","name":"AGENDA: KEY INFORMATION - PLEASE READ","loc":"","track":"","type":"Information","details":"Please click on each session to view the session details including the abstract and the authors. \n\nTo add the session to your personal agenda, please click the star. \n\nYou can view your personal agenda by returning to the home screen and clicking the 'My Agenda' icon."},{"id":"b490dc32-25a9-40e8-9c37-4750dd8cad10","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:00:00+00:00","end":"2026-07-03T08:15:00+00:00","s":"0900","e":"0915","name":"O.504 N. Hartley: The Role of High-Power X-ray Pulses in Pursuing Inertial Fusion Energy","loc":"Tinto: Level 0","track":"BPIF: Plasma Physics at XFEL facilities","type":"Session","details":"The pursuit of controlled energy gain by nuclear fusion took a huge leap forwards with the 2022 demonstration of multi-megajoule energy gain from deuterium-tritium implosions at the National Ignition Facility. Attention has now turned to applying these breakthroughs to realize commercially-viable energy production, in particular through the IFE-STAR and FIRE programs from the US Department of Energy.\nAs part of this decadal effort, the High Energy Density Science (HEDS) division at SLAC is applying its expertise in using pulses from X-ray Free Electron Lasers to study extreme states of matter. These deliver femtosecond pulses with tunable wavelength, which we have used to probe bulk properties of matter and in order to observe phase transitions, ultrafast dynamics and temperature evolution with greater fidelity than can be delivered by any other approach.\nA leading design for delivering fusion targets at Hz-level repetition rates uses polymer foam capsules wetted with liquid nuclear fuels. A new program at SLAC will study these targets in high precision experiments with powerful X-ray sources to provide the required equation of state (EoS) data for validation of hydrodynamic simulations.\nThis talk will cover some of the ways that our existing experiments have begun answering questions about fusions targets and drivers, and what new diagnostics and analysis techniques will still need to be developed. Our recent studies have developed sub-micron resolution X-ray imaging techniques and measured shock propagation, instability growth, and heating of foam targets. Inelastic X-ray scattering with spectral resolution of ΔE/E = 10-6 can resolve the ion feature and plasmons and measure the physical properties of fusion plasmas. I will show examples that use self-seeded X-rays, stochastic correlation of SASE spikes, and Quantum-entangled X-ray photons to accomplish these goals. These results motivate upgrades to the optical drives lasers at MEC at LCLS, and the proposed IFE end station at European XFEL. These future experimental capabilities will couple XFELs to higher-energy and -power lasers than ever before, accessing the pressure conditions found in fusion capsule implosions.\n\nAuthor\nDr Nicholas Hartley (HEDS Division, SLAC National Accelerator Laboratory)\n\nCo-author\nSiegfried Glenzer (SLAC National Accelerator Laboratory)"},{"id":"6b107340-19f7-450b-a8f7-594b28e49002","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:00:00+00:00","end":"2026-07-03T08:25:00+00:00","s":"0900","e":"0925","name":"I.508   A. Larosa: Phase-Space Turbulence in Space and Fusion Plasmas","loc":"Moorfoot: Level 0","track":"BSAP : Solar, Space and Astrophysical Plasmas","type":"Session","details":"The velocity distribution functions (VDFs) of space plasmas typically exhibit non-Maxwellian features owing to the extremely low level of collisionality. Fine velocity-space gradients in the VDFs may play a crucial role in plasma heating and dissipation, as they can inhibit the reversibility of energy exchange between fields and particles once a sufficient degree of phase-space complexity is reached.\n\nA powerful way to quantify this complexity is through the Hermite spectrum of the VDFs. In velocity space, a Hermite cascade—analogous to the turbulent cascade in real space—has been identified in both numerical simulations and observations in the terrestrial magnetosheath.\n\nHere, we present new results on this phenomenon using measurements from Parker Solar Probe and Solar Orbiter, together with gyrokinetic Vlasov simulations of fusion plasmas. These findings advance our understanding of the development of phase-space turbulence in both space and laboratory (fusion) plasma environments.\n\nAuthors\nAndrea Larosa (Institute for plasma science and technology, CNR-Bari, Italy)\nOreste Pezzi (Istituto per la Scienza e la Tecnologia dei Plasmi, CNR - Bari, Italy)\nLuca Sorriso-Valvo (Istituto per la Scienza e la Tecnologia dei Plasmi, CNR - Bari,Italy)\nMr Tien Vo (LASP, Colorado, USA)\nMaurizio Giacomin (Consorzio RFX (CNR, ENEA, INFN, Universit`a di Padova, Acciaierie Venete SpA) - Padua, Italy)\nDr Trevor Bowen (Space Sciences Laboratory-UCB, USA)\nDr Domenico Trotta (ESAC, Madrid)\nDr Nikolaus Sioulas (The Blackett Laboratory, Imperial College, London, UK)\nFrancesco Pucci (Istituto per la Scienza e la Tecnologia dei Plasmi, CNR - Bari, Italy)\nMr Hao Ran (UCL, London, UK)\nDr Jaye Verniero (NASA)\nDr Roberto Livi (Space Sciences Laboratory-UCB, USA)\nDr Denise Perrone (Italian Space Agency (ASI), Rome, Italy)\nProf. Francesco Valentini (UNICAL, Rende, Italy)\nProf. Sergio Servidio (UNICAL, Rende, Italy)"},{"id":"968017ac-5106-4d95-8753-7c7b049ecde8","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:00:00+00:00","end":"2026-07-03T08:30:00+00:00","s":"0900","e":"0930","name":"I:501   B. Geiger: Overview and recent results of the Helically Symmetric eXperiment (HSX) stellarator","loc":"Pentland Suite: Level +3","track":"MCF - stellarators: status and future","type":"Session","details":"The Helically Symmetric eXperiment (HSX) is a mid‑sized stellarator designed to investigate quasi‑symmetry as an approach to stellarator optimization. With its major radius of 1.2 m and magnetic fields up to 1.25 T, HSX routinely achieves electron temperatures above 1 keV, making it a valuable platform for addressing key scientific and technological challenges on the path toward a fusion power plant.\n\nHSX began operation in 2001 and was designed using the same tools and methodologies employed in the development of the W7‑X stellarator. Early research centered on demonstrating its neoclassical optimization, which was confirmed through the observation of strong plasma flows, excellent fast‑particle confinement, and low core heat fluxes. Current studies focus on validating theories and numerical models of neoclassical, turbulent, and MHD‑driven transport, exploring novel divertor configurations, advancing millimeter‑wave heating schemes, and developing next‑generation fusion diagnostics.\n\nThe device’s operation flexibility is one of its key strengths. HSX allows rapid installation and testing of new components, and its magnetic geometry can be tailored using a set of 48 planar auxiliary coils. This flexibility has enabled the experimental investigation of quasi-symmetric turbulence‑optimized configurations with reduced transport, identified previously using gyrokinetic simulations. HSX can also be configured to operate in deliberately MHD‑unstable states, resulting in reduced confinement and strong mode activity measurable with magnetic pickup coils and density and temperature fluctuation diagnostics.\n\nLooking ahead to the needs of the public sector and the broader push toward fusion power plant technologies, the HSX program is preparing for island divertor operation through the installation of new first wall components. Moreover, the device is being upgraded with a new 70‑GHz gyrotron to enable increased heating power and higher density operation.\n\nBy combining its experimental flexibility with a strong programmatic focus on plasma confinement and technology development, HSX has become a collaborative platform that actively pursues and welcomes partnerships across the public and private sectors to help close key gaps on the path toward a stellarator‑based fusion power plant.\n\nAuthor\nBenedikt Geiger (University of Wisconsin - Madison)\n\nCo-authors\nProf. Adelle Wright (University of Wisconsin - Madison)\nDr Alexis Wolfmeister (University of Wisconsin - Madison)\nDr Dieter Boeyaert (University of Wisconsin - Madison)\nMr Henrique Hillebrecht (University of Wisconsin - Madison)\nMs Kassia Schraufnagel (University of Wisconsin - Madison)\nDr MJ Pueschel (Dutch Institute for Fundamental Energy Research)\nDr Mark Nornberg (University of Wisconsin - Madison)\nDr Michael Gerard (IPP Greifswald)\nDr Wayne Goodman (University of Wisconsin - Madison)"},{"id":"90644c07-1cf2-4497-9062-2a488a2dd17e","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:15:00+00:00","end":"2026-07-03T08:30:00+00:00","s":"0915","e":"0930","name":"O.505 T. Tschentscher: A new instrument for fusion research at the European XFEL","loc":"Tinto: Level 0","track":"BPIF: Plasma Physics at XFEL facilities","type":"Session","details":"T. Tschentscher1, K. Appel1, E. Brambrink1, T. Cowan2, T. Feurer1, H. Sinn1, U. Zastrau1\n1 European XFEL, Holzkoppel 4, 22869 Schenefeld, Germany\n2 Helmholtz-Zentrum Dresden-Rossendorf, 01328 Dresden, Germany\n\nX-ray radiation in the range of 5 - 20 keV provided by high brightness Free-Electron Laser (FEL) sources offer unprecedented new opportunities for studying phenomena and materials of high relevance to laser-driven fusion. Initial imaging experiments have shown the capability to study how matter is compressed by laser irradiation and how instabilities form and propagate [1,2]. In order to perform such studies more systematically in a dedicated experimental environment, an instrument for fusion research has been proposed for the European XFEL.\nEuropean XFEL is an international large-scale user facility for research using x-ray FEL radiation. This radiation is characterized by very intense, ultrashort and coherent pulses, complementary to both synchrotron and visible laser radiation. European XFEL currently offers x-ray FEL radiation in the range from 0.25 to 25 keV (0.05 – 5 nm) to seven science instruments, each dedicated to a specific area of application [3]. We now proposed a new instrument, coupled to a nanosecond laser with kJ pulse energy at the 3rd harmonic and pulse shaping capabilities, and a complementary femtosecond laser of PW-class pulse intensity. These lasers allow to excite and dynamically compress fusion relevant materials while the coherent, ultrashort and intense XFEL pulse will be used to diagnose the targets by a variety of different x-ray methods with O(200 nm) spatial and femtosecond temporal resolution.\nExperiments will address the microphysics and dynamic behaviour of fusion targets during several, early states of compression: Non-uniformities arising from laser imprint, the development of laser-plasma instabilities, plasma formation and the onset of hydrodynamic instabilities, the launch of a shock wave into the target or ablator and, if present, shock propagation in the target, and finally hydrodynamic instability growth leading to mixing. As major x-ray techniques full-field imaging, small angle-scattering, and as well spectroscopic techniques will be available. Using these techniques the experiments will allow investigating the behaviour of different targets materials, e.g. foam or similar, under compression and laser excitation. The time- and spatially-resolved experimental data will provide important benchmarking of high-resolution rad-hydro simulations.\nThe instrument is expected to start operation before the end of this decade and an increase of the drive laser pulse energy, as well as a dedicated x-ray source, are planned for a second phase.\n\n[1] G. Rigon et al., Nat. Commun. 12, 2679 (2021), doi: 10.1038/s41467-021-22891-w\n[2] A. Laso-Garcia et al., Nat. Commun. 15, 7896 (2024), doi: 10.1038/s41467-024-52232-6\n[3] T. Tschentscher et al., Appl. Sci. 7, 592 (2017), doi: 10.3390/app7060592\n\nAuthor\nThomas Tschentscher (European XFEL)"},{"id":"9f56b46c-bbb8-4b43-8875-a3fdc067c63b","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:25:00+00:00","end":"2026-07-03T08:50:00+00:00","s":"0925","e":"0950","name":"I.514   H. Terças: Axions in plasmas: from the lab to astrophysics","loc":"Moorfoot: Level 0","track":"BSAP : Solar, Space and Astrophysical Plasmas","type":"Session","details":"Axions constitute one of the most elegant and theoretically well motivated extensions of the standard model. Despite the fact of being so far elusive, they have been proposed to solve the apparent breaking of the charge-parity (CP) symmetry in QCD - the famous strong CP problem - by promoting the small CP angle observed in experiments to a field: the axion restores the CP symmetry in QCD dynamically, via a mechanism that is reminiscent to that of the Higgs boson when giving mass to the gauge fields.\nOn the other hand, the smallness of such CP breaking implies an extremely weak coupling to photons, which renders axions one of the most appealing candidates for dark matter. Altogether, the axion is a most-hunted particle, and a plethora of experiments are currently devoted to its searches. One critical limitation to the current experimental platforms is that they rely on axion-photon conversion, which is a non-resonant process.\nA natural way to circumvent this issue is to design experiments using plasmas, thus relying on the resonant axion-plasmon conversion. We show that, by exploiting the physics of electrostatic instabilities taking place in plasmas, we are allowed to increase the conversion probability (or, equivalently, the axion decay rate) by several orders of magnitude. Moreover, by replacing real plasmas by synthetic (meta material) plasmas, we might be able to probe the axion within the parameter region predicted by the QCD.\nFinally, given the ubiquity of plasmas in the different astrophysical scenarios, we investigate some consequences of the axion-plasmon conversion in the production of axions in magnetars and discuss the importance of axion conversion in intergalactic plasmas.\n\nAuthor\nHugo Terças (Instituto Superior de Engenharia de Lisboa)"},{"id":"536f11a2-a1c3-4981-9135-d8eb20c4203e","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:30:00+00:00","end":"2026-07-03T08:45:00+00:00","s":"0930","e":"0945","name":"O.507 B. Fisher: X-ray phase contrast Imaging of propagating shocks within TMPTA using the SACLA x-ray free electron laser","loc":"Tinto: Level 0","track":"BPIF: Plasma Physics at XFEL facilities","type":"Session","details":"Direct drive inertial confinement fuison are especially susceptible to driver non-uniformities that imprint structure of on to the target surface. The imprinted structure seed hydrodynamic isntabilities whilst launching non-uniform shocks. This talk presents the results of using x-ray phase contrast imaging of a propagting shock within TMPTA foam using the x-ray free electron laser present at SACLA.\n\nAuthor\nBen Fisher (The university of York)\n\nCo-authors\nMrs Abigail James (The University of Oxford)\nAlexis Amouretti (Graduate School of Engineering, Osaka University, Osaka, Japan)\nMr Dalir Kosimov (The University of York)\nMrs Diluka Singappuli (CELIA – Centre Lasers Intenses et Applications, Universit´e de Bordeaux, Talence, France)\nMr Joeseph Umpelby-Thorp (The University of York)\nKohei Miyanishi (RIKEN SPring-8 Center, Hyogo 679-5148, Japan)\nNigel Woolsey (University of York)\nNorimasa Ozaki (University of Osaka, Japan)\nTatiana Pikuz (Institute for Laser Technology, Osaka, Japan)\nToshinori Yabuuchi (RIKEN SPring-8 Center, Hyogo 679-5148, Japan)\nXu Zhao (University of York)\nYouichi Sakawa (Institute of Laser Engineering, Osaka University, Osaka, Japan)\nMr Yuyao Wang (The University of York)"},{"id":"556e0be9-bf87-4129-ac84-a4f101dbcdd4","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:30:00+00:00","end":"2026-07-03T09:00:00+00:00","s":"0930","e":"1000","name":"I.502   R. Wolf: Progress and plans of the Wendelstein 7-X project and its role in developing the stellarator concept","loc":"Pentland Suite: Level +3","track":"MCF - stellarators: status and future","type":"Session","details":"Wendelstein 7-X (W7-X) is the first comprehensively optimised stellarator and the first magnetic fusion device to follow design principles derived from fundamental physics criteria, such as minimising neoclassical transport losses and plasma currents. As such, W7-X is a rigorous realisation of the stellarator concept, in which the plasma equilibrium depends only weakly on the plasma pressure. It is equipped with superconducting coils that demonstrate the stellarator's ability to confine plasmas in a stationary manner, ensuring plasma discharges are long enough to achieve steady-state equilibria. Thanks to neoclassical optimisation, W7-X has achieved triple product values that were previously unattainable for stellarators. With continuous pellet fuelling, plasma performance parameters can now be maintained over longer periods of time — a capability that was previously only accessible in much larger fusion experiments. These successes are based not only on a significantly better understanding of plasma transport, particularly turbulent plasma losses, but also on technical advances such as an actively cooled divertor and the power control of a multi-gyrotron ECRH facility. The future focus of the W7-X programme will be to advance the duration of high-performance plasmas further (with the aim of achieving 30 minutes at 10 MW of heating power), to improve the understanding of heat and particle exhaust (by employing a magnetic island divertor) and to investigate the crucial role of plasma edge transport and high-beta experiments in exploring stability limits and fast ion confinement. Nevertheless, the success of W7-X must not distract from the fact that many questions remain unanswered on the path to achieving burning fusion plasma or a fusion power plant, despite the conceptual advantages of stellarators. A strategy is currently being developed to address open physics questions, including those relating to divertor physics and first wall materials. The success of W7-X has significantly increased worldwide interest in the stellarator concept among governments and fusion start-ups alike. A key question is how this interest will impact stellarator development and what concrete steps are currently being considered.\n\nAuthor\nRobert Wolf (Max Planck Institute for Plasma Physics, Germany)\n\nCo-author\nW7-X Team"},{"id":"41db8315-82c6-415c-b8b6-855ee75b927b","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:45:00+00:00","end":"2026-07-03T09:00:00+00:00","s":"0945","e":"1000","name":"O.508 L. Ansia Fernández: Spatial effects on non-thermal XFEL heating of plasmas","loc":"Tinto: Level 0","track":"BPIF: Plasma Physics at XFEL facilities","type":"Session","details":"X-ray free-electron lasers (XFELs) enable the generation of dense plasmas with well-defined parameters. XFEL heating proceeds primarily through photoionization, which initially generates strongly non-thermal electron distributions, followed by energy relaxation via different pathways [1]. These conditions provide a platform to investigate plasma states far from local thermodynamic equilibrium (LTE).\n\nIn this work, we extend the collisional–radiative model BigBarT by incorporating one-dimensional spatial electron transport. This extension complements the model's self-consistent treatment of atomic kinetics and non-thermal electron distributions [2]. The framework couples the kinetic model to a Vlasov–Fokker–Planck equation, employing a spherical harmonics expansion [3] following the approach presented in [4].\n\nThis formalism is used to analyse the coupling between atomic processes and electron transport in dense plasmas. The spatial redistribution of energetic electrons alters local energy deposition, leading to observable signatures in the total emitted radiation. This approach facilitates a benchmark against the common practice of averaging independent 0D calculations at discrete local intensities, by providing a consistent description of inhomogeneous plasma conditions.\n\nFurthermore, as established in recent studies [1,5], electron thermalization is driven significantly by atomic collisions, specifically collisional ionization. We utilize the extended model to examine the impact of these effective cross sections on non-local transport, providing a basis for future experiments.\n\n[1] Ansia L. et al., Phys. Rev. E 112, 025201 (2025).\n[2] A. G. de la Varga, P. Velarde, High Energy Density Physics 9, 542-547 (2013).\n[3] M. Tzoufras, Journal of Computational Physics 230, 6475-6494 (2011).\n[4] Hai P. Lee, Phys. Rev. E 100, 6475-6494 (2011).\n[5] Y. F. Shi. et al., Phys. Plasmas 31, 082305 (2024)\n\nAuthor\nLucas Ansia Fernández (Instituto Superior Tecnico, ULisboa)\nCo-authors\nGareth Williams (Instituto Superior Tecnico)\nMarta Fajardo (Instituto Superior Tecnico)\nPedro Velarde (Insitituto de Fusion Nuclear Guillermo Velarde)"},{"id":"7451cdc3-e59d-4ae3-9a82-36b45c4e71ea","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T08:50:00+00:00","end":"2026-07-03T09:15:00+00:00","s":"0950","e":"1015","name":"O.502  M. Tamburini: Counterpart-induced millisecond-scale truncation mechanism of fast radio bursts","loc":"Moorfoot: Level 0","track":"BSAP : Solar, Space and Astrophysical Plasmas","type":"Session","details":"The observed millisecond-scale duration is an essential yet mysterious feature of fast radio bursts (FRBs). In this work, we link the observed soft gamma-ray counterpart of FRB 200428 to electron-positron pair cascades driven by Compton scattering and the Breit-Wheeler process. We demonstrate that such pair cascades can truncate FRBs to durations down to millisecond-scale, thereby establishing millisecond-scale upper bounds on their durations. The physical processes involved in the truncation mechanism occur during the propagation of FRBs after their production. Consequently, this mechanism is independent of the specific production mechanism or origin of the FRBs, suggesting that it could potentially operate in all FRBs. Our results lift the constraint on FRB production mechanisms that they must inherently generate bursts lasting only milliseconds.\n\nAuthor\nDr Matteo Tamburini (Max Planck Institute for Nuclear Physics)\nCo-authors\nProf. Christoph H. Keitel (Max Planck Institute for Nuclear Physics)\nDr Yutong He (Max Planck Institute for Nuclear Physics)"},{"id":"40237553-6271-4859-8320-17d86a3e42eb","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T09:00:00+00:00","end":"2026-07-03T09:15:00+00:00","s":"1000","e":"1015","name":"O.509 A. Matheron: Measuring vacuum birefringence using the dark-field concept at the European XFEL","loc":"Tinto: Level 0","track":"BPIF: Plasma Physics at XFEL facilities","type":"Session","details":"Quantum field theory predicts that the vacuum exhibits a nonlinear response to strong electromagnetic fields, giving rise to phenomena such as vacuum birefringence. Despite its fundamental significance, this effect has remained experimentally inaccessible and has yet to be observed in the laboratory. Detecting it would provide a distinct signature of the optical activity of the quantum vacuum and enable a precision test of nonlinear quantum electrodynamics in an unexplored regime.\n\nA central difficulty in such experiments is isolating the weak signal from the photon background of the probe beam. In the strong-field region created by a tightly focused IR pump pulse, the X-ray probe acquires a tiny vacuum-induced polarization rotation and an angular deflection. Conventional approaches rely on ultra-high-contrast polarimetry to suppress the background and reveal the signal.\n\nWe introduce here the dark-field concept, a promising alternative that creates a controlled shadow in the probe’s near field, enabling a clean angular separation between the vacuum-induced signal and the background. We report on the recent experimental campaign at the European XFEL’s High Energy Density (HED) instrument, where this technique was implemented using the X-ray beam as the probe and the ReLaX IR laser as the pump. The dark-field configuration reduced the background by roughly 15 orders of magnitude. This design not only increases the sensitivity of the measurement, but also gives access to both the polarization-flipped and non-flipped components of the probe, enabling a direct determination of the fundamental QED parameters that can be confronted with theoretical predictions. We present an overview of the setup, the experimental results from the last campaing, the expected measurable signal for the upcoming campaign, and the current status of the advanced simulation framework that models both the vacuum birefringent signal and its background.\n\nAuthor\nDr Aimé Matheron (Helmholtz Institute Jena)\n\nCo-authors\nDr Felix Karbstein (Helmholtz Institute Jena)\nProf. Matt Zepf (Helmholtz Institute Jena)\nMichal Smid (Helmholtz-Zentrum Dresden-Rossendorf)"},{"id":"41b00e4a-1d86-4bba-8384-35bb073aa46e","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T09:00:00+00:00","end":"2026-07-03T09:30:00+00:00","s":"1000","e":"1030","name":"I.503   H. Yamada: Achievements in LHD Project and Development to Post-LHD Project","loc":"Pentland Suite: Level +3","track":"MCF - stellarators: status and future","type":"Session","details":"The reconsideration of stellarator–heliotron programs is discussed in light of a review of key highlights from the LHD (Large Helical Device) and the plans for the post-LHD project. The LHD, based on the heliotron concept and employing superconducting coils, has been in operation since 1998 and will complete its mission in 2025. The LHD project has significantly advanced plasma science across a broad range of fields, both theoretically and through experimental achievements. The steady-state sustainment of 2-keV plasmas for 50 minutes and the achievement of beta values as high as 5% have demonstrated the feasibility of disruption-free, stable plasmas. A unique feature of the LHD is its ability to produce plasmas that are resistant and resilient to external disturbances, enabling novel experiments such as impurity injection and the application of magnetic perturbations. Advanced diagnostics with high spatiotemporal resolution have clarified the roles of electric fields and non-local effects in transport mechanisms. These physics lessons accumulated over 27 years will be transferred to the new machine, CHD-U (Compact Helical Device-U), a compact yet more flexible stellarator. The post-LHD project, including CHD-U, aims to explore micro-collective plasma phenomena, which are considered critical physics in the challenge toward a comprehensive understanding of toroidal plasmas. The knowledge and skills cultivated through the LHD project underpin this paradigm shift.\n\nAuthor\nProf. Hiroshi Yamada (National Institute for Fusion Science)"},{"id":"b02cce64-3e00-47cf-8558-10e74a551641","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T09:40:00+00:00","end":"2026-07-03T10:15:00+00:00","s":"1040","e":"1115","name":"PLenary Talks: I.506   K. Aleynikova - Kinetic ballooning modes in high-beta stellarators: theory and experiment","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":"High-performance stellarator operation increasingly approaches regimes where electromagnetic effects become essential for confinement. In this context, kinetic ballooning modes (KBMs), driven by total pressure gradients and finite-beta effects, can emerge as the dominant electromagnetic instability, linking ideal magnetohydrodynamic ballooning physics with kinetic microturbulence.\nThe present contribution provides a combined theoretical and experimental overview of KBMs, with a primary focus on stellarators. To establish the physical foundations, the discussion briefly revisits the ballooning mode framework in tokamaks, starting from simplified cases that illustrate the essential physics of curvature-driven instabilities at finite beta. This perspective is then extended to three-dimensional stellarator geometry, where additional geometric effects modify stability properties.\nWithin this framework, the impact of increasing beta on the microinstability spectrum is examined. As beta rises, electrostatic instabilities can be mitigated, while KBMs are destabilized and may eventually dominate the electromagnetic response. Gyrokinetic simulations are employed to identify KBM thresholds and to characterize their dependence on pressure gradients and magnetic configuration. Particular attention is paid to the role of magnetic geometry properties (iota, mirror ratio, shear) in determining KBM stability.\nThese theoretical and numerical findings are complemented by experimental observations in W7-X high-performance discharges, where coherent electromagnetic activity consistent with KBM dynamics is detected. Fluctuation measurements and equilibrium reconstructions reveal systematic trends in frequency and mode structure that align with theoretical expectations, indicating that KBMs set a practical boundary for high-performance operation.\nTaken together, these findings indicate that KBMs may define an important electromagnetic stability boundary in high-beta stellarator regimes, although the nature of this boundary, whether gradual or more abrupt, remains an active subject of investigation. Linear stability maps appear to offer a useful framework for identifying KBM-prone operational scenarios and exploring configuration optimization. Incorporating KBM physics into stellarator design and profile control strategies is therefore likely to play an important role in achieving reactor-relevant steady-state performance.\n\nAuthor\nKsenia Aleynikova (Max Planck Institute for Plasma Physics, Greifswald)\n\nCo-authors\nA von Stechow\nAlessandro Zocco (Max Planck Institute for Plasma Physics, Greifswald)\nCarolin Nührenberg (Max Planck Institute for Plasma Physics)\nCharlotte Büschel (Max Planck Institute for Plasma Physics)\nChristian Brandt\nDaniel Carralero (CIEMAT)\nE Edlund\nG. Fuchert\nHenning Thomsen (MPI f. Plasmaphysik)\nHikaru Okuwada (National Institute for Fusion Science, National Institutes of Natural Sciences, Toki, Gifu 509-5292, Japan)\nJan-Peter Bähner (Max Planck Institute for Plasma Physics, Greifswald, Germany)\nJoachim Geiger (Max Planck Institute for Plasma Physics)\nKenji Tanaka (National Institute for Fusion Science, National Institutes of Natural Science, Toki, Japan and Interdisciplinary Graduate School of Engineering Sciences, Kyushu University, Kasuga, Japan)\nKian Rahbarnia\nM. Porkolab\nDr Nikita Nikulsin (Max Planck Institute for Plasma Physics, Greifswald branch)\nNovimir Pablant (Princeton Plasma Physics Laboratory)\nPaul Mulholland (Science and Technology of Nuclear Fusion, Eindhoven University of Technology, The Netherlands)\nSergey Bozhenkov (ITER Russia)\nYann Narbutt (Max Planck Institute for Plasma Physics, Greifswald)"},{"id":"8f0543f1-4bb8-4724-8344-5f65423d134b","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T10:15:00+00:00","end":"2026-07-03T10:45:00+00:00","s":"1115","e":"1145","name":"***Friday: Morning Refreshment Break***","loc":"Strathblane: Level 0","track":"","type":"Function","details":"Please note, the afternoon refreshment break today will be held in the Strathblane."},{"id":"48efd7db-a124-49af-a107-3765bec3fda9","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T10:45:00+00:00","end":"2026-07-03T11:10:00+00:00","s":"1145","e":"1210","name":"I.510    D. Gorlova: Electron spin dynamics and spin polarisation preservation in direct laser acceleration (DLA)","loc":"Sidlaw: Level +3","track":"BPIF: Plasma-based accelerators","type":"Session","details":"The interaction of a high-intensity laser pulse with a near-critical plasma target can lead to the generation of electron beams via direct laser acceleration (DLA) in a plasma channel [1]. This mechanism yields electron beams that are relatively collimated (divergence ~0.1 rad), with charge in the tens of nC, (up to μC [2]) and an exponential energy spectrum with ‘temperatures’ in the tens of MeV. These electron beams are drastically different from the ones obtained by laser wakefield acceleration (LWFA) and are uniquely suited for applications requiring high particle fluxes, such as neutron generation, nuclear physics studies and industrial imaging.\n\nWhile electron acceleration dynamics in DLA have been well-studied analytically and in particle-in-cell (PIC) simulations [3,4], the spin dynamics of electrons in this regime have remained largely unexplored. In this work, we analytically investigate electron spin dynamics in DLA based on the Thomas-Bargmann-Michel-Telegdi (T-BMT) equation. We demonstrate that for the most energetic, planar electron trajectories, the spin projection perpendicular to the plane of motion remains conserved. Furthermore, we show that under the ultra-relativistic assumption (γ≫1) the net spin precession averaged over a single betatron oscillation period is negligible, i.e., spin averaged over a betatron oscillation period is conserved. These findings are corroborated by the test particle simulations and 3D EPOCH PIC simulations. Finally, we address the practical feasibility of generating and preserving spin-polarized electron beams in realistic DLA experimental scenarios.\n\nThis work is funded by EPSRC grant number EP/V049461/1, EP/Y01751X/1 and ELI/ERIC.\n\n[1] Pukhov, A., Sheng, Z. M. & Meyer-ter-Vehn, J. Phys. Plasmas 6, 2847–2854 (1999).\n[2] Rosmej, O. N., et al. Plasma Phys. Controlled Fusion 62, 115024 (2020).\n[3] Gahn, C., et al. Phys. Rev. Lett. 83, 4772–4775 (1999).\n[4] Arefiev, A. V., et al. Physics of Plasmas 23.5 (2016).\n\nAuthor\nDiana Gorlova (University of York)\n\nCo-authors\nChristopher Paul Ridgers (University of York)\nHolger Schmitz (Central Laser Facility, STFC Rutherford Appleton Laboratory, Didcot, United Kingdom)\nProkopis Hadjisolomou (ELI Beamlines Facility)\nSergei Vladimirovic Bulanov (ELI Beamlines Facility)"},{"id":"5e33df03-ba04-45ab-915f-221734faeb45","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T10:45:00+00:00","end":"2026-07-03T11:00:00+00:00","s":"1145","e":"1200","name":"O.517   A. Melzer: Characterizing the dynamics of dust clouds in dusty plasmas under weightlessness","loc":"Moorfoot: Level 0","track":"LTDP: Dusty Plasmas","type":"Session","details":"The dynamical properties of extended clouds of dust particles in a dusty plasma under the microgravity conditions of parabolic flights is studied. Here, micrometer-sized dust particles are immersed into a gaseous plasma of a capacitively coupled radio-frequency discharge. There the particles become confined in a large extended, nearly force-free dust cloud. The particles are illuminated by lasers and the scattered light is recorded by (high-speed) video cameras. For the dynamical analysis, features of the dust cloud are derived either directly from the image data or from physical data extracted from the dust cloud. From a comparison of different features the cloud dynamics (dust-density waves, void formation, structure formation) is characterized.\n\nFinancial support from the German Aerospace Center DLR (Contract No. 50WM2161) is gratefully acknowledged.\n\nAuthor\n ndre Melzer (University of Greifswald)\n\nCo-authors\nChristina A. Knapek\nDaniel Maier\nDaniel P. Mohr\nStefan Schütt (University of Greifswald)"},{"id":"a94051fe-24cd-4391-9fb5-3ec992fb6772","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T10:45:00+00:00","end":"2026-07-03T11:10:00+00:00","s":"1145","e":"1210","name":"I.507  U. Sheikh: The Physics and Operational Limits of Runaway Electron Mitigation: Multi-Machine Validation for ITER","loc":"Fintry: Level +3","track":"MCF: Disruption Physics","type":"Session","details":"We present a validated framework and physics basis for low-Z benign termination of runaway electrons (RE). This strategy uses hydrogenic injection as a first step, followed by a low q-edge MHD instability to deconfine and disperse the RE beam. Our multi-machine experimental campaign (AUG, COMPASS, DIII-D, JET, TCV) confirmed this robust two-step process. We established a minimum required neutral pressure for ITER (0.2-0.8 Pa) and identified an upper limit of ∼1 Pa, where the termination efficacy begins to reduce. Experimental H and D secondary gas injection comparisons above 1 Pa revealed an unexpected offset in background plasma electron density (ne) dependence on mode growth.\nMulti-code modeling was done with SOLPS-ITER, JOREK and M3D-C1. The SOLPS-ITER simulations, modelling the power balance of the REs and background plasma, reproduced the experimental non-monotonic ne trend with neutral pressure. The resulting profiles were ported to JOREK and M3D-C1 to model the MHD collapse phase. Results showed that lower ne and higher resistivity accelerate the m/n=2/1 mode growth, in line with experimental observations. The instability was shown to grow fast enough to induce strong magnetic stochasticity and significant RE transport within 0.1ms in the ASDEX simulations with M3D-C1.\nThis work provides the essential operational boundary map and multi-code physics validation necessary to implement this scheme on ITER, addressing one of the most critical challenges for the realization of fusion energy.\n\nAuthors\nCarlos Paz-Soldan (Department of Applied Physics and Applied Mathematics, Columbia University, New York, NY 10027, United States of America)\nUmar Sheikh (Ecole Polytechnique Federale de Lausanne (EPFL), Swiss Plasma Center (SPC), CH-1015 Lausanne, Switzerland)\n\nCo-authors\nDr Alexander Battey (Ecole Polytechnique Fédérale de Lausanne (EPFL), Swiss Plasma Center (SPC), CH-1015 Lausanne, Switzerland)\nCedrix Reux (CEA, IRFM, F-13108 Saint-Paul-les-Durance, France)\nDr Chang Liu (Physics Department, Peking University, Beijing, China)\nElena Tonello (Ecole Polytechnique Fédérale de Lausanne (EPFL), Swiss Plasma Center (SPC), CH-1015 Lausanne, Switzerland)\nEric Hollmann (University of California—San Diego, La Jolla, CA 92093, United States of America)\nGegerly Papp (Max-Planck-Institut für Plasmaphysik, Boltzmannstr. 2, 85748 Garching, Germany)\nJoan Decker (École Polytechnique Fédérale de Lausanne (EPFL), Swiss Plasma Center (SPC), CH-1015 Lausanne, Switzerland)\nMarta Pedrini (Ecole Polytechnique Fédérale de Lausanne (EPFL), Swiss Plasma Center (SPC), CH-1015 Lausanne, Switzerland)\nMathias Hoppe (KTH Royal Institute of Technology)\nMatthias Hoelzl (Max Planck Institute for Plasma Physics, Boltzmannstr. 2, 85748 Garching b. M., Germany)\nOndrej Ficker (Institute of Plasma Physics of the CAS, Za Slovankou 1782/3, 182 00 Praha 8, Czech Republic)\nStefan Jachmich (ITER Organization, Route de Vinon-sur-Verdon, CS 90)\nDr Vinod Bandaru (Indian Institute of Technology Guwahati, Guwahati, Assam, India)"},{"id":"b7c9efb5-e4d0-441a-b5de-550a073196f1","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T10:45:00+00:00","end":"2026-07-03T11:00:00+00:00","s":"1145","e":"1200","name":"O.605   F. Orlacchio: Turbulence characterization from density fluctuations velocity in fusion plasma using Doppler Backscattering diagnostic","loc":"Pentland Suite: Level +3","track":"MCF: Turbulence, Edge and Pedestal Physics","type":"Session","details":"Turbulence-driven transport and its self-regulation by plasma flows play a central role in confinement in magnetised fusion plasmas [1,2]. The perpendicular mean flow velocity (v_⊥) and its radial shear facilitate turbulence reduction and transport barrier formation [3]. Radial profiles of v_⊥ are accessible with Doppler Backscattering (DBS) [4], using density fluctuations as tracers. The measured v_⊥ is typically interpreted as the local E×B flow [5–7], but actually includes a contribution from the phase velocity of turbulent structures, usually neglected. Previous experiments have shown a systematic velocity increase at lower wavenumbers, suggesting a scale-dependent contribution on top of the mean flow [8,9].\nCharacterising the turbulent phase velocity provides access to the turbulence regime and flow-turbulence interaction. Here, such a characterisation is achieved for the first time, with the k_⊥ dependence of v_⊥ from DBS compared against quasilinear predictions using TGLF with saturation rule 2 [10,11]. A systematic increase of v_⊥ at lower wavenumbers is observed across L-mode configurations on WEST [12] and TCV, consistent with a finite phase velocity. This interpretation is verified using a synthetic DBS diagnostic based on full-wave simulations [13] applied to Kolmogorov-like spectra and Hasegawa-Wakatani turbulence [14], consistently recovering phase velocity signatures. The comparison with TGLF-sat2 simulations shows good quantitative agreement, establishing a robust framework for characterising turbulence phase velocity and interpreting DBS measurements.\n\nAuthor\nFrancesco Orlacchio\n\nCo-authors\nClarisse Bourdelle (CEA Cadarache)\nCyrille Honoré (Laboratoire de Physique des Plasmas (LPP), CNRS)\nEnzo Vergnaud (IRFM - CEA Cadarache - France)\nFrédéric Clairet (IRFM, CEA Cadarache)\nLaure Vermare (Laboratoire de Physique des Plasmas (LPP), CNRS, Ecole Polytechnique)\nPascale Hennequin (Laboratoire de Physique des Plasmas (LPP), CNRS)\nPierre Manas (CEA, IRFM, F-13108 Saint Paul-lez-Durance, France)\nSascha Rienäcker (Laboratoire de Physique des Plasmas (LPP), CNRS)\nÖzgür Gürcan (CNRS, LPP, Ecole Polytechnique)"},{"id":"07fa1036-31c6-49f4-8a18-01b19a65d367","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:00:00+00:00","end":"2026-07-03T11:15:00+00:00","s":"1200","e":"1215","name":"O.518   R. Peelen: Charging dynamics of single and clustered microparticles in spatiotemporal afterglow plasmas","loc":"Moorfoot: Level 0","track":"LTDP: Dusty Plasmas","type":"Session","details":"As semiconductor devices continue to shrink, maintaining ultra-clean fabrication environments becomes increasingly critical. To eliminate unwanted particles from low-pressure, high-purity processing systems, a novel technique known as the “plasma seal” has been proposed. This method uses plasma to electrically charge contaminant particles, enabling their removal through an externally applied electric field. However, because the plasma screens the particles from the electric field, effective deflection can only take place either outside the active plasma region, immediately after the plasma is switched off or during the spatiotemporal afterglow, which combines aspects of both regimes.\n\nRecent research has advanced the understanding of particle charging mechanisms in the spatiotemporal afterglow, yet the role of particle clustering remains largely unexplored. In this contribution, we examine how cluster size influences particle charging behavior. Optical emission spectroscopy is employed to link particle charge to key plasma parameters. The findings provide experimental validation of established theoretical models describing particle charging processes.\n\nAuthor\nRik Peelen (Eindhoven University of Technology)\n\nCo-authors\nPaul Blom (VDL-ETG)\nJob Beckers (Eindhoven University of Technology)"},{"id":"6eef4d55-c73c-4686-a3e7-ace9e59161f5","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:00:00+00:00","end":"2026-07-03T11:15:00+00:00","s":"1200","e":"1215","name":"O.604   L. Casali: The effect of the Isotope Mass on Divertor Detachment and Pedestal Performance","loc":"Pentland Suite: Level +3","track":"MCF: Turbulence, Edge and Pedestal Physics","type":"Session","details":"This work presents a new integrated study of hydrogen isotope effects on scrape-off layer (SOL) transport, divertor performance, and pedestal fueling combining dedicated DIII-D H-mode experiments together with SOLPS-ITER simulations with full drifts. Matched H and D discharges were specifically designed to isolate isotope effects providing a systematic comparison of pedestal structure and divertor detachment behavior. Increasing isotope mass significantly reduces divertor particle and heat fluxes prior to detachment, with particle fluxes decreasing from H to D. Detached conditions occur at ~15% higher upstream density in H after SOLPS-ITER modeling constrained by experiment indicates that carbon sputtering, rather than neutral mean free path effects, is the primary driver of the observed isotope dependence of detachment access. To isolate the fundamental mass dependence from impurity effects, simulations are extended to pure H, D, and T plasmas with both carbon and tungsten walls. The isotope effect is shown to arise primarily from parallel momentum balance: while pressure and electric-field forces are nearly identical across isotopes, heavier ions experience lower acceleration due to increased inertia, producing slower SOL parallel flows and reduced convective transport. From H to T, target particle fluxes decrease by nearly a factor of two, while divertor heat fluxes decrease by ~10% for each increase in isotope mass. These results provide a comprehensive, experimentally validated predictions of isotope effects for DT operation in future fusion devices.\n\nAuthors\nProf. Livia Casali\nDr Ray Mattes\nDr Tony Leonard\nDr Thomas Osborne\nCharlie Lasnier\nFlorian Laggner\nHuqiuan Wang"},{"id":"80442ce0-ee2f-4c98-929d-e259c64117a8","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:10:00+00:00","end":"2026-07-03T11:25:00+00:00","s":"1210","e":"1225","name":"O.514    A. Golovanov: First electron acceleration from a tunable-velocity laser wakefield","loc":"Sidlaw: Level +3","track":"BPIF: Plasma-based accelerators","type":"Session","details":"Laser-wakefield accelerators (LWFAs), which accelerate electrons in plasma waves driven by short intense laser pulses, have demonstrated the ability to produce high-quality electron beams with energies up to several GeV. One of the fundamental limitations for reaching ever higher energies is dephasing, when ultrarelativistic electrons outrun the wakefield and slip into its decelerating phase. A promising approach to overcoming this limitation is the use of structured light pulses to control the on-axis intensity propagation velocity of the laser pulse [1, 2].\n\nHere, we report on the first experimental observation of electron acceleration in a tunable-velocity wakefield and mitigation of dephasing using structured light pulses [3]. In the experiments, a 1.5 J, 27 fs laser pulse is focused using an axiparabola, a specialized mirror that produces quasi-Bessel beams with an extended focal line. The on-axis intensity propagation velocity is further modified by applying pulse-front curvature (PFC) before reflection. Through its interaction with a gas jet, we demonstrate that this structured light pulse creates coherent plasma wakefields capable of injecting and accelerating electrons to high energies. We further show that changing the PFC value induces a statistically significant shift in the cutoff energy of the accelerated electron spectrum, demonstrating experimental control over the wakefield velocity and partial mitigation of dephasing. The experimental results are supported by comprehensive simulations including FLUENT simulations of the gas density profile, axiprop simulations of the reflected laser pulse propagation from the axiparabola to the focal region, followed by particle-in-cell simulations of the structured light pulse with the obtained gas density and laser profiles.\n\n[1] C. Caizergues et al. “Phase-locked laser-wakefield electron acceleration,” Nat. Photonics. 14, 8 (2020)\n[2] J.P. Palastro et al. “Dephasingless laser wakefield acceleration,” Phys. Rev. Lett. 124, 134802 (2020)\n[3] A. Liberman et al., “First Electron Acceleration in a Tunable-Velocity Laser Wakefield,” arXiv:2509.21098\n\nAuthors\nMr Aaron Liberman (Weizmann Institute of Science)\nDr Anton Golovanov (Weizmann Institute of Science)\n\nCo-authors\nDr Anda-Maria Talposi (Weizmann Institute of Science)\nDr Igor Andriyash (LOA, CNRS, Ecole Polytechnique, ENSTA Paris, Institut Polytechnique de Paris, Palaiseau, France)\nDr Sheroy Tata (Weizmann Institute of Science)\nDr Slava Smartsev (2LOA, CNRS, Ecole Polytechnique, ENSTA Paris, Institut Polytechnique de Paris, Palaiseau, France)\nProf. Victor Malka (Weizmann Institute of Science)"},{"id":"fa97a37a-c527-48a2-b91a-1598e403f2ba","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:10:00+00:00","end":"2026-07-03T11:25:00+00:00","s":"1210","e":"1225","name":"O.510   S. Jachmich: Demonstration of shattered pellet injection schemes at ASDEX Upgrade for disruption mitigation in ITER","loc":"Fintry: Level +3","track":"MCF: Disruption Physics","type":"Session","details":"ITER will rely on shattered pellet injection (SPI) to mitigate the damaging consequences of plasma disruptions. Its disruption mitigation system (DMS) is designed to support various injection schemes and geometries to maximise material assimilation across the evolving plasma conditions during a disruption. The SPI system at ASDEX Upgrade has been adapted for the recent campaign to test a variety of injection schemes and to assess post thermal quench (TQ) injections which mimic the limited fragment plume-plasma intersection as expected for upper port injection in ITER. Experiments show that post-TQ injections suffer from weak fragment ablation due to the low plasma temperature, reducing densification and acceleration of the current quench (CQ) for minimising electromagnetic loads. In ohmic density limit disruptions, neon assimilation decreases by ~50% when fragments arrive 2 ms into the CQ compared with pre-TQ injection, leading to only partially mitigated CQs due to the comparatively low plasma resistivity.\nEarly deuterium injection aimed at avoiding the triggering of MHD activity and subsequent global reconnection event can dilute the plasma and reduce hot-tail runaway seeds. However, initial assimilation remains low (≈20%) and is further reduced by transport losses before TQ onset. Adding neon improves assimilation without shortening the pre-TQ phase to below the injection duration. Although smaller and faster fragments in general lead to a steeper density rise, their preferential edge deposition increases material losses by the time of the TQ. Intrinsic impurities, particularly tungsten in degraded H-mode plasmas, strongly influence mitigation performance. Longer pre-TQ phases and lower temperatures enhance fragment penetration and assimilation, and the presence of intrinsic impurities relaxes CQ mitigation requirements. Multiple Ne/D SPI has revealed that the assimilation deteriorates if the fragment plumes arrive more than 1 ms apart, which can be attributed to the already initiated plasma cooling. This imposes a strict requirement on the allowable fragment arrival jitter when material must be injected from several locations.\nThis contribution summarises results from recent ASDEX Upgrade SPI experiments and their implications for ITER’s disruption mitigation strategy.\n\nAuthor\nStefan Jachmich (ITER Organization)\n\nCo-authors\nOndrej Ficker (Institute of Plasma Physics of the CAS, Za Slovankou 1782/3, 182 00 Praha 8, Czech Republic)\nPaul Heinrich (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nFerenc Lengyel (HUN-REN Centre for Energy Research, Institiute for Atomic Energy Research, Budapest, Hungary)\nPascal de Marne (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nAndrew Moreau (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nGegerly Papp (Max-Planck-Institut für Plasmaphysik, Boltzmannstr. 2, 85748 Garching, Germany)\nAnsh Patel (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nUmar Sheikh (Ecole Polytechnique Federale de Lausanne (EPFL), Swiss Plasma Center (SPC), CH-1015 Lausanne, Switzerland)\nMatthias Bernert (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nAlexander Bock (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nJoerg Hobirk (Max-Planck-Institut für Plasmaphysik, 85748 Garching, Germany)\nBernd Kurzan (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nBernhard Sieglin (Max-Plank-Institut für Plasmaphysik, D-85748, Garching, Germany)\nASDEX Upgrade Team\nEUROfusion Tokamak Exploitation team"},{"id":"0c9c47c8-2ddf-4a12-8bdd-f2e808e47a1e","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:15:00+00:00","end":"2026-07-03T11:30:00+00:00","s":"1215","e":"1230","name":"O.519   C. Knapek: COMPACT: the future facility for complex (dusty) plasma research in space","loc":"Moorfoot: Level 0","track":"LTDP: Dusty Plasmas","type":"Session","details":"Experiments under microgravity conditions are a cornerstone of complex (dusty) plasma research. In microgravity, large particle systems can be generated and studied, without sedimentation overshadowing particle interaction and dynamics.\n\nThus, a series of facilities (PKE-Nefedov, PK-3 Plus, PK-4) were and are operated onboard the International Space Station since the early 2000s, providing dedicated research platforms.\n\nAn international science definition team (SDT) recently identified so-far unanswered scientific questions from the areas statistical physics, phase transitions, nonlinear dynamics, active matter, planetary physics and the use of particles as diagnostics in the plasma. The SDT compiled an extensive research program for the future facility COMPACT: an international, multi-user facility for the community with strong support by multiple agencies (DLR, NASA, ESA, NSF).\n\nCOMPACT offers a wide range of experimental capabilities such as manipulation of particles by laser, UV-light, or low-frequency electric signals, a pulsed rf discharge mode, a multi-electrode system, and a variable discharge volume. Advanced optical diagnostics include a stereoscopic camera setup for 3D particle diagnostics, and spatially and spectrally resolved plasma glow observation.\n\nA phase B study (preliminary definition) was finished successfully in early 2026, with major components identified and tested. We will present the scientific program and project status, alongside with first scientific results obtained during preliminary investigations using the COMPACT hardware on parabolic flight campaigns.\n\nThis work is funded by DLR/BMWi FKZ 50WM2161, FKZ 50WM2561.\n\nAuthor\nDr Christina A. Knapek (University of Greifswald, Greifswald, Germany)\n\nCo-authors\nProf. Adrienne Dove (University of Central Florida, Orlando, Florida, USA)\nAndre Melzer (University of Greifswald, Greifswald, Germany)\nMr Daniel Maier (University of Greifswald, Greifswald, Germany)\nDr Daniel P. Mohr (University of Greifswald, Greifswald, Germany)\nProf. Florian Zaussinger (University of Applied Sciences Mittweida, Germany)\nDr Hubertus Thomas (Institut für Materialphysik im Weltraum, Deutsches Zentrum für Luft- und Raumfahrt (DLR), Köln, Germany)\nProf. John Goree (The University of Iowa, Iowa City, USA)\nProf. Lenaic Couedel (University of Saskatchewan, Saskatoon, Canada)\nProf. Markus Thoma (Justus-Liebig-Universität Gießen, Gießen, Germany)\nStefan Schütt (University of Greifswald, Greifswald, Germany)\nSvetlana Ratynskaia (Department of Electromagnetic Engineering and Plasma Physics-KTH Royal Institute of Technology, SE-10044 Stockholm, Sweden)\nProf. Uwe Konopka (Auburn University, Auburn (AL), USA)\nDr Zhehui Wang (Los Alamos National Laboratory, USA)"},{"id":"df986bea-471e-4b8d-8a25-e46e5d9d9a00","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:25:00+00:00","end":"2026-07-03T11:40:00+00:00","s":"1225","e":"1240","name":"O.515   B. Lei: High-intensity laser-driven surface plasmon for coherent synchrotron radiation and TV/m-level plasma wakefield acceleration","loc":"Sidlaw: Level +3","track":"BPIF: Plasma-based accelerators","type":"Session","details":"Recent research into the high-intensity laser-driven surface plasmon excitation has revealed the significant potential of generating extremely strong (~TV/m) fields for particle acceleration and radiation production. This new approach has emerged by overcoming several challenges in laser-solid interactions. It therefore holds great promise for reshaping the research direction of large-scale facilities that pursue the energy frontier and micro-scale facilities that require great flexibility. At the same time, this research can provide new insights into the extremely complex nonlinear dynamics of surface plasmons (SPs) in strong fields and a new, unexplored regime of plasma-based particle acceleration.\n\nIn this study, we theoretically and numerically investigate the high-intensity laser-driven excitation of relativistic surface plasmons on the micro-scaled surfaces of structured nanomaterials, such as vertically aligned carbon nanotube (VACNT) forests. This enables the TV/m-level plasma wakefield generation for both negatively and positively charged particle acceleration [1-3]. By investigating SP mode selection on cylindrical surfaces, we have proposed a new principle for coherent radiation generation that differs fundamentally from traditional superradiance [4]. Our research offers a new approach to the development of ultrahigh-gradient and ultra-compact particle accelerators.\n\nReference:\n[1] Bifeng Lei et al. 2025 Plasma Phys. Control. Fusion 67 065036\n[2] Bifeng Lei et al. 2025 New J. Phys. 27 084301\n[3] Cristian Bonţoiu et al. Sci Rep 15, 45323 (2025).\n[4] Bifeng Lei et al. Phys. Rev. Lett. 135, 205001 (2025)\n\nAuthor\nBifeng Lei (University of Liverpool)\n\nCo-authors\nProf. Alexandre Bonatto (Universidade Federal de Ciências da Saúde de Porto Alegre)\nProf. Carsten Welsch (University of Liverpool)\nProf. Guoxing Xia (University of Manchester)\nDr Hao Zhang (University of Liverpool)\nProf. Javier Resta-Lopez (Universidad de Valencia)"},{"id":"1a221b95-c6c8-4495-aba9-cfa9ababb958","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:25:00+00:00","end":"2026-07-03T11:40:00+00:00","s":"1225","e":"1240","name":"O.511   L. Puel: 3D hot tail runaway electron generation modelling with JOREK: validation and predictions for ITER","loc":"Fintry: Level +3","track":"MCF: Disruption Physics","type":"Session","details":"Disruptions in ITER present the risk of generating large Runaway Electron (RE) beams that may cause untolerable damage when impacting plasma facing components. Assuming short Thermal Quenches (TQs) lasting around 1 ms, the hot tail mechanism, driven by the rapid temperature drop and the resulting non-Maxwellian electron population, may produce dangerous amounts of RE seeds [1]. This motivates modelling with 3D non linear MHD codes to accurately account for electron losses due to magnetic field stochasticity and other 3D aspects of the dynamics. The related physics is highly difficult to capture and remains virtually unexplored.\n\nWe leverage the JOREK 3D non-linear MHD code to post-process MHD simulations with test electrons. A dedicated computational framework has been developed to simulate a hot test electron population evolving in the pre-calculated MHD fields and undergoing collisions with the bulk electrons and ions. It has been verified in a reduced phase space against DREAM, and preliminary tested with 3D fields [2].\n\nTo approach experimental validation, the DIII-D discharge 178682, identified as producing a hot-tail RE seed [3], is modelled. A 3D MHD simulation including pellet injection is first performed, capturing phenomena typically observed during disruptions, such as stochasticity, double tearing modes, helical cooling, and 𝐸⃗ × 𝐵⃗ mixing. By using markers, and considering or neglecting the 3D components of the fields, the simulations demonstrate the critical role of stochastic losses in reducing the RE seed by orders of magnitude.\n\nFinally, the new framework is employed to perform the first full-geometry estimates of mitigated ITER 15 MA H-mode scenarios, using MHD simulations presented in [4]. We observe that Shattered Pellet Injection (SPI) enables, for a degraded H-mode case, a safe disruption with a seed current below 10e−10 A. However, the baseline H-mode case produces a potentially dangerous seed. Unlike the DIII-D case, including the 3D effects increases the generated seed from 10 mA to 670 A. For the first time, these simulations reveal a generation boost caused by the formation of acceleration cells due to the (1,1) helical cooling, as well as the transport of hot electrons from the core into these regions which overcome stochastic losses.\n\nAuthor\nLouis Puel (CEA)\n\nCo-authors\nDi Hu (Beihang University)\nEric Nardon (CEA-IRFM)\nJavier Artola (ITER Organization)\nthe JOREK team"},{"id":"4f240b28-4969-43b0-aedf-5158de3c2866","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:30:00+00:00","end":"2026-07-03T12:00:00+00:00","s":"1230","e":"1300","name":"O.520   G. Klaassen: Confined microparticle displacement caused by electrode-photon interaction","loc":"Moorfoot: Level 0","track":"LTDP: Dusty Plasmas","type":"Session","details":"When confined in a horizontally near-flat potential well in the plasma sheath region, microparticles are very sensitive to perturbations in their horizontal force balance. In this contribution we present experiments where glass microparticles confined in the sheath region of a radio frequency driven parallel plate argon plasma, react to laser light hitting surfaces near the potential well. The bottom electrode in this configuration has a shallow groove to create a potential well to confine the microparticles. When the sides of this groove are illuminated, the confined microparticles move away from the illuminated area. This displacement caused by the interaction of the light and the electrode is unexpected as the energy of the laser photons are well below the work function of the illuminated electrode surface.\n\nTo find an explanation for these observations, multiple parameters have been varied. In the presented experiments variations in laser wavelength, surface material, illumination direction, and surface geometry were considered. The confined microparticle displacement is dependent on the wavelength of the light, and stronger displacement is seen for higher intensities. Furthermore, the location and direction of illumination also influence the amount of displacement together with the surface geometry. The results of these experiments are presented, along with hypotheses for possible explanations of the observed effect and plans for future research to understand this phenomenon.\n\nAuthors\nGuido Klaassen (Technische Universiteit Eindhoven)\nJob Beckers (Eindhoven University of Technology)"},{"id":"f56b0d68-236c-47e5-84b1-e5a36dc42a42","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:40:00+00:00","end":"2026-07-03T12:00:00+00:00","s":"1240","e":"1300","name":"O.516  P. Canel: Dark-Field Shadowgraphy: An Ultra-Sensitive Diagnostic for Probing Plasma-Based Particle Accelerators","loc":"Sidlaw: Level +3","track":"BPIF: Plasma-based accelerators","type":"Session","details":"Plasma wakefield accelerators driven by ultra-intense laser pulses (LWFA) or relativistic particle beams (PWFA) have emerged as a promising route toward compact next-generation accelerators. Precise characterization of the plasma wave is essential for understanding and optimizing these schemes. Optical shadowgraphy techniques already enable direct imaging of plasma density perturbations and wakefield structures [1]. Despite these advances, the sensitivity of conventional shadowgraphy limits its application to high plasma densities, typically in the \n\nrange.\nHere, we introduce a dark-field or Schlieren shadowgraphy diagnostic that greatly enhances the sensitivity of optical shadowgraphy and enables probing ultra-low plasma densities down to the \n\nrange, where plasma waves are invisible to conventional shadowgraphy. Furthermore, we show with this new diagnostic that we clearly observe for the first time several detailed features of the plasma accelerator: (i) the position of the laser driver that typically appears as the brightest signal, (ii) the ion cavities with the plasma electrons circulating around, and (iii) the plasma electron crossing points at the back of the cavities, characterized by particularly high plasma densities and strong gradients, yielding a strong diagnostic signal. The method was experimentally tested first in Salle Jaune at LOA and more recently during campaigns at the Apollon (3 PW) facility. Our study further demonstrates the capability of this diagnostic to track the temporal evolution and damping of the wakefield with a relaxation time estimated to be on the order of 10 ps after the laser passage in good agreement with numerical simulations, together with the formation and expansion of the associated ion channel. This high-contrast, non-intrusive diagnostic thus provides a powerful tool for investigating and optimizing plasma-based particle accelerators.\nFinally, double gas-jet targets combining a low-density stage followed by a higher-density region are considered for optimizing ultra-bright gamma-ray production aimed at probing strong-field quantum electrodynamics processes such as nonlinear Breit–Wheeler pair production [2]. Dark-field shadowgraphy proves particularly well suited to characterize laser propagation and wakefield generation in such complex density profiles.\n[1] M. F. Gilljohann et al., Phys. Rev. X 9, 011046 (2019).\n[2] Matheron et al., Phys. Rev. Research 7, L032011 (2025).\n\nAuthor\nPaul Canel (CEA DAM DIF / LMCE / LOA)\n\nCo-authors\nApollon 25_LF_02 collaboration (Apollon / CEA / CELIA / ELI-NP / LOA / LULI / Lund University / SLAC / Weizmann Institute of Science)\nMax Gilljohann (LOA)\nSébastien Corde (LOA, ENSTA Paris, CNRS, École Polytechnique, Institut Polytechnique de Paris, 91762 Palaiseau, France)\nXavier Davoine (CEA, DAM, DIF, F-91297 Arpajon, France; Université Paris-Saclay, CEA, LMCE, F-91680 Bruyères-le-Châtel, France)\nYuliia Mankovska (LOA)"},{"id":"0938a35b-d693-48db-82f7-3fe916f58c40","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T11:40:00+00:00","end":"2026-07-03T12:00:00+00:00","s":"1240","e":"1300","name":"O.512   J. Hu: Disruption mitigation in EAST with metal walls: a comparative study of shattered pellet injection and massive gas injection","loc":"Fintry: Level +3","track":"MCF: Disruption Physics","type":"Session","details":"The EAST superconducting tokamak, with Mo first walls and ITER-like W divertors, has developed and tested a Shattered Pellet Injection (SPI) system [1,2] and two Massive Gas Injection (MGI) systems [3] for disruption mitigation. Neon SPI experiments revealed key disruption dynamics including helical impurity transport and radiation evolution. Compared with MGI, SPI shows superior performance: a shorter TQ, longer CQ, stronger core radiation, and ~40% lower electron temperature with ~50% reduced divertor heat flux [4]. It also generates a more uniform poloidal radiation profile near the plasma core and avoids cold VDEs seen in MGI disruptions. Impurity injection, by either SPI or MGI, can trigger MHD mode switching from an inherent n=1/2 to a new n=1 with reversed rotation, attributed to impurity–plasma interactions [5]. SPI parameter scans showed smaller fragments ablate rapidly at the edge, while larger ones penetrate deeper and ablate slowly. Although ISPI generated more uniform TQ radiation, its poorer assimilation caused a longer pre-TQ phase and weaker halo current mitigation [6]. Finally, RE plateau formation was achieved with Ar-MGI, critically dependent on pre-disruption non-Maxwellian seed electrons and suppressed by MHD activity during TQ. These EAST results provide key data and insights for ITER disruption mitigation system design and operation.\nReference\n[1] Yuan J.S. et al 2023 Fusion Eng. Des. 191 113567\n[2] Yuan J.S. et al 2024 Fusion Eng. Des. 205 114551\n[3] Zhuang H.D. et al 2015 Rev. Sci. Instrum. 86 053502\n[4] Yuan J.S. et al 2023 Nucl. Fusion 63 106008\n[5] Zhao S.B. et al 2024 Nucl. Fusion 65 016048\n[6] Li L. et al 2025 Nucl. Fusion 65 086012\n\nAuthor\n iansheng Hu (Institute of Plasma Physics, Hefei Institutes of Physical Science, Chinese Academy of Sciences)\n\nCo-authors\nProf. Dalong Chen (Institute of Plasma Physics, Hefei Institutes of Physical Science, Chinese Academy of Sciences)\nDr Guizhong Zuo (Institue of Plasma Physics, Chinese Academy of Sciences)\nDr Jingsheng Yuan (Institute of Plasma Physics, Hefei Institutes of Physical Science, Chinese Academy of Sciences)\nDr Li Li (University of Science and Technology of China)\nProf. Long Zeng (Department of Engineering Physics, Tsinghua University)\nDr Shengbo Zhao (University of Science and Technology of China)\nDr Tian Tang (Institute of Plasma Physics, Hefei Institutes of Physical Science, Chinese Academy of Sciences)\nProf. Yanmin Duan (Institute of Plasma Physics, Hefei Institutes of Physical Science, Chinese Academy of Sciences)"},{"id":"c51c38ac-530e-4131-9483-595189767b70","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T12:00:00+00:00","end":"2026-07-03T13:00:00+00:00","s":"1300","e":"1400","name":"***Friday: Lunch***","loc":"","track":"","type":"Function","details":"Please note lunch is not catered for during the event. \nThere are many options close by; we have included some recommendations here in the app.\nIt is not permitted to bring food from outside into the EICC."},{"id":"0bb3cd80-a9d7-401f-ab48-18f4d8161d64","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:00:00+00:00","end":"2026-07-03T13:25:00+00:00","s":"1400","e":"1425","name":"I.516   S. O’Neill: Kinetic effects on heat transport in direct-drive ICF simulations","loc":"Fintry: Level +3","track":"BPIF: Burning plasma and transport","type":"Session","details":"Predictive simulations of inertial confinement fusion (ICF) require accurate modeling of electron transport, particularly in regimes where temperature gradients become comparable to the electron mean free path. In these conditions, diffusive transport models commonly used in radiation-hydrodynamics codes fail to capture non-local effects. These inaccuracies compromise predictions of shock timing, laser-plasma coupling and the thermal smoothing of perturbations. We have recently developed the coupled K2-Gorgon code which allows tractable two-dimensional simulations of ICF relevant experiments with high-fidelity kinetic modeling of electron transport. K2 solves the Vlasov-Fokker-Planck (VFP) equation to evolve the electron distribution function, and provides a kinetic electron transport model for use in the multiphysics hydrodynamics code Gorgon.\n\nWe present results from 1D planar simulations of plastic target ablation using K2-Gorgon at direct-drive relevant laser intensities, benchmarking the VFP model against flux-limited diffusion and Schurtz-Nicolai-Busquets (SNB) transport models. These results demonstrate the inadequacy of the flux-limited model, revealing substantial differences in predicted coronal temperatures (> 200 eV). SNB more accurately captures observables, including shock velocity, coronal temperature and non-local preheat, with minor quantitative differences. We will discuss the extension of this work to 2D, including the role of self-generated magnetic fields and their influence on thermal transport (complementary to recent results in indirect drive hohlraums [1]). Finally, we examine the role of non-local transport in the smoothing of perturbations in the corona, a critical factor for the design of next-generation ICF facilities.\n\n[1] M. Sherlock et al., APS-DPP Abstracts (APS, 2025)\n\nThis work was undertaken as part of UPLiFT (UK Programme of Laser Inertial Fusion Technology for Energy), and is funded by the UK’s Department for Energy Security and Net Zero. This work was also supported by the EPSRC and First Light Fusion under the AMPLIFI Prosperity Partnership - EP/X025373/1\n\nAuthor\nSam O'Neill (University of York)\n\nCo-authors\nMark Sherlock (Lawrence Livermore National Laboratory)\nDivya Tank (University of York)\nPhilip Moloney (Imperial College London)\nAidan Crilly (Imperial College London)\nJeremy Chittenden (Imperial College London)\nMatthew Oxley (University of York)\nChristopher Paul Ridgers (University of York)"},{"id":"6bb775be-d190-41d7-9bc0-7a4028afdd13","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:00:00+00:00","end":"2026-07-03T13:15:00+00:00","s":"1400","e":"1415","name":"O.529   B. Barbosa: Control of nonlinear Breit-Wheeler positrons created in multi-PW strong field QED showers","loc":"Moorfoot: Level 0","track":"BPIF: High Field and QED","type":"Session","details":"Continued developments in high-power lasers will enable intensities beyond 10^23 W/cm^2. At such intensities, a laser pulse colliding with an ultra-relativistic electron beam subjects the electrons to fields nearing the Schwinger limit, triggering strong-field QED (SFQED) processes. The dominant processes in the collision are nonlinear Compton scattering, where a charged particle emits a high-energy photon, and nonlinear Breit-Wheeler pair creation, where a photon decays into an electron-positron pair. Harnessing these processes for positron generation requires control over the processes themselves and the positrons they produce. Here, we demonstrate two approaches to controlling the properties of positrons produced during nonlinear Breit-Wheeler pair creation. In the first, the asymmetric fields of a bichromatic, circularly polarized laser pulse enable simultaneous spin-polarization and angular isolation of the created positrons, producing a positron signal that is over 50% spin-polarized and nearly devoid of electrons. In the second, the collision of a monochromatic, linearly polarized laser pulse and relativistic electron beam occurs in a plasma, where the magnetic fields excited by the laser pulse focuses the positrons and expels electrons. This focusing is energy-dependent and results in smaller energy spreads than could be achieved in a vacuum collision.\n\nAuthor\n ernardo Barbosa (GoLP/IPFN - Instituto Superior Técnico, Portugal)\n\nCo-authors\nDr Qian Qian (University of Michigan, USA)\nDr Thomas Grismayer (GoLP/IPFN - Instituto Superior Técnico, Portugal)\nDr Dillon Rasmey (Laboratory for Laser Energetics, USA)\nDr Brandon Russell (Princeton University, USA)\nDr Daniel Seipt (Helmholtz Institute Jena, Germany)\nDr Alexander Thomas (University of Michigan, USA)\nDr Kale Weichman (Laboratory for Laser Energetics, USA)\nDr John Palastro (Laboratory for Laser Energetics, USA)\nDr Marija Vranic (GoLP/IPFN - Instituto Superior Técnico, Portugal)"},{"id":"cf51e461-f9ef-47c3-9c09-1ccdde12103b","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:00:00+00:00","end":"2026-07-03T13:15:00+00:00","s":"1400","e":"1415","name":"O.526   E. Los: Extreme Astrophysics with Laboratory electron-positron jets","loc":"Tinto: Level 0","track":"BSAP : Laboratory Fundamental Plasma Physics and Astrophysics","type":"Session","details":"Relativistic electron–positron (pair) plasmas play a central role in extreme astrophysical environments, including gamma-ray bursts and pulsar winds, yet their microphysics remains poorly constrained by observations. The Fireball programme generates dense, relativistic electron–positron beams in the laboratory, enabling controlled studies of pair-plasma instabilities and particle acceleration under astrophysically relevant conditions.\n\nFireball is hosted at CERN’s High Radiation Materials facility (HiRadMat) and is currently the only scheme capable of producing relativistic pair plasmas terrestrially. In this talk, we present results from the two most recent experimental campaigns, Fireball II and Fireball III. Fireball II delivered the first experimental measurements of the magnetic-field amplification associated with beam plasma instabilities involving a relativistic pair jet. Fireball III revealed significant modifications to the longitudinal beam profile and energy spectrum, consistent with electron acceleration and positron deceleration during the beam–plasma interaction.\n\nThese results provide new experimental constraints on kinetic processes thought to operate in extreme astrophysical sources and demonstrate the potential of laboratory pair plasmas as a platform for testing relativistic plasma theory.\n\nAuthor\nEva Los"},{"id":"ee175148-2300-4877-b60b-1caea8a3eef7","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:00:00+00:00","end":"2026-07-03T13:15:00+00:00","s":"1400","e":"1415","name":"O.521 J. van Vuuren: Energetic Particle Physics and Control in the TCV Tokamak: From Alfvén Eigenmodes to Ion Cyclotron Emission","loc":"Pentland Suite: Level +3","track":"MCF: Energetic Particles","type":"Session","details":"Energetic particles (EPs) provide plasma heating and current drive in fusion devices, but their confinement can be strongly affected by Alfvén eigenmodes (AEs) and other instabilities, with implications for performance and plasma–wall interactions in ITER and DEMO. Recent experiments on the Tokamak à Configuration Variable (TCV) have advanced the physics basis for AE excitation and control in plasmas with supra-Alfvénic fast ions. Scenarios were established using both co- and counter-injected neutral beams, enabling controlled variation of fast-ion drive and systematic characterization of AE activity.\nDedicated control experiments demonstrate reproducible AE suppression using electron-cyclotron heating and current drive (ECRH/ECCD). The observations indicate that multiple mechanisms contribute, including (i) temperature and density profile modifications affecting damping and resonance conditions, (ii) magnetic-shear changes driven by localized ECCD, and (iii) direct fast-ion redistribution associated with AE dynamics and EC actuation. Comparative studies in positive and negative triangularity further show that fast-ion confinement is similar during MHD-quiescent phases, while AE activity during flat-top conditions differs between shapes, highlighting sensitivity of EP-driven stability to equilibrium and profile details.\nFinally, first observations of ion cyclotron emission (ICE) on TCV open a new diagnostic window on EP dynamics, complementing established fast-ion measurements and enabling access to high-frequency signatures linked to EP populations and wave–particle coupling. The results are discussed in the context of recent findings on other tokamaks, emphasizing common trends and constraints for robust AE control and improved EP confinement in reactor-relevant regimes.\n\nAuthor\nDr Anton Jansen van Vuuren (Swiss Plasma Center, EPFL)\n\nCo-authors\nDr Alexander Karpushov (Swiss Plasma Center, EPFL)\nDr Jesús Poley sanjuán (Swiss Plasma Center, EPFL)\nDr Mads Rud Larsen (Swiss Plasma Center, EPFL)\nDr Mario Ludovico Podesta (Swiss Plasma Center, EPFL)\nDr Mykola Dreval (Kharkov Institute of Physics and Technology)\nMr Quentin Kernel (Swiss Plasma Center, EPFL)\nSamuele Mazzi (CEA Cadarache)\nSergei Sharapov (UKAEA)"},{"id":"374014a5-51a3-418f-b516-46ec15472d08","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:00:00+00:00","end":"2026-07-03T13:25:00+00:00","s":"1400","e":"1425","name":"I.512   I. Carvalho: The ITER Research Plan and its Operational Scenarios","loc":"Sidlaw: Level +3","track":"MCF: Operation with Tungsten","type":"Session","details":"One of the key elements of the 2024 ITER baseline is a revised ITER Research Plan (IRP) that has been developed in collaboration with experts from the ITER Members’ fusion institutes. It outlines the new strategy and timeline to reach the ITER Project specifications (including 500 MW of fusion power production with Q ≥ 10 for durations longer than 300 s in a reproducible way) through a three-phase programme in which incremental steps are taken towards the full D-T performance with a more realistic management of nuclear licensing constraints. The strategy and sequence to develop the operational scenarios specified in the IRP have been significantly impacted by the switch of first wall armour from Be to W in the new baseline. This change can be both favourable and unfavourable for plasma operations. Although the consequences for Q = 10 performance have been analysed in detail using a wide range of high-fidelity modelling tools, the development and control of the IRP scenarios is a complex process, requiring sophisticated plasma control and protection systems (a central component of which is disruption mitigation) which must be in an advanced state of readiness at the start of operations. This talk will describe how the plasma scenarios necessary for the success of the IRP staged approach are constructed from the operational point of view, including how the return on experience from current devices and the particular constraints imposed by the ITER machine itself impact their design.\n\nAuthor\nIvo Carvalho (ITER Organization)\n\nCo-authors\nAlberto Loarte (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nFlorian Koechl (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nIsabel Nunes (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nJavier Artola (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nLuca Zabeo (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nMaksim Dubrov (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nMireille Schneider (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nPeter De Vries (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nRichard A. Pitts (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nSimon Pinches (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nStefan Jachmich (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nSun Hee Kim (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nTom Wauters (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)\nYuri Gribov (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 St Paul Lez Durance Cedex, France)"},{"id":"4b9fd336-b6bb-456f-8c49-604bf5d2564f","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:15:00+00:00","end":"2026-07-03T13:30:00+00:00","s":"1415","e":"1430","name":"O.530   C. Arran: Optimising non-linear Breit-Wheeler pair production in simulated laser experiments","loc":"Moorfoot: Level 0","track":"BPIF: High Field and QED","type":"Session","details":"High laser intensities enable the production of electron-positron pairs from bright gamma rays passing through strong fields. Potentially the most promising approach for all-optical experiments in the near term uses dense but higher divergence electron beams from laser wakefield acceleration to produce gamma rays through inverse Compton scattering. Achieving many-photon collisions between these gamma rays and the high intensity laser pulse in practice is extremely difficult, however, due to significant shot-to-shot jitter in laser pointing and timing. In practice, this jitter reduces the yield of electron-positron pairs by orders of magnitude.\n\nWe model these practical difficulties using simulated Monte-Carlo experiments. By using a more efficient algorithm for sampling infrequent pair production with particle splitting, we enable the exploration of a multi-dimensional parameter space. Using Gaussian Process Regression we then efficiently find optimal conditions for maximising pair production by changing the laser spot size, the energy in the colliding beam, and the stand-off distance between the laser wakefield accelerator and the focus of the colliding laser pulse. We find that the optimal stand-off distance increases with the degree of laser jitter and that the best conditions for producing electron-positron pairs are not the same as the best conditions for maximising the energy in the gamma rays. With 100 J of laser energy, we estimate realistic rates of pair production of around 1 pair per 100 electrons are achievable even with jitter of 10s of microns and 10s of femtoseconds.\n\nAuthor\nChristopher Arran (Lancaster University)\n\nCo-authors\nChristopher Paul Ridgers (University of York)\nDr Stuart Morris (AWE)"},{"id":"ec4649b6-256a-45e6-9133-3f42cab83c3c","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:15:00+00:00","end":"2026-07-03T13:30:00+00:00","s":"1415","e":"1430","name":"O.527   M. Abler: First laboratory observations of residual energy generation in strong Alfvén wave interactions","loc":"Tinto: Level 0","track":"BSAP : Laboratory Fundamental Plasma Physics and Astrophysics","type":"Session","details":"In the MHD inertial range (scales larger than ion-kinetic scales) turbulent fluctuations in the solar wind are often Alfvénic in character, meaning that their magnetic and flow velocity fluctuations are proportional to each other and predominantly perpendicular to the background magnetic field. However, observations of the solar wind have shown that there is a significant difference in the energy in velocity fluctuations and normalized magnetic fluctuations. This difference, called the residual energy, should be zero for linear Alfvén waves, but is consistently observed to be negative in the solar wind, with magnetic fluctuations dominating. This work investigates the energy partition in strong three-wave interactions through an experimental campaign on the LArge Plasma Device (LAPD) in an MHD-like regime. Primary (driven) modes are launched from antennas, and secondary modes generated by a strong three-wave interaction are observed. The primary modes are shown to have no residual energy, while the secondary modes have significant residual energy - negative in the “sum” mode and positive in the “difference” mode. These results constitute the first laboratory demonstration that residual energy can indeed be generated by nonlinear mode coupling.\n\nAuthor\nDr Mel Abler (Space Science Institute)\n\nCo-authors\nDr Seth Dorfman (Space Science Institute)\nProf. Christopher HK Chen (Queen Mary University of London)"},{"id":"1c70137c-20ff-4ead-81e8-891c2db038a2","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:15:00+00:00","end":"2026-07-03T13:30:00+00:00","s":"1415","e":"1430","name":"O.522 L. Schmitz: Zonal Flows driven by Toroidicity-induced Alfven Eigenmodes, mitigating core turbulence in DIII-D","loc":"Pentland Suite: Level +3","track":"MCF: Energetic Particles","type":"Session","details":"The interaction of fast-ion-driven Alfven Eigenmodes with axisymmetric Zonal shear flows in toroidal plasmas has recently received significant attention due to the potential stabilization of microturbulence and reduction of radial transport [1,2,3]. Here, we present clear experimental evidence that multiple simultaneous Toroidicity-induced Alfven Eigenmodes [4] drive mesoscale (\n < 1/\n <\n), radially localized Zonal shear flows and suppress ITG turbulence in DIII-D. An upper single null diverted target plasma (\n) is heated via neutral beam injection (\n), intermittently destabilizing TAE modes. Multi-channel Doppler Backscattering (DBS [5]) probes the local ExB flow, flow shear, and turbulence (density fluctuation) levels at normalized radii \n. Using two multi-channel DBS systems located 180º apart toroidally, the axisymmetric nature of the measured Zonal shear flows has been confirmed. Near mid-radius, the local ExB shearing rate increases by roughly an order of magnitude (from \nx\n2x\n) and exceeds the plasma frame turbulence decorrelation rate intermittently when multiple TAE modes are present. Simultaneously, density fluctuation levels (\n) are reduced by 35-50%, with almost perfect anti-correlation between fluctuation level and local shearing rate. The observed shear flows are not localized to low order rational surfaces. DBS measurements confirm causality (the TAE amplitude leads the maximum ZF shearing rate); in turn the local ExB shearing rate leads ITG fluctuation suppression (by ~70\n) near mid-radius (\n). In contrast, the shearing rate lags fluctuation suppression in the inner core (\n), potentially indicating shear flow drive from the turbulence spectrum at this radius. Further work will be presented to elucidate the coupling and energy exchange between TAE modes, Zonal Flows and drift wave turbulence via bispectral/transfer entropy analysis.\n*This work supported by US DoE under DE-FC02-04ER54698, DE-SC0020287, DE-SC0020337, DE-SC0019352 and DE-FG02-08ER54999.\n[1] L. Chen and F. Zonca, Phys. Rev. Lett. 109, 145002 (2012).\n[2] G.J. Choi et al., Nucl. Fusion 64, 016028 (2024).\n[3] X.D. Du et al., Phys. Rev. Lett. 135, 265101 (2025).\n[4] M.A. Van Zeeland et al., Phys. Rev. Lett. 97, 135001 (2006).\n[5] W.A. Peebles et al., Rev. Sci. Instr. 81, 10D902 (2010).\n\nAuthor\nLothar Schmitz (University of California Los Angeles)\n\nCo-authors\nW.W. Heidbrink (University of California Irvine)\nX.D. Du (General Atomics)\nT. Barberis (Princeton Plasma Physics Laboratory)\nP.H. Diamond (University of California San Diego)\nR. Hong (University of California Los Angeles)\nI. Bachant (University of California Irvine)\nK.J. Callahan (University of California Irvine)\nM. VanZeeland (General Atomics)\nZ. Yan (University of Wisconsin Madison)"},{"id":"63c721e3-9657-4864-86bb-a5b9d8ac720b","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:25:00+00:00","end":"2026-07-03T13:40:00+00:00","s":"1425","e":"1440","name":"I.212   M. Khan: The shock-augmented ignition route to high gain inertial fusion energy","loc":"Fintry: Level +3","track":"BPIF: Burning plasma and transport","type":"Session","details":"With the achievement of ignition at the National Ignition Facility (NIF), the focus of inertial confinement fusion research is turning to schemes relevant to inertial fusion energy. In particular, the move from indirect drive currently used at NIF to direct drive in which lasers illuminate the fusion fuel directly. This is expected to increase the coupling efficiency and reduce driver energy requirements. Novel implosion designs are being sought that can robustly achieve high fusion energy gain.\n\nIn the shock-augmented ignition (SAI) approach, the implosion is driven at reduced velocities that provides hydrodynamic stability and is more energetically efficient. With this reduced velocity though, ignition requires the supplemental energy of a late-timed shock wave that is launched by a sudden increase in laser intensity at the end of the pulse. However, high laser intensities stimulate laser-plasma instabilities that direct energy away from driving the shock. The novel feature of SAI is that the igniting shock wave can be launched with substantially reduced laser intensities by introducing a drop in laser power before rapidly increasing again.\n\nThe effectiveness of the scheme was experimentally demonstrated on the OMEGA laser system by the performance increase achieved by optimally timing the shock launch. Key performance metrics, such as fusion yield and hot-spot pressure, saw substantial increases when the shock was timed to arrive at the implosion centre at the point of peak convergence. The optimal timing range and trend in performance were closely matched by simulations.\n\nAuthor\nMatthew Khan (Science and Technology Facilities Council)\n\nCo-authors\nDr Aarne Lees (Laboratory for Laser Energetics)\nDr Arun Nutter (Science and Technology Facilities Council)\nDr Calum Freeman (Science and Technology Facilities Council)\nDr Christian Stoeckl (Laboratory for Laser Energetics)\nDr Duncan Barlow (CEA DAM)\nDr Justin Kunimune (MIT PSFC)\nDr Kevin Glize (Science and Technology Facilities Council)\nMrs Kristen Churnetski (Laboratory for Laser Energetics)\nProf. Nigel Woolsey (University of York)\nProf. Riccardo Betti (Laboratory for Laser Energetics)\nDr Robbie H H Scott (Science and Technology Facilities Council)\nDr Robert W Paddock (Science and Technology Facilities Council)\nProf. Roberto Mancini (University of Nevada)\nProf. Sean Regan (Laboratory for Laser Energetics)\nProf. Wolfgang Theobald (Focused Energy GmbH)"},{"id":"d8e7287f-0a27-4e9e-b464-abb4f2d0b864","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:25:00+00:00","end":"2026-07-03T13:40:00+00:00","s":"1425","e":"1440","name":"O.524   P. Maget: Tungsten dust ingress in WEST: an integrated modelling approach","loc":"Sidlaw: Level +3","track":"MCF: Operation with Tungsten","type":"Session","details":"Tokamak operation with tungsten walls, as foreseen in ITER and future fusion-based power plants, faces the potential strong impact of tunsgten dust ingress in the plasma. This was documented on the WEST tokamak [Bucalossi2024], equipped with an ITER-grade tungsten divertor, during a high fluence campaign in attached divertor condition: the erosion of tungsten monoblocks generated deposits that could detach and trigger plasma disruptions [Gaspar2024]. The operation in a radiative divertor regime mitigates the risk of building tungsten deposits [Gaspar2026], but a deterioration of plasma operation could be seen after cumulating the equivalent of a single ITER pulse (Q=10, 400s) in attached divertor condition. Being able to predict the impact of such dusts in present tokamaks is therefore instrumental, although the task is on many aspects extremely complex [Smirnov2020]. The modelling of tungsten dust penetration in WEST is performed with the DUSTTRACK code [Gervasini2027], investigating the tungsten deposition dependence on the dust size and speed. It shows that for similar range of size and speed, the dust is penetrating further inside in WEST compared to JET [Lazzaro2022], due to the lower plasma temperature. The impact on the plasma evolution is then modelled with the High Fidelity Pulse Simulator (HFPS) based on JINTRAC [Romanelli2024], with different levels of complexity, from a prediction of current diffusion only, up to a prediction of particle (D, N and W) and heat transport using TGLF [Staebler2021]. With current diffusion only, resistive MHD mode triggering on q=2/1 is found for a dust mass above 20µg, consistent with experimental observations [Maget2024]. With the more complete simulation scheme, we find that the localization of the tungsten source inside the plasma boundary plays an essential role in the observed plasma evolution. The validation of this workflow on WEST is a first step towards the evaluation of the maximum allowed dust size in larger tokamaks and the associated mitigation strategies.\n\n[Bucalossi2024] Bucalossi J et al, Nuclear Fusion 64, 112022, 2024\n[Gaspar2024] Gaspar J et al, Nuclear Materials and Energy 41, 101745, 2024\n[Gaspar2026] Gaspar J et al, Plasma Surface Interaction Conference, 2026\n[Smirnov2020] Smirnov R et al, Phys. Plasmas 27, 082509, 2020\n[Gervasini2027] Gervasini G et al, J Fusion Energy 36, 25, 2017\n[Lazzaro2022] Lazzaro E et al, Nucl. Fusion 62, 126037, 2022\n[Romanelli2024] Romanelli M et al, Plasma and Fusion Research 9, 3403023, 2014\n[Staebler2021] Staebler G et al, Nuclear Fusion 61, 116007, 2021\n[Maget2024] Maget P et al, Plasma Phys. Control. Fusion 67, 045005, 2025\n\nAuthors\nPatrick MAGET (CEA)\nDr Gabriele Gervasini (Institute for Plasma Science and Technology, CNR, 20125 Milano, Italy)\nDr Enzo Lazzaro (Institute for Plasma Science and Technology, CNR, 20125 Milano, Italy)\nFrancis Casson (CCFE, Culham Science Centre, Abingdon OX14 3DB, United Kingdom of Great Britain and Northern Ireland)\nDr Federica Causa (Institute for Plasma Science and Technology, CNR, 20125 Milano, Italy)\nDr Pascal Devynck (CEA, IRFM, F-13108 Saint Paul-lez-Durance, France)\nNicolas Fedorczak (CEA, IRFM, F-13108 Saint Paul-lez-Durance, France)\nDr Jonathan Gaspar (Aix Marseille Univ, CNRS, IUSTI, Marseille, France)\nDr James Gunn (CEA, IRFM, F-13108 Saint Paul-lez-Durance, France)\nAlexis Huart (CEA, IRFM, F-13108 Saint Paul-lez-Durance, France)\nFlorian Koechl (ITER Organization, Route de Vinon-sur-Verdon, CS 90 046, 13067 Saint Paul-lezDurance Cedex, France)\nPierre Manas (CEA, IRFM, F-13108 Saint Paul-lez-Durance, France)\nDr Nicolas Rivals (CEA, IRFM, F-13108 Saint Paul-lez-Durance, France)\nPresentation materials"},{"id":"3663849b-bd9d-4260-9821-cba2dff546f3","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:30:00+00:00","end":"2026-07-03T13:45:00+00:00","s":"1430","e":"1445","name":"O.531 P. Gellersen: Experimental measurement of strong-field QED effects at the ZEUS facility","loc":"Moorfoot: Level 0","track":"BPIF: High Field and QED","type":"Session","details":"Strong-field QED (SFQED) is the regime of physics where effective fields are comparable to Ec = 1.3 x 1018 V/m, the critical field of QED. In this regime several exotic processes can be observed such as non-linear Compton scattering and non-linear Breit-Wheeler pair production. In addition, radiation reaction - the recoil experienced by particles radiating in these fields - takes a different form from classical predictions and exhibits stochasticity. Such fields and physics are relevant to astrophysical objects like magnetars and pulsars, but experimental investigation of this area is limited by the difficulty in generating such large fields.\n\nCurrently the highest power laser beams tightly-focused can still only reach fields of order 1014 V/m, but when combined with a counter-propagating relativistic particle beam the fields in the frame of the particles are upshifted to order 1017-1018 V/m, close to Ec. These relativistic beams can be generated by laser-wakefield acceleration, allowing SFQED experiments to be carried out using lasers only as drivers, with the additional advantage that achieving spatial and temporal overlap of the beams is easier. Our collaboration has previously carried out experiments of this type on the Gemini facility [1,2,3], but the ZEUS facility provides higher power beams and therefore access to stronger field interactions.\n\nIn this talk we will present an experiment carried out in September 2025 in which electron beams up to 2 GeV were generated by laser-wakefield acceleration and collided with a 200 TW beam focused to intensity ~5 x 1020 W/cm2. The electrons were diagnosed by a magnetic spectrometer, and the gamma rays generated by the collision by a LYSO profiler and CsI stack spectrometer. We will present combined analysis of these, with supporting simulations, to estimate collision parameters and SFQED effects observed.\n\nReferences:\n1. J M Cole et al, Phys Rev X 8, 011020, 2018\n2. K Poder et al, Phys Rev X 8, 031004, 2018\n3. E E Los et al, Nat Commun 17, 1157, 2026\n\nAuthor\nPaul Gellersen (University of York)\n\nCo-authors\nDr Brendan Kettle (Imperial College London)\nChris Murphy (University of York)\nChristopher Arran (Lancaster University)\nChristopher Paul Ridgers (University of York)\nDr Conor McAnespie (Queen's University Belfast)\nElias Gerstmayr (Queen's University Belfast)\nEva Los\nDr Gianluca Sarri (Queen's University Belfast)\nMs Hannah Jager (Queen's University Belfast)\nDr Matthew Streeter (Queen's University Belfast)\nOwen Lawrence (University of York)\nDr Stuart Mangles (Imperial College London)\nDr Yong Ma (University of Michigan)\nZEUS facility team (University of Michigan)"},{"id":"e86842fc-d874-42ed-af8a-05b44478f0df","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:30:00+00:00","end":"2026-07-03T13:45:00+00:00","s":"1430","e":"1445","name":"O.528   V. Stergiou: Permanent magnet-based focusing setup for MeV/c electron-positron pair beams","loc":"Tinto: Level 0","track":"BSAP : Laboratory Fundamental Plasma Physics and Astrophysics","type":"Session","details":"Relativistic outflows enriched with electron-positron pair plasma can be found in various highly energetic astrophysical environments, such as those around active galactic nuclei, black holes, or in the jets of gamma ray bursts. Understanding the mechanisms involved in the generation of particular types of plasma instabilities during the propagation of such jets is important in order to explain the radiative signature of their outflows observed on Earth. Until now, the understanding of electron-positron pair plasmas has been based on numerical studies limited in the quasi-linear regime, while experimental realizations of high charge density, quasi-neutral beams have been challenging. In our experiments, inaugurating and improving a newly developed experimental platform for such studies at the HiRadMat facility of CERN, high intensity, high density, ultra-relativistic, quasi-neutral electron-positron pair beam production was achieved, opening up the possibility to study the microphysics of such pair plasmas via experimental means.\n\nIn our experiments, we confirmed that the growth of plasma instabilities as the pair beam propagates through ambient plasma is greatly affected by the divergence and momentum spread of the pair beams. We present a study on the implementation and the performance limitations of a beam focusing setup used in one of our experiments. We designed a quadrupole triplet, based on custom-made permanent magnet quadrupoles, aiming to improve the optical and momentum properties of the electron-positron pair beam towards an increased e-/e+ density. A comparison between the experimental results and the expected performance given by different computational tools, along with the challenges of such a setup that should be considered for future implementations, is presented in this work.\n\nAuthor\nVasiliki Stergiou (University of Oxford (GB))\n\nCo-authors\nAlice Goillot (HiRadMat, CERN, Geneva, Switzerland)\nAndrea Boccardi (CERN)\nCharles D. Arrowsmith (University of Rochester Laboratory for Laser Energetics, Rochester, NY, USA)\nGianluca Gregori (University of Oxford)\nJack Halliday (Rutherford Appleton Laboratory)\nJon T. Gudmundsson (Science Institute, University of Iceland, Reykjavik, Iceland)\nMatteo Capitani (CERN)\nNikolaos Charitonidis (HiRadMat, CERN, Geneva, Switzerland)\nPablo Bilbao (University of Oxford, Oxford, United Kingdom)\nParaskevi Alexaki (HiRadMat, CERN, Geneva, Switzerland)\nPascal Simon (GSI Helmholtzzentrum für Schwerionenforschung GmbH, Darmstadt, Germany)\nRobert Bingham (SUPA and Department of Physics, University of Strathclyde, Glasgow, UK; and STFC Rutherford Appleton Laboratory, Didcot, UK)\nStephane Burger (CERN)\nVasiliki Tsouknida (National Technical University of Athens)"},{"id":"86fa1732-cdb8-4bd2-bed2-ddc2eaca4b37","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:30:00+00:00","end":"2026-07-03T13:45:00+00:00","s":"1430","e":"1445","name":"O.523 G. Brochard: Verification and validation of AE dynamics with realistic energetic particle distributions in DIII-D plasmas","loc":"Pentland Suite: Level +3","track":"MCF: Energetic Particles","type":"Session","details":"The linear stability and nonlinear dynamics of Energetic Particle (EP)-driven modes is strongly dependent on the phase space gradients of EP distributions, since these modes are driven unstable by wave-particle resonances locally in phase space [1]. Even though EPs are far from thermodynamic equilibrium, their distribution function is often reduced in numerical modelling to local Maxwellians, or more realistic analytical forms taking into account the EP slowing-down physics, which tends to under-estimate the instabilities drive at high EP energy [2]. Therefore, for accurate predictions of EP-driven modes dynamics in upcoming burning plasmas and more importantly their cross-scale interaction with microturbulence, which depends heavily on the drive ratio between drift-waves and EP-driven modes [3], realistic numerical distributions are required in kinetic-MHD/gyrokinetic modelling.\nIn this contribution, we report progress made within the ITPA-EP activities, on the numerical verification and experimental validation of gyrokinetic and kinetic-MHD codes using realistic EP distributions. A DIII-D discharge has been chosen for this activity [4], where the stability of BAEs is influenced by changes in beam injection direction. Realistic EP distributions are obtained from NUBEAM [5]. Such inputs are generally too noisy to initialise \n or full-F codes. They are therefore transformed into \n distributions in the 3D constants of motion (CoM) space \n by the EPCoM code [6]. In addition to providing numerically smooth distributions, this approach enables a direct identification of instability drive in a phase space where wave-particle resonances can be explicitly identify.\nIn particular, results from the gyrokinetic codes GTC [7] and the kinetic-MHD codes M3D-C1 [8] and XTOR-K [9] will be presented. These codes agree well regarding the AE linear stability using either EP realistic distributions or equivalent Maxwellians. The AE drive with realistic beam distributions is much stronger than with equivalent Maxwellians. CoM space analysis reveals that although anisotropic beam EPs have less wave-particle resonances available, they lead to stronger drive because the local gradient drive \n is 10 times stronger than its equivalent Maxwellian. The dependence of AE stability on beam injection angle will be compared between simulations and the experiment, as well as the modes nonlinear saturation and the associated EP transport.\n\n[1] L. Chen et al. Phys. Rev. Lett. 52, 112 (1984)\n[2] G. Brochard et al., Phys. Rev. Lett. 132, 075101 (2024)\n[3] A. Ishizawa et al., Commun Phys 8, 486 (2025)\n[4] W. W. Heidbrink et al., Nucl. Fusion 61 066031 (2021)\n[5] A. Pankin, Comput. Phys. Commun. 159 157 (2004)\n[6] G.Brochard et al., to be submitted to Comput. Phys. Commun. (2026)\n[7] Z. Lin et al., Science 281 1835–7 (1998)\n[8] S. C. Jardin et al., Comput. Sci. Discovery 5 014002 (2012)\n[9] G. Brochard et al. Nucl. Fusion 60 086002 (2020a)\n\nAuthor\nGuillaume Brochard (CNRS / Aix-Marseille University, PIIM laboratory)\n\nCo-authors\nAndreas Bierwage (National Institutes for Quantum Science and Technology)\nChang Liu (Physics Department, Peking University, Beijing, China)\nJames Carpenter (Durham University)\nMatteo Valerio Falessi (ENEA)\nDr Michael Van Zeeland (General Atomics)\nPhilipp Lauber (Max Planck Institute for Plasma Physics)\nSimon Pinches (ITER Organization)\nDr Thomas Hayward-Schneider (Max Planck Institute for Plasma Physics)\nDr Xiaodi Du (General Atomcs)\nDr Xin Wang (Max Planck Institute for Plasma Physics)\nProf. Zhihong Lin (University of California Irvine)"},{"id":"29b49f54-e6cf-4037-8abf-475decf035d2","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:40:00+00:00","end":"2026-07-03T13:55:00+00:00","s":"1440","e":"1455","name":"O.525   C. Olde: Core tungsten transport of internal transport barrier scenarios in JET with Be/W wall","loc":"Sidlaw: Level +3","track":"MCF: Operation with Tungsten","type":"Session","details":"Avoiding tungsten (W) accumulation in the core plasma will be vital for successful operations of next generation tokamaks. For the development of high-performance scenarios, which target steady state operation, it is essential that core W transport and the plasma conditions required for impurity screening at the confined plasma periphery are understood. Spontaneous formation of internal transport barriers (ITBs) may also occur in burning plasma scenarios, motivating the need to understand ITB physics to maintain control of the barrier’s strength or prevent it entirely. Studies of core impurity transport in ITB plasmas in JET-C found evidence of core impurity accumulation due to neoclassical transport, which dominates inside the ITB where the turbulent transport is stabilised [1, 2]. Previous analysis of JET-ILW (Be/W wall) hybrid scenarios demonstrated peripheral tungsten screening in D and DT plasmas [3, 4]. This analysis builds upon previous work by investigating core W transport in ITB scenarios in JET-ILW.\nStrong ITBs have been produced in low density \n JET-ILW plasmas with high NBI heating that generates high core ion temperature \n, high toroidal Mach number \n and a peaked \n profile [5]. The resulting steep \n and \n gradients have substantial effects on the neoclassical transport that dominates core W transport. Due to the sizeable concentrations of Be and Ni in these pulses, impurity-impurity collisions must be retained for accurate core W transport predictions. The drift-kinetic code NEO [6] used in this modelling captures this important physics, predicting core W accumulation after the formation of the strong ITB, which weakens outward convection of W. An integrated impurity analysis tool [7] enables interpretative analysis of the plasma impurity composition, using experimental measurements from multiple diagnostics. This tool provides input Be and Ni density profiles, which are the dominant contributors to \n, as well as W density profiles. NEO predictions are consistent with the experimental measurements, indicating core W accumulation, which codes using simplified approximations of neoclassical transport are unable to reproduce. Sensitivity scans on the gradients of key driving parameters \n, \n are performed within experimental uncertainties to enhance confidence in the model predictions.\n\nAuthor\nCameron Olde (UKAEA)\n\nCo-authors\nC Maggi (UKAEA)\nFrancis Casson (UKAEA)\nAnthony R Field (UKAEA)\nE Delabie\nEvie Litherland-Smith\nItziar Balboa (UKAEA)\nDr Michael Fitzgerald (CCFE, UK Atomic Energy Authority)\nMichał Poradziński (IPPLM)\nSheena Menmuir (UKAEA)\nŽiga Štancar (UK Atomic Energy Authority)\nEUROfusion Tokamak Exploitation Team\nJET Contributors"},{"id":"58e31d47-f58f-4f13-96b7-b97a9d6dca6c","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T13:55:00+00:00","end":"2026-07-03T14:25:00+00:00","s":"1455","e":"1525","name":"I.513   D. Fajardo (PhD prize): Theory-based integrated modelling of impurity transport in tokamaks","loc":"Sidlaw: Level +3","track":"MCF: Operation with Tungsten","type":"Session","details":"Impurities play a critical role in the integration of a hot plasma core with a cold plasma edge, which are simultaneous requirements for the viable operation of a fusion reactor. Core radiation and fuel dilution set stringent limits on the tolerable impurity concentrations to sustain thermonuclear conditions or even for the survival of the plasma itself. At the same time, injected impurities will be essential to safely dissipate excess heat before it reaches the reactor walls.\nAn integrated modelling workflow including impurities and their radiation has been developed, combining all presently known theoretical elements in the local description of quasi-linear turbulent and collisional impurity transport. An analytical model which describes the crucial effects of toroidal rotation on the neoclassical transport of impurities is introduced and shown to be accurate with respect to more complete codes but better suited for fast applications.\nThe workflow is validated against experimental data from a variety of plasmas in the ASDEX Upgrade tokamak. The modelling is able to reproduce measurements of the main plasma profiles, the impurity densities, and the radiated powers of L-mode discharges in full-radius simulations, including a discharge with impurity seeding and a high radiated power fraction.\nFurthermore, the control of impurity accumulation with central wave heating is investigated for H-mode plasmas with dominant neutral beam heating. The workflow is shown to quantitatively reproduce the experimentally observed reduction of tungsten (W) peaking at increasing wave heating power, and the physics behind this important experimental technique is analyzed.\nHaving validated the physics-based modelling workflow, a predictive study of the 15 MA ITER baseline scenario is presented, investigating the interplay between the edge concentration, transport and radiation of W, the auxiliary heating required to sustain H-mode operation, and the fusion performance. It is shown that heavy impurities are in a different core transport regime in reactors compared to present-day devices. Furthermore, the transport and effects of W in electron-heated ITER plasmas at lower currents and fields, as well as during the current ramp-up, are investigated. Overall, this analysis contributes to a more solid definition of the domain of operational conditions which allow the achievement of the main ITER targets, in particular in view of its recently proposed full-tungsten walls.\n\nAuthor\nDr Daniel Fajardo (Max-Planck-Institut für Plasmaphysik, Garching, Germany)"},{"id":"ac92bf6a-0e82-463f-a0d3-017d112da6c2","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T14:30:00+00:00","end":"2026-07-03T15:00:00+00:00","s":"1530","e":"1600","name":"***Friday: Afternoon Refreshment Break***","loc":"Cromdale: Level -2","track":"","type":"Function","details":""},{"id":"4e9d1390-fb86-4521-81cf-f41d7472b530","date":"2026-07-03","dayLabel":"Friday, July 3, 2026","start":"2026-07-03T15:00:00+00:00","end":"2026-07-03T16:00:00+00:00","s":"1600","e":"1700","name":"EPS 2026 Closing Ceremony","loc":"Pentland Suite: Level +3","track":"Plenary","type":"Session","details":""}];
